function invoiceIdFromStripeSubscription(
  subscription: Record<string, unknown>,
): string {
  const inv = subscription.latest_invoice;
  if (typeof inv === "string" && inv) return inv;
  if (inv && typeof inv === "object") {
    return String((inv as { id?: string }).id ?? "");
  }
  return `sub_${String(subscription.id ?? "unknown")}`;
}

function invoiceAmountUsdFromSubscription(
  subscription: Record<string, unknown>,
): number {
  const inv = subscription.latest_invoice;
  if (inv && typeof inv === "object") {
    const paid = Number((inv as { amount_paid?: number }).amount_paid ?? 0);
    if (paid > 0) return paid / 100;
  }
  return BILLING_PLAN_DEFAULTS.platformFeeUsd;
}

/** Idempotent Encore-branded subscription receipt (first payment + renewals). */
export async function sendBillingSubscriptionReceiptEmail(
  pool: Pool,
  tenantId: number,
  subscription: Record<string, unknown>,
  recipientEmail?: string | null,
): Promise<{ sent: boolean; skipped?: string; error?: string }> {
  const invoiceId = invoiceIdFromStripeSubscription(subscription);
  if (!invoiceId) {
    return { sent: false, skipped: "no_invoice_id" };
  }
  if (await billingSubscriptionReceiptAlreadySent(pool, tenantId, invoiceId)) {
    return { sent: false, skipped: "already_sent" };
  }

  const recipients = await resolveBillingEmailRecipients(
    pool,
    tenantId,
    recipientEmail,
  );
  if (!recipients.length) {
    return { sent: false, skipped: "no_recipient" };
  }

  const companyName = await fetchTenantCompanyName(pool, tenantId);
  const periodStart =
    stripePeriodToSqlDate(subscription.current_period_start) ??
    new Date().toISOString().slice(0, 10);
  const periodEnd =
    stripePeriodToSqlDate(subscription.current_period_end) ?? periodStart;
  const subscriptionId = String(subscription.id ?? "");
  const amountUsd = invoiceAmountUsdFromSubscription(subscription);
  const billingUrl = `${getBillingReturnBaseUrl()}/admin/billing`;

  let sentAny = false;
  let lastError: string | undefined;

  for (const recipient of recipients) {
    const html = buildBillingSubscriptionReceiptEmailHtml({
      recipientName: recipient.name,
      companyName,
      amountUsd,
      periodStart,
      periodEnd,
      subscriptionId,
      invoiceId,
      billingUrl,
      paidAt: new Date(),
    });

    const sendResult = await sendEmailMessage(
      recipient.email,
      `Subscription confirmed — ${companyName}`,
      html,
      true,
      undefined,
      { billing: systemEmailQuota("billing_subscription_receipt", invoiceId) },
    );

    if (sendResult.success) {
      sentAny = true;
    } else {
      lastError = sendResult.error ?? "send_failed";
    }
  }

  if (!sentAny) {
    return { sent: false, error: lastError ?? "send_failed" };
  }

  await markBillingSubscriptionReceiptSent(pool, tenantId, invoiceId);
  return { sent: true };
}

/** Idempotent payment-failed notice when Stripe renewal is declined. */
export async function sendBillingPaymentFailedEmail(
  pool: Pool,
  tenantId: number,
  invoice: Record<string, unknown>,
  graceEndsAt: Date,
): Promise<{ sent: boolean; skipped?: string; error?: string }> {
  const invoiceId = String(invoice.id ?? "");
  if (!invoiceId) {
    return { sent: false, skipped: "no_invoice_id" };
  }
  if (await billingPaymentFailedAlreadySent(pool, tenantId, invoiceId)) {
    return { sent: false, skipped: "already_sent" };
  }

  const recipients = await resolveBillingEmailRecipients(pool, tenantId);
  if (!recipients.length) {
    return { sent: false, skipped: "no_recipient" };
  }

  const companyName = await fetchTenantCompanyName(pool, tenantId);
  const amountUsd =
    Number((invoice as { amount_due?: number }).amount_due ?? 0) / 100 ||
    BILLING_PLAN_DEFAULTS.platformFeeUsd;
  const billingUrl = `${getBillingReturnBaseUrl()}/admin/billing`;
  const updatePaymentUrl =
    (invoice as { hosted_invoice_url?: string | null }).hosted_invoice_url ??
    billingUrl;

  let sentAny = false;
  let lastError: string | undefined;

  for (const recipient of recipients) {
    const html = buildBillingPaymentFailedEmailHtml({
      recipientName: recipient.name,
      companyName,
      amountUsd,
      graceEndsAt,
      invoiceId,
      billingUrl,
      updatePaymentUrl,
    });

    const sendResult = await sendEmailMessage(
      recipient.email,
      `Payment failed — update your card (${companyName})`,
      html,
      true,
      undefined,
      { billing: systemEmailQuota("billing_payment_failed", invoiceId) },
    );

    if (sendResult.success) {
      sentAny = true;
    } else {
      lastError = sendResult.error ?? "send_failed";
    }
  }

  if (!sentAny) {
    return { sent: false, error: lastError ?? "send_failed" };
  }

  await markBillingPaymentFailedSent(pool, tenantId, invoiceId);
  return { sent: true };
}

/** Reset quota ledger/period rows to plan defaults for the canonical subscription period. */
export async function resetTenantBillingQuotaToPlanDefaults(
  pool: Pool,
  tenantId: number,
): Promise<void> {
  await pool.query(
    `DELETE FROM tenant_usage_ledger WHERE tenant_id = ? AND action = 'top_up'`,
    [tenantId],
  );

  const [subRows] = await pool.query<RowDataPacket[]>(
    `SELECT period_start,
            included_sms_segments, included_voice_minutes, included_email_sends,
            included_scheduler_bookings, included_mortgi_ai_tokens
     FROM tenant_subscription WHERE tenant_id = ? LIMIT 1`,
    [tenantId],
  );
  const sub = subRows[0];
  if (!sub) return;

  const periodStart =
    toSqlDate(sub.period_start) ?? currentCalendarMonthStart();

  await pool.query(`DELETE FROM tenant_usage_period WHERE tenant_id = ?`, [
    tenantId,
  ]);

  const dimensions: Array<[UsageDimension, number]> = [
    [
      "sms_segments",
      Number(
        sub.included_sms_segments ?? BILLING_PLAN_DEFAULTS.includedSmsSegments,
      ),
    ],
    [
      "voice_minutes",
      Number(
        sub.included_voice_minutes ??
          BILLING_PLAN_DEFAULTS.includedVoiceMinutes,
      ),
    ],
    [
      "email_sends",
      Number(
        sub.included_email_sends ?? BILLING_PLAN_DEFAULTS.includedEmailSends,
      ),
    ],
    [
      "scheduler_bookings",
      Number(
        sub.included_scheduler_bookings ??
          BILLING_PLAN_DEFAULTS.includedSchedulerBookings,
      ),
    ],
    [
      "mortgi_ai_tokens",
      Number(
        sub.included_mortgi_ai_tokens ??
          BILLING_PLAN_DEFAULTS.includedMortgiAiTokens,
      ),
    ],
  ];

  for (const [dimension, includedUnits] of dimensions) {
    await pool.query(
      `INSERT INTO tenant_usage_period
         (tenant_id, period_start, dimension, included_units, used_units, reserved_units)
       VALUES (?, ?, ?, ?, 0, 0)`,
      [tenantId, periodStart, dimension, includedUnits],
    );
  }
}

async function cancelAllStripeCustomerSubscriptions(
  stripe: StripeClient,
  customerId: string,
): Promise<void> {
  let startingAfter: string | undefined;
  for (;;) {
    const page = await stripe.subscriptions.list({
      customer: customerId,
      status: "all",
      limit: 100,
      ...(startingAfter ? { starting_after: startingAfter } : {}),
    });
    for (const sub of page.data) {
      const status = String(sub.status ?? "");
      if (status !== "canceled" && status !== "incomplete_expired") {
        await stripe.subscriptions.cancel(String(sub.id));
      }
    }
    if (!page.has_more || page.data.length === 0) break;
    startingAfter = String(page.data[page.data.length - 1]?.id ?? "");
    if (!startingAfter) break;
  }
}

export async function resetStripeSubscriptionForTest(
  pool: Pool,
  stripe: StripeClient,
  tenantId: number,
): Promise<{ reset: boolean; message: string }> {
  const billing = await loadTenantStripeBilling(pool, tenantId);
  const periodStart = currentCalendarMonthStart();

  if (billing.stripeCustomerId) {
    try {
      await cancelAllStripeCustomerSubscriptions(
        stripe,
        billing.stripeCustomerId,
      );
    } catch (err) {
      console.error(
        "Stripe test reset: cancel customer subscriptions failed:",
        err,
      );
      throw new Error("Failed to cancel Stripe test subscriptions");
    }
  } else if (billing.stripeSubscriptionId) {
    try {
      const sub = await stripe.subscriptions.retrieve(
        billing.stripeSubscriptionId,
      );
      const status = String(sub.status ?? "");
      if (status !== "canceled" && status !== "incomplete_expired") {
        await stripe.subscriptions.cancel(billing.stripeSubscriptionId);
      }
    } catch (err) {
      console.error("Stripe test reset cancel failed:", err);
      throw new Error("Failed to cancel Stripe test subscription");
    }
  }

  await pool.query(
    `UPDATE tenant_subscription
     SET stripe_subscription_id = NULL,
         status = 'inactive',
         period_start = ?,
         period_end = NULL,
         past_due_at = NULL,
         grace_ends_at = NULL,
         restricted_at = NULL,
         suspended_at = NULL,
         updated_at = UTC_TIMESTAMP()
     WHERE tenant_id = ?`,
    [periodStart, tenantId],
  );

  await resetTenantBillingQuotaToPlanDefaults(pool, tenantId);

  await pool.query(
    `DELETE FROM system_settings
     WHERE tenant_id = ? AND setting_key LIKE 'billing_receipt_sent_%'`,
    [tenantId],
  );

  await pool.query(`DELETE FROM stripe_webhook_events`);

  return {
    reset: true,
    message:
      "Test billing reset — subscription canceled, quotas cleared. Click “Start subscription checkout” to subscribe again.",
  };
}

function mapStripeSubscriptionStatus(
  status: string,
): "active" | "trialing" | "past_due" | "canceled" | "inactive" {
  const s = status.toLowerCase();
  if (s === "active") return "active";
  if (s === "trialing") return "trialing";
  if (s === "canceled" || s === "incomplete_expired") return "canceled";
  if (s === "past_due" || s === "unpaid") return "past_due";
  if (s === "incomplete") return "inactive";
  return "inactive";
}

function getSubscriptionPlatformPriceId(
  subscription: Record<string, unknown>,
): string | null {
  const items = subscription.items as
    | { data?: Array<{ price?: string | { id?: string } }> }
    | undefined;
  const price = items?.data?.[0]?.price;
  if (!price) return null;
  if (typeof price === "string") return price;
  return price.id ?? null;
}

async function clearDbStripeSubscriptionId(
  pool: Pool,
  tenantId: number,
): Promise<void> {
  await pool.query(
    `UPDATE tenant_subscription
     SET stripe_subscription_id = NULL, status = 'inactive', updated_at = UTC_TIMESTAMP()
     WHERE tenant_id = ?`,
    [tenantId],
  );
}

function stripePeriodToSqlDate(unixSeconds: unknown): string | null {
  const n = Number(unixSeconds);
  if (!Number.isFinite(n) || n <= 0) return null;
  const d = new Date(n * 1000);
  return `${d.getUTCFullYear()}-${String(d.getUTCMonth() + 1).padStart(2, "0")}-${String(d.getUTCDate()).padStart(2, "0")}`;
}

/** Stripe Basil+ uses invoice.confirmation_secret; older API used payment_intent. Max 4 expand levels. */
const SUBSCRIPTION_PAYMENT_EXPAND = [
  "latest_invoice.confirmation_secret",
  "latest_invoice.payment_intent",
] as const;

function extractSubscriptionPaymentClientSecret(
  subscription: Record<string, unknown>,
): string | null {
  const invoice = subscription.latest_invoice as
    | Record<string, unknown>
    | string
    | null
    | undefined;
  if (!invoice || typeof invoice === "string") return null;

  const confirmationSecret = invoice.confirmation_secret as
    | { client_secret?: string }
    | null
    | undefined;
  if (typeof confirmationSecret?.client_secret === "string") {
    return confirmationSecret.client_secret;
  }

  const pi = invoice.payment_intent as
    | Record<string, unknown>
    | string
    | null
    | undefined;
  if (pi && typeof pi !== "string") {
    const legacySecret = pi.client_secret;
    if (typeof legacySecret === "string") return legacySecret;
  }

  const payments = invoice.payments as
    | {
        data?: Array<{
          payment?: { payment_intent?: Record<string, unknown> | string };
        }>;
      }
    | undefined;
  const nestedPi = payments?.data?.[0]?.payment?.payment_intent;
  if (nestedPi && typeof nestedPi !== "string") {
    const nestedSecret = nestedPi.client_secret;
    if (typeof nestedSecret === "string") return nestedSecret;
  }

  return null;
}

async function loadTenantStripeBilling(
  pool: Pool,
  tenantId: number,
): Promise<{
  stripeCustomerId: string | null;
  stripeSubscriptionId: string | null;
  status: string | null;
}> {
  const [rows] = await pool.query(
    `SELECT stripe_customer_id, stripe_subscription_id, status
     FROM tenant_subscription WHERE tenant_id = ? LIMIT 1`,
    [tenantId],
  );
  const row = (
    rows as {
      stripe_customer_id?: string;
      stripe_subscription_id?: string;
      status?: string;
    }[]
  )[0];
  return {
    stripeCustomerId: row?.stripe_customer_id ?? null,
    stripeSubscriptionId: row?.stripe_subscription_id ?? null,
    status: row?.status ?? null,
  };
}

async function syncStripeSubscriptionToDb(
  pool: Pool,
  tenantId: number,
  subscription: Record<string, unknown>,
): Promise<void> {
  await ensureTenantSubscription(pool, tenantId);
  const subId = String(subscription.id ?? "");
  const mapped = mapStripeSubscriptionStatus(
    String(subscription.status ?? "inactive"),
  );
  const periodStart = stripePeriodToSqlDate(subscription.current_period_start);
  const periodEnd = stripePeriodToSqlDate(subscription.current_period_end);

  await pool.query(
    `UPDATE tenant_subscription
     SET stripe_subscription_id = COALESCE(?, stripe_subscription_id),
         status = ?,
         period_start = COALESCE(?, period_start),
         period_end = COALESCE(?, period_end),
         updated_at = UTC_TIMESTAMP()
     WHERE tenant_id = ?`,
    [subId || null, mapped, periodStart, periodEnd, tenantId],
  );

  if (mapped === "active" || mapped === "trialing") {
    await markSubscriptionActive(pool, tenantId);
  } else if (mapped === "past_due") {
    const graceDays = await getGraceDays(pool, tenantId);
    await markSubscriptionPastDue(pool, tenantId, graceDays);
  }
}

function paymentMethodIdFromSetupIntent(
  paymentMethod: string | { id?: string } | null | undefined,
): string | null {
  if (!paymentMethod) return null;
  if (typeof paymentMethod === "string") return paymentMethod;
  return paymentMethod.id ?? null;
}

function summarizePaymentMethod(
  paymentMethod: Record<string, unknown> | null | undefined,
): {
  id: string;
  brand: string;
  last4: string;
  expMonth: number;
  expYear: number;
} | null {
  if (!paymentMethod || typeof paymentMethod !== "object") return null;
  const id = String(paymentMethod.id ?? "");
  const card = paymentMethod.card as StripePaymentMethodCard | undefined;
  if (!id || !card?.last4) return null;
  return {
    id,
    brand: String(card.brand ?? "card"),
    last4: String(card.last4),
    expMonth: Number(card.exp_month ?? 0),
    expYear: Number(card.exp_year ?? 0),
  };
}

async function fetchSavedPaymentMethodSummary(
  stripe: StripeClient,
  customerId: string,
  subscriptionId?: string | null,
): Promise<ReturnType<typeof summarizePaymentMethod>> {
  try {
    const customer = await stripe.customers.retrieve(customerId, {
      expand: ["invoice_settings.default_payment_method"],
    });
    const invoiceSettings = customer.invoice_settings as
      | { default_payment_method?: Record<string, unknown> | string | null }
      | undefined;
    const pm = invoiceSettings?.default_payment_method;
    if (pm && typeof pm !== "string") {
      const summarized = summarizePaymentMethod(pm);
      if (summarized) return summarized;
    }
  } catch (err) {
    console.warn("Stripe customer payment method lookup failed:", err);
  }

  if (!subscriptionId) return null;

  try {
    const sub = await stripe.subscriptions.retrieve(subscriptionId, {
      expand: ["default_payment_method"],
    });
    const subPm = sub.default_payment_method;
    if (subPm && typeof subPm !== "string") {
      const summarized = summarizePaymentMethod(
        subPm as Record<string, unknown>,
      );
      if (summarized) return summarized;
    }
    if (typeof subPm === "string") {
      const retrieved = await stripe.paymentMethods.retrieve(subPm);
      return summarizePaymentMethod(
        retrieved as unknown as Record<string, unknown>,
      );
    }
  } catch (err) {
    console.warn("Stripe subscription payment method lookup failed:", err);
  }

  return null;
}

async function syncSubscriptionDefaultPaymentMethod(
  pool: Pool,
  stripe: StripeClient,
  tenantId: number,
  subscription: Record<string, unknown>,
): Promise<ReturnType<typeof summarizePaymentMethod>> {
  let pmId = paymentMethodIdFromSetupIntent(
    subscription.default_payment_method as string | { id?: string } | null,
  );

  if (!pmId) {
    const invoice = subscription.latest_invoice as
      | Record<string, unknown>
      | string
      | null
      | undefined;
    if (invoice && typeof invoice !== "string") {
      const pi = invoice.payment_intent as
        | Record<string, unknown>
        | string
        | null
        | undefined;
      if (pi && typeof pi !== "string") {
        pmId = paymentMethodIdFromSetupIntent(
          pi.payment_method as string | { id?: string } | null,
        );
      }
    }
  }

  if (!pmId) return null;

  await applyDefaultPaymentMethod(pool, stripe, tenantId, pmId);
  const billing = await loadTenantStripeBilling(pool, tenantId);
  if (!billing.stripeCustomerId) return null;
  return fetchSavedPaymentMethodSummary(
    stripe,
    billing.stripeCustomerId,
    billing.stripeSubscriptionId,
  );
}

async function applyDefaultPaymentMethod(
  pool: Pool,
  stripe: StripeClient,
  tenantId: number,
  paymentMethodId: string,
): Promise<void> {
  const billing = await loadTenantStripeBilling(pool, tenantId);
  if (!billing.stripeCustomerId) return;

  await stripe.customers.update(billing.stripeCustomerId, {
    invoice_settings: { default_payment_method: paymentMethodId },
  });

  if (billing.stripeSubscriptionId) {
    await stripe.subscriptions.update(billing.stripeSubscriptionId, {
      default_payment_method: paymentMethodId,
    });
  }
}

async function loadStripe(): Promise<StripeClient | null> {
  const key = process.env.STRIPE_SECRET_KEY;
  if (!key) return null;
  try {
    const Stripe = (await import("stripe")).default;
    return new Stripe(key, {
      apiVersion: "2025-02-24.acacia",
    }) as unknown as StripeClient;
  } catch {
    return null;
  }
}

function packMetadata(tenantId: number, packId: string) {
  const pack = TOP_UP_PACKS[packId];
  if (!pack) return null;
  return {
    tenant_id: String(tenantId),
    pack_id: packId,
    quote_key: `${pack.dimension}:${pack.units}`,
    dimension: pack.dimension,
    units: String(pack.units),
    amount_cents: String(pack.amountCents),
    label: pack.label,
  };
}

function quoteMetadata(tenantId: number, quote: TopUpQuote) {
  return {
    tenant_id: String(tenantId),
    pack_id: quote.tierId,
    quote_key: quote.quoteKey,
    dimension: quote.dimension,
    units: String(quote.units),
    amount_cents: String(quote.amountCents),
    label: quote.label,
  };
}

function serializeTopUpQuote(quote: TopUpQuote, includeEconomics: boolean) {
  const payload = {
    quoteKey: quote.quoteKey,
    tierId: quote.tierId,
    dimension: quote.dimension,
    tierIndex: quote.tierIndex,
    units: quote.units,
    amountCents: quote.amountCents,
    label: quote.label,
  };
  if (!includeEconomics) return payload;
  const economics = computeTopUpQuoteEconomics(quote);
  return {
    ...payload,
    economics: {
      variableCogsUsd: economics.variableCogsUsd,
      stripeFeeUsd: economics.stripeFeeUsd,
      netMarginUsd: economics.netMarginUsd,
      marginPct: economics.marginPct,
    },
  };
}

async function getOrCreateStripeCustomer(
  pool: Pool,
  stripe: StripeClient,
  tenantId: number,
  email?: string | null,
): Promise<string | null> {
  const [rows] = await pool.query(
    `SELECT stripe_customer_id FROM tenant_subscription WHERE tenant_id = ? LIMIT 1`,
    [tenantId],
  );
  const existing = (rows as { stripe_customer_id?: string }[])[0]
    ?.stripe_customer_id;
  if (existing) {
    try {
      await stripe.customers.retrieve(existing);
      return existing;
    } catch (retrieveErr) {
      console.warn(
        "[billing] Stale stripe_customer_id — recreating customer:",
        existing,
        retrieveErr,
      );
      await pool.query(
        `UPDATE tenant_subscription
         SET stripe_customer_id = NULL,
             stripe_subscription_id = NULL,
             status = 'inactive',
             updated_at = UTC_TIMESTAMP()
         WHERE tenant_id = ?`,
        [tenantId],
      );
    }
  }
  if (!email) return null;

  await ensureTenantSubscription(pool, tenantId);

  const customer = await stripe.customers.create({
    email,
    metadata: { tenant_id: String(tenantId) },
  });
  await pool.query(
    `UPDATE tenant_subscription SET stripe_customer_id = ?, updated_at = UTC_TIMESTAMP() WHERE tenant_id = ?`,
    [customer.id, tenantId],
  );
  return customer.id;
}

async function fulfillFromMetadata(
  fulfill: StripeFulfillFn,
  defaultTenantId: number,
  paymentIntentId: string,
  metadata: Record<string, string>,
  source: "webhook" | "confirm",
  onTopUpGranted?: TopUpGrantedHandler,
  recipientEmail?: string,
): Promise<{ granted: boolean; alreadyFulfilled: boolean }> {
  const tid = Number(metadata.tenant_id ?? defaultTenantId);
  const dimension = metadata.dimension as UsageDimension | undefined;
  const units = Number(metadata.units ?? 0);
  const packId = metadata.pack_id ?? "unknown";
  if (!dimension || units <= 0) {
    return { granted: false, alreadyFulfilled: false };
  }
  const result = await fulfill(
    tid,
    paymentIntentId,
    dimension,
    units,
    packId,
    source,
  );
  if (result.granted && onTopUpGranted) {
    const pack = TOP_UP_PACKS[packId];
    const amountCents = Number(metadata.amount_cents ?? pack?.amountCents ?? 0);
    Promise.resolve(
      onTopUpGranted({
        tenantId: tid,
        paymentIntentId,
        packId,
        recipientEmail,
        amountCents,
      }),
    ).catch((err) =>
      console.error("[billing] Top-up receipt email failed:", err),
    );
  }
  return result;
}

async function resolveTenantIdFromStripeObject(
  pool: Pool,
  obj: Record<string, unknown>,
): Promise<number | null> {
  const customerId =
    typeof obj.customer === "string"
      ? obj.customer
      : typeof obj.customer === "object" && obj.customer != null
        ? String((obj.customer as { id?: string }).id ?? "")
        : null;
  const subscriptionId =
    typeof obj.subscription === "string"
      ? obj.subscription
      : obj.object === "subscription" && typeof obj.id === "string"
        ? obj.id
        : null;

  if (subscriptionId) {
    const [rows] = await pool.query(
      `SELECT tenant_id FROM tenant_subscription WHERE stripe_subscription_id = ? LIMIT 1`,
      [subscriptionId],
    );
    const tid = (rows as { tenant_id?: number }[])[0]?.tenant_id;
    if (tid) return tid;
  }

  if (customerId) {
    const [rows] = await pool.query(
      `SELECT tenant_id FROM tenant_subscription WHERE stripe_customer_id = ? LIMIT 1`,
      [customerId],
    );
    const tid = (rows as { tenant_id?: number }[])[0]?.tenant_id;
    if (tid) return tid;
  }

  const metadata = (obj.metadata ?? {}) as Record<string, string>;
  const metaTid = Number(metadata.tenant_id ?? 0);
  if (metaTid > 0) return metaTid;

  return null;
}

async function getGraceDays(pool: Pool, tenantId: number): Promise<number> {
  const [rows] = await pool.query(
    `SELECT setting_value FROM system_settings
     WHERE setting_key = 'billing_grace_days' AND (tenant_id = ? OR tenant_id IS NULL)
     ORDER BY tenant_id DESC LIMIT 1`,
    [tenantId],
  );
  const val = Number(
    (rows as { setting_value?: string }[])[0]?.setting_value ?? 3,
  );
  return Math.max(1, val || 3);
}

async function handleSubscriptionStatusChange(
  pool: Pool,
  tenantId: number,
  status: string,
): Promise<void> {
  const normalized = status.toLowerCase();
  if (normalized === "active" || normalized === "trialing") {
    await markSubscriptionActive(pool, tenantId);
    return;
  }
  if (normalized === "past_due" || normalized === "unpaid") {
    const graceDays = await getGraceDays(pool, tenantId);
    await markSubscriptionPastDue(pool, tenantId, graceDays);
  }
}

/** Register before `express.json()` so Stripe signature verification gets raw body. */
export function registerStripeWebhookEarly(
  app: express.Application,
  pool: Pool,
  tenantId: number,
  fulfill: StripeFulfillFn,
  onTopUpGranted?: TopUpGrantedHandler,
) {
  app.post(
    "/api/billing/stripe/webhook",
    express.raw({ type: "application/json" }),
    async (req, res) => {
      try {
        const stripe = await loadStripe();
        const webhookSecret = process.env.STRIPE_WEBHOOK_SECRET;
        if (!stripe || !webhookSecret) {
          return res.status(503).send("Stripe webhook not configured");
        }

        const signature = req.headers["stripe-signature"] as string;
        const event = stripe.webhooks.constructEvent(
          req.body,
          signature,
          webhookSecret,
        );

        const eventId = String(event.id ?? "");
        if (!eventId) {
          return res.status(400).send("Missing Stripe event id");
        }

        let webhookRecorded = false;
        try {
          await pool.query(
            `INSERT INTO stripe_webhook_events (event_id, event_type) VALUES (?, ?)`,
            [eventId, String(event.type ?? "unknown")],
          );
          webhookRecorded = true;
        } catch (err: unknown) {
          if (isMysqlDuplicateError(err)) {
            return res.json({ received: true, duplicate: true });
          }
          throw err;
        }

        try {
          await processStripeWebhookEvent(
            pool,
            stripe,
            tenantId,
            event,
            fulfill,
            onTopUpGranted,
          );
          return res.json({ received: true });
        } catch (processErr) {
          if (webhookRecorded) {
            await pool
              .query(`DELETE FROM stripe_webhook_events WHERE event_id = ?`, [
                eventId,
              ])
              .catch((delErr) =>
                console.error(
                  "[billing] Failed to roll back webhook dedup row:",
                  delErr,
                ),
              );
          }
          throw processErr;
        }
      } catch (error) {
        console.error("Stripe webhook error:", error);
        return res.status(500).send("Webhook handler failed");
      }
    },
  );
}

async function processStripeWebhookEvent(
  pool: Pool,
  stripe: StripeClient,
  defaultTenantId: number,
  event: {
    id: string;
    type: string;
    data: { object: Record<string, unknown> };
  },
  fulfill: StripeFulfillFn,
  onTopUpGranted?: TopUpGrantedHandler,
): Promise<void> {
  if (event.type === "checkout.session.completed") {
    const session = event.data.object;
    const metadata = (session.metadata ?? {}) as Record<string, string>;
    if (session.mode === "subscription" && session.subscription) {
      const tid = await resolveTenantIdFromStripeObject(pool, session);
      const subId =
        typeof session.subscription === "string"
          ? session.subscription
          : String((session.subscription as { id?: string }).id ?? "");
      if (tid && subId) {
        const sub = await stripe.subscriptions.retrieve(subId);
        await syncStripeSubscriptionToDb(pool, tid, sub);
      }
    } else if (metadata.pack_id) {
      const piId =
        typeof session.payment_intent === "string"
          ? session.payment_intent
          : null;
      if (piId) {
        await fulfillFromMetadata(
          fulfill,
          defaultTenantId,
          piId,
          metadata,
          "webhook",
          onTopUpGranted,
        );
      }
    }
  }

  if (event.type === "payment_intent.succeeded") {
    const intent = event.data.object;
    const metadata = (intent.metadata ?? {}) as Record<string, string>;
    const piId = String(intent.id ?? "");
    if (piId && metadata.pack_id) {
      await fulfillFromMetadata(
        fulfill,
        defaultTenantId,
        piId,
        metadata,
        "webhook",
        onTopUpGranted,
      );
    }
  }

  if (event.type === "customer.subscription.created") {
    const subscription = event.data.object;
    const tid = await resolveTenantIdFromStripeObject(pool, subscription);
    if (tid) {
      await syncStripeSubscriptionToDb(pool, tid, subscription);
    } else {
      console.warn(
        "Stripe customer.subscription.created: unresolved tenant, skipping",
      );
    }
  }

  if (event.type === "setup_intent.succeeded") {
    const setupIntent = event.data.object;
    const tid = await resolveTenantIdFromStripeObject(pool, setupIntent);
    const pmId = paymentMethodIdFromSetupIntent(
      setupIntent.payment_method as string | { id?: string } | null,
    );
    if (tid && pmId) {
      await applyDefaultPaymentMethod(pool, stripe, tid, pmId);
    } else {
      console.warn(
        "Stripe setup_intent.succeeded: unresolved tenant or payment method",
      );
    }
  }

  if (event.type === "invoice.payment_failed") {
    const invoice = event.data.object;
    const tid = await resolveTenantIdFromStripeObject(pool, invoice);
    if (tid) {
      const graceDays = await getGraceDays(pool, tid);
      await markSubscriptionPastDue(pool, tid, graceDays);
      const [subRows] = await pool.query<RowDataPacket[]>(
        `SELECT grace_ends_at FROM tenant_subscription WHERE tenant_id = ? LIMIT 1`,
        [tid],
      );
      const graceEndsRaw = subRows[0]?.grace_ends_at;
      const graceEndsAt = graceEndsRaw
        ? new Date(String(graceEndsRaw))
        : new Date(Date.now() + graceDays * 86400000);
      sendBillingPaymentFailedEmail(pool, tid, invoice, graceEndsAt).catch(
        (err) => console.error("[billing] Payment failed email error:", err),
      );
    } else {
      console.warn(
        "Stripe invoice.payment_failed: unresolved tenant, skipping",
      );
    }
  }

  if (event.type === "invoice.payment_succeeded") {
    const invoice = event.data.object;
    if (invoice.subscription) {
      const tid = await resolveTenantIdFromStripeObject(pool, invoice);
      if (tid) {
        const subId =
          typeof invoice.subscription === "string"
            ? invoice.subscription
            : String((invoice.subscription as { id?: string }).id ?? "");
        if (subId) {
          const sub = await stripe.subscriptions.retrieve(subId, {
            expand: ["latest_invoice"],
          });
          await syncStripeSubscriptionToDb(pool, tid, sub);
          sendBillingSubscriptionReceiptEmail(pool, tid, sub).catch((err) =>
            console.error("[billing] Subscription receipt email failed:", err),
          );
        } else {
          await markSubscriptionActive(pool, tid);
        }
      } else {
        console.warn(
          "Stripe invoice.payment_succeeded: unresolved tenant, skipping",
        );
      }
    }
  }

  if (event.type === "customer.subscription.updated") {
    const subscription = event.data.object;
    const tid = await resolveTenantIdFromStripeObject(pool, subscription);
    if (!tid) {
      console.warn(
        "Stripe customer.subscription.updated: unresolved tenant, skipping",
      );
    } else {
      await syncStripeSubscriptionToDb(pool, tid, subscription);
    }
  }

  if (event.type === "customer.subscription.deleted") {
    const subscription = event.data.object;
    const tid = await resolveTenantIdFromStripeObject(pool, subscription);
    if (tid) {
      await pool.query(
        `UPDATE tenant_subscription SET status = 'canceled', updated_at = UTC_TIMESTAMP() WHERE tenant_id = ?`,
        [tid],
      );
    } else {
      console.warn(
        "Stripe customer.subscription.deleted: unresolved tenant, skipping",
      );
    }
  }
}

// =====================================================
// Bulk CSV import (inlined for Vercel serverless — no local api imports)
// =====================================================

export interface BulkImportRouteDeps {
  pool: Pool;
  tenantId: number;
  verifyBrokerSession: RequestHandler;
  createAuditLog: (params: {
    actorType: "user" | "broker";
    actorId: number;
    action: string;
    entityType?: string;
    entityId?: number;
    changes?: unknown;
    status?: "success" | "failure" | "warning";
  }) => Promise<void>;
  sendClientManualWelcomeEmail?: (
    email: string,
    firstName: string,
    lastName: string,
    brokerName: string,
  ) => Promise<void>;
  sendBrokerManualWelcomeEmail?: (
    email: string,
    firstName: string,
    lastName: string,
    role: string,
  ) => Promise<void>;
}

const bulkImportUpload = multer({
  storage: multer.memoryStorage(),
  limits: { fileSize: BULK_IMPORT_MAX_FILE_BYTES },
});

const requireBulkImportEnabled: RequestHandler = (_req, res, next) => {
  if (!resolveBulkCsvImportEnabled()) {
    return res.status(404).json({
      success: false,
      message: "Bulk CSV import is not enabled",
    });
  }
  next();
};

const requireBulkImportAccess: RequestHandler = (req, res, next) => {
  const brokerRole = (req as express.Request & { brokerRole?: string }).brokerRole;
  if (brokerRole !== "platform_owner" && brokerRole !== "admin") {
    return res.status(403).json({
      success: false,
      message: "Only mortgage bankers and platform owners can bulk import",
    });
  }
  next();
};

async function cleanupExpiredBulkImportJobs(pool: Pool, tenantId: number): Promise<void> {
  try {
    await pool.query(
      `UPDATE bulk_import_jobs SET status = 'expired'
       WHERE tenant_id = ? AND status = 'validated' AND expires_at < NOW()
       LIMIT 200`,
      [tenantId],
    );
    await pool.query(
      `DELETE FROM bulk_import_jobs
       WHERE tenant_id = ? AND status IN ('expired', 'failed')
         AND expires_at < DATE_SUB(NOW(), INTERVAL 7 DAY)
       LIMIT 200`,
      [tenantId],
    );
  } catch {
    // non-blocking housekeeping
  }
}

const BULK_PREFLIGHT_IN_CHUNK = 100;

async function loadClientEmailConflicts(
  pool: Pool,
  tenantId: number,
  emails: string[],
): Promise<Map<string, RowDataPacket>> {
  const map = new Map<string, RowDataPacket>();
  for (let i = 0; i < emails.length; i += BULK_PREFLIGHT_IN_CHUNK) {
    const chunk = emails.slice(i, i + BULK_PREFLIGHT_IN_CHUNK);
    if (!chunk.length) continue;
    const [rows] = await pool.query<RowDataPacket[]>(
      `SELECT id, first_name, last_name, email FROM clients
       WHERE tenant_id = ? AND email IN (${chunk.map(() => "?").join(",")})`,
      [tenantId, ...chunk],
    );
    for (const row of rows) {
      map.set(String(row.email).toLowerCase(), row);
    }
  }
  return map;
}

async function loadClientPhoneConflicts(
  pool: Pool,
  tenantId: number,
  phones: string[],
): Promise<Map<string, RowDataPacket>> {
  const map = new Map<string, RowDataPacket>();
  for (let i = 0; i < phones.length; i += BULK_PREFLIGHT_IN_CHUNK) {
    const chunk = phones.slice(i, i + BULK_PREFLIGHT_IN_CHUNK);
    if (!chunk.length) continue;
    const [rows] = await pool.query<RowDataPacket[]>(
      `SELECT id, first_name, last_name, normalized_phone FROM clients
       WHERE tenant_id = ? AND normalized_phone IN (${chunk.map(() => "?").join(",")})
         AND phone IS NOT NULL`,
      [tenantId, ...chunk],
    );
    for (const row of rows) {
      map.set(String(row.normalized_phone), row);
    }
  }
  return map;
}

async function loadBrokerEmailConflicts(
  pool: Pool,
  tenantId: number,
  emails: string[],
): Promise<Map<string, RowDataPacket>> {
  const map = new Map<string, RowDataPacket>();
  for (let i = 0; i < emails.length; i += BULK_PREFLIGHT_IN_CHUNK) {
    const chunk = emails.slice(i, i + BULK_PREFLIGHT_IN_CHUNK);
    if (!chunk.length) continue;
    const [rows] = await pool.query<RowDataPacket[]>(
      `SELECT id, email FROM brokers
       WHERE tenant_id = ? AND email IN (${chunk.map(() => "?").join(",")})`,
      [tenantId, ...chunk],
    );
    for (const row of rows) {
      map.set(String(row.email).toLowerCase(), row);
    }
  }
  return map;
}

async function loadBrokerPhoneConflicts(
  pool: Pool,
  tenantId: number,
  last10List: string[],
): Promise<Map<string, RowDataPacket>> {
  const map = new Map<string, RowDataPacket>();
  for (let i = 0; i < last10List.length; i += 20) {
    const chunk = last10List.slice(i, i + 20);
    if (!chunk.length) continue;
    const conditions = chunk.map(() => `REGEXP_REPLACE(phone, '[^0-9]', '') LIKE ?`).join(" OR ");
    const [rows] = await pool.query<RowDataPacket[]>(
      `SELECT id, phone FROM brokers WHERE tenant_id = ? AND (${conditions})`,
      [tenantId, ...chunk.map((d) => `%${d}`)],
    );
    for (const row of rows) {
      const digits = String(row.phone ?? "").replace(/\D/g, "").slice(-10);
      if (digits) map.set(digits, row);
    }
  }
  return map;
}

async function applyClientDbPreflight(
  pool: Pool,
  tenantId: number,
  validation: BulkImportValidationResult,
): Promise<BulkImportValidationResult> {
  if (!validation.normalized_clients) return validation;

  const rows = validation.normalized_clients;
  const ready = rows.filter((r) => r.status === "will_create");
  const emails = [
    ...new Set(
      ready.map((r) => r.email).filter((e): e is string => Boolean(e)),
    ),
  ];
  const phones = [
    ...new Set(
      ready
        .map((r) => r.normalized_phone)
        .filter((p): p is string => Boolean(p)),
    ),
  ];

  const [emailMap, phoneMap] = await Promise.all([
    loadClientEmailConflicts(pool, tenantId, emails),
    loadClientPhoneConflicts(pool, tenantId, phones),
  ]);

  for (const row of rows) {
    if (row.status !== "will_create") continue;

    if (row.email) {
      const existing = emailMap.get(row.email.toLowerCase());
      if (existing) {
        row.status = "skipped";
        row.message = `Email already exists (client #${existing.id})`;
        row.conflict_client_id = existing.id as number;
        continue;
      }
    }

    if (row.normalized_phone) {
      const phoneRow = phoneMap.get(row.normalized_phone);
      if (phoneRow) {
        row.status = "skipped";
        row.message = `Phone already exists (client #${phoneRow.id})`;
        row.conflict_client_id = phoneRow.id as number;
      }
    }
  }

  return rebuildClientValidation(validation, rows);
}

async function applyRealtorDbPreflight(
  pool: Pool,
  tenantId: number,
  validation: BulkImportValidationResult,
): Promise<BulkImportValidationResult> {
  if (!validation.normalized_realtors) return validation;

  const rows = validation.normalized_realtors;
  const ready = rows.filter((r) => r.status === "will_create");
  const emails = [
    ...new Set(ready.map((r) => r.email).filter(Boolean)),
  ];
  const phoneLast10 = [
    ...new Set(
      ready
        .map((r) => r.phone?.replace(/\D/g, "").slice(-10) ?? "")
        .filter((d) => d.length === 10),
    ),
  ];

  const [emailMap, phoneMap] = await Promise.all([
    loadBrokerEmailConflicts(pool, tenantId, emails),
    loadBrokerPhoneConflicts(pool, tenantId, phoneLast10),
  ]);

  for (const row of rows) {
    if (row.status !== "will_create") continue;

    const existing = emailMap.get(row.email.toLowerCase());
    if (existing) {
      row.status = "skipped";
      row.message = `Email already exists (broker #${existing.id})`;
      row.conflict_broker_id = existing.id as number;
      continue;
    }

    const last10 = row.phone?.replace(/\D/g, "").slice(-10);
    if (last10) {
      const phoneRow = phoneMap.get(last10);
      if (phoneRow) {
        row.status = "skipped";
        row.message = `Phone already exists (broker #${phoneRow.id})`;
        row.conflict_broker_id = phoneRow.id as number;
      }
    }
  }

  return rebuildRealtorValidation(validation, rows);
}

function rebuildClientValidation(
  validation: BulkImportValidationResult,
  rows: NormalizedClientBulkRow[],
): BulkImportValidationResult {
  const preview_rows = rows.map((row) => ({
    row_number: row.row_number,
    status: row.status,
    message: row.message,
    external_ref: row.external_ref,
    display_name: `${row.first_name} ${row.last_name}`.trim(),
    email: row.email,
    phone: row.phone,
    badge: row.lead_source,
    conflict_entity_id: row.conflict_client_id ?? null,
  }));

  const breakdown: Record<string, number> = {};
  for (const row of rows) {
    if (row.status === "will_create") {
      breakdown[row.lead_source] = (breakdown[row.lead_source] ?? 0) + 1;
    }
  }

  const will_create_count = preview_rows.filter((r) => r.status === "will_create").length;
  const skipped_count = preview_rows.filter((r) => r.status === "skipped").length;
  const error_count = preview_rows.filter((r) => r.status === "error").length;

  return {
    ...validation,
    normalized_clients: rows,
    preview_rows,
    breakdown,
    will_create_count,
    skipped_count,
    error_count,
  };
}

function rebuildRealtorValidation(
  validation: BulkImportValidationResult,
  rows: NormalizedRealtorBulkRow[],
): BulkImportValidationResult {
  const preview_rows = rows.map((row) => ({
    row_number: row.row_number,
    status: row.status,
    message: row.message,
    external_ref: row.external_ref,
    display_name: `${row.first_name} ${row.last_name}`.trim(),
    email: row.email,
    phone: row.phone,
    badge: row.partner_type,
    conflict_entity_id: row.conflict_broker_id ?? null,
  }));

  const breakdown: Record<string, number> = {};
  for (const row of rows) {
    if (row.status === "will_create") {
      breakdown[row.partner_type] = (breakdown[row.partner_type] ?? 0) + 1;
    }
  }

  const will_create_count = preview_rows.filter((r) => r.status === "will_create").length;
  const skipped_count = preview_rows.filter((r) => r.status === "skipped").length;
  const error_count = preview_rows.filter((r) => r.status === "error").length;

  return {
    ...validation,
    normalized_realtors: rows,
    preview_rows,
    breakdown,
    will_create_count,
    skipped_count,
    error_count,
  };
}

function validationToPreviewPayload(validation: BulkImportValidationResult) {
  return {
    entity: validation.entity,
    row_count: validation.row_count,
    will_create_count: validation.will_create_count,
    skipped_count: validation.skipped_count,
    error_count: validation.error_count,
    preview_rows: validation.preview_rows,
    breakdown: validation.breakdown,
    normalized_clients: validation.normalized_clients,
    normalized_realtors: validation.normalized_realtors,
  };
}

async function linkClientPhoneThreads(
  pool: Pool,
  tenantId: number,
  clientId: number,
  brokerId: number,
  phone: string | null,
  email: string | null,
  clientFullName: string,
): Promise<void> {
  if (!phone) return;
  const lastTen = phone.replace(/\D/g, "").slice(-10);
  if (lastTen.length !== 10) return;

  await pool.query(
    `UPDATE conversation_threads
     SET client_id    = COALESCE(client_id, ?),
         client_name  = COALESCE(client_name, ?),
         client_email = COALESCE(client_email, ?),
         broker_id    = COALESCE(broker_id, ?),
         updated_at   = NOW()
     WHERE tenant_id = ?
       AND client_id IS NULL
       AND (
         (conversation_id LIKE 'conv_phone_%'
          AND RIGHT(REGEXP_REPLACE(conversation_id, '[^0-9]', ''), 10) = ?)
         OR
         (client_phone IS NOT NULL
          AND RIGHT(REGEXP_REPLACE(client_phone, '[^0-9]', ''), 10) = ?)
       )`,
    [clientId, clientFullName, email, brokerId, tenantId, lastTen, lastTen],
  );
}

export function registerBulkImportRoutes(
  expressApp: express.Application,
  deps: BulkImportRouteDeps,
): void {
  const bulkImportAuth = [
    deps.verifyBrokerSession,
    requireBulkImportEnabled,
    requireBulkImportAccess,
  ];

  expressApp.get(
    "/api/admin/bulk-import/templates/clients.csv",
    ...bulkImportAuth,
    (_req, res) => {
      res.setHeader("Content-Type", "text/csv; charset=utf-8");
      res.setHeader(
        "Content-Disposition",
        'attachment; filename="encore_clients_import_template.csv"',
      );
      res.send(buildClientTemplateCsv());
    },
  );

  expressApp.get(
    "/api/admin/bulk-import/templates/realtors.csv",
    ...bulkImportAuth,
    (_req, res) => {
      res.setHeader("Content-Type", "text/csv; charset=utf-8");
      res.setHeader(
        "Content-Disposition",
        'attachment; filename="encore_realtors_import_template.csv"',
      );
      res.send(buildRealtorTemplateCsv());
    },
  );

  expressApp.post(
    "/api/admin/bulk-import/validate",
    ...bulkImportAuth,
    bulkImportUpload.single("file"),
    async (req, res) => {
      try {
        await cleanupExpiredBulkImportJobs(deps.pool, deps.tenantId);

        const brokerId = (req as express.Request & { brokerId?: number }).brokerId!;
        const brokerRole = (req as express.Request & { brokerRole?: string })
          .brokerRole!;
        const entity = (req.body?.entity ?? "") as BulkImportEntity;
        if (entity !== "clients" && entity !== "realtors") {
          return res.status(400).json({
            success: false,
            message: "entity must be clients or realtors",
          });
        }

        const file = req.file;
        if (!file?.buffer?.length) {
          return res.status(400).json({
            success: false,
            message: "CSV file is required",
          });
        }

        const text = file.buffer.toString("utf8");
        let validation = parseAndValidateBulkCsv(text, entity);
        if (!validation.success) {
          return res.status(400).json({
            success: false,
            file_error: validation.file_error,
            file_error_code: validation.file_error_code,
            message: validation.file_error,
          });
        }

        validation =
          entity === "clients"
            ? await applyClientDbPreflight(deps.pool, deps.tenantId, validation)
            : await applyRealtorDbPreflight(deps.pool, deps.tenantId, validation);

        validation = applyBulkImportImporterRestrictions(validation, brokerRole);

        const fileSha = crypto
          .createHash("sha256")
          .update(file.buffer)
          .digest("hex");
        const expiresAt = new Date(Date.now() + BULK_IMPORT_JOB_TTL_MS);
        const previewPayload = validationToPreviewPayload(validation);

        const [ins] = await deps.pool.query<ResultSetHeader>(
          `INSERT INTO bulk_import_jobs
             (tenant_id, entity, uploaded_by_broker_id, file_name, file_sha256,
              status, options_json, preview_json, row_count, created_count, skipped_count,
              error_count, expires_at)
           VALUES (?, ?, ?, ?, ?, 'validated', ?, ?, ?, 0, ?, ?, ?)`,
          [
            deps.tenantId,
            entity,
            brokerId,
            file.originalname?.slice(0, 255) || "import.csv",
            fileSha,
            JSON.stringify({
              link_phone_threads: true,
              send_welcome_emails: false,
            }),
            JSON.stringify(previewPayload),
            validation.row_count,
            validation.skipped_count,
            validation.error_count,
            expiresAt,
          ],
        );

        return res.json({
          success: true,
          job_id: ins.insertId,
          entity,
          file_name: file.originalname,
          row_count: validation.row_count,
          will_create_count: validation.will_create_count,
          skipped_count: validation.skipped_count,
          error_count: validation.error_count,
          preview_rows: validation.preview_rows,
          breakdown: validation.breakdown,
          expires_at: expiresAt.toISOString(),
        });
      } catch (err) {
        console.error("[bulk-import] validate error:", err);
        return res.status(500).json({
          success: false,
          message: err instanceof Error ? err.message : "Validation failed",
        });
      }
    },
  );

  expressApp.get(
    "/api/admin/bulk-import/:jobId",
    ...bulkImportAuth,
    async (req, res) => {
      try {
        const brokerId = (req as express.Request & { brokerId?: number }).brokerId!;
        const jobId = parseInt(req.params.jobId, 10);
        if (Number.isNaN(jobId)) {
          return res.status(400).json({ success: false, message: "Invalid job id" });
        }

        const [rows] = await deps.pool.query<RowDataPacket[]>(
          `SELECT * FROM bulk_import_jobs
           WHERE id = ? AND tenant_id = ? AND uploaded_by_broker_id = ?
           LIMIT 1`,
          [jobId, deps.tenantId, brokerId],
        );
        if (!rows.length) {
          return res.status(404).json({ success: false, message: "Job not found" });
        }

        const job = rows[0];
        const preview = job.preview_json
          ? typeof job.preview_json === "string"
            ? JSON.parse(job.preview_json)
            : job.preview_json
          : {};
        const results = job.result_json
          ? typeof job.result_json === "string"
            ? JSON.parse(job.result_json)
            : job.result_json
          : null;

        return res.json({
          success: true,
          job: {
            id: job.id,
            entity: job.entity,
            status: job.status,
            file_name: job.file_name,
            row_count: job.row_count,
            created_count: job.created_count,
            skipped_count: job.skipped_count,
            error_count: job.error_count,
            expires_at: job.expires_at,
            committed_at: job.committed_at,
            preview_rows: preview.preview_rows,
            results: results?.results,
          },
        });
      } catch (err) {
        console.error("[bulk-import] get job error:", err);
        return res.status(500).json({ success: false, message: "Failed to load job" });
      }
    },
  );

  expressApp.post(
    "/api/admin/bulk-import/:jobId/commit",
    ...bulkImportAuth,
    async (req, res) => {
      try {
        const brokerId = (req as express.Request & { brokerId?: number }).brokerId!;
        const brokerRole = (req as express.Request & { brokerRole?: string }).brokerRole!;
        const jobId = parseInt(req.params.jobId, 10);
        if (Number.isNaN(jobId)) {
          return res.status(400).json({ success: false, message: "Invalid job id" });
        }

        const linkPhoneThreads = req.body?.link_phone_threads !== false;
        const sendWelcomeEmails = req.body?.send_welcome_emails === true;

        const [jobRows] = await deps.pool.query<RowDataPacket[]>(
          `SELECT * FROM bulk_import_jobs
           WHERE id = ? AND tenant_id = ? AND uploaded_by_broker_id = ?
           LIMIT 1`,
          [jobId, deps.tenantId, brokerId],
        );
        if (!jobRows.length) {
          return res.status(404).json({ success: false, message: "Job not found" });
        }

        const job = jobRows[0];
        if (job.status === "committed") {
          return res.status(409).json({
            success: false,
            message: "Job already committed",
          });
        }
        if (job.status === "processing") {
          return res.status(409).json({
            success: false,
            message: "Import is already in progress for this job",
          });
        }
        if (new Date(job.expires_at as string) < new Date()) {
          await deps.pool.query(
            `UPDATE bulk_import_jobs SET status = 'expired' WHERE id = ?`,
            [jobId],
          );
          return res.status(410).json({
            success: false,
            message: "Import job expired — please re-upload",
          });
        }

        const [claim] = await deps.pool.query<ResultSetHeader>(
          `UPDATE bulk_import_jobs SET status = 'processing'
           WHERE id = ? AND tenant_id = ? AND uploaded_by_broker_id = ? AND status = 'validated'`,
          [jobId, deps.tenantId, brokerId],
        );
        if (claim.affectedRows === 0) {
          return res.status(409).json({
            success: false,
            message: "Job is no longer available to commit",
          });
        }

        try {
          const preview = job.preview_json
            ? typeof job.preview_json === "string"
              ? JSON.parse(job.preview_json)
              : job.preview_json
            : null;
          if (!preview) {
            await deps.pool.query(
              `UPDATE bulk_import_jobs SET status = 'failed' WHERE id = ? AND status = 'processing'`,
              [jobId],
            );
            return res.status(400).json({ success: false, message: "Invalid job data" });
          }

          const entity = job.entity as BulkImportEntity;
        const results: Array<{
          row_number: number;
          external_ref?: string | null;
          status: "created" | "skipped" | "error";
          entity_id?: number | null;
          owner_broker_id?: number | null;
          message?: string;
        }> = [];

        let createdCount = 0;
        let skippedCount = 0;
        let errorCount = 0;

        const [[importer]] = await deps.pool.query<RowDataPacket[]>(
          `SELECT first_name, last_name FROM brokers WHERE id = ? AND tenant_id = ? LIMIT 1`,
          [brokerId, deps.tenantId],
        );
        const brokerFullName = importer
          ? `${importer.first_name} ${importer.last_name}`.trim()
          : "Your Loan Officer";

        if (entity === "clients" && preview.normalized_clients) {
          const rows = preview.normalized_clients as NormalizedClientBulkRow[];
          const willCreate = rows.filter((r) => r.status === "will_create");
          const [clientEmailDups, clientPhoneDups] = await Promise.all([
            loadClientEmailConflicts(
              deps.pool,
              deps.tenantId,
              [
                ...new Set(
                  willCreate
                    .map((r) => r.email)
                    .filter((e): e is string => Boolean(e)),
                ),
              ],
            ),
            loadClientPhoneConflicts(
              deps.pool,
              deps.tenantId,
              [
                ...new Set(
                  willCreate
                    .map((r) => r.normalized_phone)
                    .filter((p): p is string => Boolean(p)),
                ),
              ],
            ),
          ]);

          for (const row of rows) {
            if (row.status === "error") {
              errorCount++;
              results.push({
                row_number: row.row_number,
                external_ref: row.external_ref,
                status: "error",
                message: row.message,
              });
              continue;
            }
            if (row.status === "skipped") {
              skippedCount++;
              results.push({
                row_number: row.row_number,
                external_ref: row.external_ref,
                status: "skipped",
                entity_id: row.conflict_client_id ?? null,
                message: row.message,
              });
              continue;
            }

            try {
              const trimmedEmail = row.email;
              if (trimmedEmail) {
                const dup = clientEmailDups.get(trimmedEmail.toLowerCase());
                if (dup) {
                  skippedCount++;
                  results.push({
                    row_number: row.row_number,
                    external_ref: row.external_ref,
                    status: "skipped",
                    entity_id: dup.id as number,
                    message: "Email already exists",
                  });
                  continue;
                }
              }

              if (row.normalized_phone) {
                const dupPhone = clientPhoneDups.get(row.normalized_phone);
                if (dupPhone) {
                  skippedCount++;
                  results.push({
                    row_number: row.row_number,
                    external_ref: row.external_ref,
                    status: "skipped",
                    entity_id: dupPhone.id as number,
                    message: "Phone already exists",
                  });
                  continue;
                }
              }

              const finalEmail =
                trimmedEmail ??
                `noemail_job${jobId}_r${row.row_number}_${crypto.randomBytes(4).toString("hex")}@noemail.placeholder`;

              const [ins] = await deps.pool.query<ResultSetHeader>(
                `INSERT INTO clients
                   (tenant_id, first_name, middle_name, last_name, email, phone, normalized_phone,
                    alternate_phone, date_of_birth, address_street, address_unit, address_city,
                    address_state, address_zip, citizenship_status, status, assigned_broker_id,
                    income_type, source)
                 VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'active', ?, 'W-2', ?)`,
                [
                  deps.tenantId,
                  row.first_name,
                  row.middle_name,
                  row.last_name,
                  finalEmail,
                  row.phone,
                  row.normalized_phone,
                  row.alternate_phone,
                  row.date_of_birth,
                  row.address_street,
                  row.address_unit,
                  row.address_city,
                  row.address_state,
                  row.address_zip,
                  row.citizenship_status,
                  brokerId,
                  row.lead_source,
                ],
              );

              const newId = ins.insertId;
              createdCount++;
              results.push({
                row_number: row.row_number,
                external_ref: row.external_ref,
                status: "created",
                entity_id: newId,
                owner_broker_id: brokerId,
              });

              const clientFullName = `${row.first_name} ${row.last_name}`.trim();
              if (linkPhoneThreads) {
                await linkClientPhoneThreads(
                  deps.pool,
                  deps.tenantId,
                  newId,
                  brokerId,
                  row.phone,
                  trimmedEmail,
                  clientFullName,
                );
              }

              if (
                sendWelcomeEmails &&
                deps.sendClientManualWelcomeEmail &&
                trimmedEmail &&
                !finalEmail.startsWith("noemail_")
              ) {
                deps
                  .sendClientManualWelcomeEmail(
                    trimmedEmail,
                    row.first_name,
                    row.last_name,
                    brokerFullName,
                  )
                  .catch(() => undefined);
              }
            } catch (rowErr) {
              errorCount++;
              results.push({
                row_number: row.row_number,
                external_ref: row.external_ref,
                status: "error",
                message:
                  rowErr instanceof Error ? rowErr.message : "Insert failed",
              });
            }
          }
        } else if (entity === "realtors" && preview.normalized_realtors) {
          const rows = preview.normalized_realtors as NormalizedRealtorBulkRow[];
          const willCreate = rows.filter((r) => r.status === "will_create");
          const realtorEmailDups = await loadBrokerEmailConflicts(
            deps.pool,
            deps.tenantId,
            [...new Set(willCreate.map((r) => r.email))],
          );

          for (const row of rows) {
            if (row.status === "error") {
              errorCount++;
              results.push({
                row_number: row.row_number,
                external_ref: row.external_ref,
                status: "error",
                message: row.message,
              });
              continue;
            }
            if (row.status === "skipped") {
              skippedCount++;
              results.push({
                row_number: row.row_number,
                external_ref: row.external_ref,
                status: "skipped",
                entity_id: row.conflict_broker_id ?? null,
                message: row.message,
              });
              continue;
            }

            try {
              if (
                brokerRole !== "platform_owner" &&
                (row.role === "admin" || row.partner_type === "mortgage_banker")
              ) {
                errorCount++;
                results.push({
                  row_number: row.row_number,
                  external_ref: row.external_ref,
                  status: "error",
                  message: "Mortgage bankers can only bulk-import realtor partners",
                });
                continue;
              }

              const dup = realtorEmailDups.get(row.email.toLowerCase());
              if (dup) {
                skippedCount++;
                results.push({
                  row_number: row.row_number,
                  external_ref: row.external_ref,
                  status: "skipped",
                  entity_id: dup.id as number,
                  message: "Email already exists",
                });
                continue;
              }

              const [ins] = await deps.pool.query<ResultSetHeader>(
                `INSERT INTO brokers
                   (tenant_id, email, first_name, last_name, phone, role, license_number,
                    specializations, status, email_verified, created_by_broker_id, public_token)
                 VALUES (?, ?, ?, ?, ?, ?, ?, ?, 'active', 0, ?, UUID())`,
                [
                  deps.tenantId,
                  row.email,
                  row.first_name,
                  row.last_name,
                  row.phone,
                  row.role,
                  row.license_number,
                  row.specializations ? JSON.stringify(row.specializations) : null,
                  brokerId,
                ],
              );

              const newBrokerId = ins.insertId;

              const hasProfile =
                row.office_address ||
                row.office_city ||
                row.office_state ||
                row.office_zip ||
                row.bio;
              if (hasProfile) {
                await deps.pool.query(
                  `INSERT INTO broker_profiles
                     (broker_id, bio, office_address, office_city, office_state, office_zip)
                   VALUES (?, ?, ?, ?, ?, ?)`,
                  [
                    newBrokerId,
                    row.bio,
                    row.office_address,
                    row.office_city,
                    row.office_state,
                    row.office_zip,
                  ],
                );
              }

              createdCount++;
              results.push({
                row_number: row.row_number,
                external_ref: row.external_ref,
                status: "created",
                entity_id: newBrokerId,
                owner_broker_id: brokerId,
              });

              if (sendWelcomeEmails && deps.sendBrokerManualWelcomeEmail) {
                deps
                  .sendBrokerManualWelcomeEmail(
                    row.email,
                    row.first_name,
                    row.last_name,
                    row.role,
                  )
                  .catch(() => undefined);
              }
            } catch (rowErr) {
              errorCount++;
              results.push({
                row_number: row.row_number,
                external_ref: row.external_ref,
                status: "error",
                message:
                  rowErr instanceof Error ? rowErr.message : "Insert failed",
              });
            }
          }
        }

          const resultJson = { results };
          await deps.pool.query(
            `UPDATE bulk_import_jobs SET
               status = 'committed',
               created_count = ?,
               skipped_count = ?,
               error_count = ?,
               result_json = ?,
               committed_at = NOW(),
               options_json = ?
             WHERE id = ? AND tenant_id = ? AND status = 'processing'`,
            [
              createdCount,
              skippedCount,
              errorCount,
              JSON.stringify(resultJson),
              JSON.stringify({
                link_phone_threads: linkPhoneThreads,
                send_welcome_emails: sendWelcomeEmails,
              }),
              jobId,
              deps.tenantId,
            ],
          );

          await deps.createAuditLog({
            actorType: "broker",
            actorId: brokerId,
            action:
              entity === "clients" ? "bulk_import_clients" : "bulk_import_realtors",
            entityType: "bulk_import_job",
            entityId: jobId,
            changes: {
              created_count: createdCount,
              skipped_count: skippedCount,
              error_count: errorCount,
              file_name: job.file_name,
            },
          });

          return res.json({
            success: true,
            job_id: jobId,
            created_count: createdCount,
            skipped_count: skippedCount,
            error_count: errorCount,
            results,
            message: `Imported ${createdCount} record(s)`,
          });
        } catch (commitErr) {
          await deps.pool
            .query(
              `UPDATE bulk_import_jobs SET status = 'failed' WHERE id = ? AND status = 'processing'`,
              [jobId],
            )
            .catch(() => undefined);
          throw commitErr;
        }
      } catch (err) {
        console.error("[bulk-import] commit error:", err);
        return res.status(500).json({
          success: false,
          message: err instanceof Error ? err.message : "Commit failed",
        });
      }
    },
  );
}

export function registerStripeBillingRoutes(
  app: express.Application,
  pool: Pool,
  tenantId: number,
  fulfill: StripeFulfillFn,
  verifyBrokerSession: RequestHandler,
  getQuotaSummary: (tid: number) => Promise<unknown>,
  onTopUpGranted?: TopUpGrantedHandler,
) {
  const requirePlatformOwner: RequestHandler = (req, res, next) => {
    const brokerRole = (req as express.Request & { brokerRole?: string })
      .brokerRole;
    if (brokerRole !== "platform_owner") {
      return res.status(403).json({
        success: false,
        message: "Only platform owners can access billing",
      });
    }
    next();
  };

  const billingOwnerAuth: RequestHandler[] = [
    verifyBrokerSession,
    requirePlatformOwner,
  ];

  const BILLING_PAYMENT_UNAVAILABLE_MESSAGE =
    "We're unable to take payment right now. Please try again later.";

  const logBillingPaymentError = (context: string, detail: unknown): void => {
    console.error(`[billing] ${context}:`, detail);
  };

  const respondPaymentUnavailable = (
    res: express.Response,
    context: string,
    detail: unknown,
    statusCode = 500,
  ) => {
    logBillingPaymentError(context, detail);
    return res.status(statusCode).json({
      success: false,
      error: BILLING_PAYMENT_UNAVAILABLE_MESSAGE,
    });
  };

  app.get("/api/billing/stripe/config", ...billingOwnerAuth, (_req, res) => {
    const cfg = getStripePublicConfig();
    return res.json({ success: true, ...cfg });
  });

  app.get("/api/billing/stripe/packs", ...billingOwnerAuth, (_req, res) => {
    const packs = Object.entries(TOP_UP_PACK_DEFINITIONS).map(([id, pack]) => {
      const economics = computeTopUpPackEconomics(
        id as keyof typeof TOP_UP_PACK_DEFINITIONS,
      );
      return {
        id,
        ...pack,
        economics: {
          variableCogsUsd: economics.variableCogsUsd,
          stripeFeeUsd: economics.stripeFeeUsd,
          netMarginUsd: economics.netMarginUsd,
          marginPct: economics.marginPct,
        },
      };
    });
    return res.json({
      success: true,
      packs: isBillingInternalEconomicsEnabled()
        ? packs
        : stripInternalPackEconomics(packs),
    });
  });

  app.get(
    "/api/billing/stripe/top-up-options",
    ...billingOwnerAuth,
    (_req, res) => {
      const internal = isBillingInternalEconomicsEnabled();
      const channels = TOP_UP_CHANNELS.map((channel) => ({
        ...channel,
        tiers: TOP_UP_TIERS_BY_DIMENSION[channel.dimension].map(
          (tier, tierIndex) => {
            const quote = computeTopUpQuote(channel.dimension, tierIndex)!;
            const economics = internal
              ? computeTopUpQuoteEconomics(quote)
              : null;
            return {
              tierIndex,
              tierId: tier.tierId,
              units: tier.units,
              amountCents: tier.amountCents,
              label: tier.label,
              chipLabel: tier.chipLabel,
              ...(economics
                ? {
                    economics: {
                      variableCogsUsd: economics.variableCogsUsd,
                      stripeFeeUsd: economics.stripeFeeUsd,
                      netMarginUsd: economics.netMarginUsd,
                      marginPct: economics.marginPct,
                    },
                  }
                : {}),
            };
          },
        ),
      }));
      return res.json({ success: true, channels });
    },
  );

  app.post("/api/billing/stripe/quote", ...billingOwnerAuth, (req, res) => {
    const body = (req.body ?? {}) as {
      dimension?: string;
      tier_index?: number;
    };
    const dimension = String(body.dimension ?? "");
    if (!isUsageDimension(dimension)) {
      return res
        .status(400)
        .json({ success: false, error: "Invalid dimension" });
    }
    const tierIndex = Number(body.tier_index ?? 0);
    const quote = computeTopUpQuote(dimension, tierIndex);
    if (!quote) {
      return res
        .status(400)
        .json({ success: false, error: "Invalid tier_index" });
    }
    return res.json({
      success: true,
      quote: serializeTopUpQuote(quote, isBillingInternalEconomicsEnabled()),
    });
  });

  app.post(
    "/api/billing/stripe/charge-quote",
    ...billingOwnerAuth,
    async (req, res) => {
      try {
        const stripe = await loadStripe();
        if (!stripe) {
          logBillingPaymentError("charge-quote", "Stripe keys not configured");
          return res.status(503).json({
            success: false,
            error: BILLING_PAYMENT_UNAVAILABLE_MESSAGE,
          });
        }

        const body = (req.body ?? {}) as {
          dimension?: string;
          tier_index?: number;
        };
        const dimension = String(body.dimension ?? "");
        if (!isUsageDimension(dimension)) {
          return res
            .status(400)
            .json({ success: false, error: "Invalid dimension" });
        }
        const tierIndex = Number(body.tier_index ?? 0);
        const quote = computeTopUpQuote(dimension, tierIndex);
        if (!quote) {
          return res
            .status(400)
            .json({ success: false, error: "Invalid tier_index" });
        }

        const metadata = quoteMetadata(tenantId, quote);
        const broker = (
          req as express.Request & { broker?: { email?: string } }
        ).broker;
        const customerId = await getOrCreateStripeCustomer(
          pool,
          stripe,
          tenantId,
          broker?.email,
        );
        if (!customerId) {
          return res.status(400).json({
            success: false,
            error: "No billing customer — complete subscription payment first",
          });
        }

        const savedPm = await fetchSavedPaymentMethodSummary(
          stripe,
          customerId,
        );
        if (!savedPm) {
          return res.status(400).json({
            success: false,
            error:
              "No payment method on file. Complete subscription payment to save your card.",
            code: "no_payment_method",
          });
        }

        let intent;
        try {
          intent = await stripe.paymentIntents.create({
            amount: quote.amountCents,
            currency: "usd",
            customer: customerId,
            payment_method: savedPm.id,
            off_session: true,
            confirm: true,
            payment_method_types: ["card"],
            metadata,
            description: quote.label,
          });
        } catch (chargeErr: unknown) {
          const stripeErr = chargeErr as {
            code?: string;
            payment_intent?: { id?: string; client_secret?: string };
          };
          if (
            stripeErr.code === "authentication_required" &&
            stripeErr.payment_intent?.client_secret
          ) {
            return res.status(402).json({
              success: false,
              error: "Card authentication required",
              code: "authentication_required",
              client_secret: stripeErr.payment_intent.client_secret,
              payment_intent_id: stripeErr.payment_intent.id,
            });
          }
          throw chargeErr;
        }

        if (intent.status !== "succeeded") {
          logBillingPaymentError(
            "charge-quote",
            `payment intent not succeeded: ${intent.status}`,
          );
          return res.status(400).json({
            success: false,
            error: BILLING_PAYMENT_UNAVAILABLE_MESSAGE,
            status: intent.status,
            client_secret: intent.client_secret,
            payment_intent_id: intent.id,
          });
        }

        const result = await fulfillFromMetadata(
          fulfill,
          tenantId,
          intent.id,
          metadata,
          "confirm",
          onTopUpGranted,
          broker?.email,
        );
        const quota = await getQuotaSummary(tenantId);

        return res.json({
          success: true,
          granted: result.granted,
          already_fulfilled: result.alreadyFulfilled,
          quote: serializeTopUpQuote(quote, false),
          quota,
        });
      } catch (error: unknown) {
        return respondPaymentUnavailable(res, "charge-quote", error);
      }
    },
  );

  app.post(
    "/api/billing/stripe/payment-intent",
    ...billingOwnerAuth,
    async (req, res) => {
      try {
        const stripe = await loadStripe();
        if (!stripe) {
          logBillingPaymentError(
            "payment-intent",
            "Stripe keys not configured",
          );
          return res.status(503).json({
            success: false,
            error: BILLING_PAYMENT_UNAVAILABLE_MESSAGE,
          });
        }

        const packId = String((req.body as { pack_id?: string }).pack_id ?? "");
        const pack = TOP_UP_PACKS[packId];
        if (!pack) {
          return res
            .status(400)
            .json({ success: false, error: "Invalid pack_id" });
        }

        const metadata = packMetadata(tenantId, packId);
        if (!metadata) {
          return res
            .status(400)
            .json({ success: false, error: "Invalid pack" });
        }

        const broker = (
          req as express.Request & { broker?: { email?: string } }
        ).broker;
        const customerId = await getOrCreateStripeCustomer(
          pool,
          stripe,
          tenantId,
          broker?.email,
        );

        const intent = await stripe.paymentIntents.create({
          amount: pack.amountCents,
          currency: "usd",
          payment_method_types: ["card"],
          metadata,
          description: pack.label,
          ...(customerId
            ? { customer: customerId, setup_future_usage: "off_session" }
            : {}),
        });

        if (!intent.client_secret) {
          logBillingPaymentError(
            "payment-intent",
            "Stripe returned no client_secret",
          );
          return res.status(500).json({
            success: false,
            error: BILLING_PAYMENT_UNAVAILABLE_MESSAGE,
          });
        }

        return res.json({
          success: true,
          client_secret: intent.client_secret,
          payment_intent_id: intent.id,
          pack: { id: packId, ...pack },
        });
      } catch (error: unknown) {
        return respondPaymentUnavailable(res, "payment-intent", error);
      }
    },
  );

  app.post(
    "/api/billing/stripe/charge-pack",
    ...billingOwnerAuth,
    async (req, res) => {
      try {
        const stripe = await loadStripe();
        if (!stripe) {
          logBillingPaymentError("charge-pack", "Stripe keys not configured");
          return res.status(503).json({
            success: false,
            error: BILLING_PAYMENT_UNAVAILABLE_MESSAGE,
          });
        }

        const packId = String((req.body as { pack_id?: string }).pack_id ?? "");
        const pack = TOP_UP_PACKS[packId];
        if (!pack) {
          return res
            .status(400)
            .json({ success: false, error: "Invalid pack_id" });
        }

        const metadata = packMetadata(tenantId, packId);
        if (!metadata) {
          return res
            .status(400)
            .json({ success: false, error: "Invalid pack" });
        }

        const broker = (
          req as express.Request & { broker?: { email?: string } }
        ).broker;
        const customerId = await getOrCreateStripeCustomer(
          pool,
          stripe,
          tenantId,
          broker?.email,
        );
        if (!customerId) {
          return res.status(400).json({
            success: false,
            error: "No billing customer — complete subscription payment first",
          });
        }

        const savedPm = await fetchSavedPaymentMethodSummary(
          stripe,
          customerId,
        );
        if (!savedPm) {
          return res.status(400).json({
            success: false,
            error:
              "No payment method on file. Complete subscription payment to save your card.",
            code: "no_payment_method",
          });
        }

        let intent;
        try {
          intent = await stripe.paymentIntents.create({
            amount: pack.amountCents,
            currency: "usd",
            customer: customerId,
            payment_method: savedPm.id,
            off_session: true,
            confirm: true,
            payment_method_types: ["card"],
            metadata,
            description: pack.label,
          });
        } catch (chargeErr: unknown) {
          const stripeErr = chargeErr as {
            code?: string;
            payment_intent?: { id?: string; client_secret?: string };
          };
          if (
            stripeErr.code === "authentication_required" &&
            stripeErr.payment_intent?.client_secret
          ) {
            return res.status(402).json({
              success: false,
              error: "Card authentication required",
              code: "authentication_required",
              client_secret: stripeErr.payment_intent.client_secret,
              payment_intent_id: stripeErr.payment_intent.id,
            });
          }
          throw chargeErr;
        }

        if (intent.status !== "succeeded") {
          logBillingPaymentError(
            "charge-pack",
            `payment intent not succeeded: ${intent.status}`,
          );
          return res.status(400).json({
            success: false,
            error: BILLING_PAYMENT_UNAVAILABLE_MESSAGE,
            status: intent.status,
            client_secret: intent.client_secret,
            payment_intent_id: intent.id,
          });
        }

        const result = await fulfillFromMetadata(
          fulfill,
          tenantId,
          intent.id,
          metadata,
          "confirm",
          onTopUpGranted,
          broker?.email,
        );
        const quota = await getQuotaSummary(tenantId);

        return res.json({
          success: true,
          granted: result.granted,
          already_fulfilled: result.alreadyFulfilled,
          pack: {
            id: packId,
            label: pack.label,
            units: pack.units,
            dimension: pack.dimension,
            amountCents: pack.amountCents,
          },
          quota,
        });
      } catch (error: unknown) {
        return respondPaymentUnavailable(res, "charge-pack", error);
      }
    },
  );

  app.post(
    "/api/billing/stripe/confirm-payment",
    ...billingOwnerAuth,
    async (req, res) => {
      try {
        const stripe = await loadStripe();
        if (!stripe) {
          logBillingPaymentError(
            "confirm-payment",
            "Stripe keys not configured",
          );
          return res.status(503).json({
            success: false,
            error: BILLING_PAYMENT_UNAVAILABLE_MESSAGE,
          });
        }

        const paymentIntentId = String(
          (req.body as { payment_intent_id?: string }).payment_intent_id ?? "",
        );
        if (!paymentIntentId) {
          return res.status(400).json({
            success: false,
            error: "payment_intent_id is required",
          });
        }

        const intent = await stripe.paymentIntents.retrieve(paymentIntentId);
        if (intent.status !== "succeeded") {
          logBillingPaymentError(
            "confirm-payment",
            `payment intent not succeeded: ${intent.status}`,
          );
          return res.status(400).json({
            success: false,
            error: BILLING_PAYMENT_UNAVAILABLE_MESSAGE,
            status: intent.status,
          });
        }

        const billingRow = await loadTenantStripeBilling(pool, tenantId);
        const pmId =
          typeof intent.payment_method === "string"
            ? intent.payment_method
            : (intent.payment_method as { id?: string } | null)?.id;
        if (pmId && billingRow.stripeCustomerId) {
          await applyDefaultPaymentMethod(pool, stripe, tenantId, pmId);
        }

        const metadata = intent.metadata ?? {};
        const tid = Number(metadata.tenant_id ?? tenantId);
        if (tid !== tenantId) {
          return res.status(403).json({
            success: false,
            error: "Payment does not belong to this tenant",
          });
        }

        const broker = (
          req as express.Request & {
            broker?: { email?: string };
          }
        ).broker;

        const result = await fulfillFromMetadata(
          fulfill,
          tenantId,
          paymentIntentId,
          metadata,
          "confirm",
          onTopUpGranted,
          broker?.email,
        );

        const pack = TOP_UP_PACKS[metadata.pack_id ?? ""];
        const quota = await getQuotaSummary(tenantId);

        return res.json({
          success: true,
          granted: result.granted,
          already_fulfilled: result.alreadyFulfilled,
          pack: pack
            ? {
                id: metadata.pack_id,
                label: pack.label,
                units: pack.units,
                dimension: pack.dimension,
                amountCents: pack.amountCents,
              }
            : null,
          quota,
        });
      } catch (error: unknown) {
        return respondPaymentUnavailable(res, "confirm-payment", error);
      }
    },
  );

  app.post(
    "/api/billing/stripe/checkout",
    ...billingOwnerAuth,
    async (req, res) => {
      try {
        const stripe = await loadStripe();
        if (!stripe) {
          logBillingPaymentError("checkout", "Stripe keys not configured");
          return res.status(503).json({
            success: false,
            error: BILLING_PAYMENT_UNAVAILABLE_MESSAGE,
          });
        }

        const packId = String((req.body as { pack_id?: string }).pack_id ?? "");
        const pack = TOP_UP_PACKS[packId];
        if (!pack) {
          return res
            .status(400)
            .json({ success: false, error: "Invalid pack_id" });
        }

        const baseUrl = getBillingReturnBaseUrl();
        const session = await stripe.checkout.sessions.create({
          mode: "payment",
          line_items: [
            {
              price_data: {
                currency: "usd",
                unit_amount: pack.amountCents,
                product_data: { name: pack.label },
              },
              quantity: 1,
            },
          ],
          success_url: `${baseUrl}/admin/billing?payment=success`,
          cancel_url: `${baseUrl}/admin/billing?payment=cancel`,
          metadata: packMetadata(tenantId, packId) ?? {},
        });

        return res.json({
          success: true,
          url: session.url,
          session_id: session.id,
        });
      } catch (error: unknown) {
        return respondPaymentUnavailable(res, "checkout", error);
      }
    },
  );

  app.post(
    "/api/billing/stripe/portal",
    ...billingOwnerAuth,
    async (req, res) => {
      try {
        const stripe = await loadStripe();
        if (!stripe) {
          logBillingPaymentError("portal", "Stripe keys not configured");
          return res.status(503).json({
            success: false,
            error: BILLING_PAYMENT_UNAVAILABLE_MESSAGE,
          });
        }

        const broker = (
          req as express.Request & { broker?: { email?: string } }
        ).broker;
        const customerId = await getOrCreateStripeCustomer(
          pool,
          stripe,
          tenantId,
          broker?.email,
        );
        if (!customerId) {
          return res.status(400).json({
            success: false,
            error:
              "Subscribe or complete a payment first to create your Stripe customer profile.",
          });
        }

        const flow = String((req.body as { flow?: string }).flow ?? "");
        const baseUrl = getBillingReturnBaseUrl();
        const sessionParams: Record<string, unknown> = {
          customer: customerId,
          return_url: `${baseUrl}/admin/billing`,
        };
        if (flow === "payment_method_update") {
          sessionParams.flow_data = { type: "payment_method_update" };
        }

        const session =
          await stripe.billingPortal.sessions.create(sessionParams);
        return res.json({ success: true, url: session.url });
      } catch (error: unknown) {
        return respondPaymentUnavailable(res, "portal", error);
      }
    },
  );

  app.get(
    "/api/billing/stripe/payment-method",
    ...billingOwnerAuth,
    async (_req, res) => {
      try {
        const stripe = await loadStripe();
        if (!stripe) {
          logBillingPaymentError(
            "payment-method",
            "Stripe keys not configured",
          );
          return res.status(503).json({
            success: false,
            error: BILLING_PAYMENT_UNAVAILABLE_MESSAGE,
          });
        }

        const billing = await loadTenantStripeBilling(pool, tenantId);
        if (!billing.stripeCustomerId) {
          return res.json({ success: true, payment_method: null });
        }

        const paymentMethod = await fetchSavedPaymentMethodSummary(
          stripe,
          billing.stripeCustomerId,
        );
        return res.json({ success: true, payment_method: paymentMethod });
      } catch (error: unknown) {
        return respondPaymentUnavailable(res, "payment-method", error);
      }
    },
  );

  app.post(
    "/api/billing/stripe/payment-method-setup",
    ...billingOwnerAuth,
    async (req, res) => {
      try {
        const stripe = await loadStripe();
        if (!stripe) {
          logBillingPaymentError(
            "payment-method-setup",
            "Stripe keys not configured",
          );
          return res.status(503).json({
            success: false,
            error: BILLING_PAYMENT_UNAVAILABLE_MESSAGE,
          });
        }

        const broker = (
          req as express.Request & { broker?: { email?: string } }
        ).broker;
        const customerId = await getOrCreateStripeCustomer(
          pool,
          stripe,
          tenantId,
          broker?.email,
        );
        if (!customerId) {
          return res.status(400).json({
            success: false,
            error:
              "Subscribe or complete a payment first to save a card on file.",
          });
        }

        const setupIntent = await stripe.setupIntents.create({
          customer: customerId,
          payment_method_types: ["card"],
          metadata: { tenant_id: String(tenantId) },
          usage: "off_session",
        });

        if (!setupIntent.client_secret) {
          logBillingPaymentError(
            "payment-method-setup",
            "Stripe returned no client_secret",
          );
          return res.status(500).json({
            success: false,
            error: BILLING_PAYMENT_UNAVAILABLE_MESSAGE,
          });
        }

        return res.json({
          success: true,
          client_secret: setupIntent.client_secret,
          setup_intent_id: setupIntent.id,
        });
      } catch (error: unknown) {
        return respondPaymentUnavailable(res, "payment-method-setup", error);
      }
    },
  );

  app.post(
    "/api/billing/stripe/confirm-payment-method",
    ...billingOwnerAuth,
    async (req, res) => {
      try {
        const stripe = await loadStripe();
        if (!stripe) {
          logBillingPaymentError(
            "confirm-payment-method",
            "Stripe keys not configured",
          );
          return res.status(503).json({
            success: false,
            error: BILLING_PAYMENT_UNAVAILABLE_MESSAGE,
          });
        }

        const setupIntentId = String(
          (req.body as { setup_intent_id?: string }).setup_intent_id ?? "",
        );
        if (!setupIntentId) {
          return res.status(400).json({
            success: false,
            error: "setup_intent_id is required",
          });
        }

        const setupIntent = await stripe.setupIntents.retrieve(setupIntentId);
        const metadata = setupIntent.metadata ?? {};
        const tid = Number(metadata.tenant_id ?? tenantId);
        if (tid !== tenantId) {
          return res.status(403).json({
            success: false,
            error: "Setup intent does not belong to this tenant",
          });
        }

        if (setupIntent.status !== "succeeded") {
          logBillingPaymentError(
            "confirm-payment-method",
            `setup intent not succeeded: ${setupIntent.status}`,
          );
          return res.status(400).json({
            success: false,
            error: BILLING_PAYMENT_UNAVAILABLE_MESSAGE,
            status: setupIntent.status,
          });
        }

        const pmId = paymentMethodIdFromSetupIntent(setupIntent.payment_method);
        if (!pmId) {
          return res.status(400).json({
            success: false,
            error: "No payment method on setup intent",
          });
        }

        await applyDefaultPaymentMethod(pool, stripe, tenantId, pmId);

        const billing = await loadTenantStripeBilling(pool, tenantId);
        const paymentMethod = billing.stripeCustomerId
          ? await fetchSavedPaymentMethodSummary(
              stripe,
              billing.stripeCustomerId,
            )
          : null;

        return res.json({ success: true, payment_method: paymentMethod });
      } catch (error: unknown) {
        return respondPaymentUnavailable(res, "confirm-payment-method", error);
      }
    },
  );

  app.post(
    "/api/billing/stripe/subscription-setup",
    ...billingOwnerAuth,
    async (req, res) => {
      try {
        const stripe = await loadStripe();
        const priceId = getPlatformPriceId();
        if (!stripe) {
          logBillingPaymentError(
            "subscription-setup",
            "Stripe keys not configured",
          );
          return res.status(503).json({
            success: false,
            error: BILLING_PAYMENT_UNAVAILABLE_MESSAGE,
          });
        }
        if (!priceId) {
          logBillingPaymentError(
            "subscription-setup",
            "STRIPE_PLATFORM_PRICE_ID missing or invalid",
          );
          return res.status(503).json({
            success: false,
            error: BILLING_PAYMENT_UNAVAILABLE_MESSAGE,
          });
        }

        const broker = (
          req as express.Request & { broker?: { email?: string } }
        ).broker;
        if (!broker?.email) {
          return res.status(400).json({
            success: false,
            error:
              "Your broker account must have an email address to start a subscription.",
          });
        }

        const customerId = await getOrCreateStripeCustomer(
          pool,
          stripe,
          tenantId,
          broker.email,
        );
        if (!customerId) {
          logBillingPaymentError(
            "subscription-setup",
            "getOrCreateStripeCustomer returned null",
          );
          return res.status(500).json({
            success: false,
            error: BILLING_PAYMENT_UNAVAILABLE_MESSAGE,
          });
        }

        const billing = await loadTenantStripeBilling(pool, tenantId);
        const forceNew = Boolean(
          (req.body as { force_new?: boolean }).force_new,
        );

        if (forceNew && billing.stripeSubscriptionId) {
          try {
            const stale = await stripe.subscriptions.retrieve(
              billing.stripeSubscriptionId,
            );
            const staleStatus = String(stale.status ?? "");
            if (
              staleStatus === "incomplete" ||
              staleStatus === "incomplete_expired" ||
              staleStatus === "canceled"
            ) {
              if (staleStatus !== "canceled") {
                await stripe.subscriptions.cancel(billing.stripeSubscriptionId);
              }
              await pool.query(
                `UPDATE tenant_subscription
                 SET stripe_subscription_id = NULL, status = 'inactive', updated_at = UTC_TIMESTAMP()
                 WHERE tenant_id = ?`,
                [tenantId],
              );
              billing.stripeSubscriptionId = null;
            }
          } catch (cancelErr) {
            console.warn("Stripe subscription reset failed:", cancelErr);
          }
        }

        if (billing.stripeSubscriptionId) {
          const existing = await stripe.subscriptions.retrieve(
            billing.stripeSubscriptionId,
            {
              expand: [...SUBSCRIPTION_PAYMENT_EXPAND],
            },
          );
          const stripeStatus = String(existing.status ?? "");
          const existingPriceId = getSubscriptionPlatformPriceId(
            existing as Record<string, unknown>,
          );
          if (existingPriceId && existingPriceId !== priceId) {
            console.warn(
              `Stripe subscription ${billing.stripeSubscriptionId} uses price ${existingPriceId}, expected ${priceId}; recreating`,
            );
            try {
              if (
                stripeStatus !== "canceled" &&
                stripeStatus !== "incomplete_expired"
              ) {
                await stripe.subscriptions.cancel(billing.stripeSubscriptionId);
              }
            } catch (cancelErr) {
              console.warn(
                "Stripe subscription price-mismatch cancel failed:",
                cancelErr,
              );
            }
            await clearDbStripeSubscriptionId(pool, tenantId);
            billing.stripeSubscriptionId = null;
          } else if (stripeStatus === "active" || stripeStatus === "trialing") {
            const savedPm = await fetchSavedPaymentMethodSummary(
              stripe,
              customerId,
              billing.stripeSubscriptionId,
            );
            if (savedPm) {
              await syncStripeSubscriptionToDb(pool, tenantId, existing);
              return res.json({
                success: true,
                already_active: true,
                subscription_id: billing.stripeSubscriptionId,
                stripe_status: stripeStatus,
              });
            }
          } else if (stripeStatus === "incomplete") {
            const clientSecret =
              extractSubscriptionPaymentClientSecret(existing);
            if (clientSecret) {
              return res.json({
                success: true,
                client_secret: clientSecret,
                subscription_id: billing.stripeSubscriptionId,
                stripe_status: stripeStatus,
              });
            }
          }
        }

        const subscription = await stripe.subscriptions.create({
          customer: customerId,
          items: [{ price: priceId }],
          payment_behavior: "default_incomplete",
          payment_settings: { save_default_payment_method: "on_subscription" },
          expand: [...SUBSCRIPTION_PAYMENT_EXPAND],
          metadata: { tenant_id: String(tenantId) },
        });

        const subscriptionId = String(subscription.id ?? "");
        const clientSecret =
          extractSubscriptionPaymentClientSecret(subscription);
        if (!subscriptionId || !clientSecret) {
          logBillingPaymentError(
            "subscription-setup",
            "subscription created without client_secret",
          );
          return res.status(500).json({
            success: false,
            error: BILLING_PAYMENT_UNAVAILABLE_MESSAGE,
          });
        }

        await pool.query(
          `UPDATE tenant_subscription
           SET stripe_subscription_id = ?, status = 'inactive', updated_at = UTC_TIMESTAMP()
           WHERE tenant_id = ?`,
          [subscriptionId, tenantId],
        );

        return res.json({
          success: true,
          client_secret: clientSecret,
          subscription_id: subscriptionId,
          stripe_status: String(subscription.status ?? "incomplete"),
        });
      } catch (error: unknown) {
        return respondPaymentUnavailable(res, "subscription-setup", error);
      }
    },
  );

  app.post(
    "/api/billing/stripe/confirm-subscription",
    ...billingOwnerAuth,
    async (req, res) => {
      try {
        const stripe = await loadStripe();
        if (!stripe) {
          logBillingPaymentError(
            "confirm-subscription",
            "Stripe keys not configured",
          );
          return res.status(503).json({
            success: false,
            error: BILLING_PAYMENT_UNAVAILABLE_MESSAGE,
          });
        }

        const subscriptionId = String(
          (req.body as { subscription_id?: string }).subscription_id ?? "",
        );
        if (!subscriptionId) {
          return res.status(400).json({
            success: false,
            error: "subscription_id is required",
          });
        }

        let subscription = await stripe.subscriptions.retrieve(subscriptionId, {
          expand: ["latest_invoice", "default_payment_method"],
        });
        const metadata = (subscription.metadata ?? {}) as Record<
          string,
          string
        >;
        const tid = Number(metadata.tenant_id ?? tenantId);
        if (tid !== tenantId) {
          return res.status(403).json({
            success: false,
            error: "Subscription does not belong to this tenant",
          });
        }

        let stripeStatus = String(subscription.status ?? "");
        if (stripeStatus !== "active" && stripeStatus !== "trialing") {
          await new Promise((resolve) => setTimeout(resolve, 1500));
          subscription = await stripe.subscriptions.retrieve(subscriptionId, {
            expand: ["latest_invoice", "default_payment_method"],
          });
          stripeStatus = String(subscription.status ?? "");
        }
        if (stripeStatus !== "active" && stripeStatus !== "trialing") {
          logBillingPaymentError(
            "confirm-subscription",
            `subscription not active yet: ${stripeStatus}`,
          );
          return res.status(400).json({
            success: false,
            error: BILLING_PAYMENT_UNAVAILABLE_MESSAGE,
            stripe_status: stripeStatus,
          });
        }

        await syncStripeSubscriptionToDb(pool, tenantId, subscription);
        const paymentMethod = await syncSubscriptionDefaultPaymentMethod(
          pool,
          stripe,
          tenantId,
          subscription,
        );
        const broker = (
          req as express.Request & { broker?: { email?: string } }
        ).broker;
        if (broker?.email) {
          await storeBillingSubscriberEmail(pool, tenantId, broker.email);
        }
        const receiptEmail = await sendBillingSubscriptionReceiptEmail(
          pool,
          tenantId,
          subscription,
          broker?.email,
        ).catch((err) => {
          console.error("[billing] Subscription receipt email failed:", err);
          return { sent: false, error: "send_failed" };
        });
        await getUnifiedQuotaSummary(pool, tenantId);
        const config = await getBillingConfig(pool, tenantId);

        return res.json({
          success: true,
          stripe_status: stripeStatus,
          subscription: config.subscription,
          payment_method: paymentMethod,
          receipt_email: receiptEmail,
        });
      } catch (error: unknown) {
        return respondPaymentUnavailable(res, "confirm-subscription", error);
      }
    },
  );

  app.post(
    "/api/billing/stripe/reset-subscription-test",
    ...billingOwnerAuth,
    async (req, res) => {
      try {
        const stripePublic = getStripePublicConfig();
        if (!stripePublic.testMode) {
          return res.status(403).json({
            success: false,
            error: "Test reset is only available with Stripe test keys",
          });
        }
        const stripe = await loadStripe();
        if (!stripe) {
          logBillingPaymentError("charge-quote", "Stripe keys not configured");
          return res.status(503).json({
            success: false,
            error: BILLING_PAYMENT_UNAVAILABLE_MESSAGE,
          });
        }
        const result = await resetStripeSubscriptionForTest(
          pool,
          stripe,
          tenantId,
        );
        return res.json({ success: true, ...result });
      } catch (error: unknown) {
        console.error("Stripe test reset error:", error);
        return res.status(500).json({
          success: false,
          error: "Failed to reset test subscription",
        });
      }
    },
  );
}

