/**
 * Send SMS message via Twilio
 */
async function sendSMSMessage(
  to: string,
  body: string,
  metadata?: any,
  from?: string,
  mediaUrl?: string,
  billing?: QuotaWireContext,
): Promise<{
  success: boolean;
  external_id?: string;
  error?: string;
  cost?: number;
  provider_response?: any;
  quota_exceeded?: boolean;
  billing_action_required?: boolean;
}> {
  if (!twilioClient) {
    return {
      success: false,
      error: "Twilio not configured - SMS sending disabled",
    };
  }

  try {
    if (billing) {
      const quotaPrecheck = mediaUrl ? precheckMmsQuota : precheckSmsQuota;
      const quotaResult = await quotaPrecheck(body, billing);
      if (!quotaResult.allowed) {
        const denial = quotaDenialPayload(quotaResult);
        return {
          success: false,
          error: denial.error,
          quota_exceeded: Boolean(quotaResult.quotaExceeded),
          billing_action_required: Boolean(quotaResult.billingBlocked),
        };
      }
    }
    // Normalize to E.164 format:
    // - Already E.164 (+52..., +1...): use as-is
    // - 11-digit starting with 1 (15551234567): prepend +
    // - 10-digit US number (5551234567): prepend +1
    // - Formatted US (555-123-4567, (555) 123-4567): strip non-digits then prepend +1
    const digits = to.replace(/\D/g, "");
    let normalizedPhone: string;
    if (to.startsWith("+")) {
      normalizedPhone = to; // already E.164
    } else if (digits.length === 11 && digits.startsWith("1")) {
      normalizedPhone = `+${digits}`; // 1XXXXXXXXXX → +1XXXXXXXXXX
    } else if (digits.length === 10) {
      normalizedPhone = `+1${digits}`; // XXXXXXXXXX → +1XXXXXXXXXX
    } else {
      // Fallback: trust what was stored (may already have + or be international)
      normalizedPhone = to.startsWith("+") ? to : `+${digits}`;
    }

    // Resolve the "from" number: explicit arg → otp_from_number DB setting
    let effectiveFrom = from || undefined;
    if (!effectiveFrom) {
      const [otpNumRows] = await pool.query<RowDataPacket[]>(
        `SELECT setting_value FROM system_settings
         WHERE setting_key = 'otp_from_number'
         ORDER BY tenant_id DESC LIMIT 1`,
      );
      effectiveFrom = otpNumRows[0]?.setting_value || undefined;
    }

    const baseUrl = getBaseUrl();
    const isPublicUrl =
      !baseUrl.includes("localhost") && !baseUrl.includes("127.0.0.1");

    const message = await twilioClient.messages.create({
      body,
      to: normalizedPhone,
      from: effectiveFrom,
      ...(mediaUrl ? { mediaUrl: [mediaUrl] } : {}),
      ...(isPublicUrl
        ? { statusCallback: `${baseUrl}/api/webhooks/sms-status` }
        : {}),
      ...metadata,
    });

    console.log(
      `[SMS Trace] sendSMSMessage OK — sid=${message.sid} status=${message.status} from=${effectiveFrom} to=${normalizedPhone} price=${message.price}`,
    );

    if (billing) {
      const quotaRecord = mediaUrl ? recordMmsQuota : recordSmsQuota;
      await quotaRecord(body, billing);
    }

    const twilioCost = parseFloat(message.price || "0");
    const estimatedCost = resolveOutboundCommunicationCostUsd({
      channel: mediaUrl ? "mms" : "sms",
      body,
      twilioPriceUsd: twilioCost,
    });

    const sid = message.sid;

    // Non-blocking delayed status check: after 15 s, fetch the actual delivery
    // outcome from Twilio and update the DB. This catches failures (undelivered,
    // failed, carrier-filtered) without relying on the webhook being reachable.
    setTimeout(async () => {
      try {
        const fetched = await twilioClient!.messages(sid).fetch();
        const statusMap: Record<string, string> = {
          sent: "sent",
          delivered: "delivered",
          read: "read",
          failed: "failed",
          undelivered: "failed",
        };
        const mapped = statusMap[fetched.status] ?? null;
        console.log(
          `[SMS Trace] 15s status check — sid=${sid} twilio_status=${fetched.status} mapped=${mapped} errorCode=${fetched.errorCode ?? "none"} errorMessage=${fetched.errorMessage ?? "none"}`,
        );
        if (mapped && mapped !== "sent") {
          await pool.query(
            `UPDATE communications
             SET delivery_status = ?, status = ?
               ${fetched.errorCode ? ", error_message = ?" : ""}
             WHERE external_id = ? AND tenant_id = ?`,
            [
              mapped,
              mapped,
              ...(fetched.errorCode
                ? [`Twilio ${fetched.errorCode}: ${fetched.errorMessage ?? ""}`]
                : []),
              sid,
              MORTGAGE_TENANT_ID,
            ],
          );

          if (mapped === "failed") {
            // Publish Ably event so the UI can show a failed-delivery indicator
            publishToAbly("conversations:all", "sms-delivery-failed", {
              sid,
              errorCode: fetched.errorCode,
              errorMessage: fetched.errorMessage,
            }).catch(() => undefined);
          }
        }
      } catch (checkErr: any) {
        console.warn(
          `[SMS Trace] 15s status check failed for sid=${sid}:`,
          checkErr?.message || checkErr,
        );
      }
    }, 15_000);

    return {
      success: true,
      external_id: sid,
      cost: estimatedCost,
      provider_response: {
        sid: message.sid,
        status: message.status,
        direction: message.direction,
        uri: message.uri,
      },
    };
  } catch (error: any) {
    console.error("❌ SMS sending failed:", error);
    // Twilio 21408: SMS not enabled for the destination region/country
    const userError =
      error.code === 21408
        ? "SMS is not enabled for this phone number's region. Please use email verification instead."
        : error.message || "Failed to send SMS";
    return {
      success: false,
      error: userError,
      provider_response: error,
    };
  }
}

/**
 * Send OTP via voice call using Twilio — reads the code aloud using TwiML <Say>.
 * Dynamically picks the first voice-capable "All Mortgage Bankers" number (i.e. a
 * Twilio number that is NOT exclusively assigned to any individual broker).
 */
/** 60-second in-process cache — mirrors getSharedSmsNumber() to avoid a Twilio
 * REST round-trip on every outbound call TwiML request. */
let _sharedVoiceNumberCache: { value: string | null; at: number } | null = null;

async function getSharedVoiceNumber(): Promise<string | null> {
  if (!twilioClient) return null;
  const now = Date.now();
  if (_sharedVoiceNumberCache && now - _sharedVoiceNumberCache.at < 60_000) {
    return _sharedVoiceNumberCache.value;
  }
  try {
    // Collect all SIDs AND phone numbers exclusively assigned to individual brokers
    // (mirrors getSharedSmsNumber — must filter by both to avoid returning a broker's
    //  personal line when only twilio_caller_id is set and twilio_phone_sid is NULL)
    const [assignedRows] = await pool.query<RowDataPacket[]>(
      `SELECT twilio_phone_sid, twilio_caller_id FROM brokers
       WHERE tenant_id = ?
         AND ((twilio_phone_sid IS NOT NULL AND twilio_phone_sid != '')
              OR (twilio_caller_id IS NOT NULL AND twilio_caller_id != ''))`,
      [MORTGAGE_TENANT_ID],
    );
    const assignedSids = new Set(
      (assignedRows as RowDataPacket[])
        .map((r) => r.twilio_phone_sid as string)
        .filter(Boolean),
    );
    const assignedNumbers = new Set(
      (assignedRows as RowDataPacket[])
        .map((r) => r.twilio_caller_id as string)
        .filter(Boolean),
    );

    // List all Twilio numbers and return the first voice-capable unassigned one
    const numbers = await twilioClient.incomingPhoneNumbers.list({ limit: 50 });
    const shared = numbers.find(
      (n: any) =>
        n.capabilities?.voice &&
        !assignedSids.has(n.sid) &&
        !assignedNumbers.has(n.phoneNumber),
    );
    const value = shared?.phoneNumber ?? null;
    _sharedVoiceNumberCache = { value, at: now };
    return value;
  } catch (err) {
    console.error("❌ getSharedVoiceNumber failed:", err);
    return null;
  }
}

/**
 * Dynamically picks the first SMS-capable "All Mortgage Bankers" number —
 * a Twilio number that is NOT exclusively assigned to any individual broker.
 * Used for outbound SMS/MMS/WhatsApp from brokers who have no personal line
 * and when no shared number can be derived from existing thread history.
 * Results are cached for 60s to avoid hitting the Twilio API on every send.
 */
let _sharedSmsNumberCache: { value: string | null; at: number } | null = null;
async function getSharedSmsNumber(): Promise<string | null> {
  if (!twilioClient) return null;
  const now = Date.now();
  if (_sharedSmsNumberCache && now - _sharedSmsNumberCache.at < 60_000) {
    return _sharedSmsNumberCache.value;
  }
  try {
    const [assignedRows] = await pool.query<RowDataPacket[]>(
      `SELECT twilio_phone_sid, twilio_caller_id FROM brokers
       WHERE tenant_id = ?
         AND ((twilio_phone_sid IS NOT NULL AND twilio_phone_sid <> '')
              OR (twilio_caller_id IS NOT NULL AND twilio_caller_id <> ''))`,
      [MORTGAGE_TENANT_ID],
    );
    const assignedSids = new Set(
      (assignedRows as RowDataPacket[])
        .map((r) => r.twilio_phone_sid as string)
        .filter(Boolean),
    );
    const assignedNumbers = new Set(
      (assignedRows as RowDataPacket[])
        .map((r) => r.twilio_caller_id as string)
        .filter(Boolean),
    );

    const numbers = await twilioClient.incomingPhoneNumbers.list({ limit: 50 });
    const shared = numbers
      .filter(
        (n: any) =>
          n.capabilities?.sms &&
          !assignedSids.has(n.sid) &&
          !assignedNumbers.has(n.phoneNumber),
      )
      .sort((a: any, b: any) => a.phoneNumber.localeCompare(b.phoneNumber))[0];
    const value = shared?.phoneNumber ?? null;
    _sharedSmsNumberCache = { value, at: now };
    return value;
  } catch (err) {
    console.error("❌ getSharedSmsNumber failed:", err);
    return null;
  }
}

async function sendVoiceOTP(
  to: string,
  code: number,
): Promise<{ success: boolean; error?: string }> {
  if (!twilioClient) {
    return { success: false, error: "Twilio not configured" };
  }

  const fromNumber = await getSharedVoiceNumber();
  if (!fromNumber) {
    return {
      success: false,
      error:
        "No shared voice number available. Please use email or SMS verification.",
    };
  }

  // Normalise to E.164
  const digits = to.replace(/\D/g, "");
  let normalizedPhone: string;
  if (to.startsWith("+")) {
    normalizedPhone = to;
  } else if (digits.length === 11 && digits.startsWith("1")) {
    normalizedPhone = `+${digits}`;
  } else if (digits.length === 10) {
    normalizedPhone = `+1${digits}`;
  } else {
    normalizedPhone = `+${digits}`;
  }

  // Spell out each digit with pauses for clarity
  const spokenCode = String(code).split("").join(". ");
  const twiml = `<?xml version="1.0" encoding="UTF-8"?>
<Response>
  <Say voice="Polly.Joanna" language="en-US">Hello! Your Encore Mortgage verification code is: ${spokenCode}. I repeat: ${spokenCode}. Goodbye.</Say>
</Response>`;

  try {
    await twilioClient.calls.create({
      to: normalizedPhone,
      from: fromNumber,
      twiml,
    });
    return { success: true };
  } catch (error: any) {
    console.error("❌ Voice OTP call failed:", error);
    return { success: false, error: error.message || "Failed to place call" };
  }
}

/**
 * Send WhatsApp message via Twilio
 */
async function sendWhatsAppMessage(
  to: string,
  body: string,
  metadata?: any,
  billing?: QuotaWireContext,
): Promise<{
  success: boolean;
  external_id?: string;
  error?: string;
  cost?: number;
  provider_response?: any;
  quota_exceeded?: boolean;
  billing_action_required?: boolean;
}> {
  if (!twilioClient) {
    return {
      success: false,
      error: "Twilio not configured - WhatsApp sending disabled",
    };
  }

  try {
    if (billing) {
      const quotaResult = await precheckWhatsappQuota(body, billing);
      if (!quotaResult.allowed) {
        const denial = quotaDenialPayload(quotaResult);
        return {
          success: false,
          error: denial.error,
          quota_exceeded: Boolean(quotaResult.quotaExceeded),
          billing_action_required: Boolean(quotaResult.billingBlocked),
        };
      }
    }
    // Normalize phone number for WhatsApp
    const normalizedPhone = to.startsWith("+")
      ? to
      : `+1${to.replace(/\D/g, "")}`;
    const whatsappNumber = `whatsapp:${normalizedPhone}`;
    const whatsappFrom = `whatsapp:${process.env.TWILIO_WHATSAPP_NUMBER || process.env.TWILIO_PHONE_NUMBER}`;

    // Attach delivery status callback so the WhatsApp message can progress from
    // ✓ (sent) → ✓✓ (delivered) → ✓✓ blue (read), matching SMS behavior.
    // Twilio cannot reach localhost, so only attach for public URLs.
    const baseUrl = getBaseUrl();
    const isPublicUrl =
      !baseUrl.includes("localhost") && !baseUrl.includes("127.0.0.1");

    const message = await twilioClient.messages.create({
      body,
      to: whatsappNumber,
      from: whatsappFrom,
      ...(isPublicUrl
        ? { statusCallback: `${baseUrl}/api/webhooks/sms-status` }
        : {}),
      ...metadata,
    });

    if (billing) {
      await recordWhatsappQuota(body, billing);
    }

    const twilioCost = parseFloat(message.price || "0");
    const estimatedCost = resolveOutboundCommunicationCostUsd({
      channel: "whatsapp",
      body,
      twilioPriceUsd: twilioCost,
    });

    return {
      success: true,
      external_id: message.sid,
      cost: estimatedCost,
      provider_response: {
        sid: message.sid,
        status: message.status,
        direction: message.direction,
        uri: message.uri,
      },
    };
  } catch (error: any) {
    console.error("❌ WhatsApp sending failed:", error);
    return {
      success: false,
      error: error.message || "Failed to send WhatsApp message",
      provider_response: error,
    };
  }
}

/**
 * Send Email message via SMTP
 */
async function sendEmailMessage(
  to: string,
  subject: string,
  body: string,
  isHTML: boolean = false,
  conversationId?: string,
  options?: {
    channel?: "default" | "reminder_flow";
    billing?: QuotaWireContext;
  },
): Promise<{
  success: boolean;
  external_id?: string;
  error?: string;
  provider_response?: any;
  quota_exceeded?: boolean;
  billing_action_required?: boolean;
}> {
  const isReminderFlowChannel = options?.channel === "reminder_flow";
  const smtpFrom = isReminderFlowChannel
    ? process.env.REMINDER_SMTP_FROM || process.env.SMTP_FROM
    : process.env.SMTP_FROM;

  console.log(
    `📧 sendEmailMessage: to=${to} | subject="${subject}" | channel=${isReminderFlowChannel ? "reminder_flow" : "default"} | isHTML=${isHTML} | conv=${conversationId ?? "none"} | from=${smtpFrom ?? "(not set)"}`,
  );

  try {
    const billing = options?.billing;
    if (billing && !billing.skipQuota) {
      const quotaResult = await precheckEmailQuota(billing);
      if (!quotaResult.allowed) {
        const denial = quotaDenialPayload(quotaResult);
        return {
          success: false,
          error: denial.error,
          quota_exceeded: Boolean(quotaResult.quotaExceeded),
          billing_action_required: Boolean(quotaResult.billingBlocked),
        };
      }
    }

    // Derive the domain from SMTP_FROM for threading headers.
    const smtpFromEmail =
      smtpFrom?.match(/<([^>]+)>/)?.[1] || smtpFrom || "noreply@example.com";
    const emailDomain = smtpFromEmail.split("@")[1] || "example.com";

    // Encode conversationId into the Message-ID for email threading.
    const messageId = conversationId
      ? `<enc-${conversationId}-${Date.now()}@${emailDomain}>`
      : undefined;

    // Reply-To: use a dedicated IMAP mailbox (IMAP_USER) when configured.
    const inboundMailbox = process.env.IMAP_USER;
    const inboundDomain = process.env.INBOUND_EMAIL_DOMAIN;
    const replyTo = inboundMailbox
      ? inboundMailbox
      : conversationId && inboundDomain
        ? `reply+${conversationId}@${inboundDomain}`
        : smtpFrom;

    const headers: Record<string, string> = {};
    if (conversationId) headers["X-Conversation-Id"] = conversationId;
    if (messageId) headers["Message-ID"] = messageId;

    const info = await sendViaResend(
      {
        from: smtpFrom || RESEND_FROM,
        to,
        subject,
        replyTo: replyTo || undefined,
        headers: Object.keys(headers).length ? headers : undefined,
        ...(isHTML ? { html: body } : { text: body }),
      },
      billing ? { ...billing, skipQuota: true } : undefined,
    );

    if (billing && !billing.skipQuota) {
      await recordEmailQuota(billing);
    }

    return {
      success: true,
      external_id: info.messageId,
      provider_response: { messageId: info.messageId },
    };
  } catch (error: any) {
    console.error(
      `❌ sendEmailMessage failed: to=${to} | subject="${subject}" | error=${error.message}`,
      error,
    );
    return {
      success: false,
      error: error.message || "Failed to send email",
      provider_response: error,
    };
  }
}

/**
 * Process template variables in message body
 */
function processTemplateVariables(
  template: string,
  variables: Record<string, any>,
): string {
  let processed = template;

  for (const [key, value] of Object.entries(variables)) {
    const placeholder = `{{${key}}}`;
    processed = processed.replace(new RegExp(placeholder, "gi"), value || "");
  }

  return processed;
}

/** Last-10-digit phone match (same logic as thread list + ownership guard). */
function phoneLastTen(phone: string | null | undefined): string | null {
  if (!phone) return null;
  const last = phone.replace(/\D/g, "").slice(-10);
  return last.length === 10 ? last : null;
}

/**
 * Resolve {{first_name}}, {{client_name}}, {{broker_name}}, etc. for Conversations send.
 * Uses client_id when provided; otherwise thread row, normalized phone/email, and
 * denormalized client_name — matching how the UI displays contact names.
 */
async function resolveConversationTemplateVariables(opts: {
  clientId?: number | null;
  applicationId?: number | null;
  conversationId?: string | null;
  recipientPhone?: string | null;
  recipientEmail?: string | null;
  recipientBrokerId?: number | null;
  senderBrokerId?: number | null;
}): Promise<Record<string, string>> {
  let clientFirstName = "";
  let clientLastName = "";
  let clientFullName = "";
  let applicationNumber = opts.applicationId ? String(opts.applicationId) : "";

  const loadClientById = async (id: number) => {
    const [rows] = await pool.query<RowDataPacket[]>(
      `SELECT first_name, last_name FROM clients WHERE id = ? AND tenant_id = ? LIMIT 1`,
      [id, MORTGAGE_TENANT_ID],
    );
    if (rows.length > 0) {
      clientFirstName = rows[0].first_name || "";
      clientLastName = rows[0].last_name || "";
      clientFullName = `${clientFirstName} ${clientLastName}`.trim();
    }
  };

  const loadClientByPhone = async (phone: string) => {
    const lastTen = phoneLastTen(phone);
    if (!lastTen) return;
    const [rows] = await pool.query<RowDataPacket[]>(
      `SELECT first_name, last_name FROM clients
       WHERE tenant_id = ?
         AND RIGHT(REGEXP_REPLACE(phone, '[^0-9]', ''), 10) = ?
       LIMIT 1`,
      [MORTGAGE_TENANT_ID, lastTen],
    );
    if (rows.length > 0) {
      clientFirstName = rows[0].first_name || "";
      clientLastName = rows[0].last_name || "";
      clientFullName = `${clientFirstName} ${clientLastName}`.trim();
    }
  };

  const loadClientByEmail = async (email: string) => {
    const [rows] = await pool.query<RowDataPacket[]>(
      `SELECT first_name, last_name FROM clients
       WHERE tenant_id = ? AND LOWER(email) = LOWER(?) LIMIT 1`,
      [MORTGAGE_TENANT_ID, email],
    );
    if (rows.length > 0) {
      clientFirstName = rows[0].first_name || "";
      clientLastName = rows[0].last_name || "";
      clientFullName = `${clientFirstName} ${clientLastName}`.trim();
    }
  };

  const applyDisplayName = (name: string | null | undefined) => {
    const trimmed = (name || "").trim();
    if (!trimmed) return;
    const parts = trimmed.split(/\s+/);
    clientFirstName = parts[0] || "";
    clientLastName = parts.slice(1).join(" ");
    clientFullName = trimmed;
  };

  if (opts.clientId) {
    await loadClientById(opts.clientId);
  }

  if (!clientFirstName && opts.conversationId) {
    const [threadRows] = await pool.query<RowDataPacket[]>(
      `SELECT client_id, client_name, client_phone, client_email, contact_broker_id
       FROM conversation_threads
       WHERE conversation_id = ? AND tenant_id = ? LIMIT 1`,
      [opts.conversationId, MORTGAGE_TENANT_ID],
    );
    if (threadRows.length > 0) {
      const t = threadRows[0];
      if (t.client_id) {
        await loadClientById(t.client_id as number);
      }
      if (!clientFirstName && t.client_name) {
        applyDisplayName(t.client_name as string);
      }
      if (!clientFirstName && t.client_phone) {
        await loadClientByPhone(t.client_phone as string);
      }
      if (!clientFirstName && t.client_email) {
        await loadClientByEmail(t.client_email as string);
      }
      if (!clientFirstName && t.contact_broker_id) {
        const [bRows] = await pool.query<RowDataPacket[]>(
          `SELECT first_name, last_name FROM brokers WHERE id = ? AND tenant_id = ? LIMIT 1`,
          [t.contact_broker_id, MORTGAGE_TENANT_ID],
        );
        if (bRows.length > 0) {
          clientFirstName = bRows[0].first_name || "";
          clientLastName = bRows[0].last_name || "";
          clientFullName =
            `${clientFirstName} ${clientLastName}`.trim() || clientFirstName;
        }
      }
    }
  }

  if (!clientFirstName && opts.recipientPhone) {
    await loadClientByPhone(opts.recipientPhone);
  }
  if (!clientFirstName && opts.recipientEmail) {
    await loadClientByEmail(opts.recipientEmail);
  }
  if (!clientFirstName && opts.recipientBrokerId) {
    const [bRows] = await pool.query<RowDataPacket[]>(
      `SELECT first_name, last_name FROM brokers WHERE id = ? AND tenant_id = ? LIMIT 1`,
      [opts.recipientBrokerId, MORTGAGE_TENANT_ID],
    );
    if (bRows.length > 0) {
      clientFirstName = bRows[0].first_name || "";
      clientLastName = bRows[0].last_name || "";
      clientFullName =
        `${clientFirstName} ${clientLastName}`.trim() || clientFirstName;
    }
  }

  if (opts.applicationId) {
    const [appRows] = await pool.query<RowDataPacket[]>(
      `SELECT application_number, id FROM loan_applications WHERE id = ? AND tenant_id = ? LIMIT 1`,
      [opts.applicationId, MORTGAGE_TENANT_ID],
    );
    if (appRows.length > 0) {
      applicationNumber =
        appRows[0].application_number || String(appRows[0].id);
    }
  }

  let brokerFirstName = "";
  let brokerLastName = "";
  let brokerFullName = "";
  if (opts.senderBrokerId) {
    const [brokerRows] = await pool.query<RowDataPacket[]>(
      `SELECT first_name, last_name FROM brokers WHERE id = ? AND tenant_id = ? LIMIT 1`,
      [opts.senderBrokerId, MORTGAGE_TENANT_ID],
    );
    if (brokerRows.length > 0) {
      brokerFirstName = brokerRows[0].first_name || "";
      brokerLastName = brokerRows[0].last_name || "";
      brokerFullName = `${brokerFirstName} ${brokerLastName}`.trim();
    }
  }

  return {
    first_name: clientFirstName,
    last_name: clientLastName,
    client_name: clientFullName || clientFirstName,
    client_first_name: clientFirstName,
    client_last_name: clientLastName,
    application_id: applicationNumber,
    application_number: applicationNumber,
    broker_name: brokerFullName || brokerFirstName || "Your Loan Officer",
    broker_first_name: brokerFirstName,
    broker_last_name: brokerLastName,
    current_date: new Date().toLocaleDateString("en-US", {
      month: "long",
      day: "numeric",
      year: "numeric",
    }),
  };
}

