/**
 * P1-3: JWT revocation helpers.
 * Logout inserts the token's jti into `revoked_tokens`; auth middleware
 * rejects any token whose jti is present until natural expiry.
 */
const isJtiRevoked = async (jti: string | undefined): Promise<boolean> => {
  if (!jti || typeof jti !== "string") return false;
  try {
    const [rows] = await pool.query<any[]>(
      "SELECT 1 FROM revoked_tokens WHERE jti = ? LIMIT 1",
      [jti],
    );
    return rows.length > 0;
  } catch (err) {
    // Fail-open on infra errors so a transient DB issue doesn't lock everyone out.
    console.error("isJtiRevoked query failed:", err);
    return false;
  }
};

const revokeJti = async (
  jti: string | undefined,
  userType: "client" | "broker",
  userId: number | undefined,
  exp: number | undefined,
): Promise<void> => {
  if (!jti || !userId || !exp) return;
  try {
    await pool.query(
      `INSERT IGNORE INTO revoked_tokens (jti, user_type, user_id, expires_at)
       VALUES (?, ?, ?, FROM_UNIXTIME(?))`,
      [jti, userType, userId, exp],
    );
  } catch (err) {
    console.error("revokeJti insert failed:", err);
  }
};

/**
 * Middleware to verify client session
 */
const verifyClientSession = async (
  req: express.Request,
  res: express.Response,
  next: express.NextFunction,
) => {
  try {
    const authHeader = req.headers.authorization;

    if (!authHeader || !authHeader.startsWith("Bearer ")) {
      return res.status(401).json({
        success: false,
        message: "No session token provided",
      });
    }

    const sessionToken = authHeader.substring(7);

    try {
      const decoded = jwt.verify(sessionToken, JWT_SECRET, {
        algorithms: ["HS256"],
      }) as any;

      if (decoded.userType !== "client") {
        return res.status(403).json({
          success: false,
          message: "Access denied",
        });
      }

      // P1-3: reject revoked tokens
      if (await isJtiRevoked(decoded.jti)) {
        return res.status(401).json({
          success: false,
          message: "Session has been revoked",
        });
      }

      // Get client details
      const [clients] = await pool.query<any[]>(
        "SELECT * FROM clients WHERE id = ? AND status = 'active' AND tenant_id = ?",
        [decoded.clientId, MORTGAGE_TENANT_ID],
      );

      if (clients.length === 0) {
        return res.status(401).json({
          success: false,
          message: "Client not found or inactive",
        });
      }

      // Attach client info to request
      (req as any).client = clients[0];
      (req as any).clientId = decoded.clientId;

      next();
    } catch (jwtError) {
      return res.status(401).json({
        success: false,
        message: "Invalid or expired session",
      });
    }
  } catch (error) {
    console.error("Error verifying client session:", error);
    res.status(500).json({
      success: false,
      message: "Failed to verify session",
    });
  }
};

/**
 * Middleware to verify broker session
 */
const verifyBrokerSession = async (
  req: express.Request,
  res: express.Response,
  next: express.NextFunction,
) => {
  try {
    const authHeader = req.headers.authorization;

    if (!authHeader || !authHeader.startsWith("Bearer ")) {
      return res.status(401).json({
        success: false,
        message: "No session token provided",
      });
    }

    const sessionToken = authHeader.substring(7);

    try {
      const decoded = jwt.verify(sessionToken, JWT_SECRET, {
        algorithms: ["HS256"],
      }) as any;

      if (decoded.userType !== "broker") {
        return res.status(403).json({
          success: false,
          message: "Access denied",
        });
      }

      // P1-3: reject revoked tokens
      if (await isJtiRevoked(decoded.jti)) {
        return res.status(401).json({
          success: false,
          message: "Session has been revoked",
        });
      }

      // Get broker details with profile avatar so header avatar does not flicker/reset.
      const [brokers] = await pool.query<any[]>(
        `SELECT b.*, bp.avatar_url
         FROM brokers b
         LEFT JOIN broker_profiles bp ON bp.broker_id = b.id
         WHERE b.id = ? AND b.status = 'active' AND b.tenant_id = ?`,
        [decoded.brokerId, MORTGAGE_TENANT_ID],
      );

      if (brokers.length === 0) {
        return res.status(401).json({
          success: false,
          message: "Broker not found or inactive",
        });
      }

      // Attach broker info to request
      (req as any).broker = brokers[0];
      (req as any).brokerId = decoded.brokerId;
      (req as any).brokerRole = brokers[0].role;

      next();
    } catch (jwtError) {
      return res.status(401).json({
        success: false,
        message: "Invalid or expired session",
      });
    }
  } catch (error) {
    console.error("Error verifying broker session:", error);
    res.status(500).json({
      success: false,
      message: "Failed to verify session",
    });
  }
};

// =====================================================
// BROKER NOTIFICATION HELPER
// =====================================================

type BrokerNotificationCategory =
  | "message"
  | "call"
  | "loan"
  | "client"
  | "task"
  | "flow"
  | "lead"
  | "system";

/**
 * 4-path loan/client ownership SQL (aliases: la = loan_applications, c = clients).
 * See docs/OWNERSHIP_MODEL.md — path 4: MB owns the partner on partner_broker_id.
 */
const LOAN_OWNERSHIP_WHERE_SQL = `(c.assigned_broker_id = ? OR la.broker_user_id = ? OR la.partner_broker_id = ? OR EXISTS (
  SELECT 1 FROM brokers op
  WHERE op.id = la.partner_broker_id AND op.created_by_broker_id = ? AND op.tenant_id = la.tenant_id
))`;

function loanOwnershipWhereParams(brokerId: number): number[] {
  return [brokerId, brokerId, brokerId, brokerId];
}

/** Non–platform-owner calendar visibility: own events + client-linked via ownership paths. */
const CALENDAR_EVENT_BROKER_VISIBILITY_SQL = `(
  ce.broker_id = ?
  OR (
    ce.linked_client_id IS NOT NULL
    AND EXISTS (
      SELECT 1 FROM clients c
      LEFT JOIN loan_applications la
        ON la.client_user_id = c.id AND la.tenant_id = c.tenant_id
      WHERE c.id = ce.linked_client_id
        AND c.tenant_id = ce.tenant_id
        AND ${LOAN_OWNERSHIP_WHERE_SQL}
    )
  )
)`;

async function brokerCanAccessLinkedClient(
  broker: { id: number; tenant_id: number; role: string },
  clientId: number,
): Promise<boolean> {
  if (broker.role === "platform_owner") return true;
  const [rows] = await pool.query<RowDataPacket[]>(
    `SELECT 1 FROM clients c
     LEFT JOIN loan_applications la
       ON la.client_user_id = c.id AND la.tenant_id = c.tenant_id
     WHERE c.id = ? AND c.tenant_id = ?
       AND ${LOAN_OWNERSHIP_WHERE_SQL}
     LIMIT 1`,
    [clientId, broker.tenant_id, ...loanOwnershipWhereParams(broker.id)],
  );
  return rows.length > 0;
}

async function brokerCanAccessCalendarEvent(
  broker: { id: number; tenant_id: number; role: string },
  event: { broker_id: number | null; linked_client_id: number | null },
): Promise<boolean> {
  if (broker.role === "platform_owner") return true;
  if (event.broker_id === broker.id) return true;
  if (event.linked_client_id == null) return false;
  return brokerCanAccessLinkedClient(broker, event.linked_client_id);
}

function rowHasLoanOwnershipAccess(
  brokerId: number,
  row:
    | RowDataPacket
    | {
        assigned_broker_id?: number | null;
        broker_user_id?: number | null;
        partner_broker_id?: number | null;
        partner_owner_broker_id?: number | null;
      },
): boolean {
  const r = row as RowDataPacket;
  return (
    Number(r.assigned_broker_id) === brokerId ||
    Number(r.broker_user_id) === brokerId ||
    Number(r.partner_broker_id) === brokerId ||
    Number(r.partner_owner_broker_id) === brokerId
  );
}

async function fetchLoanAccessRow(
  loanId: number,
): Promise<RowDataPacket | null> {
  const [rows] = await pool.query<RowDataPacket[]>(
    `SELECT la.id, la.status, la.broker_user_id, la.partner_broker_id,
            c.assigned_broker_id, op.created_by_broker_id AS partner_owner_broker_id
     FROM loan_applications la
     INNER JOIN clients c ON c.id = la.client_user_id AND c.tenant_id = la.tenant_id
     LEFT JOIN brokers op ON op.id = la.partner_broker_id AND op.tenant_id = la.tenant_id
     WHERE la.id = ? AND la.tenant_id = ?
     LIMIT 1`,
    [loanId, MORTGAGE_TENANT_ID],
  );
  return rows.length ? rows[0] : null;
}

async function assertLoanAccess(
  brokerId: number,
  brokerRole: string,
  loanId: number,
): Promise<
  | { ok: true; loan: RowDataPacket }
  | { ok: false; status: number; error: string }
> {
  const loan = await fetchLoanAccessRow(loanId);
  if (!loan) {
    return { ok: false, status: 404, error: "Loan not found" };
  }
  if (brokerRole === "platform_owner") {
    return { ok: true, loan };
  }
  if (!rowHasLoanOwnershipAccess(brokerId, loan)) {
    return { ok: false, status: 403, error: "Access denied" };
  }
  return { ok: true, loan };
}

/**
 * Resolve every broker who "owns" a loan application:
 *   - broker_user_id        (primary loan officer / mortgage banker)
 *   - partner_broker_id     (assigned realtor partner)
 *   - clients.assigned_broker_id (fallback if loan has no broker yet)
 *   - partner's created_by_broker_id (mortgage banker who owns the partner)
 * Returns a deduped array of broker IDs. Empty array if nothing resolved.
 */
async function getApplicationOwnerBrokerIds(
  applicationId: number | null | undefined,
): Promise<number[]> {
  if (!applicationId) return [];
  try {
    const [rows] = await pool.query<RowDataPacket[]>(
      `SELECT a.broker_user_id, a.partner_broker_id, c.assigned_broker_id,
              op.created_by_broker_id AS partner_owner_broker_id
         FROM loan_applications a
         LEFT JOIN clients c ON a.client_user_id = c.id
         LEFT JOIN brokers op ON op.id = a.partner_broker_id AND op.tenant_id = a.tenant_id
        WHERE a.id = ? AND a.tenant_id = ?
        LIMIT 1`,
      [applicationId, MORTGAGE_TENANT_ID],
    );
    if (rows.length === 0) return [];
    const ids = [
      rows[0].broker_user_id,
      rows[0].partner_broker_id,
      rows[0].assigned_broker_id,
      rows[0].partner_owner_broker_id,
    ]
      .map((v) => (typeof v === "number" ? v : v != null ? Number(v) : null))
      .filter((v): v is number => Number.isFinite(v as number));
    return Array.from(new Set(ids));
  } catch (err) {
    console.error("getApplicationOwnerBrokerIds failed:", err);
    return [];
  }
}

/**
 * Create an in-app notification for one or more brokers (admin bell feed).
 * Non-fatal: errors are logged and swallowed so callers never break the
 * primary action because of a notification failure.
 */
async function createBrokerNotification(params: {
  brokerIds: number | number[] | null | undefined;
  title: string;
  message: string;
  category: BrokerNotificationCategory;
  type?: "info" | "success" | "warning" | "error";
  actionUrl?: string | null;
  /** When brokerIds is null/empty, notify ALL active brokers (admins). */
  notifyAllAdminsOnEmpty?: boolean;
}): Promise<void> {
  try {
    let ids: number[] = [];
    if (Array.isArray(params.brokerIds)) {
      ids = params.brokerIds.filter((n) => Number.isFinite(n)) as number[];
    } else if (typeof params.brokerIds === "number") {
      ids = [params.brokerIds];
    }
    if (ids.length === 0 && params.notifyAllAdminsOnEmpty) {
      const [admins] = await pool.query<any[]>(
        "SELECT id FROM brokers WHERE tenant_id = ? AND status = 'active' AND role IN ('admin', 'superadmin', 'platform_owner')",
        [MORTGAGE_TENANT_ID],
      );
      ids = admins.map((a: any) => a.id);
    }
    if (ids.length === 0) return;
    const type = params.type ?? "info";
    const values: any[] = [];
    const placeholders: string[] = [];
    for (const brokerId of ids) {
      placeholders.push("(?, ?, 'broker', ?, ?, ?, ?, ?)");
      values.push(
        MORTGAGE_TENANT_ID,
        brokerId,
        params.title,
        params.message,
        type,
        params.category,
        params.actionUrl ?? null,
      );
    }
    // Strip any HTML from notification messages before storage so the bell
    // and toast always show readable plain text regardless of the caller.
    const safeMessage = stripHtmlForStorage(params.message ?? "").slice(0, 500);
    for (let i = 0; i < values.length; i++) {
      // Each placeholder has 7 params; index 3 is 'message'
      if (i % 7 === 3) values[i] = safeMessage;
    }
    await pool.query(
      `INSERT INTO notifications
         (tenant_id, user_id, recipient_type, title, message, notification_type, category, action_url)
       VALUES ${placeholders.join(", ")}`,
      values,
    );

    // Real-time fanout via Ably so brokers see the bell update instantly
    // without polling. One message per recipient on a per-broker channel.
    // Non-fatal: publishToAbly already swallows errors internally.
    const arrivedAt = new Date().toISOString();
    await Promise.all(
      ids.map((brokerId) =>
        publishToAbly(`broker-notifications:${brokerId}`, "new", {
          title: params.title,
          message: safeMessage,
          notification_type: type,
          category: params.category,
          action_url: params.actionUrl ?? null,
          created_at: arrivedAt,
        }),
      ),
    );
  } catch (err) {
    console.error("createBrokerNotification failed (non-fatal):", err);
  }
}

