/**
 * Create an audit log entry
 */
async function createAuditLog({
  actorType,
  actorId,
  action,
  entityType,
  entityId,
  changes,
  status = "success",
  errorMessage,
  requestId,
  durationMs,
  ipAddress,
  userAgent,
}: {
  actorType: "user" | "broker";
  actorId: number;
  action: string;
  entityType?: string;
  entityId?: number;
  changes?: any;
  status?: "success" | "failure" | "warning";
  errorMessage?: string;
  requestId?: string;
  durationMs?: number;
  ipAddress?: string;
  userAgent?: string;
}): Promise<void> {
  try {
    const userId = actorType === "user" ? actorId : null;
    const brokerId = actorType === "broker" ? actorId : null;

    await pool.query(
      `INSERT INTO audit_logs (
        tenant_id, user_id, broker_id, actor_type, action, entity_type, entity_id, 
        changes, status, error_message, request_id, duration_ms, 
        ip_address, user_agent, created_at
      ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, NOW())`,
      [
        MORTGAGE_TENANT_ID,
        userId,
        brokerId,
        actorType,
        action,
        entityType || null,
        entityId || null,
        changes ? JSON.stringify(changes) : null,
        status,
        errorMessage || null,
        requestId || null,
        durationMs || null,
        ipAddress || null,
        userAgent || null,
      ],
    );
  } catch (error) {
    console.error("Error creating audit log:", error);
    // Don't throw - audit logging should not break the main flow
  }
}

