/**
 * Create email template
 */
const handleCreateEmailTemplate: RequestHandler = async (req, res) => {
  try {
    const {
      name,
      subject,
      body_html,
      body_text,
      template_type,
      is_active,
      category,
    } = req.body;
    const brokerId = (req as any).brokerId || 1;

    if (!name || !subject || !body_html) {
      return res.status(400).json({
        success: false,
        error: "Name, subject, and body_html are required",
      });
    }

    const [result] = (await pool.query(
      `INSERT INTO templates 
        (tenant_id, name, subject, body, template_type, category, is_active, created_by_broker_id) 
       VALUES (?, ?, ?, ?, ?, ?, ?, ?)`,
      [
        MORTGAGE_TENANT_ID,
        name,
        subject,
        body_html,
        "email",
        template_type || category || "system",
        is_active !== false ? 1 : 0,
        brokerId,
      ],
    )) as [ResultSetHeader, any];

    const [templates] = (await pool.query(
      `SELECT id, name, subject, body AS body_html, NULL AS body_text, category AS template_type, is_active, created_at, updated_at
       FROM templates WHERE id = ? AND tenant_id = ?`,
      [result.insertId, MORTGAGE_TENANT_ID],
    )) as [RowDataPacket[], any];

    res.json({
      success: true,
      template: { ...templates[0], is_active: Boolean(templates[0].is_active) },
      message: "Email template created successfully",
    });
  } catch (error) {
    console.error("Error creating email template:", error);
    res.status(500).json({
      success: false,
      error:
        error instanceof Error
          ? error.message
          : "Failed to create email template",
    });
  }
};

/**
 * Update email template
 */
const handleUpdateEmailTemplate: RequestHandler = async (req, res) => {
  try {
    const { templateId } = req.params;
    const {
      name,
      subject,
      body_html,
      body_text,
      template_type,
      is_active,
      category,
    } = req.body;

    // Check if template exists
    const [existingRows] = (await pool.query(
      "SELECT id FROM templates WHERE id = ? AND tenant_id = ? AND template_type = 'email'",
      [templateId, MORTGAGE_TENANT_ID],
    )) as [RowDataPacket[], any];

    if (existingRows.length === 0) {
      return res.status(404).json({
        success: false,
        error: "Email template not found",
      });
    }

    // Build update query dynamically
    const updates: string[] = [];
    const values: any[] = [];

    if (name !== undefined) {
      updates.push("name = ?");
      values.push(name);
    }
    if (subject !== undefined) {
      updates.push("subject = ?");
      values.push(subject);
    }
    if (body_html !== undefined) {
      updates.push("body = ?");
      values.push(body_html);
    }
    // Map client's template_type (category concept) to DB category column.
    // The template_type ENUM column (email/sms/whatsapp) is immutable.
    const resolvedCategory =
      template_type !== undefined ? template_type : category;
    if (resolvedCategory !== undefined) {
      updates.push("category = ?");
      values.push(resolvedCategory);
    }
    if (is_active !== undefined) {
      updates.push("is_active = ?");
      values.push(is_active ? 1 : 0);
    }

    if (updates.length === 0) {
      return res.status(400).json({
        success: false,
        error: "No fields to update",
      });
    }

    values.push(templateId);
    values.push(MORTGAGE_TENANT_ID);

    await pool.query(
      `UPDATE templates SET ${updates.join(", ")} WHERE id = ? AND tenant_id = ?`,
      values,
    );

    const [templates] = (await pool.query(
      `SELECT id, name, subject, body AS body_html, NULL AS body_text, category AS template_type, is_active, created_at, updated_at
       FROM templates WHERE id = ? AND tenant_id = ?`,
      [templateId, MORTGAGE_TENANT_ID],
    )) as [RowDataPacket[], any];

    res.json({
      success: true,
      template: { ...templates[0], is_active: Boolean(templates[0].is_active) },
      message: "Email template updated successfully",
    });
  } catch (error) {
    console.error("Error updating email template:", error);
    res.status(500).json({
      success: false,
      error:
        error instanceof Error
          ? error.message
          : "Failed to update email template",
    });
  }
};

