/**
 * POST /api/conversations/mailboxes/:mailboxId/sync
 */
const handleSyncConversationMailbox: RequestHandler = async (req, res) => {
  try {
    const brokerId = (req as any).brokerId;
    const mailboxId = Number(req.params.mailboxId);
    if (!Number.isFinite(mailboxId)) {
      return res
        .status(400)
        .json({ success: false, message: "Invalid mailboxId" });
    }

    const [rows] = await pool.query<ConversationMailboxRow[]>(
      `SELECT * FROM conversation_email_mailboxes
       WHERE id = ? AND tenant_id = ? AND provider = 'office365'
       LIMIT 1`,
      [mailboxId, MORTGAGE_TENANT_ID],
    );

    if (rows.length === 0) {
      return res
        .status(404)
        .json({ success: false, message: "Mailbox not found" });
    }

    const mailbox = rows[0];

    // Ownership check — mailboxes are strictly per-broker regardless of role
    if (mailbox.assigned_broker_id !== brokerId) {
      return res.status(403).json({
        success: false,
        message: "Not authorized to sync this mailbox",
      });
    }

    // Open a sync log entry
    const [logResult] = await pool.query<any>(
      `INSERT INTO email_sync_log (tenant_id, mailbox_id, \`trigger\`, started_at, status)
       VALUES (?, ?, 'manual', NOW(), 'running')`,
      [MORTGAGE_TENANT_ID, mailbox.id],
    );
    const syncLogId: number = logResult.insertId;

    const result = await syncOffice365Mailbox(mailbox);
    const syncStatus =
      result.errors > 0 ? (result.processed > 0 ? "partial" : "error") : "ok";
    const syncError =
      result.errors > 0 ? `Encountered ${result.errors} message errors` : null;

    await pool.query(
      `UPDATE conversation_email_mailboxes
       SET last_sync_at = NOW(),
           last_sync_status = ?,
           last_sync_error = ?,
           status = ?,
           updated_at = NOW()
       WHERE id = ? AND tenant_id = ?`,
      [
        result.errors > 0 ? "error" : "ok",
        syncError,
        "active",
        mailbox.id,
        MORTGAGE_TENANT_ID,
      ],
    );

    // Close the sync log entry
    await pool.query(
      `UPDATE email_sync_log
       SET finished_at = NOW(), messages_synced = ?, errors = ?, status = ?, error_detail = ?
       WHERE id = ?`,
      [result.processed, result.errors, syncStatus, syncError, syncLogId],
    );

    return res.json({
      success: true,
      mailbox_id: mailbox.id,
      processed: result.processed,
      errors: result.errors,
    });
  } catch (error: any) {
    console.error("Sync mailbox error:", error);
    return res.status(500).json({
      success: false,
      message: error?.message || "Failed to sync mailbox",
    });
  }
};

/**
 * GET /api/cron/sync-office365-mailboxes
 *
 * Secret-protected cron endpoint that syncs all active Office365 mailboxes.
 */
const handleCronSyncOffice365Mailboxes: RequestHandler = async (req, res) => {
  try {
    const secret = process.env.CRON_SECRET;
    if (secret) {
      const authHeader = req.headers.authorization;
      const provided =
        (authHeader?.startsWith("Bearer ") ? authHeader.slice(7) : null) ||
        (req.query.secret as string);
      if (provided !== secret) {
        return res.status(401).json({ success: false, error: "Unauthorized" });
      }
    }

    // Determine if an app-level token is available — if so, we can also sync
    // mailboxes that are in 'auth_required' state (their delegated token is
    // revoked, but the app token doesn't require per-user consent).
    const hasAppToken = !!(await getOffice365MailAppToken());

    const statusFilter = hasAppToken
      ? "('active', 'error', 'auth_required')"
      : "('active', 'error')";

    const [rows] = await pool.query<ConversationMailboxRow[]>(
      `SELECT * FROM conversation_email_mailboxes
       WHERE tenant_id = ? AND provider = 'office365' AND status IN ${statusFilter}`,
      [MORTGAGE_TENANT_ID],
    );

    let totalProcessed = 0;
    let totalErrors = 0;

    for (const mailbox of rows) {
      // Skip auth_required mailboxes when no app token is available — the
      // delegated refresh token is dead and only user re-auth can fix it.
      if (mailbox.status === "auth_required" && !hasAppToken) {
        continue;
      }

      try {
        const result = await syncOffice365Mailbox(mailbox);
        totalProcessed += result.processed;
        totalErrors += result.errors;

        await pool.query(
          `UPDATE conversation_email_mailboxes
           SET last_sync_at = NOW(),
               last_sync_status = ?,
               last_sync_error = ?,
               status = 'active',
               updated_at = NOW()
           WHERE id = ? AND tenant_id = ?`,
          [
            result.errors > 0 ? "error" : "ok",
            result.errors > 0
              ? `Encountered ${result.errors} message errors`
              : null,
            mailbox.id,
            MORTGAGE_TENANT_ID,
          ],
        );
      } catch (mailboxErr: any) {
        totalErrors++;
        // If it's an auth error, preserve auth_required status instead of
        // overwriting with generic 'error' so the UI shows the correct state.
        const isAuthErr = mailboxErr instanceof Office365AuthRequiredError;
        await pool.query(
          `UPDATE conversation_email_mailboxes
           SET last_sync_at = NOW(),
               last_sync_status = 'error',
               last_sync_error = ?,
               status = ?,
               updated_at = NOW()
           WHERE id = ? AND tenant_id = ?`,
          [
            mailboxErr?.message || "Mailbox sync failed",
            isAuthErr ? "auth_required" : "error",
            mailbox.id,
            MORTGAGE_TENANT_ID,
          ],
        );
      }
    }

    return res.json({
      success: true,
      mailboxes: rows.length,
      processed: totalProcessed,
      errors: totalErrors,
    });
  } catch (error) {
    console.error("Office365 cron sync error:", error);
    return res
      .status(500)
      .json({ success: false, error: "Office365 sync failed" });
  }
};

/**
 * GET /api/cron/sync-o365-calendars
 *
 * Secret-protected cron endpoint that syncs Outlook calendar events into
 * scheduler_blocked_ranges for every active Office 365 mailbox.
 * Only active mailboxes are processed — auth_required mailboxes are skipped
 * because the delegated token may lack the Calendars.Read scope granted
 * during reconnect. Errors per-mailbox are logged but don't fail the whole job.
 *
 * Suggested schedule: every 30 minutes.
 *   curl -s "https://yourdomain.com/api/cron/sync-o365-calendars?secret=CRON_SECRET"
 */
const handleCronSyncO365Calendars: RequestHandler = async (req, res) => {
  try {
    const secret = process.env.CRON_SECRET;
    if (secret) {
      const authHeader = req.headers.authorization;
      const provided =
        (authHeader?.startsWith("Bearer ") ? authHeader.slice(7) : null) ||
        (req.query.secret as string);
      if (provided !== secret) {
        return res.status(401).json({ success: false, error: "Unauthorized" });
      }
    }

    const [rows] = await pool.query<ConversationMailboxRow[]>(
      `SELECT * FROM conversation_email_mailboxes
       WHERE tenant_id = ? AND provider = 'office365' AND status = 'active'
         AND assigned_broker_id IS NOT NULL`,
      [MORTGAGE_TENANT_ID],
    );

    let totalSynced = 0;
    let totalErrors = 0;
    const results: Array<{
      mailbox_id: number;
      email: string;
      synced_count: number;
      error?: string;
    }> = [];

    for (const mailbox of rows) {
      const brokerId = mailbox.assigned_broker_id;
      try {
        const { synced_count } = await syncO365CalendarForBroker(
          mailbox,
          brokerId,
        );
        totalSynced += synced_count;
        results.push({
          mailbox_id: mailbox.id,
          email: mailbox.mailbox_email,
          synced_count,
        });
        // Notify broker's client in real-time
        publishToAbly(
          `broker-notifications:${brokerId}`,
          "o365_calendar_synced",
          { synced_count },
        ).catch(() => {
          /* non-fatal */
        });
      } catch (mailboxErr: any) {
        totalErrors++;
        const errMsg =
          mailboxErr?.response?.data?.error?.message ||
          mailboxErr?.message ||
          "Unknown error";
        console.error(
          `[cronSyncO365Calendars] mailbox #${mailbox.id} <${mailbox.mailbox_email}> failed:`,
          errMsg,
        );
        results.push({
          mailbox_id: mailbox.id,
          email: mailbox.mailbox_email,
          synced_count: 0,
          error: errMsg,
        });
      }
    }

    return res.json({
      success: true,
      mailboxes: rows.length,
      total_synced: totalSynced,
      errors: totalErrors,
      results,
    });
  } catch (error) {
    console.error("[cronSyncO365Calendars] fatal error:", error);
    return res
      .status(500)
      .json({ success: false, error: "Calendar cron sync failed" });
  }
};

/**
 * GET /api/cron/reactivate-office365-mailboxes
 *
 * One-shot (or cron-able) endpoint that attempts to reactivate all mailboxes
 * in 'error' or 'auth_required' state by syncing them via the app-level token.
 * If the Azure App has Mail.Read Application permission, broken mailboxes are
 * healed automatically without any user re-authorization.
 */
const handleCronReactivateOffice365Mailboxes: RequestHandler = async (
  req,
  res,
) => {
  try {
    const secret = process.env.CRON_SECRET;
    if (secret) {
      const authHeader = req.headers.authorization;
      const provided =
        (authHeader?.startsWith("Bearer ") ? authHeader.slice(7) : null) ||
        (req.query.secret as string);
      if (provided !== secret) {
        return res.status(401).json({ success: false, error: "Unauthorized" });
      }
    }

    // First verify the app token has Mail.Read — this also primes the cache.
    const appToken = await getOffice365MailAppToken();
    if (!appToken) {
      return res.status(200).json({
        success: false,
        message:
          "App token unavailable or Mail.Read Application permission not granted. " +
          "Add Mail.Read + Mail.Send Application permissions in Azure Portal and grant admin consent.",
        healed: 0,
      });
    }

    const [rows] = await pool.query<ConversationMailboxRow[]>(
      `SELECT * FROM conversation_email_mailboxes
       WHERE tenant_id = ? AND provider = 'office365'
         AND status IN ('error', 'auth_required')`,
      [MORTGAGE_TENANT_ID],
    );

    let healed = 0;
    let failed = 0;
    const details: Array<{ email: string; result: string }> = [];

    for (const mailbox of rows) {
      try {
        // Quick probe: list top 1 message to confirm app token works for this mailbox.
        await axios.get(
          `https://graph.microsoft.com/v1.0/users/${encodeURIComponent(mailbox.mailbox_email)}/mailFolders/Inbox/messages?$top=1&$select=id`,
          { headers: { Authorization: `Bearer ${appToken}` } },
        );

        // Probe passed — reset mailbox to active.
        await pool.query(
          `UPDATE conversation_email_mailboxes
           SET status = 'active',
               last_sync_status = 'ok',
               last_sync_error = NULL,
               last_sync_at = NOW(),
               updated_at = NOW()
           WHERE id = ? AND tenant_id = ?`,
          [mailbox.id, MORTGAGE_TENANT_ID],
        );
        healed++;
        details.push({ email: mailbox.mailbox_email, result: "reactivated" });
      } catch (err: any) {
        failed++;
        details.push({
          email: mailbox.mailbox_email,
          result: `failed: ${err?.response?.data?.error?.code || err?.message}`,
        });
      }
    }

    return res.json({
      success: true,
      total: rows.length,
      healed,
      failed,
      details,
      message:
        healed > 0
          ? `${healed} mailbox(es) reactivated via app token — no re-authorization needed.`
          : rows.length === 0
            ? "No broken mailboxes found — all good."
            : "App token obtained but Graph API calls failed. Check Mail.Read Application permission and admin consent.",
    });
  } catch (error: any) {
    console.error("Reactivate office365 mailboxes error:", error);
    return res.status(500).json({
      success: false,
      error: error?.message || "Internal error",
    });
  }
};

/**
 * GET /api/cron/sync-teams-policy
 */
const handleCronSyncTeamsPolicy: RequestHandler = async (req, res) => {
  try {
    const secret = process.env.CRON_SECRET;
    if (secret) {
      const authHeader = req.headers.authorization;
      const provided =
        (authHeader?.startsWith("Bearer ") ? authHeader.slice(7) : null) ||
        (req.query.secret as string);
      if (provided !== secret) {
        return res.status(401).json({ success: false, error: "Unauthorized" });
      }
    }

    const scriptPath = path.resolve(
      process.cwd(),
      "scripts/teams-policy-sync.sh",
    );
    const { stdout, stderr } = await execFileAsync("bash", [scriptPath], {
      timeout: 10 * 60 * 1000,
      maxBuffer: 1024 * 1024,
    });

    return res.json({
      success: true,
      message: "Teams policy sync completed",
      output: stdout?.trim() || null,
      warnings: stderr?.trim() || null,
    });
  } catch (error: any) {
    const stderr =
      typeof error?.stderr === "string" ? error.stderr.trim() : null;
    const stdout =
      typeof error?.stdout === "string" ? error.stdout.trim() : null;

    console.error("Teams policy cron sync error:", error);

    return res.status(500).json({
      success: false,
      error: stderr || error?.message || "Teams policy sync failed",
      output: stdout,
    });
  }
};

/**
 * GET /api/cron/poll-inbound-email
 *
 * Called on a schedule (Vercel Cron or HostGator cPanel cron via curl).
 * Connects to the IMAP mailbox defined by IMAP_* env vars, reads unseen
 * messages, extracts the conversation_id from the In-Reply-To / References
 * or X-Conversation-Id header, and inserts an inbound `communications` row.
 *
 * Protected by CRON_SECRET — pass it as:
 *   Authorization: Bearer {CRON_SECRET}
 * or ?secret={CRON_SECRET} query param (for curl-based cron).
 *
 * Required env vars:
 *   IMAP_HOST     e.g. mail.yourdomain.com
 *   IMAP_PORT     993 (TLS) or 143 (STARTTLS)
 *   IMAP_USER     reply@yourdomain.com
 *   IMAP_PASSWORD your-email-password
 *   IMAP_TLS      true | false (default true)
 *   CRON_SECRET   random secret to protect this endpoint
 */
const handlePollInboundEmail: RequestHandler = async (req, res) => {
  try {
    // --- Auth ---
    const secret = process.env.CRON_SECRET;
    if (secret) {
      const authHeader = req.headers.authorization;
      const provided =
        (authHeader?.startsWith("Bearer ") ? authHeader.slice(7) : null) ||
        (req.query.secret as string);
      if (provided !== secret) {
        return res.status(401).json({ success: false, error: "Unauthorized" });
      }
    }

    // --- Config ---
    const host = process.env.IMAP_HOST;
    const user = process.env.IMAP_USER;
    const pass = process.env.IMAP_PASSWORD;

    if (!host || !user || !pass) {
      return res.json({
        success: true,
        skipped: true,
        reason: "IMAP not configured",
      });
    }

    const port = parseInt(process.env.IMAP_PORT || "993");
    const tls = process.env.IMAP_TLS !== "false";
    // IMAP_REJECT_UNAUTHORIZED=false disables strict TLS cert validation.
    // Set to "false" when the mail server has a self-signed or expired certificate.
    const rejectUnauthorized = process.env.IMAP_REJECT_UNAUTHORIZED !== "false";

    const client = new ImapFlow({
      host,
      port,
      secure: tls,
      auth: { user, pass },
      logger: false,
      tls: { rejectUnauthorized },
    });

    await client.connect();
    let processed = 0;
    let errors = 0;

    try {
      const lock = await client.getMailboxLock("INBOX");
      try {
        // Fetch all unseen messages
        for await (const msg of client.fetch(
          { seen: false },
          {
            envelope: true,
            headers: [
              "in-reply-to",
              "references",
              "x-conversation-id",
              "message-id",
            ],
            bodyStructure: true,
            source: true,
          },
        )) {
          try {
            // --- Parse raw headers buffer into a lookup map ---
            const rawHeaders = msg.headers?.toString("utf8") || "";
            const headerMap: Record<string, string> = {};
            for (const line of rawHeaders.split(/\r?\n/)) {
              const colon = line.indexOf(":");
              if (colon > 0) {
                const key = line.slice(0, colon).toLowerCase().trim();
                const val = line.slice(colon + 1).trim();
                headerMap[key] = val;
              }
            }

            // --- Extract conversation_id ---
            let conversationId: string | null = null;

            // 1. X-Conversation-Id header (set explicitly on outbound)
            const xConvId = headerMap["x-conversation-id"];
            if (xConvId) conversationId = xConvId.trim();

            // 2. Parse enc-{conversationId}-{timestamp}@domain from In-Reply-To / References
            if (!conversationId) {
              const inReplyTo = headerMap["in-reply-to"] || "";
              const references = headerMap["references"] || "";
              const combined = `${inReplyTo} ${references}`;
              const match = combined.match(/<enc-([^-]+(?:-[^-]+)*)-\d+@/);
              if (match) {
                conversationId = match[1];
              }
            }

            if (!conversationId) {
              // Can't route — mark as seen so we don't reprocess, then skip
              await client.messageFlagsAdd(msg.uid, ["\\Seen"], { uid: true });
              continue;
            }

            // --- Get sender address ---
            const fromAddress = msg.envelope?.from?.[0];
            const senderEmail = fromAddress?.address || "";
            const senderName = fromAddress?.name || senderEmail;

            // --- Build plain-text body from source ---
            // Use raw source for simplicity; strip quoted reply for cleaner preview
            const rawSource = msg.source?.toString("utf8") || "";
            // Extract text between headers and quoted reply marker (> or On ... wrote:)
            const bodyStart = rawSource.indexOf("\r\n\r\n");
            const rawBody =
              bodyStart >= 0 ? rawSource.slice(bodyStart + 4) : rawSource;
            // Trim quoted text (lines starting with >) for the stored preview
            const bodyLines = rawBody
              .split("\n")
              .filter(
                (l) =>
                  !l.trimStart().startsWith(">") && !l.match(/^On .+ wrote:/i),
              )
              .join("\n")
              .trim();
            const bodyText = bodyLines.slice(0, 5000) || "(empty reply)";

            const subject = msg.envelope?.subject || "(no subject)";
            const messageIdHeader = msg.envelope?.messageId || "";

            // --- Look up the conversation thread ---
            const [threadRows] = await pool.query<RowDataPacket[]>(
              `SELECT ct.broker_id, ct.client_id, ct.application_id, ct.lead_id
               FROM conversation_threads ct
               WHERE ct.conversation_id = ? AND ct.tenant_id = ?
               LIMIT 1`,
              [conversationId, MORTGAGE_TENANT_ID],
            );

            let brokerId: number | null = null;
            let clientId: number | null = null;
            let applicationId: number | null = null;
            let leadId: number | null = null;

            if (threadRows.length > 0) {
              brokerId = threadRows[0].broker_id;
              clientId = threadRows[0].client_id;
              applicationId = threadRows[0].application_id;
              leadId = threadRows[0].lead_id;
            } else if (senderEmail) {
              // Thread doesn't exist yet — match by sender email
              const [clientRows] = await pool.query<RowDataPacket[]>(
                "SELECT id, assigned_broker_id FROM clients WHERE email = ? AND tenant_id = ? LIMIT 1",
                [senderEmail, MORTGAGE_TENANT_ID],
              );
              if (clientRows.length > 0) {
                clientId = clientRows[0].id;
                brokerId = clientRows[0].assigned_broker_id;
              }
            }

            // --- Insert inbound communications record ---
            await pool.query(
              `INSERT INTO communications (
                tenant_id, application_id, lead_id,
                from_user_id, to_broker_id,
                communication_type, direction,
                subject, body, status,
                conversation_id, message_type,
                delivery_status, external_id,
                sent_at, created_at
              ) VALUES (?, ?, ?, ?, ?, 'email', 'inbound', ?, ?, 'delivered',
                        ?, 'text', 'delivered', ?, NOW(), NOW())`,
              [
                MORTGAGE_TENANT_ID,
                applicationId || null,
                leadId || null,
                clientId || null,
                brokerId || null,
                subject,
                bodyText,
                conversationId,
                messageIdHeader || null,
              ],
            );

            await upsertConversationThread({
              tenantId: MORTGAGE_TENANT_ID,
              commId: 0,
              conversationId,
              applicationId: applicationId || null,
              leadId: leadId || null,
              fromUserId: clientId || null,
              fromBrokerId: null,
              toUserId: null,
              toBrokerId: brokerId || null,
              communicationType: "email",
              direction: "inbound",
              body: bodyText,
            });

            // Mark email as seen so it won't be picked up next poll
            await client.messageFlagsAdd(msg.uid, ["\\Seen"], { uid: true });

            // ── Sync to reminder flows ──────────────────────────────────────
            // Mark any active flow executions waiting on this conversation as
            // responded so the cron will advance them on the next run.
            await markExecutionsRespondedForConversation(
              conversationId,
              MORTGAGE_TENANT_ID,
            );

            processed++;
            console.log(
              `📥 Inbound reply stored: conv=${conversationId} from=${senderEmail}`,
            );
          } catch (msgErr) {
            console.error("❌ Error processing inbound message:", msgErr);
            errors++;
          }
        }
      } finally {
        lock.release();
      }
    } finally {
      await client.logout();
    }

    res.json({ success: true, processed, errors });
  } catch (error) {
    console.error("❌ IMAP poll error:", error);
    res.status(500).json({ success: false, error: "IMAP poll failed" });
  }
};

// =====================================================
// INBOUND EMAIL WEBHOOK
// =====================================================

/**
 * POST /api/webhooks/inbound-email
 *
 * Receives inbound email payloads from Postmark, Mailgun, or SendGrid.
 * The provider must be configured to POST to:
 *   https://yourdomain.com/api/webhooks/inbound-email
 * with a shared secret in the header "X-Webhook-Secret" (= INBOUND_WEBHOOK_SECRET env var)
 * and set to catch emails sent to  reply+*@{INBOUND_EMAIL_DOMAIN}.
 *
 * Normalises the three provider formats into one shape, extracts the
 * conversation_id from the recipient address, and inserts an inbound
 * `communications` row so the thread appears in the Conversations section.
 *
 * Provider body shapes expected:
 *   Postmark : { From, To, Subject, TextBody, HtmlBody, Headers[], MessageID, ... }
 *   Mailgun  : { sender, recipient, subject, "body-plain", "body-html", "Message-Id", ... }
 *   SendGrid : JSON array [{ from, to, subject, text, html, headers, ... }]
 */
const handleInboundEmail: RequestHandler = async (req, res) => {
  try {
    // Verify shared secret to reject unauthenticated POSTs
    const secret = process.env.INBOUND_WEBHOOK_SECRET;
    if (secret) {
      const provided =
        req.headers["x-webhook-secret"] ||
        req.headers["x-postmark-secret"] ||
        req.query.secret;
      if (provided !== secret) {
        return res.status(401).json({ success: false, error: "Unauthorized" });
      }
    }

    // ---- Normalise payload across Postmark / Mailgun / SendGrid ----
    let rawPayload = req.body;
    // SendGrid wraps events in an array
    if (Array.isArray(rawPayload)) rawPayload = rawPayload[0];

    const fromAddress: string =
      rawPayload.From || rawPayload.from || rawPayload.sender || "";

    const toAddress: string =
      rawPayload.To || rawPayload.to || rawPayload.recipient || "";

    const subjectRaw: string =
      rawPayload.Subject || rawPayload.subject || "(no subject)";

    const textBody: string =
      rawPayload.TextBody || rawPayload["body-plain"] || rawPayload.text || "";

    const htmlBody: string =
      rawPayload.HtmlBody || rawPayload["body-html"] || rawPayload.html || "";

    const messageId: string =
      rawPayload.MessageID ||
      rawPayload["Message-Id"] ||
      rawPayload.headers?.["Message-Id"] ||
      "";

    // Always prefer the plain-text body. If only HTML is available, strip tags
    // so downstream storage and notifications never contain raw markup.
    const body =
      textBody ||
      (htmlBody ? stripHtmlForStorage(htmlBody) : "") ||
      "(empty message)";

    // ---- Extract conversation_id ----
    // Look for reply+{conversation_id}@domain in the To address first,
    // then fall back to custom X-Conversation-Id header embedded on send.
    let conversationId: string | null = null;

    const subAddressMatch = toAddress.match(/reply\+([^@]+)@/);
    if (subAddressMatch) {
      conversationId = subAddressMatch[1];
    }

    // Check custom header (Postmark passes them in Headers[])
    if (!conversationId) {
      const headers: any[] = rawPayload.Headers || [];
      const convHeader = headers.find(
        (h: any) => h.Name?.toLowerCase() === "x-conversation-id",
      );
      if (convHeader) conversationId = convHeader.Value;
    }

    // Mailgun / SendGrid store headers as an object
    if (!conversationId && rawPayload.headers) {
      conversationId =
        rawPayload.headers["x-conversation-id"] ||
        rawPayload.headers["X-Conversation-Id"] ||
        null;
    }

    if (!conversationId) {
      console.warn("⚠️  Inbound email received but no conversation_id found", {
        toAddress,
        fromAddress,
      });
      // Acknowledge the webhook so the provider doesn't retry
      return res.json({
        success: true,
        message: "Acknowledged — no conversation matched",
      });
    }

    // ---- Resolve mailbox_id from conversationId pattern (conv_o365_{mailboxId}_…)
    // or from the existing thread record so the communication is always associated
    // with the correct mailbox and shows up in the inbox.
    let webhookMailboxId: number | null = null;
    const mbMatch = conversationId.match(/^conv_o365_(\d+)_/);
    if (mbMatch) webhookMailboxId = parseInt(mbMatch[1], 10);

    // ---- Look up the conversation thread to get broker + client context ----
    const [threadRows] = await pool.query<RowDataPacket[]>(
      `SELECT ct.broker_id, ct.client_id, ct.application_id, ct.lead_id, ct.mailbox_id
       FROM conversation_threads ct
       WHERE ct.conversation_id = ? AND ct.tenant_id = ?
       LIMIT 1`,
      [conversationId, MORTGAGE_TENANT_ID],
    );

    let brokerId: number | null = null;
    let clientId: number | null = null;
    let applicationId: number | null = null;
    let leadId: number | null = null;

    if (threadRows.length > 0) {
      brokerId = threadRows[0].broker_id;
      clientId = threadRows[0].client_id;
      applicationId = threadRows[0].application_id;
      leadId = threadRows[0].lead_id;
      // Prefer the already-stored mailbox_id if available
      if (threadRows[0].mailbox_id) webhookMailboxId = threadRows[0].mailbox_id;
    } else {
      // Thread doesn't exist yet — try matching by sender email to find the client
      const senderEmail = fromAddress.match(/<([^>]+)>/)?.[1] || fromAddress;
      const [clientRows] = await pool.query<RowDataPacket[]>(
        `SELECT c.id, c.assigned_broker_id
         FROM clients c
         WHERE c.email = ? AND c.tenant_id = ?
         LIMIT 1`,
        [senderEmail, MORTGAGE_TENANT_ID],
      );
      if (clientRows.length > 0) {
        clientId = clientRows[0].id;
        brokerId = clientRows[0].assigned_broker_id;
      }
    }

    // ---- Insert the inbound communications record ----
    await pool.query(
      `INSERT INTO communications (
        tenant_id, application_id, lead_id,
        from_user_id, to_broker_id,
        communication_type, direction,
        subject, body, status,
        conversation_id, message_type,
        delivery_status, external_id,
        mailbox_id,
        sent_at, created_at
      ) VALUES (?, ?, ?, ?, ?, 'email', 'inbound', ?, ?, 'delivered', ?, 'text', 'delivered', ?, ?, NOW(), NOW())`,
      [
        MORTGAGE_TENANT_ID,
        applicationId || null,
        leadId || null,
        clientId || null,
        brokerId || null,
        subjectRaw,
        body,
        conversationId,
        messageId || null,
        webhookMailboxId,
      ],
    );

    try {
      await upsertEmailThread({
        tenantId: MORTGAGE_TENANT_ID,
        commId: 0,
        conversationId,
        applicationId: applicationId || null,
        leadId: leadId || null,
        fromUserId: clientId || null,
        fromBrokerId: null,
        toUserId: null,
        toBrokerId: brokerId || null,
        direction: "inbound",
        body,
        mailboxId: webhookMailboxId ?? undefined,
      });
    } catch (upsertErr) {
      console.error(
        "⚠️  upsertEmailThread failed for inbound email:",
        upsertErr,
      );
    }

    console.log(
      `📥 Inbound email stored: conv=${conversationId} from=${fromAddress}`,
    );

    // ── Sync to reminder flows ──────────────────────────────────────────────
    // Mark any active flow executions waiting on this conversation as responded
    // so the cron will advance them to the 'responded' branch on the next run.
    await markExecutionsRespondedForConversation(
      conversationId,
      MORTGAGE_TENANT_ID,
    );

    res.json({ success: true });
  } catch (error) {
    console.error("❌ Inbound email webhook error:", error);
    // Always return 200 so the provider doesn't flood with retries
    res.status(200).json({ success: false, error: "Internal error" });
  }
};

// =====================================================
// INBOUND SMS WEBHOOK  (Twilio)
// =====================================================

/**
 * POST /api/webhooks/inbound-sms
 *
 * Receives inbound SMS from Twilio's webhook.
 * Configure Twilio to POST to:
 *   https://yourdomain.com/api/webhooks/inbound-sms
 *
 * Twilio sends application/x-www-form-urlencoded with:
 *   Body      — message text
 *   From      — sender's E.164 phone  (+15550001111)
 *   To        — your Twilio number    (+15559990000)
 *   MessageSid — Twilio message SID
 *   AccountSid — Twilio account SID
 *
 * Security: optionally validate the INBOUND_WEBHOOK_SECRET header
 * OR the Twilio request signature (set TWILIO_AUTH_TOKEN + TWILIO_SMS_WEBHOOK_URL).
 *
 * On success the handler:
 *  1. Looks up the client by From phone number.
 *  2. Finds the latest active execution for that client to determine
 *     which conversation_id to associate the message with.
 *  3. Inserts an inbound `communications` record (triggers the DB trigger
 *     to update / create the conversation_thread).
 *  4. Marks all active executions waiting on that conversation as responded.
 *  5. Returns an empty TwiML <Response> (stops Twilio from sending an auto-reply).
 */
const handleInboundSMS: RequestHandler = async (req, res) => {
  try {
    // Security: validate using Twilio signature (preferred) OR fallback to shared secret
    const twilioAuthToken = process.env.TWILIO_AUTH_TOKEN;
    const webhookUrl = process.env.TWILIO_SMS_WEBHOOK_URL; // e.g. https://portal.encoremortgage.org/api/webhooks/inbound-sms

    if (twilioAuthToken && webhookUrl) {
      const twilioSignature =
        (req.headers["x-twilio-signature"] as string) ?? "";
      const isValid = twilio.validateRequest(
        twilioAuthToken,
        twilioSignature,
        webhookUrl,
        req.body as Record<string, any>,
      );
      if (!isValid) {
        console.warn("⚠️  Inbound SMS rejected — invalid Twilio signature");
        res.set("Content-Type", "text/xml");
        return res.status(200).send("<Response></Response>");
      }
    } else {
      // Fallback to shared secret in header or query param
      const secret = process.env.INBOUND_WEBHOOK_SECRET;
      if (secret) {
        const provided =
          req.headers["x-webhook-secret"] ?? (req.query.secret as string);
        if (provided !== secret) {
          console.warn("⚠️  Inbound SMS rejected — bad webhook secret");
          res.set("Content-Type", "text/xml");
          return res.status(200).send("<Response></Response>");
        }
      }
    }

    // Parse Twilio fields (sent as form-encoded or JSON depending on config)
    const body: string = req.body?.Body ?? req.body?.body ?? "";
    const fromRaw: string = req.body?.From ?? req.body?.from ?? "";
    const toRaw: string = req.body?.To ?? req.body?.to ?? "";
    const messageSid: string =
      req.body?.MessageSid ?? req.body?.messageSid ?? "";

    // MMS media fields — Twilio sends NumMedia + MediaUrl0/MediaContentType0..N
    const numMedia = parseInt((req.body?.NumMedia as string) ?? "0", 10);
    const mediaUrls: string[] = [];
    for (let i = 0; i < numMedia; i++) {
      const u = req.body?.[`MediaUrl${i}`] as string | undefined;
      if (u) mediaUrls.push(u);
    }
    const primaryMediaUrl: string | null =
      mediaUrls.length > 0
        ? mediaUrls.length === 1
          ? mediaUrls[0]
          : JSON.stringify(mediaUrls)
        : null;
    const primaryContentType: string | null =
      numMedia > 0
        ? ((req.body?.["MediaContentType0"] as string | undefined) ?? null)
        : null;

    // Allow image-only MMS (empty text body with media attached)
    if (!fromRaw || (!body && numMedia === 0)) {
      res.set("Content-Type", "text/xml");
      return res.status(200).send("<Response></Response>");
    }

    // Derive message_type from media content type
    const msgType: string = primaryContentType
      ? primaryContentType.startsWith("image/")
        ? "image"
        : primaryContentType.startsWith("video/")
          ? "video"
          : primaryContentType.startsWith("audio/")
            ? "audio"
            : "document"
      : "text";

    // Normalise phones
    const fromPhone = fromRaw.replace(/[^\d+]/g, "");
    const toPhone = toRaw.replace(/[^\d+]/g, "") || null; // The Twilio number that received this SMS

    // ── STOP/START consent handling for broadcast SMS ─────────────────────────
    const inboundKeyword = body.trim().toUpperCase();
    if (["START", "UNSTOP"].includes(inboundKeyword)) {
      const fromDigitsNorm = fromPhone.replace(/\D/g, "");
      const fromLast10 = fromDigitsNorm.slice(-10);
      await pool.query(
        `UPDATE brokers SET sms_blast_opted_in = 1, updated_at = NOW()
         WHERE tenant_id = ?
           AND (
             REGEXP_REPLACE(twilio_caller_id, '[^0-9]', '') = ?
             OR RIGHT(REGEXP_REPLACE(phone, '[^0-9]', ''), 10) = ?
           )`,
        [MORTGAGE_TENANT_ID, fromDigitsNorm, fromLast10],
      );
      await pool.query(
        `UPDATE clients
         SET sms_blast_opted_in = 1, updated_at = NOW()
         WHERE tenant_id = ?
           AND RIGHT(REGEXP_REPLACE(phone, '[^0-9]', ''), 10) = ?`,
        [MORTGAGE_TENANT_ID, fromLast10],
      );
      res.set("Content-Type", "text/xml");
      return res
        .status(200)
        .send(
          "<Response><Message>You are now subscribed to SMS broadcast messages. Reply STOP to unsubscribe.</Message></Response>",
        );
    }

    if (inboundKeyword === "STOP") {
      const fromDigitsNorm = fromPhone.replace(/\D/g, "");
      const fromLast10 = fromDigitsNorm.slice(-10);
      // Mark the sender opted out of broadcast SMS blasts
      await pool.query(
        `UPDATE brokers SET sms_blast_opted_in = 0, updated_at = NOW()
         WHERE tenant_id = ?
           AND (
             REGEXP_REPLACE(twilio_caller_id, '[^0-9]', '') = ?
             OR RIGHT(REGEXP_REPLACE(phone, '[^0-9]', ''), 10) = ?
           )`,
        [MORTGAGE_TENANT_ID, fromDigitsNorm, fromLast10],
      );
      await pool.query(
        `UPDATE clients
         SET sms_blast_opted_in = 0, updated_at = NOW()
         WHERE tenant_id = ?
           AND RIGHT(REGEXP_REPLACE(phone, '[^0-9]', ''), 10) = ?`,
        [MORTGAGE_TENANT_ID, fromLast10],
      );
      // Also mark any pending broadcast recipient rows as opted_out
      await pool.query(
        `UPDATE realtor_broadcast_recipients
         SET sms_status = 'opted_out', updated_at = NOW()
         WHERE RIGHT(REPLACE(REPLACE(REPLACE(recipient_phone, '+', ''), '-', ''), ' ', ''), 10) = ?
           AND sms_status = 'pending'`,
        [fromLast10],
      );
      res.set("Content-Type", "text/xml");
      return res
        .status(200)
        .send(
          "<Response><Message>You have been unsubscribed from broadcast messages. Reply START to opt back in.</Message></Response>",
        );
    }

    // Group MMS — separate path when OtherRecipients present (skips direct 1:1)
    const groupConv = getGroupConversationsModule();
    if (groupConv.enabled) {
      const groupHandled = await groupConv.processInboundGroupMms({
        tenantId: MORTGAGE_TENANT_ID,
        fromRaw,
        toRaw,
        body,
        messageSid,
        primaryMediaUrl,
        primaryContentType,
        msgType,
        webhookBody: (req.body ?? {}) as Record<string, unknown>,
      });
      if (groupHandled) {
        res.set("Content-Type", "text/xml");
        return res.status(200).send("<Response></Response>");
      }
      const groupReplyHandled =
        await groupConv.processInboundGroupIndividualReply({
          tenantId: MORTGAGE_TENANT_ID,
          fromRaw,
          toRaw,
          body,
          messageSid,
          primaryMediaUrl,
          primaryContentType,
          msgType,
          webhookBody: (req.body ?? {}) as Record<string, unknown>,
        });
      if (groupReplyHandled) {
        res.set("Content-Type", "text/xml");
        return res.status(200).send("<Response></Response>");
      }
    }

    // ── Find the client by phone number ──────────────────────────────────────
    // Strip ALL non-digit characters from both sides so any stored format
    // ((323) 475-6240, 323-475-6240, 3234756240, +13234756240, etc.) all match.
    const fromDigits = fromPhone.replace(/\D/g, ""); // e.g. "13234756240"
    const fromDigits10 =
      fromDigits.length === 11 && fromDigits.startsWith("1")
        ? fromDigits.slice(1) // strip leading country code "1" → "3234756240"
        : fromDigits;
    const [clientRows] = await pool.query<RowDataPacket[]>(
      `SELECT c.id, c.assigned_broker_id, la.id AS loan_id
       FROM clients c
       LEFT JOIN loan_applications la ON la.client_user_id = c.id
                                      AND la.tenant_id = c.tenant_id
                                      AND la.status NOT IN ('loan_funded', 'declined')
       WHERE c.tenant_id = ?
         AND (
           c.phone = ?
           OR c.phone = ?
           OR REGEXP_REPLACE(c.phone, '[^0-9]', '') = ?
           OR REGEXP_REPLACE(c.phone, '[^0-9]', '') = ?
           OR c.normalized_phone = ?
           OR (
             c.alternate_phone IS NOT NULL
             AND RIGHT(REGEXP_REPLACE(c.alternate_phone, '[^0-9]', ''), 10) = ?
           )
         )
       ORDER BY la.created_at DESC
       LIMIT 1`,
      [
        MORTGAGE_TENANT_ID,
        fromPhone,
        fromRaw,
        fromDigits,
        fromDigits10,
        fromDigits10,
        fromDigits10,
      ],
    );

    let clientId: number | null = null;
    let brokerId: number | null = null;
    let loanId: number | null = null;

    if (clientRows.length > 0) {
      clientId = clientRows[0].id;
      brokerId = clientRows[0].assigned_broker_id ?? null;
      loanId = clientRows[0].loan_id ?? null;
    }

    // Route SMS replies into an active Encore group before opening a 1:1 client thread.
    if (groupConv.enabled && clientId) {
      const groupReplyHandled =
        await groupConv.processInboundGroupIndividualReply({
          tenantId: MORTGAGE_TENANT_ID,
          fromRaw,
          toRaw,
          body,
          messageSid,
          primaryMediaUrl,
          primaryContentType,
          msgType,
          webhookBody: (req.body ?? {}) as Record<string, unknown>,
          knownClientId: clientId,
        });
      if (groupReplyHandled) {
        res.set("Content-Type", "text/xml");
        return res.status(200).send("<Response></Response>");
      }
    }

    // Ownership rule: if the client sent to a Twilio number that is currently a
    // broker's personal line, the OWNER of that number always gets the message —
    // even if the client has a different assigned_broker_id. This ensures
    // reassignment takes effect immediately (previous owner stops receiving
    // messages to numbers they no longer own) and personal-line promises are kept.
    if (toPhone) {
      const [ownerRows] = await pool.query<RowDataPacket[]>(
        `SELECT id FROM brokers
         WHERE tenant_id = ? AND status = 'active'
           AND twilio_caller_id = ?
         LIMIT 1`,
        [MORTGAGE_TENANT_ID, toPhone],
      );
      if (ownerRows.length > 0) {
        brokerId = ownerRows[0].id;
      }
    }
    // If still no broker (shared line + unknown client), leave brokerId NULL —
    // the thread becomes a shared-inbox thread visible to all brokers.
    void 0;

    // ── Determine conversation_id ────────────────────────────────────────────
    // Priority order:
    // 1. Most recent conversation_thread for this client (covers broker-initiated threads)
    // 2. Most recent active reminder_flow_execution
    // 3. Deterministic fallback
    let conversationId: string | null = null;

    if (clientId) {
      const canonicalClientConversationId = `conv_client_${clientId}`;
      // First: prefer the thread that was established on this exact inbox number.
      // This prevents an inbound message on Broker A's personal line from
      // being routed into a thread that belongs to Broker B just because
      // Broker B's thread happened to be more recently active.
      if (toPhone) {
        const [inboxThreadRows] = await pool.query<RowDataPacket[]>(
          `SELECT conversation_id FROM conversation_threads
           WHERE tenant_id = ? AND client_id = ? AND inbox_number = ?
           ORDER BY
             CASE WHEN conversation_id = ? THEN 0 ELSE 1 END,
             last_message_at DESC,
             created_at DESC
           LIMIT 1`,
          [
            MORTGAGE_TENANT_ID,
            clientId,
            toPhone,
            canonicalClientConversationId,
          ],
        );
        if (inboxThreadRows.length > 0) {
          conversationId = inboxThreadRows[0].conversation_id;
        }
      }

      // Fallback: most recent thread for this client on any inbox
      if (!conversationId) {
        const [threadRows] = await pool.query<RowDataPacket[]>(
          `SELECT conversation_id FROM conversation_threads
           WHERE tenant_id = ? AND client_id = ?
           ORDER BY
             CASE WHEN conversation_id = ? THEN 0 ELSE 1 END,
             last_message_at DESC,
             created_at DESC
           LIMIT 1`,
          [MORTGAGE_TENANT_ID, clientId, canonicalClientConversationId],
        );
        if (threadRows.length > 0) {
          conversationId = threadRows[0].conversation_id;
        }
      }
      console.log(
        `[InboundSMS Trace] client=${clientId} canonical=${canonicalClientConversationId} selected=${conversationId ?? "none"} inbox=${toPhone ?? "none"}`,
      );
    }

    if (!conversationId && clientId) {
      // Second: active reminder flow execution
      const [execRows] = await pool.query<RowDataPacket[]>(
        `SELECT conversation_id FROM reminder_flow_executions
         WHERE tenant_id = ? AND client_id = ? AND status = 'active'
           AND conversation_id IS NOT NULL
         ORDER BY created_at DESC
         LIMIT 1`,
        [MORTGAGE_TENANT_ID, clientId],
      );
      if (execRows.length > 0) {
        conversationId = execRows[0].conversation_id;
      }
    }

    // Phase C lazy-thread fallback:
    // If no thread exists yet, bind inbound SMS to the most recent broadcast
    // conversation sent to this phone (optionally same inbox number). This
    // preserves reply context without creating blast threads at send-time.
    if (!conversationId) {
      const fromLastTen = fromPhone.replace(/\D/g, "").slice(-10);
      if (fromLastTen.length === 10) {
        const [broadcastRows] = await pool.query<RowDataPacket[]>(
          `SELECT rbr.conversation_id
           FROM realtor_broadcast_recipients rbr
           JOIN realtor_broadcasts rb
             ON rb.id = rbr.broadcast_id
            AND rb.tenant_id = rbr.tenant_id
           LEFT JOIN brokers sb
             ON sb.id = rb.created_by
            AND sb.tenant_id = rb.tenant_id
           WHERE rbr.tenant_id = ?
             AND rbr.conversation_id IS NOT NULL
             AND rbr.sms_status = 'sent'
             AND RIGHT(REGEXP_REPLACE(rbr.recipient_phone, '[^0-9]', ''), 10) = ?
             AND (
               ? IS NULL
               OR RIGHT(REGEXP_REPLACE(sb.twilio_caller_id, '[^0-9]', ''), 10)
                  = RIGHT(REGEXP_REPLACE(?, '[^0-9]', ''), 10)
             )
           ORDER BY rbr.sent_at DESC, rbr.id DESC
           LIMIT 1`,
          [MORTGAGE_TENANT_ID, fromLastTen, toPhone || null, toPhone || null],
        );
        if (broadcastRows.length > 0) {
          conversationId = broadcastRows[0].conversation_id as string;
        }
      }
    }

    // Fall back to a deterministic ID if no thread found at all
    if (!conversationId && clientId) {
      conversationId = `conv_client_${clientId}`;
    }

    // For unknown senders (no client record), derive a stable ID from the phone
    // so all future messages from the same number land in the same thread.
    if (!conversationId) {
      conversationId = await resolvePhoneConversationId(
        pool,
        MORTGAGE_TENANT_ID,
        {
          phone: fromPhone,
          inboxNumber: toPhone,
        },
      );
    } else if (clientId) {
      // Known client — always canonical (never reuse legacy conv_phone_* thread ids).
      conversationId = `conv_client_${clientId}`;
    }

    // Idempotency: Twilio may retry the same MessageSid — skip duplicate inserts.
    if (messageSid) {
      const [[existingSms]] = await pool.query<RowDataPacket[]>(
        `SELECT id FROM communications
         WHERE tenant_id = ? AND external_id = ? AND communication_type = 'sms'
         LIMIT 1`,
        [MORTGAGE_TENANT_ID, messageSid],
      );
      if (existingSms) {
        res.set("Content-Type", "text/xml");
        return res.status(200).send("<Response></Response>");
      }
    }

    // ── Insert inbound communications record ─────────────────────────────────
    await pool.query(
      `INSERT INTO communications (
        tenant_id, application_id,
        from_user_id, to_broker_id,
        communication_type, direction,
        body, media_url, media_content_type, status,
        conversation_id, message_type,
        delivery_status, external_id,
        sent_at, created_at
      ) VALUES (?, ?, ?, ?, 'sms', 'inbound', ?, ?, ?, 'delivered', ?, ?, 'delivered', ?, NOW(), NOW())`,
      [
        MORTGAGE_TENANT_ID,
        loanId ?? null,
        clientId ?? null,
        brokerId ?? null,
        body.slice(0, 5000),
        primaryMediaUrl,
        primaryContentType,
        conversationId,
        msgType,
        messageSid || null,
      ],
    );

    try {
      await upsertConversationThread({
        tenantId: MORTGAGE_TENANT_ID,
        commId: 0,
        conversationId,
        applicationId: loanId ?? null,
        leadId: null,
        fromUserId: clientId ?? null,
        fromBrokerId: null,
        toUserId: null,
        toBrokerId: brokerId ?? null,
        communicationType: "sms",
        direction: "inbound",
        body: body.slice(0, 5000),
        inboxNumber: toPhone,
        recipientPhone: fromPhone || null,
      });

      // Ownership enforcement: if the called number is currently owned by a
      // broker (personal line), force the thread's broker_id AND inbox_number
      // to reflect the CURRENT owner — overriding any stale values from when
      // the thread was first created under a different (or no) owner. This
      // ensures reassignments take effect immediately: the previous owner
      // stops seeing the thread, the new owner sees it.
      if (brokerId && toPhone) {
        await pool.query(
          `UPDATE conversation_threads
           SET broker_id = ?,
               inbox_number = ?,
               updated_at = NOW()
           WHERE conversation_id = ? AND tenant_id = ?`,
          [brokerId, toPhone, conversationId, MORTGAGE_TENANT_ID],
        );
      }
    } catch (upsertErr) {
      // Non-fatal for the webhook — Twilio must always receive a 200.
      console.error(
        "⚠️  upsertConversationThread failed for inbound SMS:",
        upsertErr,
      );
    }

    // For unknown senders (no client record), persist the sender's phone on the
    // thread so brokers can reply without needing a client_id.
    if (!clientId && fromPhone) {
      await pool.query(
        `UPDATE conversation_threads
         SET client_phone = COALESCE(client_phone, ?), updated_at = NOW()
         WHERE conversation_id = ? AND tenant_id = ?`,
        [fromPhone, conversationId, MORTGAGE_TENANT_ID],
      );
    }

    console.log(
      `📥 Inbound SMS stored: conv=${conversationId} from=${fromPhone}`,
    );

    // ── Notify connected browsers via Ably ───────────────────────────────────
    if (conversationId) {
      const [[threadStatusRow]] = await pool.query<RowDataPacket[]>(
        `SELECT status FROM conversation_threads
         WHERE conversation_id = ? AND tenant_id = ?
         LIMIT 1`,
        [conversationId, MORTGAGE_TENANT_ID],
      );
      const threadStatus =
        (threadStatusRow?.status as string | undefined) ?? "active";

      await publishToAbly(`conversation:${conversationId}`, "new-message", {
        conversationId,
        direction: "inbound",
        communicationType: "sms",
        body: body.slice(0, 200),
      });
      await publishToAbly("conversations:all", "thread-updated", {
        conversationId,
        thread: { status: threadStatus },
      });
    }

    // ── Sync to reminder flows ────────────────────────────────────────────────
    if (conversationId) {
      await markExecutionsRespondedForConversation(
        conversationId,
        MORTGAGE_TENANT_ID,
      );
    }

    // Return empty TwiML so Twilio does not auto-reply
    res.set("Content-Type", "text/xml");
    return res.status(200).send("<Response></Response>");
  } catch (error) {
    console.error("❌ Inbound SMS webhook error:", error);
    // Always return 200 with empty TwiML so Twilio doesn't retry
    res.set("Content-Type", "text/xml");
    return res.status(200).send("<Response></Response>");
  }
};

// =====================================================
// CONVERSATION HANDLERS
// =====================================================

/**
 * GET /api/conversations/ably-token
 * Issues a short-lived Ably token for the authenticated broker so the browser
 * can subscribe to real-time channels without exposing the API key.
 */
const handleAblyToken: RequestHandler = async (req, res) => {
  if (!ablyClient) {
    return res.status(503).json({ error: "Real-time service not configured" });
  }
  try {
    const brokerId = (req as any).brokerId;
    const tokenRequest = await (ablyClient as any).auth.requestToken({
      clientId: `broker-${brokerId}`,
      capability: {
        "conversation:*": ["subscribe"],
        "conversations:all": ["subscribe"],
        "voice:incoming": ["subscribe"],
        [`broker-notifications:${brokerId}`]: ["subscribe"],
      },
      ttl: 3_600_000, // 1 hour in ms
    });
    return res.json(tokenRequest);
  } catch (error) {
    console.error("❌ Ably token error:", error);
    return res.status(500).json({ error: "Failed to generate token" });
  }
};

/**
 * GET /api/conversations/threads
 * Get conversation threads with filters and pagination
 */
const handleGetConversationThreads: RequestHandler = async (req, res) => {
  try {
    const brokerId = (req as any).brokerId;
    const brokerRole = (req as any).brokerRole;
    const isSuperAdmin = brokerRole === "superadmin";
    const isAdmin = brokerRole === "admin";
    const {
      page = 1,
      limit = 20,
      status = "all",
      priority,
      search,
      folder,
      mailbox_id,
      include_broadcast,
    } = req.query;

    const offset = (parseInt(page as string) - 1) * parseInt(limit as string);

    let whereConditions = ["ct.tenant_id = ?"];
    let queryParams: any[] = [MORTGAGE_TENANT_ID];

    // For non-superadmins: a thread is visible only if the requesting broker:
    //   a) is directly assigned to the thread  (ct.broker_id = ?)
    //   b) the thread has no resolved client   (unknown caller — shared inbox)
    //   c) owns the client via 3-path ownership (assigned_broker_id, broker_user_id,
    //      or partner_broker_id on a linked loan)
    //
    // NOTE: "participated in" (sent a message) was deliberately removed as a
    // standalone visibility condition. Allowing visibility purely because a
    // broker sent one message was the root cause of cross-broker conversation
    // leakage (a broker could initiate a thread against another broker's client
    // and then always see it). Ownership is the authoritative gate.
    if (!isSuperAdmin) {
      const groupVis = getGroupConversationsModule().enabled
        ? getGroupConversationsModule().groupVisibilitySql()
        : "";
      whereConditions.push(
        `(ct.broker_id = ?
          OR (ct.client_id IS NULL AND ct.broker_id IS NULL)
          ${
            isAdmin
              ? `-- Admins recover threads whose assigned broker is inactive/suspended
          OR (ct.client_id IS NULL AND ct.broker_id IS NOT NULL
              AND NOT EXISTS (
                SELECT 1 FROM brokers ib
                WHERE ib.id = ct.broker_id
                  AND ib.tenant_id = ct.tenant_id
                  AND ib.status = 'active'
              ))`
              : ""
          }
          OR EXISTS (
           SELECT 1 FROM clients cl_own
           WHERE cl_own.id = ct.client_id
             AND cl_own.tenant_id = ct.tenant_id
             AND (
               cl_own.assigned_broker_id = ?
               OR EXISTS (
                 SELECT 1 FROM loan_applications la_own
                 WHERE la_own.client_user_id = ct.client_id
                   AND la_own.tenant_id = ct.tenant_id
                   AND (la_own.broker_user_id = ? OR la_own.partner_broker_id = ?)
               )
             )
         )
         ${groupVis})`,
      );
      queryParams.push(brokerId, brokerId, brokerId, brokerId);
      if (getGroupConversationsModule().enabled) {
        queryParams.push(brokerId, brokerId, brokerId, brokerId);
      }
    }

    if (status !== "all") {
      whereConditions.push("ct.status = ?");
      queryParams.push(status);
    } else {
      // Default view shows only active threads (excludes 'closed' and any
      // legacy 'archived' rows that may still exist in the data).
      whereConditions.push("ct.status = 'active'");
    }

    const isEmailFolderView = folder === "inbox" || folder === "sent";
    if (isEmailFolderView) {
      // Email section: only email threads (inbox/sent folder filters apply below)
      whereConditions.push("ct.last_message_type = 'email'");
    } else {
      // Conversations page: exclude email threads so SMS/call pagination stays accurate
      whereConditions.push(
        "(ct.last_message_type IS NULL OR ct.last_message_type != 'email')",
      );

      const includeBroadcastThreads =
        String(include_broadcast || "")
          .toLowerCase()
          .trim() === "1" ||
        String(include_broadcast || "")
          .toLowerCase()
          .trim() === "true";
      if (!includeBroadcastThreads) {
        // Phase A + reply-promotion:
        // Hide broadcast-delivery threads by default, but auto-promote into the
        // normal inbox once the contact replies (has inbound communication).
        // Uses persisted tag (`broadcast_hidden`) with legacy ID-prefix fallback.
        whereConditions.push(`(
          (
            ct.conversation_id NOT LIKE 'broadcast-%'
            AND (
              ct.tags IS NULL
              OR JSON_CONTAINS(ct.tags, JSON_QUOTE('broadcast_hidden')) = 0
            )
          )
          OR EXISTS (
            SELECT 1 FROM communications c_in
            WHERE c_in.conversation_id = ct.conversation_id
              AND c_in.tenant_id = ct.tenant_id
              AND c_in.direction = 'inbound'
          )
        )`);
      }
    }

    if (priority) {
      whereConditions.push("ct.priority = ?");
      queryParams.push(priority);
    }

    // Folder filter: inbox = has inbound email, sent = broker sent outbound email
    // Mailbox filter: show threads for the selected mailbox OR threads with no
    // mailbox_id (received via inbound webhook before mailbox was resolved).
    if (mailbox_id) {
      whereConditions.push("(ct.mailbox_id = ? OR ct.mailbox_id IS NULL)");
      queryParams.push(Number(mailbox_id));
    }

    if (folder === "inbox") {
      whereConditions.push(
        `EXISTS (
           SELECT 1 FROM communications cf
           WHERE cf.conversation_id = ct.conversation_id
             AND cf.tenant_id = ct.tenant_id
             AND cf.communication_type = 'email'
             AND cf.direction = 'inbound'
         )`,
      );
    } else if (folder === "sent") {
      whereConditions.push(
        `EXISTS (
           SELECT 1 FROM communications cf
           WHERE cf.conversation_id = ct.conversation_id
             AND cf.tenant_id = ct.tenant_id
             AND cf.communication_type = 'email'
             AND cf.direction = 'outbound'
             AND cf.from_broker_id = ?
         )`,
      );
      queryParams.push(brokerId);
    }

    if (search) {
      // Also search broker/realtor names for threads that resolve via contact_broker_id
      // or a phone-matched broker row (so "Unknown Client" threads appear when
      // searching by realtor name or partial phone).
      const groupSearch = getGroupConversationsModule().enabled
        ? getGroupConversationsModule().groupSearchSql()
        : "";
      whereConditions.push(
        `(ct.client_name LIKE ?
          OR ct.client_email LIKE ?
          OR ct.client_phone LIKE ?
          OR EXISTS (
            SELECT 1 FROM brokers bsrch
            WHERE bsrch.id = ct.contact_broker_id
              AND CONCAT(bsrch.first_name, ' ', bsrch.last_name) LIKE ?
          )
          OR EXISTS (
            SELECT 1 FROM brokers bsrch2
            WHERE bsrch2.tenant_id = ct.tenant_id
              AND ct.client_name IS NULL
              AND ct.client_id IS NULL
              AND ct.contact_broker_id IS NULL
              AND RIGHT(REGEXP_REPLACE(bsrch2.phone, '[^0-9]', ''), 10)
                  = RIGHT(REGEXP_REPLACE(ct.client_phone, '[^0-9]', ''), 10)
              AND CONCAT(bsrch2.first_name, ' ', bsrch2.last_name) LIKE ?
          )
          OR EXISTS (
            SELECT 1 FROM clients csrch
            WHERE csrch.id = ct.client_id
              AND CONCAT(csrch.first_name, ' ', csrch.last_name) LIKE ?
          )
          ${groupSearch})`,
      );
      const searchTerm = `%${search}%`;
      queryParams.push(
        searchTerm,
        searchTerm,
        searchTerm,
        searchTerm,
        searchTerm,
        searchTerm,
      );
      if (getGroupConversationsModule().enabled) {
        queryParams.push(searchTerm, searchTerm);
      }
    }

    const whereClause = whereConditions.join(" AND ");

    // Get threads with client information
    const threadsQuery = `
      SELECT 
        ct.*,
        la.application_number,
        CONCAT(c.first_name, ' ', c.last_name) as client_full_name,
        c.email as client_email_current,
        c.phone as client_phone_current,
        -- Resolve display name: stored value → linked client → linked contact broker
        --   → JIT client phone lookup (fixes threads created before client was added)
        --   → phone-matched broker
        COALESCE(
          ct.client_name,
          CONCAT(c.first_name, ' ', c.last_name),
          CONCAT(cb.first_name, ' ', cb.last_name),
          -- JIT: client was added AFTER first inbound call — match by phone
          (SELECT CONCAT(pc.first_name, ' ', pc.last_name)
           FROM clients pc
           WHERE pc.tenant_id = ct.tenant_id
             AND ct.client_id IS NULL
             AND ct.client_name IS NULL
             AND ct.client_phone IS NOT NULL
             AND RIGHT(REGEXP_REPLACE(pc.phone, '[^0-9]', ''), 10)
                 = RIGHT(REGEXP_REPLACE(ct.client_phone, '[^0-9]', ''), 10)
           LIMIT 1),
          (SELECT CONCAT(pb.first_name, ' ', pb.last_name)
           FROM brokers pb
           WHERE pb.tenant_id = ct.tenant_id
             AND ct.client_name IS NULL
             AND ct.client_id IS NULL
             AND ct.contact_broker_id IS NULL
             AND ct.client_phone IS NOT NULL
             AND RIGHT(REGEXP_REPLACE(pb.phone, '[^0-9]', ''), 10)
                 = RIGHT(REGEXP_REPLACE(ct.client_phone, '[^0-9]', ''), 10)
           LIMIT 1)
        ) AS resolved_client_name,
        CASE WHEN ct.client_id IS NOT NULL THEN 1 ELSE 0 END AS can_view_client,
        -- When the thread's broker_id differs from the client's assigned broker,
        -- surface the assigned broker's name so the UI can show an ownership hint.
        CASE
          WHEN c.assigned_broker_id IS NOT NULL
            AND ct.broker_id IS NOT NULL
            AND c.assigned_broker_id != ct.broker_id
          THEN CONCAT(ab.first_name, ' ', ab.last_name)
          ELSE NULL
        END AS client_assigned_broker_name,
        c.assigned_broker_id AS client_assigned_broker_id
      FROM conversation_threads ct
      LEFT JOIN loan_applications la ON ct.application_id = la.id
      LEFT JOIN clients c ON ct.client_id = c.id
      LEFT JOIN brokers cb ON ct.contact_broker_id = cb.id
      LEFT JOIN brokers ab ON c.assigned_broker_id = ab.id AND ab.tenant_id = ct.tenant_id
      WHERE ${whereClause}
      ORDER BY ct.last_message_at DESC, ct.id DESC
      LIMIT ${parseInt(limit as string)} OFFSET ${offset}
    `;

    const [threads] = await pool.query<RowDataPacket[]>(
      threadsQuery,
      queryParams,
    );

    // Get total count
    const countQuery = `
      SELECT COUNT(*) as total 
      FROM conversation_threads ct 
      WHERE ${whereClause}
    `;
    const [countResult] = await pool.query<RowDataPacket[]>(
      countQuery,
      queryParams,
    );

    const total = countResult[0]?.total || 0;
    const totalPages = Math.ceil(total / parseInt(limit as string));

    const groupEnrichment = getGroupConversationsModule().enabled
      ? await getGroupConversationsModule().enrichThreadRows(threads)
      : {};

    res.json({
      success: true,
      threads: threads.map((thread) => {
        const convId = thread.conversation_id as string;
        const groupExtra = groupEnrichment[convId] ?? {};
        return {
          ...thread,
          ...groupExtra,
          thread_type: groupExtra.thread_type ?? thread.thread_type ?? "direct",
          // Use the resolved name (covers broker/realtor contacts and backfills
          // existing threads that were stored with client_name = NULL)
          client_name:
            groupExtra.client_name ??
            groupExtra.display_title ??
            thread.resolved_client_name ??
            thread.client_name,
          tags: parseThreadTags(thread.tags),
          can_view_client: !!thread.can_view_client,
          client_assigned_broker_name:
            thread.client_assigned_broker_name ?? null,
          client_assigned_broker_id: thread.client_assigned_broker_id ?? null,
        };
      }),
      pagination: {
        page: parseInt(page as string),
        limit: parseInt(limit as string),
        total,
        totalPages,
      },
    });
  } catch (error) {
    console.error("Error fetching conversation threads:", error);
    res.status(500).json({
      success: false,
      message: "Failed to fetch conversation threads",
    });
  }
};

/**
 * GET /api/conversations/:conversationId/messages
 * Get messages for a specific conversation
 */
const handleGetConversationMessages: RequestHandler = async (req, res) => {
  try {
    const { conversationId } = req.params;
    const { page = 1, limit = 50 } = req.query;
    const brokerId = (req as any).brokerId;
    const brokerRole = (req as any).brokerRole;
    const isSuperAdmin = brokerRole === "superadmin";
    const isAdmin = brokerRole === "admin";

    const offset = (parseInt(page as string) - 1) * parseInt(limit as string);

    // Verify broker has access to this conversation using the same 3-path
    // ownership model as GET /threads:
    //   a) thread is directly assigned to this broker
    //   b) shared inbox — thread has no broker and no resolved client
    //   c) broker owns the client via assigned_broker_id or loan co-ownership
    //   d) group participant / co-owned client (when feature enabled)
    // Superadmins bypass ownership and see all threads.
    let threadCheckSql: string;
    let threadCheckParams: any[];
    if (isSuperAdmin) {
      threadCheckSql = `SELECT id FROM conversation_threads
       WHERE conversation_id = ? AND tenant_id = ?`;
      threadCheckParams = [conversationId, MORTGAGE_TENANT_ID];
    } else {
      const groupVis = getGroupConversationsModule().enabled
        ? getGroupConversationsModule().groupVisibilitySql()
        : "";
      threadCheckSql = `SELECT id FROM conversation_threads ct
       WHERE ct.conversation_id = ? AND ct.tenant_id = ?
         AND (
           ct.broker_id = ?
           OR (ct.client_id IS NULL AND ct.broker_id IS NULL)
           ${
             isAdmin
               ? `OR (ct.client_id IS NULL AND ct.broker_id IS NOT NULL
               AND NOT EXISTS (
                 SELECT 1 FROM brokers ib
                 WHERE ib.id = ct.broker_id
                   AND ib.tenant_id = ct.tenant_id
                   AND ib.status = 'active'
               ))`
               : ""
           }
           OR EXISTS (
             SELECT 1 FROM clients cl
             WHERE cl.id = ct.client_id
               AND cl.tenant_id = ct.tenant_id
               AND (
                 cl.assigned_broker_id = ?
                 OR EXISTS (
                   SELECT 1 FROM loan_applications la
                   WHERE la.client_user_id = ct.client_id
                     AND la.tenant_id = ct.tenant_id
                     AND (la.broker_user_id = ? OR la.partner_broker_id = ?)
                 )
               )
           )
           ${groupVis}
         )`;
      threadCheckParams = [
        conversationId,
        MORTGAGE_TENANT_ID,
        brokerId,
        brokerId,
        brokerId,
        brokerId,
      ];
      if (getGroupConversationsModule().enabled) {
        threadCheckParams.push(brokerId, brokerId, brokerId, brokerId);
      }
    }
    const [threadCheck] = await pool.query<RowDataPacket[]>(
      threadCheckSql,
      threadCheckParams,
    );

    if (threadCheck.length === 0) {
      return res.status(404).json({
        success: false,
        message: "Conversation not found or access denied",
      });
    }

    // Get messages
    const [messages] = await pool.query<RowDataPacket[]>(
      `SELECT 
        c.*,
        t.name as template_name,
        COALESCE(
          NULLIF(CONCAT(b.first_name, ' ', b.last_name), ' '),
          NULLIF(CONCAT(fc.first_name, ' ', fc.last_name), ' '),
          'System'
        ) as sender_name,
        COALESCE(CONCAT(cl.first_name, ' ', cl.last_name), 'Client') as recipient_name
      FROM communications c
      LEFT JOIN templates t ON c.template_id = t.id
      LEFT JOIN brokers b ON c.from_broker_id = b.id
      LEFT JOIN clients cl ON c.to_user_id = cl.id
      LEFT JOIN clients fc ON c.from_user_id = fc.id
      WHERE c.conversation_id = ? AND c.tenant_id = ?
      ORDER BY c.created_at DESC, c.id DESC
      LIMIT ${parseInt(limit as string)} OFFSET ${offset}`,
      [conversationId, MORTGAGE_TENANT_ID],
    );

    // Get thread info — apply the same broker/realtor name resolution as the
    // threads list so "Unknown Client" is never shown when opening a thread
    // whose contact is a broker/realtor (stored with client_name = NULL).
    // Also includes JIT client-phone lookup: fixes threads where the client
    // was added to the CRM AFTER their first inbound call.
    const [threadInfo] = await pool.query<RowDataPacket[]>(
      `SELECT ct.*,
              la.application_number,
              CONCAT(cl.first_name, ' ', cl.last_name) AS client_full_name,
              COALESCE(
                ct.client_name,
                CONCAT(cl.first_name, ' ', cl.last_name),
                CONCAT(cb.first_name, ' ', cb.last_name),
                -- JIT: client added after first call — match by phone
                CONCAT(pc.first_name, ' ', pc.last_name),
                CONCAT(pb.first_name, ' ', pb.last_name)
              ) AS resolved_client_name
       FROM conversation_threads ct
       LEFT JOIN loan_applications la ON ct.application_id = la.id
       LEFT JOIN clients cl ON ct.client_id = cl.id
       LEFT JOIN brokers cb ON ct.contact_broker_id = cb.id
       LEFT JOIN clients pc ON pc.tenant_id = ct.tenant_id
         AND ct.client_id IS NULL
         AND ct.client_name IS NULL
         AND ct.client_phone IS NOT NULL
         AND RIGHT(REGEXP_REPLACE(pc.phone, '[^0-9]', ''), 10)
             = RIGHT(REGEXP_REPLACE(ct.client_phone, '[^0-9]', ''), 10)
       LEFT JOIN brokers pb ON pb.tenant_id = ct.tenant_id
         AND ct.client_name IS NULL
         AND ct.client_id IS NULL
         AND ct.contact_broker_id IS NULL
         AND ct.client_phone IS NOT NULL
         AND RIGHT(REGEXP_REPLACE(pb.phone, '[^0-9]', ''), 10)
             = RIGHT(REGEXP_REPLACE(ct.client_phone, '[^0-9]', ''), 10)
       WHERE ct.conversation_id = ? AND ct.tenant_id = ?`,
      [conversationId, MORTGAGE_TENANT_ID],
    );
    // Normalise: promote resolved_client_name → client_name so the frontend
    // always receives a populated name without any special-case handling.
    if (threadInfo[0] && threadInfo[0].resolved_client_name) {
      threadInfo[0].client_name = threadInfo[0].resolved_client_name;
    }

    // Get total message count
    const [countResult] = await pool.query<RowDataPacket[]>(
      "SELECT COUNT(*) as total FROM communications WHERE conversation_id = ? AND tenant_id = ?",
      [conversationId, MORTGAGE_TENANT_ID],
    );

    // Server-side mark-as-read: opening a conversation clears its unread badge
    // for everyone (no need for a separate endpoint or client retry).
    if (threadInfo[0] && (threadInfo[0].unread_count ?? 0) > 0) {
      pool
        .query(
          `UPDATE conversation_threads SET unread_count = 0, updated_at = NOW()
           WHERE conversation_id = ? AND tenant_id = ?`,
          [conversationId, MORTGAGE_TENANT_ID],
        )
        .then(() =>
          publishToAbly("conversations:all", "thread-read", {
            conversationId,
          }).catch(() => undefined),
        )
        .catch((e) => console.warn("⚠️ Failed to reset unread_count:", e));
      // Reflect the reset in the response so the client UI matches the DB.
      threadInfo[0].unread_count = 0;
    }

    const total = countResult[0]?.total || 0;
    const totalPages = Math.ceil(total / parseInt(limit as string));

    res.json({
      success: true,
      messages: messages.map((msg) => {
        let metadata = null;
        let provider_response = null;
        try {
          metadata =
            msg.metadata && typeof msg.metadata === "string"
              ? JSON.parse(msg.metadata)
              : (msg.metadata ?? null);
        } catch {
          metadata = null;
        }
        try {
          provider_response =
            msg.provider_response && typeof msg.provider_response === "string"
              ? JSON.parse(msg.provider_response)
              : (msg.provider_response ?? null);
        } catch {
          provider_response = null;
        }
        return { ...msg, metadata, provider_response };
      }),
      thread: {
        ...threadInfo[0],
        // Always guarantee conversation_id is present — if threadInfo somehow
        // returned no row (e.g. race condition after upsert), fall back to the
        // URL param so the client never loses track of which thread it is in.
        conversation_id: threadInfo[0]?.conversation_id ?? conversationId,
        client_name:
          threadInfo[0]?.client_name ??
          threadInfo[0]?.resolved_client_name ??
          null,
        tags: parseThreadTags(threadInfo[0]?.tags),
      },
      pagination: {
        page: parseInt(page as string),
        limit: parseInt(limit as string),
        total,
        totalPages,
      },
    });
  } catch (error) {
    console.error("Error fetching conversation messages:", error);
    res.status(500).json({
      success: false,
      message: "Failed to fetch conversation messages",
    });
  }
};

/**
 * DELETE /api/conversations/:conversationId/messages/:messageId
 * Delete a single message from a conversation (broker-only, own messages only)
 */
const handleDeleteConversationMessage: RequestHandler = async (req, res) => {
  try {
    const { conversationId, messageId } = req.params;
    const brokerId = (req as any).brokerId;

    // Only let the broker delete messages they sent (or any message if they own the thread)
    const [rows] = await pool.query<RowDataPacket[]>(
      `SELECT c.id, c.from_broker_id, ct.broker_id AS thread_owner
       FROM communications c
       JOIN conversation_threads ct ON ct.conversation_id = c.conversation_id AND ct.tenant_id = c.tenant_id
       WHERE c.id = ? AND c.conversation_id = ? AND c.tenant_id = ?`,
      [messageId, conversationId, MORTGAGE_TENANT_ID],
    );

    if (rows.length === 0) {
      return res
        .status(404)
        .json({ success: false, message: "Message not found" });
    }

    const msg = rows[0];
    const brokerRole = (req as any).brokerRole;
    const isAdminRole =
      brokerRole === "admin" ||
      brokerRole === "superadmin" ||
      brokerRole === "platform_owner";
    const canDelete =
      msg.from_broker_id === brokerId ||
      msg.thread_owner === brokerId ||
      isAdminRole;
    if (!canDelete) {
      return res.status(403).json({
        success: false,
        message: "Not authorized to delete this message",
      });
    }

    await pool.query(
      `DELETE FROM communications WHERE id = ? AND tenant_id = ?`,
      [messageId, MORTGAGE_TENANT_ID],
    );

    // Recount thread stats — strip HTML from preview so it never shows raw markup
    await pool.query(
      `UPDATE conversation_threads ct
       SET
         message_count = (SELECT COUNT(*) FROM communications c WHERE c.conversation_id = ct.conversation_id AND c.tenant_id = ct.tenant_id),
         last_message_at = (SELECT MAX(c.created_at) FROM communications c WHERE c.conversation_id = ct.conversation_id AND c.tenant_id = ct.tenant_id),
         last_message_preview = (SELECT LEFT(REGEXP_REPLACE(REGEXP_REPLACE(c.body, '<[^>]*>', ' '), '\\s+', ' '), 200)
                                  FROM communications c WHERE c.conversation_id = ct.conversation_id AND c.tenant_id = ct.tenant_id ORDER BY c.created_at DESC LIMIT 1),
         updated_at = NOW()
       WHERE ct.conversation_id = ? AND ct.tenant_id = ?`,
      [conversationId, MORTGAGE_TENANT_ID],
    );

    return res.json({ success: true, messageId });
  } catch (error) {
    console.error("Error deleting conversation message:", error);
    return res
      .status(500)
      .json({ success: false, message: "Failed to delete message" });
  }
};

/**
 * POST /api/conversations/send
 * Send a new message (SMS, WhatsApp, or Email)
 */
const handleSendMessage: RequestHandler = async (req, res) => {
  try {
    const brokerId = (req as any).brokerId;
    const brokerRole = (req as any).brokerRole;
    const {
      conversation_id,
      application_id,
      lead_id,
      client_id,
      broker_id: recipientBrokerId,
      mailbox_id,
      communication_type,
      recipient_phone,
      recipient_email,
      subject,
      body,
      template_id,
      message_type = "text",
      scheduled_at,
      media_url,
      media_content_type,
      media_filename,
      cc,
      bcc,
    } = req.body;

    console.log(
      `[SMS Trace] handleSendMessage — broker=${brokerId} type=${communication_type} conv=${conversation_id} client_id=${client_id} phone=${recipient_phone} body_len=${body?.length ?? 0} media_url=${media_url ?? "none"}`,
    );

    // Validation
    if (!communication_type || (!body && !media_url)) {
      return res.status(400).json({
        success: false,
        message: "communication_type and body are required",
      });
    }

    if (!["email", "sms", "whatsapp"].includes(communication_type)) {
      return res.status(400).json({
        success: false,
        message: "Invalid communication_type. Must be email, sms, or whatsapp",
      });
    }

    // Group threads must use the dedicated group send endpoint (Group MMS).
    if (conversation_id) {
      const [groupCheck] = await pool.query<RowDataPacket[]>(
        `SELECT thread_type FROM conversation_threads
         WHERE conversation_id = ? AND tenant_id = ? LIMIT 1`,
        [conversation_id, MORTGAGE_TENANT_ID],
      );
      if (groupCheck[0]?.thread_type === "group") {
        return res.status(400).json({
          success: false,
          message:
            "This is a group conversation. Use POST /api/conversations/groups/:conversationId/send",
        });
      }
    }

    // Validate recipient info
    if (
      communication_type === "email" &&
      !recipient_email &&
      !client_id &&
      !application_id
    ) {
      return res.status(400).json({
        success: false,
        message: "recipient_email is required for email communications",
      });
    }

    // Get recipient info if not provided but client_id, application_id, or conversation_id is available
    let finalRecipientEmail = recipient_email;
    let finalRecipientPhone = recipient_phone;

    if (!finalRecipientEmail || !finalRecipientPhone) {
      let clientQuery = "";
      let clientParams: any[] = [];

      if (client_id) {
        clientQuery =
          "SELECT email, phone FROM clients WHERE id = ? AND tenant_id = ?";
        clientParams = [client_id, MORTGAGE_TENANT_ID];
      } else if (application_id) {
        clientQuery = `
          SELECT c.email, c.phone 
          FROM clients c 
          JOIN loan_applications la ON c.id = la.client_user_id 
          WHERE la.id = ? AND la.tenant_id = ?
        `;
        clientParams = [application_id, MORTGAGE_TENANT_ID];
      }

      if (clientQuery) {
        const [clientInfo] = await pool.query<RowDataPacket[]>(
          clientQuery,
          clientParams,
        );

        if (clientInfo.length > 0) {
          finalRecipientEmail = finalRecipientEmail || clientInfo[0].email;
          finalRecipientPhone = finalRecipientPhone || clientInfo[0].phone;
        }
      }

      // Fallback: look up phone/email from the conversation thread itself.
      // This handles unknown-sender threads (no client_id) where the phone
      // is stored directly on the thread row.
      if ((!finalRecipientPhone || !finalRecipientEmail) && conversation_id) {
        const [threadPhone] = await pool.query<RowDataPacket[]>(
          `SELECT client_phone, client_email, inbox_number FROM conversation_threads
           WHERE conversation_id = ? AND tenant_id = ? LIMIT 1`,
          [conversation_id, MORTGAGE_TENANT_ID],
        );
        if (threadPhone.length > 0) {
          finalRecipientPhone =
            finalRecipientPhone || threadPhone[0].client_phone || null;
          finalRecipientEmail =
            finalRecipientEmail || threadPhone[0].client_email || null;
        }
      }

      // Broker/realtor recipient — look up their contact details directly.
      if (recipientBrokerId && (!finalRecipientPhone || !finalRecipientEmail)) {
        const [brokerContactInfo] = await pool.query<RowDataPacket[]>(
          `SELECT phone, email FROM brokers WHERE id = ? AND tenant_id = ? AND status = 'active' LIMIT 1`,
          [recipientBrokerId, MORTGAGE_TENANT_ID],
        );
        if (brokerContactInfo.length > 0) {
          finalRecipientPhone =
            finalRecipientPhone || brokerContactInfo[0].phone || null;
          finalRecipientEmail =
            finalRecipientEmail || brokerContactInfo[0].email || null;
        }
      }
    }

    console.log(
      `[SMS Trace] Resolved recipients — phone=${finalRecipientPhone ?? "NONE"} email=${finalRecipientEmail ?? "NONE"}`,
    );

    // ── Cross-broker ownership guard ─────────────────────────────────────────
    // platform_owner may message any client.
    // Mortgage bankers may continue threads they own after reassignment.
    // New outbound to another broker's client is blocked unless loan co-ownership.
    // Guard is bypassed when messaging a broker/realtor (recipientBrokerId).
    if (!recipientBrokerId) {
      let guardClientId: number | null =
        typeof client_id === "number" ? client_id : null;

      if (!guardClientId && finalRecipientPhone) {
        const lastTen = finalRecipientPhone.replace(/\D/g, "").slice(-10);
        if (lastTen.length === 10) {
          const [gcPhoneRows] = await pool.query<RowDataPacket[]>(
            `SELECT id FROM clients
             WHERE tenant_id = ?
               AND RIGHT(REGEXP_REPLACE(phone, '[^0-9]', ''), 10) = ?
             LIMIT 1`,
            [MORTGAGE_TENANT_ID, lastTen],
          );
          if (gcPhoneRows.length > 0)
            guardClientId = gcPhoneRows[0].id as number;
        }
      }

      if (!guardClientId && finalRecipientEmail) {
        const [gcEmailRows] = await pool.query<RowDataPacket[]>(
          `SELECT id FROM clients
           WHERE tenant_id = ? AND LOWER(email) = LOWER(?)
           LIMIT 1`,
          [MORTGAGE_TENANT_ID, finalRecipientEmail],
        );
        if (gcEmailRows.length > 0) guardClientId = gcEmailRows[0].id as number;
      }

      if (guardClientId) {
        const allowed = await canBrokerMessageClient(
          guardClientId,
          brokerId,
          brokerRole,
          conversation_id ?? null,
        );
        if (!allowed) {
          return res.status(403).json({
            success: false,
            error:
              "This contact is assigned to another broker. You do not have permission to message them.",
          });
        }
      }
    }

    // Determine which Twilio number to send from, honoring ownership rules:
    //   Rule 1: Broker with a personal number must ALWAYS use it (absolute priority,
    //           even for replies on old threads that used a shared number).
    //   Rule 2: Broker with NO personal number uses the thread's existing inbox_number
    //           if that number is NOT someone else's personal line. Otherwise falls
    //           through to the first available shared number.
    //   Rule 3: Never send from a number that is now assigned as another broker's
    //           personal line (prevents ownership leakage after reassignment).
    let fromNumber: string = "";

    // Fetch broker's personal number AND the set of all personal lines in one shot
    const [brokerPhoneRows] = await pool.query<RowDataPacket[]>(
      `SELECT twilio_caller_id FROM brokers
       WHERE id = ? AND tenant_id = ? AND twilio_caller_id IS NOT NULL LIMIT 1`,
      [brokerId, MORTGAGE_TENANT_ID],
    );
    const brokerPersonalNumber: string | null =
      brokerPhoneRows[0]?.twilio_caller_id ?? null;

    const [allPersonalRows] = await pool.query<RowDataPacket[]>(
      `SELECT twilio_caller_id FROM brokers
       WHERE tenant_id = ? AND twilio_caller_id IS NOT NULL AND twilio_caller_id <> ''`,
      [MORTGAGE_TENANT_ID],
    );
    const personalLines = new Set(
      (allPersonalRows as RowDataPacket[]).map(
        (r) => r.twilio_caller_id as string,
      ),
    );
    const otherBrokerPersonalLines = new Set(personalLines);
    if (brokerPersonalNumber)
      otherBrokerPersonalLines.delete(brokerPersonalNumber);

    // Step 1: If broker has a personal number → use it unconditionally (Rule 1)
    if (brokerPersonalNumber) {
      fromNumber = brokerPersonalNumber;
    }

    // Step 2: No personal number → try thread's inbox_number, but skip it if it's
    // now another broker's personal line (Rule 3 — reassignment safety)
    if (!fromNumber && conversation_id) {
      const [threadRow] = await pool.query<RowDataPacket[]>(
        `SELECT inbox_number FROM conversation_threads
         WHERE conversation_id = ? AND tenant_id = ? LIMIT 1`,
        [conversation_id, MORTGAGE_TENANT_ID],
      );
      const inboxNum: string | null = threadRow[0]?.inbox_number ?? null;
      if (inboxNum && !otherBrokerPersonalLines.has(inboxNum)) {
        fromNumber = inboxNum;
      }
    }

    // Step 3: First shared number — derived from inbox_number values seen on
    // existing threads, excluding any number that is now a broker's personal line.
    // Sorted deterministically so the same broker always picks the same shared
    // number until reassignment.
    if (!fromNumber) {
      try {
        const [sharedRows] = await pool.query<RowDataPacket[]>(
          `SELECT DISTINCT ct.inbox_number
           FROM conversation_threads ct
           WHERE ct.tenant_id = ?
             AND ct.inbox_number IS NOT NULL
             AND ct.inbox_number <> ''
             AND ct.inbox_number NOT IN (
               SELECT twilio_caller_id FROM brokers
               WHERE tenant_id = ? AND twilio_caller_id IS NOT NULL
             )
           ORDER BY ct.inbox_number ASC
           LIMIT 1`,
          [MORTGAGE_TENANT_ID, MORTGAGE_TENANT_ID],
        );
        if (sharedRows.length > 0) fromNumber = sharedRows[0].inbox_number;
      } catch (_e) {
        // ignore — fall through to last resort
      }
    }

    // Step 4: Query Twilio directly for the first SMS-capable shared line.
    // This is the authoritative source: any Twilio number NOT assigned as a
    // broker's personal line (by SID or caller_id) is considered shared.
    // Replaces the previous `otp_from_number` lookup which could hold a
    // number that has since been reassigned as a personal line.
    if (!fromNumber) {
      try {
        const twilioShared = await getSharedSmsNumber();
        if (twilioShared) {
          fromNumber = twilioShared;
        }
      } catch (e) {
        console.warn("⚠️ Step 4 (Twilio shared lookup) failed:", e);
      }
    }

    // Step 5 (absolute last resort): otp_from_number from system_settings,
    // only if it is NOT a broker's personal line. Prevents sending from
    // another broker's exclusive number when all other steps fail.
    if (!fromNumber) {
      try {
        const [settingRows] = await pool.query<RowDataPacket[]>(
          `SELECT setting_value FROM system_settings
           WHERE tenant_id = ? AND setting_key = 'otp_from_number' LIMIT 1`,
          [MORTGAGE_TENANT_ID],
        );
        const candidate = settingRows[0]?.setting_value as string | undefined;
        if (candidate && !personalLines.has(candidate)) {
          fromNumber = candidate;
        } else if (candidate && personalLines.has(candidate)) {
          console.warn(
            `⚠️ otp_from_number=${candidate} is now a broker's personal line — refusing to use.`,
          );
        }
      } catch (e) {
        console.warn("⚠️ Step 5 from-number fallback failed:", e);
      }
    }

    if (
      ["sms", "whatsapp"].includes(communication_type) &&
      !finalRecipientPhone
    ) {
      console.error(
        `[SMS Trace] BLOCKED — no finalRecipientPhone for ${communication_type}. conv=${conversation_id} client_id=${client_id}`,
      );
      return res.status(400).json({
        success: false,
        message: "recipient_phone is required for SMS/WhatsApp communications",
      });
    }

    console.log(
      `[SMS Trace] fromNumber resolved="${fromNumber || "NONE"}" personalNumber="${brokerPersonalNumber ?? "none"}"`,
    );

    // Generate conversation_id if not provided — use canonical per-client ID when possible
    let finalConversationId = conversation_id;
    if (!finalConversationId) {
      if (client_id) {
        finalConversationId = `conv_client_${client_id}`;
      } else if (recipientBrokerId) {
        // Canonical thread per sender+broker pair so broker-to-broker messages thread correctly
        finalConversationId = `conv_broker_${brokerId}_${recipientBrokerId}`;
      } else if (finalRecipientPhone) {
        const recipientLast10 = phoneLast10(finalRecipientPhone);
        const [existingThreadRows] = await pool.query<RowDataPacket[]>(
          `SELECT conversation_id, client_id FROM conversation_threads
           WHERE tenant_id = ?
             AND normalized_client_phone = ?
             AND (broker_id = ? OR broker_id IS NULL)
           ORDER BY
             CASE WHEN conversation_id LIKE 'conv_client_%' THEN 0 ELSE 1 END,
             last_message_at DESC
           LIMIT 1`,
          [MORTGAGE_TENANT_ID, recipientLast10, brokerId],
        );
        if (
          existingThreadRows.length > 0 &&
          existingThreadRows[0].conversation_id
        ) {
          const rowClientId = existingThreadRows[0].client_id as number | null;
          finalConversationId =
            rowClientId != null
              ? `conv_client_${rowClientId}`
              : (existingThreadRows[0].conversation_id as string);
          console.log(
            `[SMS Trace] Recovered existing conv for phone=${finalRecipientPhone}: ${finalConversationId}`,
          );
        } else if (recipientLast10) {
          const phoneClientId = await resolveClientIdByPhone(
            pool,
            MORTGAGE_TENANT_ID,
            finalRecipientPhone,
          );
          if (phoneClientId) {
            finalConversationId = `conv_client_${phoneClientId}`;
            console.log(
              `[SMS Trace] Canonical conv for phone=${finalRecipientPhone}: ${finalConversationId}`,
            );
          } else {
            finalConversationId = `conv_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
            console.log(
              `[SMS Trace] No existing conv found for phone=${finalRecipientPhone}, creating new: ${finalConversationId}`,
            );
          }
        } else {
          finalConversationId = `conv_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
        }
      } else {
        finalConversationId = `conv_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
      }
    }

    // Resolve {{first_name}} and other merge tags (template picker or pasted body)
    let processedBody = body;
    let processedSubject = subject;

    let effectiveClientId: number | null = null;
    if (client_id != null && client_id !== "") {
      const parsed = Number(client_id);
      if (!Number.isNaN(parsed)) effectiveClientId = parsed;
    }
    if (!effectiveClientId && finalConversationId) {
      const [threadClientRows] = await pool.query<RowDataPacket[]>(
        `SELECT client_id FROM conversation_threads
         WHERE conversation_id = ? AND tenant_id = ? AND client_id IS NOT NULL LIMIT 1`,
        [finalConversationId, MORTGAGE_TENANT_ID],
      );
      if (threadClientRows.length > 0) {
        effectiveClientId = threadClientRows[0].client_id as number;
      }
    }

    const bodyHasPlaceholders = /\{\{[^}]+\}\}/.test(processedBody || "");
    const subjectHasPlaceholders = /\{\{[^}]+\}\}/.test(processedSubject || "");
    const shouldResolveTemplate =
      !!template_id ||
      message_type === "template" ||
      bodyHasPlaceholders ||
      subjectHasPlaceholders;

    if (shouldResolveTemplate) {
      const templateVariables = await resolveConversationTemplateVariables({
        clientId: effectiveClientId,
        applicationId: application_id ?? null,
        conversationId: finalConversationId,
        recipientPhone: finalRecipientPhone,
        recipientEmail: finalRecipientEmail,
        recipientBrokerId: recipientBrokerId ?? null,
        senderBrokerId: brokerId,
      });

      if (!templateVariables.first_name && bodyHasPlaceholders) {
        console.warn(
          `[handleSendMessage] first_name unresolved — conv=${finalConversationId} client_id=${effectiveClientId} phone=${finalRecipientPhone ?? "none"}`,
        );
      }

      let bodyToProcess = processedBody;
      let subjectToProcess = processedSubject;

      if (template_id) {
        const [templates] = await pool.query<RowDataPacket[]>(
          `SELECT * FROM templates WHERE id = ? AND tenant_id = ?`,
          [template_id, MORTGAGE_TENANT_ID],
        );
        if (templates.length > 0) {
          const template = templates[0];
          if (!bodyToProcess?.trim()) bodyToProcess = template.body;
          if (communication_type === "email" && !subjectToProcess?.trim()) {
            subjectToProcess = template.subject || "";
          }
        }
      }

      processedBody = processTemplateVariables(
        bodyToProcess || "",
        templateVariables,
      );
      if (communication_type === "email" && subjectToProcess) {
        processedSubject = processTemplateVariables(
          subjectToProcess,
          templateVariables,
        );
      }
    }

    // Insert communication record
    const [result] = (await pool.query(
      `INSERT INTO communications (
        tenant_id, application_id, lead_id, from_broker_id, to_user_id,
        communication_type, direction, subject, body, media_url, media_content_type, media_filename, status,
        conversation_id, message_type, template_id, metadata, scheduled_at, created_at
      ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, NOW())`,
      [
        MORTGAGE_TENANT_ID,
        application_id || null,
        lead_id || null,
        brokerId,
        effectiveClientId,
        communication_type,
        "outbound",
        processedSubject || null,
        processedBody,
        media_url || null,
        media_url
          ? media_content_type ||
            (media_url.match(/\.(mp4|mov|avi)$/i)
              ? "video/mp4"
              : media_url.match(/\.(mp3|ogg|wav)$/i)
                ? "audio/mpeg"
                : media_url.match(/\.pdf$/i)
                  ? "application/pdf"
                  : "image/jpeg")
          : null,
        media_filename || null,
        scheduled_at ? "pending" : "pending",
        finalConversationId,
        message_type,
        template_id || null,
        mailbox_id
          ? JSON.stringify({
              mailbox_id,
              provider: "office365",
              to_recipients: finalRecipientEmail
                ? [{ email: finalRecipientEmail }]
                : [],
              cc_recipients: Array.isArray(cc) ? cc : [],
            })
          : null,
        scheduled_at || null,
      ],
    )) as [ResultSetHeader, any];

    const communicationId = result.insertId;

    if (communication_type === "email") {
      await upsertEmailThread({
        tenantId: MORTGAGE_TENANT_ID,
        commId: communicationId,
        conversationId: finalConversationId,
        applicationId: application_id || null,
        leadId: lead_id || null,
        fromUserId: null,
        fromBrokerId: brokerId,
        toUserId: effectiveClientId,
        toBrokerId: null,
        direction: "outbound",
        body: processedBody,
        recipientEmail: finalRecipientEmail || null,
      });
    } else {
      await upsertConversationThread({
        tenantId: MORTGAGE_TENANT_ID,
        commId: communicationId,
        conversationId: finalConversationId,
        applicationId: application_id || null,
        leadId: lead_id || null,
        fromUserId: null,
        fromBrokerId: brokerId,
        toUserId: effectiveClientId,
        toBrokerId: recipientBrokerId || null,
        contactBrokerId: recipientBrokerId || null,
        communicationType: communication_type,
        direction: "outbound",
        body: processedBody,
        inboxNumber: fromNumber || null,
        recipientPhone: finalRecipientPhone || null,
      });
    }

    // New outbound conversation (caller did not supply an existing conversation_id):
    // The broker explicitly initiated a new conversation from the wizard, so the
    // thread must be 'active' regardless of its prior status. Without this, a
    // previously-closed thread stays closed and is invisible in the active view.
    if (!conversation_id) {
      await pool.query(
        `UPDATE conversation_threads
         SET status = 'active', updated_at = NOW()
         WHERE conversation_id = ? AND tenant_id = ?`,
        [finalConversationId, MORTGAGE_TENANT_ID],
      );
    }

    // Ownership-aware inbox_number refresh:
    //   - If broker has a personal number, ALWAYS overwrite the thread's
    //     inbox_number with it (Rule 1: absolute priority). This ensures
    //     transitions from shared→personal take effect immediately and the
    //     sidebar displays the current owner's line.
    //   - Otherwise, only stamp inbox_number if it was NULL (don't overwrite
    //     an existing shared-pool number).
    if (fromNumber) {
      if (brokerPersonalNumber && fromNumber === brokerPersonalNumber) {
        await pool.query(
          `UPDATE conversation_threads
           SET inbox_number = ?, updated_at = NOW()
           WHERE conversation_id = ? AND tenant_id = ?
             AND (inbox_number IS NULL OR inbox_number <> ?)`,
          [fromNumber, finalConversationId, MORTGAGE_TENANT_ID, fromNumber],
        );
      } else {
        await pool.query(
          `UPDATE conversation_threads
           SET inbox_number = ?, updated_at = NOW()
           WHERE conversation_id = ? AND tenant_id = ? AND inbox_number IS NULL`,
          [fromNumber, finalConversationId, MORTGAGE_TENANT_ID],
        );
      }
    }

    // Auto-claim: if this thread was previously unassigned (shared inbox),
    // assign it to the broker who just replied. This removes it from other
    // brokers' unassigned queues and makes it a personal thread.
    const [claimResult] = await pool.query<any>(
      `UPDATE conversation_threads
       SET broker_id = ?, updated_at = NOW()
       WHERE conversation_id = ? AND tenant_id = ? AND broker_id IS NULL`,
      [brokerId, finalConversationId, MORTGAGE_TENANT_ID],
    );
    // Only notify if an actual claim happened (affectedRows > 0)
    if (claimResult.affectedRows > 0) {
      await publishToAbly("conversations:all", "thread-claimed", {
        conversationId: finalConversationId,
        claimedByBrokerId: brokerId,
      });
    }

    // Send the actual message
    let sendResult: any = { success: false, error: "Unknown error" };

    if (scheduled_at) {
      // For scheduled messages, just mark as pending
      sendResult = { success: true };
    } else {
      // Send immediately
      switch (communication_type) {
        case "sms":
          if (finalRecipientPhone) {
            console.log(
              `[SMS Trace] Calling sendSMSMessage — to=${finalRecipientPhone} from=${fromNumber || "NONE"} body_len=${processedBody?.length ?? 0} media=${media_url ?? "none"}`,
            );
            sendResult = await sendSMSMessage(
              finalRecipientPhone,
              processedBody,
              undefined,
              fromNumber,
              media_url || undefined,
              {
                source: "conversation",
                refType: "conversation",
                refId: finalConversationId || undefined,
              },
            );
            console.log(
              `[SMS Trace] sendSMSMessage result — success=${sendResult.success} external_id=${sendResult.external_id ?? "none"} error=${sendResult.error ?? "none"}`,
            );
          } else {
            sendResult = { success: false, error: "No phone number available" };
            console.error(`[SMS Trace] SMS skipped — no finalRecipientPhone`);
          }
          break;

        case "whatsapp":
          if (finalRecipientPhone) {
            sendResult = await sendWhatsAppMessage(
              finalRecipientPhone,
              processedBody,
              undefined,
              {
                source: "conversation",
                refType: "conversation",
                refId: finalConversationId || undefined,
              },
            );
          } else {
            sendResult = { success: false, error: "No phone number available" };
          }
          break;

        case "email":
          if (finalRecipientEmail) {
            // Auto-detect HTML content so template-based emails render correctly
            const isHtmlEmail = /<[a-z][\s\S]*>/i.test(processedBody);

            // Build a dynamic fallback subject when none was provided.
            // Priority: 1) caller-supplied subject  2) "Re: <prior subject>" for replies
            //           3) "<Broker Name>, from <Company>" personalised greeting
            let emailSubject = processedSubject;
            if (!emailSubject) {
              // Check if there's a prior subject on this thread to use as "Re: …"
              if (finalConversationId) {
                const [priorSubjectRows] = await pool.query<RowDataPacket[]>(
                  `SELECT subject FROM communications
                   WHERE conversation_id = ? AND tenant_id = ? AND subject IS NOT NULL AND subject <> ''
                   ORDER BY created_at ASC LIMIT 1`,
                  [finalConversationId, MORTGAGE_TENANT_ID],
                );
                if (priorSubjectRows.length > 0) {
                  const prior = priorSubjectRows[0].subject as string;
                  emailSubject = prior.startsWith("Re:")
                    ? prior
                    : `Re: ${prior}`;
                }
              }

              // Still no subject — build personalised greeting from broker + tenant
              if (!emailSubject) {
                const [[brokerRow], [tenantRow]] = await Promise.all([
                  pool.query<RowDataPacket[]>(
                    `SELECT first_name, last_name FROM brokers WHERE id = ? AND tenant_id = ? LIMIT 1`,
                    [brokerId, MORTGAGE_TENANT_ID],
                  ),
                  pool.query<RowDataPacket[]>(
                    `SELECT company_name, name FROM tenants WHERE id = ? LIMIT 1`,
                    [MORTGAGE_TENANT_ID],
                  ),
                ]);
                const brokerFirst =
                  (brokerRow as RowDataPacket[])[0]?.first_name || "";
                const brokerLast =
                  (brokerRow as RowDataPacket[])[0]?.last_name || "";
                const company =
                  (tenantRow as RowDataPacket[])[0]?.company_name ||
                  (tenantRow as RowDataPacket[])[0]?.name ||
                  "Encore Mortgage";
                const brokerName =
                  `${brokerFirst} ${brokerLast}`.trim() || "Your Loan Officer";
                emailSubject = `${brokerName}, from ${company}`;
              }
            }

            const convoEmailQuota: QuotaWireContext = {
              source: "conversation",
              refType: "conversation",
              refId: finalConversationId || undefined,
            };
            const convoEmailCheck = await precheckEmailQuota(convoEmailQuota);
            if (!convoEmailCheck.allowed) {
              const denial = quotaDenialPayload(convoEmailCheck);
              sendResult = {
                success: false,
                error: denial.error,
                quota_exceeded: Boolean(convoEmailCheck.quotaExceeded),
                billing_action_required: Boolean(
                  convoEmailCheck.billingBlocked,
                ),
              };
              break;
            }

            if (mailbox_id) {
              sendResult = await sendEmailMessageViaOffice365({
                mailboxId: Number(mailbox_id),
                to: finalRecipientEmail,
                subject: emailSubject,
                body: processedBody,
                isHtml: isHtmlEmail,
                conversationId: finalConversationId,
                cc: Array.isArray(cc) ? cc : undefined,
                bcc: Array.isArray(bcc) ? bcc : undefined,
              });
            } else {
              sendResult = await sendEmailMessage(
                finalRecipientEmail,
                emailSubject,
                processedBody,
                isHtmlEmail,
                finalConversationId,
                {
                  billing: { ...convoEmailQuota, skipQuota: true },
                },
              );
            }
            if (sendResult.success) {
              await recordEmailQuota(convoEmailQuota);
            }
          } else {
            sendResult = {
              success: false,
              error: "No email address available",
            };
          }
          break;

        default:
          sendResult = { success: false, error: "Invalid communication type" };
      }
    }

    // Update communication record with sending results
    const updateFields: string[] = [];
    const updateValues: any[] = [];

    if (sendResult.success) {
      updateFields.push("status = ?", "delivery_status = ?", "sent_at = NOW()");
      updateValues.push("sent", "sent");

      if (sendResult.external_id) {
        updateFields.push("external_id = ?");
        updateValues.push(sendResult.external_id);
      }

      const outboundCost =
        sendResult.cost ??
        resolveOutboundCommunicationCostUsd({
          channel:
            communication_type === "whatsapp"
              ? "whatsapp"
              : communication_type === "sms" && media_url
                ? "mms"
                : communication_type === "sms"
                  ? "sms"
                  : "email",
          body: processedBody,
        });
      if (outboundCost > 0) {
        updateFields.push("cost = ?");
        updateValues.push(outboundCost);
      }

      if (sendResult.provider_response) {
        updateFields.push("provider_response = ?");
        updateValues.push(JSON.stringify(sendResult.provider_response));
      }
    } else {
      updateFields.push(
        "status = ?",
        "delivery_status = ?",
        "error_message = ?",
      );
      updateValues.push("failed", "failed", sendResult.error);

      if (sendResult.provider_response) {
        updateFields.push("provider_response = ?");
        updateValues.push(JSON.stringify(sendResult.provider_response));
      }
    }

    updateValues.push(communicationId);

    await pool.query(
      `UPDATE communications SET ${updateFields.join(", ")} WHERE id = ?`,
      updateValues,
    );

    console.log(
      `[SMS Trace] DB updated — comm_id=${communicationId} status=${sendResult.success ? "sent" : "failed"} conv=${finalConversationId}`,
    );

    // Create audit log entry
    await pool.query(
      `INSERT INTO audit_logs (
        tenant_id, broker_id, actor_type, action, entity_type, entity_id, 
        changes, status, created_at
      ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, NOW())`,
      [
        MORTGAGE_TENANT_ID,
        brokerId,
        "broker",
        `send_${communication_type}`,
        "communication",
        communicationId,
        JSON.stringify({
          recipient:
            communication_type === "email"
              ? finalRecipientEmail
              : finalRecipientPhone,
          template_used: template_id ? true : false,
          scheduled: scheduled_at ? true : false,
        }),
        sendResult.success ? "success" : "failure",
      ],
    );

    if (!sendResult.success) {
      const billingDenied =
        Boolean(
          (sendResult as { billing_action_required?: boolean })
            .billing_action_required,
        ) ||
        Boolean((sendResult as { quota_exceeded?: boolean }).quota_exceeded);
      const statusCode = billingDenied ? 402 : 400;
      console.error(
        `[SMS Trace] Send FAILED — returning ${statusCode} to client. type=${communication_type} error="${sendResult.error}" comm_id=${communicationId}`,
      );
      return res.status(statusCode).json({
        success: false,
        message: `Failed to send ${communication_type}: ${sendResult.error}`,
        error: sendResult.error,
        communication_id: communicationId,
        conversation_id: finalConversationId,
        quota_exceeded:
          (sendResult as { quota_exceeded?: boolean }).quota_exceeded ?? false,
        billing_action_required:
          (sendResult as { billing_action_required?: boolean })
            .billing_action_required ?? false,
      });
    }

    // Notify connected browsers in real-time so the thread list and message panel
    // update immediately without requiring a manual page refresh.
    try {
      await publishToAbly(
        `conversation:${finalConversationId}`,
        "new-message",
        {
          conversationId: finalConversationId,
          direction: "outbound",
          communicationType: communication_type,
          body: processedBody.slice(0, 200),
        },
      );
      // Fetch the freshly-updated thread row so other clients can patch their
      // sidebar in-place (no full refetch needed).
      const [refreshedThread] = await pool.query<RowDataPacket[]>(
        `SELECT ct.*, la.application_number,
                COALESCE(
                  ct.client_name,
                  CONCAT(cl.first_name, ' ', cl.last_name),
                  CONCAT(cb.first_name, ' ', cb.last_name),
                  CONCAT(pb.first_name, ' ', pb.last_name)
                ) AS client_name,
                CONCAT(cl.first_name, ' ', cl.last_name) AS client_full_name
         FROM conversation_threads ct
         LEFT JOIN loan_applications la ON ct.application_id = la.id
         LEFT JOIN clients cl ON ct.client_id = cl.id
         LEFT JOIN brokers cb ON ct.contact_broker_id = cb.id
         LEFT JOIN brokers pb ON pb.tenant_id = ct.tenant_id
           AND ct.client_name IS NULL AND ct.client_id IS NULL AND ct.contact_broker_id IS NULL
           AND ct.client_phone IS NOT NULL
           AND RIGHT(REGEXP_REPLACE(pb.phone, '[^0-9]', ''), 10)
               = RIGHT(REGEXP_REPLACE(ct.client_phone, '[^0-9]', ''), 10)
         WHERE ct.conversation_id = ? AND ct.tenant_id = ?
         LIMIT 1`,
        [finalConversationId, MORTGAGE_TENANT_ID],
      );
      await publishToAbly("conversations:all", "thread-updated", {
        conversationId: finalConversationId,
        thread: refreshedThread[0]
          ? {
              ...refreshedThread[0],
              tags: parseThreadTags(refreshedThread[0].tags),
            }
          : null,
      });
    } catch (ablyErr) {
      console.warn("Ably publish failed (non-fatal):", ablyErr);
    }

    res.json({
      success: true,
      message: "Message sent successfully",
      communication_id: communicationId,
      conversation_id: finalConversationId,
      external_id: sendResult.external_id,
      cost: sendResult.cost,
    });
  } catch (error) {
    console.error("Error sending message:", error);
    res.status(500).json({
      success: false,
      message: "Failed to send message",
    });
  }
};

/**
 * POST /api/conversations/:conversationId/save-contact
 * Save an unknown caller/SMS sender as a client and link them to the thread.
 * Body: { first_name, last_name, email? }
 */
const handleSaveContactFromConversation: RequestHandler = async (req, res) => {
  try {
    const brokerId = (req as any).brokerId;
    const { conversationId } = req.params;
    const {
      first_name,
      last_name,
      email,
      phone,
      alternate_phone,
      date_of_birth,
      address_street,
      address_city,
      address_state,
      address_zip,
      employment_status,
      income_type,
      annual_income,
      credit_score,
      citizenship_status,
      create_pipeline_draft,
      loan_type,
      notes,
    } = req.body as {
      first_name?: string;
      last_name?: string;
      email?: string;
      phone?: string;
      alternate_phone?: string;
      date_of_birth?: string;
      address_street?: string;
      address_city?: string;
      address_state?: string;
      address_zip?: string;
      employment_status?: string;
      income_type?: "W-2" | "1099" | "Self-Employed" | "Investor" | "Mixed";
      annual_income?: number;
      credit_score?: number;
      citizenship_status?:
        | "us_citizen"
        | "permanent_resident"
        | "non_resident"
        | "other";
      create_pipeline_draft?: boolean;
      loan_type?: "purchase" | "refinance";
      notes?: string;
    };

    if (!first_name?.trim() || !last_name?.trim()) {
      return res.status(400).json({
        success: false,
        error: "first_name and last_name are required",
      });
    }

    if (create_pipeline_draft && !loan_type) {
      return res.status(400).json({
        success: false,
        error: "loan_type is required when create_pipeline_draft is true",
      });
    }

    const VALID_INCOME_TYPES = [
      "W-2",
      "1099",
      "Self-Employed",
      "Investor",
      "Mixed",
    ];
    const VALID_CITIZENSHIP = [
      "us_citizen",
      "permanent_resident",
      "non_resident",
      "other",
    ];
    if (income_type && !VALID_INCOME_TYPES.includes(income_type)) {
      return res
        .status(400)
        .json({ success: false, error: "Invalid income_type" });
    }
    if (citizenship_status && !VALID_CITIZENSHIP.includes(citizenship_status)) {
      return res
        .status(400)
        .json({ success: false, error: "Invalid citizenship_status" });
    }

    // Load thread
    const [[thread]] = await pool.query<RowDataPacket[]>(
      `SELECT id, client_phone, client_email, client_id
       FROM conversation_threads
       WHERE conversation_id = ? AND tenant_id = ? LIMIT 1`,
      [conversationId, MORTGAGE_TENANT_ID],
    );
    if (!thread) {
      return res
        .status(404)
        .json({ success: false, error: "Thread not found" });
    }
    if (thread.client_id) {
      return res
        .status(409)
        .json({ success: false, error: "Thread already has a linked client" });
    }

    // Resolve email — required in DB, so use a placeholder when omitted
    const providedEmail = email?.trim().toLowerCase() || null;
    const placeholderEmail = `noemail_${(thread.client_phone || String(Date.now())).replace(/\D/g, "")}@noemail.placeholder`;
    const clientEmail = providedEmail ?? placeholderEmail;

    // Guard against duplicate email (only for real emails)
    if (providedEmail) {
      const [[dup]] = await pool.query<RowDataPacket[]>(
        "SELECT id FROM clients WHERE tenant_id = ? AND email = ? LIMIT 1",
        [MORTGAGE_TENANT_ID, clientEmail],
      );
      if (dup) {
        return res.status(409).json({
          success: false,
          error: "A client with this email already exists",
        });
      }
    }

    // Resolve phone — prefer explicitly provided, fall back to thread phone
    const clientPhone = phone?.trim() || thread.client_phone || null;

    // Create client with all provided fields
    const [result] = await pool.query<any>(
      `INSERT INTO clients (
         tenant_id, first_name, last_name, email, phone, alternate_phone,
         date_of_birth, address_street, address_city, address_state, address_zip,
         employment_status, income_type, annual_income, credit_score,
         citizenship_status, status, assigned_broker_id
       ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'active', ?)`,
      [
        MORTGAGE_TENANT_ID,
        first_name.trim(),
        last_name.trim(),
        clientEmail,
        clientPhone,
        alternate_phone?.trim() || null,
        date_of_birth || null,
        address_street?.trim() || null,
        address_city?.trim() || null,
        address_state?.trim().toUpperCase() || null,
        address_zip?.trim() || null,
        employment_status || null,
        income_type || "W-2",
        annual_income != null ? Number(annual_income) : null,
        credit_score != null ? Number(credit_score) : null,
        citizenship_status || null,
        brokerId,
      ],
    );
    const newClientId: number = result.insertId;
    const fullName = `${first_name.trim()} ${last_name.trim()}`;
    const canonicalConvId = `conv_client_${newClientId}`;

    // Rename the random conversation_id to the canonical one so future
    // outbound messages to this client reuse the same thread. We only do
    // this when the original ID was a random auto-generated one (not already
    // canonical). Communications rows must be updated first due to FK.
    const isRandomId = !conversationId.startsWith("conv_client_");
    if (isRandomId) {
      await pool.query(
        `UPDATE communications SET conversation_id = ? WHERE conversation_id = ? AND tenant_id = ?`,
        [canonicalConvId, conversationId, MORTGAGE_TENANT_ID],
      );
    }

    // Link thread to new client (and rename if needed)
    await pool.query(
      `UPDATE conversation_threads
       SET client_id = ?, client_name = ?, client_email = COALESCE(NULLIF(client_email, ''), ?),
           conversation_id = ?
       WHERE conversation_id = ? AND tenant_id = ?`,
      [
        newClientId,
        fullName,
        providedEmail,
        isRandomId ? canonicalConvId : conversationId,
        conversationId,
        MORTGAGE_TENANT_ID,
      ],
    );

    // Link inbound communications to new client
    await pool.query(
      `UPDATE communications
       SET from_user_id = ?
       WHERE conversation_id = ? AND direction = 'inbound' AND tenant_id = ?`,
      [newClientId, conversationId, MORTGAGE_TENANT_ID],
    );

    // Optionally create a draft loan application as a pipeline action item
    let draftApplicationId: number | null = null;
    let draftApplicationNumber: string | null = null;
    if (create_pipeline_draft && loan_type) {
      const appNumber = `LA${Date.now().toString().slice(-8)}`;
      const [loanResult] = await pool.query<any>(
        `INSERT INTO loan_applications (
          tenant_id, application_number, client_user_id, broker_user_id,
          loan_type, loan_amount, property_value,
          status, current_step, total_steps, notes, submitted_at
        ) VALUES (?, ?, ?, ?, ?, 0, 0, 'draft', 1, 8, ?, NOW())`,
        [
          MORTGAGE_TENANT_ID,
          appNumber,
          newClientId,
          brokerId,
          loan_type,
          notes?.trim() || null,
        ],
      );
      draftApplicationId = loanResult.insertId;
      draftApplicationNumber = appNumber;
    }

    return res.json({
      success: true,
      client_id: newClientId,
      client_name: fullName,
      client_email: providedEmail,
      // Return the final conversation_id so Redux can update the thread key
      conversation_id: isRandomId ? canonicalConvId : conversationId,
      original_conversation_id: conversationId,
      ...(draftApplicationId
        ? {
            pipeline_draft: {
              application_id: draftApplicationId,
              application_number: draftApplicationNumber,
            },
          }
        : {}),
    });
  } catch (error) {
    console.error("[handleSaveContactFromConversation] Error:", error);
    return res
      .status(500)
      .json({ success: false, error: "Failed to save contact" });
  }
};

/**
 * PUT /api/conversations/:conversationId
 * Update conversation thread (status, priority, tags)
 */
const handleUpdateConversation: RequestHandler = async (req, res) => {
  try {
    const { conversationId } = req.params;
    const { status, priority, tags } = req.body;
    const brokerId = (req as any).brokerId;

    // Verify broker has access to this conversation using the same 3-path
    // ownership model as GET /threads. Superadmins can update any thread.
    const brokerRole = (req as any).brokerRole;
    const isSuperAdmin = brokerRole === "superadmin";
    const isAdmin = brokerRole === "admin";
    let threadCheckSql: string;
    let threadCheckParams: any[];
    if (isSuperAdmin) {
      threadCheckSql = `SELECT id FROM conversation_threads
       WHERE conversation_id = ? AND tenant_id = ?`;
      threadCheckParams = [conversationId, MORTGAGE_TENANT_ID];
    } else {
      const groupVis = getGroupConversationsModule().enabled
        ? getGroupConversationsModule().groupVisibilitySql()
        : "";
      threadCheckSql = `SELECT id FROM conversation_threads ct
       WHERE ct.conversation_id = ? AND ct.tenant_id = ?
         AND (
           ct.broker_id = ?
           OR (ct.client_id IS NULL AND ct.broker_id IS NULL)
           ${
             isAdmin
               ? `OR (ct.client_id IS NULL AND ct.broker_id IS NOT NULL
               AND NOT EXISTS (
                 SELECT 1 FROM brokers ib
                 WHERE ib.id = ct.broker_id
                   AND ib.tenant_id = ct.tenant_id
                   AND ib.status = 'active'
               ))`
               : ""
           }
           OR EXISTS (
             SELECT 1 FROM clients cl
             WHERE cl.id = ct.client_id
               AND cl.tenant_id = ct.tenant_id
               AND (
                 cl.assigned_broker_id = ?
                 OR EXISTS (
                   SELECT 1 FROM loan_applications la
                   WHERE la.client_user_id = ct.client_id
                     AND la.tenant_id = ct.tenant_id
                     AND (la.broker_user_id = ? OR la.partner_broker_id = ?)
                 )
               )
           )
           ${groupVis}
         )`;
      threadCheckParams = [
        conversationId,
        MORTGAGE_TENANT_ID,
        brokerId,
        brokerId,
        brokerId,
        brokerId,
      ];
      if (getGroupConversationsModule().enabled) {
        threadCheckParams.push(brokerId, brokerId, brokerId, brokerId);
      }
    }
    const [threadCheck] = await pool.query<RowDataPacket[]>(
      threadCheckSql,
      threadCheckParams,
    );

    if (threadCheck.length === 0) {
      return res.status(404).json({
        success: false,
        message: "Conversation not found or access denied",
      });
    }

    const updateFields: string[] = [];
    const updateValues: any[] = [];

    if (status && ["active", "closed"].includes(status)) {
      updateFields.push("status = ?");
      updateValues.push(status);
      // Clear archived_at when reopening; set it when closing
      if (status === "closed") {
        updateFields.push("archived_at = NOW()");
      } else {
        updateFields.push("archived_at = NULL");
      }
    }

    if (priority && ["low", "normal", "high", "urgent"].includes(priority)) {
      updateFields.push("priority = ?");
      updateValues.push(priority);
    }

    if (tags !== undefined) {
      updateFields.push("tags = ?");
      updateValues.push(JSON.stringify(tags));
    }

    if (updateFields.length === 0) {
      return res.status(400).json({
        success: false,
        message: "No valid fields to update",
      });
    }

    updateFields.push("updated_at = NOW()");
    updateValues.push(conversationId);
    updateValues.push(MORTGAGE_TENANT_ID);

    await pool.query(
      `UPDATE conversation_threads SET ${updateFields.join(", ")} 
       WHERE conversation_id = ? AND tenant_id = ?`,
      updateValues,
    );

    // Insert a system_event communication to record the status change in the
    // conversation history (visible as a timeline separator in the chat view).
    if (status === "closed" || status === "active") {
      await pool.query(
        `INSERT INTO communications
           (tenant_id, conversation_id, communication_type, direction, body,
            status, delivery_status, from_broker_id, created_at)
         VALUES (?, ?, 'system_event', 'outbound', ?, 'sent', 'sent', ?, NOW())`,
        [
          MORTGAGE_TENANT_ID,
          conversationId,
          status === "closed" ? "closed" : "reopened",
          brokerId ?? null,
        ],
      );
    }

    // Get updated thread
    const [updatedThread] = await pool.query<RowDataPacket[]>(
      `SELECT ct.*,
              la.application_number,
              COALESCE(
                ct.client_name,
                CONCAT(cl.first_name, ' ', cl.last_name),
                CONCAT(cb.first_name, ' ', cb.last_name),
                CONCAT(pb.first_name, ' ', pb.last_name)
              ) AS client_name,
              CONCAT(cl.first_name, ' ', cl.last_name) AS client_full_name
       FROM conversation_threads ct
       LEFT JOIN loan_applications la ON ct.application_id = la.id
       LEFT JOIN clients cl ON ct.client_id = cl.id
       LEFT JOIN brokers cb ON ct.contact_broker_id = cb.id
       LEFT JOIN brokers pb ON pb.tenant_id = ct.tenant_id
         AND ct.client_name IS NULL AND ct.client_id IS NULL AND ct.contact_broker_id IS NULL
         AND ct.client_phone IS NOT NULL
         AND RIGHT(REGEXP_REPLACE(pb.phone, '[^0-9]', ''), 10)
             = RIGHT(REGEXP_REPLACE(ct.client_phone, '[^0-9]', ''), 10)
       WHERE ct.conversation_id = ? AND ct.tenant_id = ?`,
      [conversationId, MORTGAGE_TENANT_ID],
    );

    const updatedThreadPayload = updatedThread[0]
      ? {
          ...updatedThread[0],
          tags: parseThreadTags(updatedThread[0].tags),
        }
      : null;

    // Broadcast the update to all listening clients (other tabs / other brokers)
    // so close/reopen/priority/tag changes appear instantly without a refetch.
    if (updatedThreadPayload) {
      try {
        await publishToAbly("conversations:all", "thread-updated", {
          conversationId,
          thread: updatedThreadPayload,
        });
      } catch (publishErr) {
        console.warn("⚠️ Ably publish (thread-updated) failed:", publishErr);
      }
    }

    res.json({
      success: true,
      thread: updatedThreadPayload ?? { conversation_id: conversationId },
    });
  } catch (error) {
    console.error("Error updating conversation:", error);
    res.status(500).json({
      success: false,
      message: "Failed to update conversation",
    });
  }
};

/**
 * DELETE /api/conversations/:conversationId
 * Permanently delete a conversation thread and all its messages.
 */
const handleDeleteConversation: RequestHandler = async (req, res) => {
  try {
    const { conversationId } = req.params;
    const brokerId = (req as any).brokerId;

    // Verify broker has access — admins can delete any thread; brokers can delete own or unassigned
    const brokerRole = (req as any).brokerRole;
    const isAdminRole =
      brokerRole === "admin" ||
      brokerRole === "superadmin" ||
      brokerRole === "platform_owner";
    const [threadCheck] = await pool.query<RowDataPacket[]>(
      `SELECT id FROM conversation_threads
       WHERE conversation_id = ? AND tenant_id = ?
         AND (broker_id = ? OR broker_id IS NULL OR ?)`,
      [conversationId, MORTGAGE_TENANT_ID, brokerId, isAdminRole],
    );

    if (threadCheck.length === 0) {
      return res.status(404).json({
        success: false,
        message: "Conversation not found or access denied",
      });
    }

    // Delete messages first (FK constraint)
    await pool.query(
      `DELETE FROM communications WHERE conversation_id = ? AND tenant_id = ?`,
      [conversationId, MORTGAGE_TENANT_ID],
    );

    // Delete thread
    await pool.query(
      `DELETE FROM conversation_threads WHERE conversation_id = ? AND tenant_id = ?`,
      [conversationId, MORTGAGE_TENANT_ID],
    );

    // Notify other connected clients
    await publishToAbly("conversations:all", "thread-deleted", {
      conversationId,
    }).catch(() => {});

    res.json({ success: true, conversation_id: conversationId });
  } catch (error) {
    console.error("Error deleting conversation:", error);
    res.status(500).json({
      success: false,
      message: "Failed to delete conversation",
    });
  }
};

/**
 * GET /api/conversations/templates
 * Get communication templates for sending messages
 */
const handleGetConversationTemplates: RequestHandler = async (req, res) => {
  try {
    const { type } = req.query;

    let whereCondition = "WHERE tenant_id = ? AND is_active = 1";
    const queryParams: any[] = [MORTGAGE_TENANT_ID];

    if (type && ["email", "sms", "whatsapp"].includes(type as string)) {
      whereCondition += " AND template_type = ?";
      queryParams.push(type);
    }

    const [templates] = await pool.query<RowDataPacket[]>(
      `SELECT 
        id,
        name,
        description,
        template_type,
        category,
        subject,
        body,
        variables,
        usage_count,
        created_at,
        updated_at
      FROM templates
      ${whereCondition}
      ORDER BY usage_count DESC, category, name`,
      queryParams,
    );

    res.json({
      success: true,
      templates: templates.map((template) => {
        let variables = [];
        if (template.variables) {
          try {
            const parsed = JSON.parse(template.variables);
            variables = Array.isArray(parsed) ? parsed : [];
          } catch {
            // Handle legacy comma-separated strings
            variables = String(template.variables)
              .split(",")
              .map((v: string) => v.trim())
              .filter(Boolean);
          }
        }
        return {
          ...template,
          variables,
        };
      }),
    });
  } catch (error) {
    console.error("Error fetching conversation templates:", error);
    res.status(500).json({
      success: false,
      message: "Failed to fetch conversation templates",
    });
  }
};

/**
 * GET /api/conversations/stats
 * Get conversation statistics for dashboard
 */
const handleGetConversationStats: RequestHandler = async (req, res) => {
  try {
    const brokerId = (req as any).brokerId;

    // Total conversations
    const [totalResult] = await pool.query<RowDataPacket[]>(
      `SELECT COUNT(*) as total FROM conversation_threads 
       WHERE broker_id = ? AND tenant_id = ?`,
      [brokerId, MORTGAGE_TENANT_ID],
    );

    // Active conversations
    const [activeResult] = await pool.query<RowDataPacket[]>(
      `SELECT COUNT(*) as active FROM conversation_threads 
       WHERE broker_id = ? AND tenant_id = ? AND status = 'active'`,
      [brokerId, MORTGAGE_TENANT_ID],
    );

    // Unread messages
    const [unreadResult] = await pool.query<RowDataPacket[]>(
      `SELECT COALESCE(SUM(unread_count), 0) as unread 
       FROM conversation_threads 
       WHERE broker_id = ? AND tenant_id = ?`,
      [brokerId, MORTGAGE_TENANT_ID],
    );

    // Today's messages
    const [todayResult] = await pool.query<RowDataPacket[]>(
      `SELECT COUNT(*) as today_messages 
       FROM communications 
       WHERE from_broker_id = ? AND tenant_id = ? 
         AND DATE(created_at) = CURDATE()`,
      [brokerId, MORTGAGE_TENANT_ID],
    );

    // Channel breakdown
    const [channelResult] = await pool.query<RowDataPacket[]>(
      `SELECT 
        communication_type,
        COUNT(*) as count
      FROM communications c
      LEFT JOIN conversation_threads ct
        ON c.conversation_id = ct.conversation_id
       AND ct.tenant_id = c.tenant_id
      WHERE c.tenant_id = ?
        AND (ct.broker_id = ? OR c.from_broker_id = ?)
        AND c.created_at >= DATE_SUB(NOW(), INTERVAL 30 DAY)
      GROUP BY communication_type`,
      [MORTGAGE_TENANT_ID, brokerId, brokerId],
    );

    // Priority breakdown
    const [priorityResult] = await pool.query<RowDataPacket[]>(
      `SELECT 
        priority,
        COUNT(*) as count
      FROM conversation_threads 
      WHERE broker_id = ? AND tenant_id = ?
      GROUP BY priority`,
      [brokerId, MORTGAGE_TENANT_ID],
    );

    // Calculate average response time (mock for now)
    const avgResponseTime = 45; // 45 minutes average

    const stats = {
      total_conversations: totalResult[0]?.total || 0,
      active_conversations: activeResult[0]?.active || 0,
      unread_messages: unreadResult[0]?.unread || 0,
      today_messages: todayResult[0]?.today_messages || 0,
      response_time_avg: avgResponseTime,
      channels: {
        email: 0,
        sms: 0,
        whatsapp: 0,
      },
      by_priority: {
        low: 0,
        normal: 0,
        high: 0,
        urgent: 0,
      },
    };

    // Fill channel data
    channelResult.forEach((row) => {
      if (row.communication_type in stats.channels) {
        (stats.channels as any)[row.communication_type] = row.count;
      }
    });

    // Fill priority data
    priorityResult.forEach((row) => {
      if (row.priority in stats.by_priority) {
        (stats.by_priority as any)[row.priority] = row.count;
      }
    });

    res.json({
      success: true,
      stats,
    });
  } catch (error) {
    console.error("Error fetching conversation stats:", error);
    res.status(500).json({
      success: false,
      message: "Failed to fetch conversation statistics",
    });
  }
};

/**
 * GET /api/conversations/check-whatsapp?phone=+12345678900
 * Check if a phone number is registered on WhatsApp via Twilio Lookup v2.
 * Returns { registered: boolean } — cached in memory for 24 h to minimise Lookup costs.
 */
const whatsappCheckCache = new Map<
  string,
  { registered: boolean; ts: number }
>();
const WHATSAPP_CACHE_TTL_MS = 24 * 60 * 60 * 1000; // 24 hours

const handleCheckWhatsApp: RequestHandler = async (req, res) => {
  const { phone } = req.query as { phone?: string };
  if (!phone) {
    return res
      .status(400)
      .json({ success: false, message: "phone is required" });
  }

  const normalised = phone.trim().replace(/\s+/g, "");

  // Return from cache if fresh
  const cached = whatsappCheckCache.get(normalised);
  if (cached && Date.now() - cached.ts < WHATSAPP_CACHE_TTL_MS) {
    return res.json({
      success: true,
      registered: cached.registered,
      cached: true,
    });
  }

  if (!twilioClient) {
    // Twilio not configured – default to false
    return res.json({
      success: true,
      registered: false,
      reason: "twilio_not_configured",
    });
  }

  try {
    const lookup = await twilioClient.lookups.v2
      .phoneNumbers(normalised)
      .fetch({ fields: "whatsapp" });

    const registered: boolean = lookup?.whatsapp?.registered ?? false;
    whatsappCheckCache.set(normalised, { registered, ts: Date.now() });
    return res.json({ success: true, registered });
  } catch (err: any) {
    console.error("WhatsApp Lookup error:", err?.message ?? err);
    // On lookup failure fall back to optimistic true so UI doesn't block
    return res.json({
      success: true,
      registered: true,
      reason: "lookup_failed",
    });
  }
};

// ─────────────────────────────────────────────────────────────────────────────
// VOICE / CALLING  (Twilio Voice SDK + REST)
// ─────────────────────────────────────────────────────────────────────────────

/** Cache the TwiML App SID so we only look it up / create it once per process */
let cachedTwimlAppSid: string | null = process.env.TWILIO_TWIML_APP_SID || null;
/** Whether we've already verified the TwiML App's voiceUrl this process lifetime */
let twimlAppVerified = false;

function getVoiceBaseUrl(): string {
  return (
    process.env.APP_URL ||
    process.env.TWILIO_SMS_WEBHOOK_URL?.replace(
      /\/api\/webhooks\/inbound-sms$/,
      "",
    ) ||
    "https://portal.encoremortgage.org"
  );
}

/**
 * Express middleware that validates the Twilio request signature for voice
 * webhook endpoints. Only active when BOTH TWILIO_AUTH_TOKEN and APP_URL are
 * set (i.e. production). Local dev / ngrok environments skip validation to
 * avoid URL-mismatch false positives.
 */
const twilioWebhookGuard: RequestHandler = (req, res, next) => {
  const twilioAuthToken = process.env.TWILIO_AUTH_TOKEN;
  const baseUrl = process.env.APP_URL; // only validate when canonical URL is known
  if (!twilioAuthToken || !baseUrl) return next();

  const twilioSignature = (req.headers["x-twilio-signature"] as string) ?? "";
  const webhookUrl = `${baseUrl}${req.originalUrl}`;
  const isValid = twilio.validateRequest(
    twilioAuthToken,
    twilioSignature,
    webhookUrl,
    req.body as Record<string, string>,
  );
  if (!isValid) {
    console.warn(
      `⚠️  Twilio webhook rejected — invalid signature: ${req.path}`,
    );
    res.set("Content-Type", "text/xml");
    return res.status(403).send("<Response></Response>");
  }
  return next();
};

async function getOrCreateTwimlAppSid(): Promise<string | null> {
  if (!twilioClient) return null;

  const voiceUrl = `${getVoiceBaseUrl()}/api/voice/twiml`;

  // If we have a SID from env and haven't verified this process run yet, verify now
  if (cachedTwimlAppSid && !twimlAppVerified) {
    try {
      const app = await twilioClient.applications(cachedTwimlAppSid).fetch();
      if (app.voiceUrl !== voiceUrl) {
        await twilioClient.applications(cachedTwimlAppSid).update({
          voiceUrl,
          voiceMethod: "POST",
        });
        console.log(
          `✅ Fixed TwiML App ${cachedTwimlAppSid} voiceUrl → ${voiceUrl}`,
        );
      }
      twimlAppVerified = true;
      return cachedTwimlAppSid;
    } catch (err) {
      console.warn(
        `⚠️ Env TWILIO_TWIML_APP_SID ${cachedTwimlAppSid} fetch failed — will search/create`,
        err,
      );
      // Fall through to search/create below
      cachedTwimlAppSid = null;
    }
  }

  if (cachedTwimlAppSid) return cachedTwimlAppSid;

  const appName = "Mortgage Portal Voice App";

  try {
    const apps = await twilioClient.applications.list({
      friendlyName: appName,
      limit: 1,
    });
    if (apps.length > 0) {
      const existing = apps[0];
      // Always ensure the voiceUrl is correct — update if stale
      if (existing.voiceUrl !== voiceUrl) {
        await twilioClient.applications(existing.sid).update({
          voiceUrl,
          voiceMethod: "POST",
        });
        console.log(
          `✅ Updated TwiML App ${existing.sid} voiceUrl → ${voiceUrl}`,
        );
      }
      cachedTwimlAppSid = existing.sid;
      twimlAppVerified = true;
      return cachedTwimlAppSid;
    }
    const app = await twilioClient.applications.create({
      friendlyName: appName,
      voiceUrl,
      voiceMethod: "POST",
    });
    cachedTwimlAppSid = app.sid;
    twimlAppVerified = true;
    console.log(`✅ Created TwiML App ${cachedTwimlAppSid} → ${voiceUrl}`);
    return cachedTwimlAppSid;
  } catch (err) {
    console.error("Failed to get/create TwiML App:", err);
    return null;
  }
}

/**
 * POST /api/voice/token
 * Returns a short-lived Twilio Access Token that enables the browser Voice SDK.
 */
const handleVoiceToken: RequestHandler = async (req, res) => {
  try {
    if (!twilioClient) {
      return res
        .status(503)
        .json({ success: false, error: "Twilio not configured" });
    }
    const brokerId = (req as any).brokerId;

    const voicePrecheck = await quotaService.precheck(MORTGAGE_TENANT_ID, {
      dimension: "voice_minutes",
      units: Math.ceil(VOICE_MIN_PER_CALL_EST),
      source: "conversation",
      refType: "voice_token",
      refId: String(brokerId),
    });
    if (!voicePrecheck.allowed) {
      return res.status(402).json(quotaDenialPayload(voicePrecheck));
    }

    const twimlAppSid = await getOrCreateTwimlAppSid();
    if (!twimlAppSid) {
      return res
        .status(503)
        .json({ success: false, error: "TwiML App unavailable" });
    }

    const AccessToken = twilio.jwt.AccessToken;
    const VoiceGrant = AccessToken.VoiceGrant;

    const apiKey =
      process.env.TWILIO_API_KEY || process.env.TWILIO_ACCOUNT_SID!;
    const apiSecret =
      process.env.TWILIO_API_SECRET || process.env.TWILIO_AUTH_TOKEN!;

    const token = new AccessToken(
      process.env.TWILIO_ACCOUNT_SID!,
      apiKey,
      apiSecret,
      { identity: `broker_${brokerId}`, ttl: 3600 },
    );

    const voiceGrant = new VoiceGrant({
      outgoingApplicationSid: twimlAppSid,
      incomingAllow: true,
    });
    token.addGrant(voiceGrant);

    return res.json({ success: true, token: token.toJwt() });
  } catch (error) {
    console.error("Error generating voice token:", error);
    return res
      .status(500)
      .json({ success: false, error: "Failed to generate voice token" });
  }
};

/**
 * POST /api/voice/twiml
 * TwiML webhook called by Twilio when the browser SDK places a call.
 * No broker-session auth — this URL is called by Twilio servers.
 * Uses the broker's assigned twilio_caller_id when available, falls back to
 * the global TWILIO_PHONE_NUMBER env var.
 */
const handleVoiceTwiml: RequestHandler = async (req, res) => {
  const To = (req.body?.To || req.query?.To) as string | undefined;
  // When the browser SDK places a call, Twilio sends the caller identity as
  // From: "client:broker_270004". req.body?.Called is the destination phone
  // number — not the identity — so we must read From and strip "client:".
  const fromParam = (req.body?.From ||
    req.body?.Caller ||
    req.body?.Identity ||
    "") as string;
  const identity = fromParam.replace(/^client:/, "");

  res.setHeader("Content-Type", "text/xml");

  if (!To) {
    return res.send(
      "<Response><Say>Missing destination number.</Say></Response>",
    );
  }

  // Resolve caller ID:
  //  1. Broker's own personal line (twilio_caller_id in brokers table)
  //  2. First shared "All Mortgage Bankers" number (not assigned to any broker)
  //  3. TWILIO_PHONE_NUMBER env var as last resort
  // NEVER fall back to another broker's personal line — that causes the
  // recipient to see the wrong number and that broker to get missed-call alerts.
  let callerId = "";
  try {
    const brokerIdMatch = identity.match(/broker_(\d+)/);
    if (brokerIdMatch) {
      const [rows] = await pool.query<any>(
        `SELECT twilio_caller_id FROM brokers WHERE id = ? AND tenant_id = ? AND twilio_caller_id IS NOT NULL`,
        [parseInt(brokerIdMatch[1], 10), MORTGAGE_TENANT_ID],
      );
      if (rows.length > 0 && rows[0].twilio_caller_id) {
        callerId = rows[0].twilio_caller_id;
      }
    }
    // Broker has no personal line — use a shared (All Mortgage Bankers) number
    if (!callerId) {
      callerId =
        (await getSharedVoiceNumber()) ?? process.env.TWILIO_PHONE_NUMBER ?? "";
    }
  } catch {
    // Non-critical — callerId stays empty, Twilio will use account default
  }

  const VoiceResponse = twilio.twiml.VoiceResponse;
  const twiml = new VoiceResponse();
  const dial = twiml.dial({
    callerId,
    timeout: 30,
    record: "record-from-answer-dual",
    recordingStatusCallback: `${getVoiceBaseUrl()}/api/voice/recording-status`,
    recordingStatusCallbackMethod: "POST",
    // answerOnBridge: true keeps the ringing audio flowing until the callee answers,
    // preventing a silent gap and ensuring early media (ringback) works correctly.
    answerOnBridge: true,
    // trim-silence strips the leading/trailing silence Twilio injects at connection
    // time — this is what recipients hear as a "weird noise" at call start.
    trim: "trim-silence",
  } as any);
  // Using <Number> with statusCallback lets Twilio send us call-status events.
  // No codec attribute here — codec negotiation is handled by the SDK (Opus preferred).
  dial.number({}, To);

  return res.send(twiml.toString());
};

/**
 * POST /api/voice/availability
 * Called by the CRM frontend when the broker toggles Available / Unavailable.
 * Updates voice_available in the DB so inbound routing knows who is online.
 */
const handleVoiceAvailability: RequestHandler = async (req, res) => {
  try {
    const brokerId = (req as any).brokerId as number;
    const { available } = req.body as { available: boolean };
    if (typeof available !== "boolean") {
      return res
        .status(400)
        .json({ success: false, error: "available must be a boolean" });
    }
    await pool.query(
      `UPDATE brokers SET voice_available = ? WHERE id = ? AND tenant_id = ?`,
      [available ? 1 : 0, brokerId, MORTGAGE_TENANT_ID],
    );
    return res.json({ success: true, available });
  } catch (err) {
    console.error("[handleVoiceAvailability] Error:", err);
    return res
      .status(500)
      .json({ success: false, error: "Failed to update availability" });
  }
};

/**
 * GET /api/voice/call-forwarding
 * Returns the authenticated broker's call forwarding settings.
 */
const handleGetCallForwarding: RequestHandler = async (req, res) => {
  try {
    const brokerId = (req as any).brokerId;
    const [rows] = await pool.query<RowDataPacket[]>(
      `SELECT call_forwarding_enabled, call_forwarding_phone, phone
       FROM brokers WHERE id = ? AND tenant_id = ?`,
      [brokerId, MORTGAGE_TENANT_ID],
    );
    if (rows.length === 0) {
      return res
        .status(404)
        .json({ success: false, error: "Broker not found" });
    }
    return res.json({
      success: true,
      call_forwarding_enabled: !!rows[0].call_forwarding_enabled,
      call_forwarding_phone:
        rows[0].call_forwarding_phone ?? rows[0].phone ?? null,
    });
  } catch (err) {
    console.error("[handleGetCallForwarding] Error:", err);
    return res.status(500).json({
      success: false,
      error: "Failed to get call forwarding settings",
    });
  }
};

/**
 * PUT /api/voice/call-forwarding
 * Updates call forwarding settings for the authenticated broker.
 * Body: { enabled: boolean, phone?: string }
 */
const handleUpdateCallForwarding: RequestHandler = async (req, res) => {
  try {
    const brokerId = (req as any).brokerId;
    const { enabled, phone } = req.body as { enabled: boolean; phone?: string };

    if (typeof enabled !== "boolean") {
      return res
        .status(400)
        .json({ success: false, error: "enabled (boolean) is required" });
    }

    // Normalise phone to E.164 if provided
    let normalizedPhone: string | null = null;
    if (phone && phone.trim()) {
      const digits = phone.replace(/\D/g, "");
      if (digits.length === 10) normalizedPhone = `+1${digits}`;
      else if (digits.length === 11 && digits.startsWith("1"))
        normalizedPhone = `+${digits}`;
      else
        normalizedPhone = phone.trim().startsWith("+")
          ? phone.trim()
          : `+${digits}`;
    }

    await pool.query(
      `UPDATE brokers
       SET call_forwarding_enabled = ?, call_forwarding_phone = ?, updated_at = NOW()
       WHERE id = ? AND tenant_id = ?`,
      [enabled ? 1 : 0, normalizedPhone, brokerId, MORTGAGE_TENANT_ID],
    );

    return res.json({
      success: true,
      call_forwarding_enabled: enabled,
      call_forwarding_phone: normalizedPhone,
    });
  } catch (err) {
    console.error("[handleUpdateCallForwarding] Error:", err);
    return res.status(500).json({
      success: false,
      error: "Failed to update call forwarding settings",
    });
  }
};

/**
 * GET /api/voice/voicemail-settings
 * Returns the authenticated broker's voicemail overrides AND the resolved
 * tenant defaults. The frontend uses this to render the Voicemail Settings UI.
 */
const handleGetVoicemailSettings: RequestHandler = async (req, res) => {
  try {
    const brokerId = (req as any).brokerId as number;

    const [brokerRows] = await pool.query<RowDataPacket[]>(
      `SELECT voicemail_enabled, voicemail_greeting_text, voicemail_greeting_url,
              twilio_caller_id
       FROM brokers WHERE id = ? AND tenant_id = ?`,
      [brokerId, MORTGAGE_TENANT_ID],
    );
    if (brokerRows.length === 0) {
      return res
        .status(404)
        .json({ success: false, error: "Broker not found" });
    }

    const [tenantRows] = await pool.query<RowDataPacket[]>(
      `SELECT voicemail_enabled, voicemail_greeting_text, voicemail_greeting_url,
              voicemail_max_seconds, voicemail_transcribe
       FROM tenants WHERE id = ? LIMIT 1`,
      [MORTGAGE_TENANT_ID],
    );
    const tenant: any = tenantRows[0] || {};
    const broker: any = brokerRows[0];

    return res.json({
      success: true,
      broker: {
        // null on these fields means "inherit from tenant"
        voicemail_enabled:
          broker.voicemail_enabled === null ? null : !!broker.voicemail_enabled,
        voicemail_greeting_text: broker.voicemail_greeting_text ?? null,
        voicemail_greeting_url: broker.voicemail_greeting_url ?? null,
        has_personal_line: !!broker.twilio_caller_id,
      },
      tenant: {
        voicemail_enabled: !!(tenant.voicemail_enabled ?? 1),
        voicemail_greeting_text: tenant.voicemail_greeting_text ?? null,
        voicemail_greeting_url: tenant.voicemail_greeting_url ?? null,
        voicemail_max_seconds:
          parseInt(String(tenant.voicemail_max_seconds ?? 120), 10) || 120,
        voicemail_transcribe: !!(tenant.voicemail_transcribe ?? 1),
      },
    });
  } catch (err) {
    console.error("[handleGetVoicemailSettings] Error:", err);
    return res.status(500).json({
      success: false,
      error: "Failed to load voicemail settings",
    });
  }
};

/**
 * PUT /api/voice/voicemail-settings
 * Updates the authenticated broker's voicemail overrides.
 * Body: { enabled?: boolean | null, greeting_text?: string | null, greeting_url?: string | null }
 * Pass null on any field to clear the override and inherit from the tenant.
 */
const handleUpdateVoicemailSettings: RequestHandler = async (req, res) => {
  try {
    const brokerId = (req as any).brokerId as number;
    const { enabled, greeting_text, greeting_url } = req.body as {
      enabled?: boolean | null;
      greeting_text?: string | null;
      greeting_url?: string | null;
    };

    const enabledVal =
      enabled === undefined
        ? undefined
        : enabled === null
          ? null
          : enabled
            ? 1
            : 0;

    const fields: string[] = [];
    const values: any[] = [];

    if (enabledVal !== undefined) {
      fields.push("voicemail_enabled = ?");
      values.push(enabledVal);
    }
    if (greeting_text !== undefined) {
      const text =
        greeting_text === null || !greeting_text.trim()
          ? null
          : greeting_text.trim().slice(0, 1000);
      fields.push("voicemail_greeting_text = ?");
      values.push(text);
    }
    if (greeting_url !== undefined) {
      const url =
        greeting_url === null || !greeting_url.trim()
          ? null
          : greeting_url.trim().slice(0, 500);
      fields.push("voicemail_greeting_url = ?");
      values.push(url);
    }

    if (fields.length === 0) {
      return res
        .status(400)
        .json({ success: false, error: "No fields to update" });
    }

    fields.push("updated_at = NOW()");
    values.push(brokerId, MORTGAGE_TENANT_ID);

    await pool.query(
      `UPDATE brokers SET ${fields.join(", ")} WHERE id = ? AND tenant_id = ?`,
      values,
    );

    return res.json({ success: true });
  } catch (err) {
    console.error("[handleUpdateVoicemailSettings] Error:", err);
    return res.status(500).json({
      success: false,
      error: "Failed to update voicemail settings",
    });
  }
};

/**
 * PUT /api/voice/voicemail-settings/tenant
 * Admin-only: updates tenant-level voicemail defaults.
 * Body: { enabled?, greeting_text?, greeting_url?, max_seconds?, transcribe? }
 */
const handleUpdateTenantVoicemailSettings: RequestHandler = async (
  req,
  res,
) => {
  try {
    const role = (req as any).brokerRole as string | undefined;
    if (role !== "admin" && role !== "platform_owner") {
      return res
        .status(403)
        .json({ success: false, error: "Admin access required" });
    }

    const { enabled, greeting_text, greeting_url, max_seconds, transcribe } =
      req.body as {
        enabled?: boolean;
        greeting_text?: string | null;
        greeting_url?: string | null;
        max_seconds?: number;
        transcribe?: boolean;
      };

    const fields: string[] = [];
    const values: any[] = [];

    if (typeof enabled === "boolean") {
      fields.push("voicemail_enabled = ?");
      values.push(enabled ? 1 : 0);
    }
    if (greeting_text !== undefined) {
      const text =
        greeting_text === null || !greeting_text.trim()
          ? null
          : greeting_text.trim().slice(0, 1000);
      fields.push("voicemail_greeting_text = ?");
      values.push(text);
    }
    if (greeting_url !== undefined) {
      const url =
        greeting_url === null || !greeting_url.trim()
          ? null
          : greeting_url.trim().slice(0, 500);
      fields.push("voicemail_greeting_url = ?");
      values.push(url);
    }
    if (typeof max_seconds === "number") {
      const clamped = Math.min(Math.max(Math.round(max_seconds), 10), 600);
      fields.push("voicemail_max_seconds = ?");
      values.push(clamped);
    }
    if (typeof transcribe === "boolean") {
      fields.push("voicemail_transcribe = ?");
      values.push(transcribe ? 1 : 0);
    }

    if (fields.length === 0) {
      return res
        .status(400)
        .json({ success: false, error: "No fields to update" });
    }

    fields.push("updated_at = NOW()");
    values.push(MORTGAGE_TENANT_ID);

    await pool.query(
      `UPDATE tenants SET ${fields.join(", ")} WHERE id = ?`,
      values,
    );

    return res.json({ success: true });
  } catch (err) {
    console.error("[handleUpdateTenantVoicemailSettings] Error:", err);
    return res.status(500).json({
      success: false,
      error: "Failed to update tenant voicemail settings",
    });
  }
};

/**
 * POST /api/voice/dial-status
 * Twilio statusCallback fired when the <Dial> verb finishes (any leg answered,
 * or all legs failed/no-answer/busy/canceled).
 *
 * Behaviour:
 *   • DialCallStatus = "answered"  → broadcast Ably so all browsers dismiss
 *     the ringing UI, return empty TwiML so the call ends after the answerer
 *     hangs up.
 *   • DialCallStatus = "no-answer" | "busy" | "failed" | "canceled" →
 *     fall through to voicemail: play greeting + <Record> the caller.
 *
 * No broker-session auth — called by Twilio servers.
 */
const handleDialStatus: RequestHandler = async (req, res) => {
  res.set("Content-Type", "text/xml");
  try {
    const callSid = (req.body?.CallSid as string) || "";
    const dialCallStatus = (req.body?.DialCallStatus as string) || "";
    const calledNumber =
      (req.body?.To as string) || (req.body?.Called as string) || "";

    // Log the FULL body so we can diagnose unexpected DialCallStatus values
    // (e.g. "completed" instead of "answered", or "no-answer" missing).
    console.log(
      "[dial-status] received",
      JSON.stringify({
        CallSid: callSid,
        DialCallStatus: dialCallStatus,
        DialCallDuration: req.body?.DialCallDuration,
        CallStatus: req.body?.CallStatus,
        To: req.body?.To,
        Called: req.body?.Called,
        From: req.body?.From,
        Direction: req.body?.Direction,
      }),
    );

    // Answered → notify and end the call gracefully.
    // Note: Twilio may send "completed" for a real answered+finished call.
    if (
      callSid &&
      (dialCallStatus === "answered" || dialCallStatus === "completed")
    ) {
      await publishToAbly("voice:incoming", "call-answered", { callSid });
      return res.status(200).send("<Response></Response>");
    }

    // Unanswered states — drop into voicemail if enabled.
    const unanswered = ["no-answer", "busy", "failed", "canceled"].includes(
      dialCallStatus,
    );

    if (!unanswered) {
      return res.status(200).send("<Response></Response>");
    }

    // Stamp the original call row so the frontend knows no recording will ever
    // arrive for this leg — avoids infinite "Recording processing..." spinner.
    // Map all unanswered Twilio states to the 'failed' ENUM value (the only
    // valid non-success value in the delivery_status column).
    if (callSid) {
      pool
        .query(
          `UPDATE communications
           SET delivery_status = 'failed'
           WHERE external_id = ? AND communication_type = 'call' AND tenant_id = ?`,
          [callSid, MORTGAGE_TENANT_ID],
        )
        .catch((e) =>
          console.warn("[handleDialStatus] delivery_status update failed:", e),
        );
    }

    const VoiceResponse = twilio.twiml.VoiceResponse;
    const twiml = new VoiceResponse();

    // ── resolve voicemail settings (broker override → tenant default) ──
    const settings = await resolveVoicemailSettings(calledNumber);

    if (!settings.enabled) {
      twiml.say(
        { voice: "Polly.Joanna" },
        "Sorry, no one is available to take your call right now. Please try again later. Goodbye.",
      );
      twiml.hangup();
      return res.status(200).send(twiml.toString());
    }

    // 1) Greeting — pre-recorded MP3 wins, else TTS, else default.
    if (settings.greetingUrl) {
      twiml.play(settings.greetingUrl);
    } else if (settings.greetingText && settings.greetingText.trim()) {
      twiml.say({ voice: "Polly.Joanna" }, settings.greetingText.trim());
    } else {
      twiml.say(
        { voice: "Polly.Joanna" },
        "Hello, you've reached our office. We're unable to answer right now. Please leave your name, number, and a brief message after the tone, and we'll get back to you as soon as possible.",
      );
    }

    // 2) Record the voicemail.
    // Twilio's recordingStatusCallback / transcribeCallback do NOT include
    // the original From/To in their POST body — only the recording metadata.
    // We forward the caller (From) and called number (To) as query params so
    // the voicemail row is correctly attributed to the inbound caller.
    const callerFrom = (req.body?.From as string) || "";
    const callerTo = calledNumber || "";
    const cbQs = `?from=${encodeURIComponent(callerFrom)}&to=${encodeURIComponent(callerTo)}`;

    twiml.record({
      action: `${getVoiceBaseUrl()}/api/voice/voicemail-complete`,
      method: "POST",
      maxLength: settings.maxSeconds,
      finishOnKey: "#",
      playBeep: true,
      trim: "trim-silence",
      timeout: 5,
      recordingStatusCallback: `${getVoiceBaseUrl()}/api/voice/voicemail-recording${cbQs}`,
      recordingStatusCallbackMethod: "POST",
      recordingStatusCallbackEvent: ["completed"],
      transcribe: settings.transcribe,
      transcribeCallback: settings.transcribe
        ? `${getVoiceBaseUrl()}/api/voice/voicemail-transcription${cbQs}`
        : undefined,
    } as any);

    // If recording finishes without explicit hangup, say goodbye.
    twiml.say({ voice: "Polly.Joanna" }, "Thank you. Goodbye.");
    twiml.hangup();

    return res.status(200).send(twiml.toString());
  } catch (err) {
    console.error("[handleDialStatus] Error:", err);
    return res.status(200).send("<Response></Response>");
  }
};

/**
 * Resolve effective voicemail settings for an inbound call.
 * Voicemail is ONLY enabled for personal (assigned) lines — i.e. when the
 * dialled number matches a broker's twilio_caller_id. Shared/main lines
 * never record voicemails. Tenant settings only provide defaults (max
 * length, transcribe, greeting fallback) for assigned lines whose broker
 * hasn't customized their own greeting.
 */
async function resolveVoicemailSettings(calledNumber: string): Promise<{
  enabled: boolean;
  greetingUrl: string | null;
  greetingText: string | null;
  maxSeconds: number;
  transcribe: boolean;
}> {
  console.log("[resolveVoicemailSettings] calledNumber:", calledNumber);
  // Tenant defaults
  const [tenantRows] = await pool.query<RowDataPacket[]>(
    `SELECT voicemail_enabled, voicemail_greeting_text, voicemail_greeting_url,
            voicemail_max_seconds, voicemail_transcribe
     FROM tenants WHERE id = ? LIMIT 1`,
    [MORTGAGE_TENANT_ID],
  );
  const tenant: any = tenantRows[0] || {};

  const maxSeconds = Math.min(
    Math.max(
      parseInt(String(tenant.voicemail_max_seconds ?? 120), 10) || 120,
      10,
    ),
    600,
  );
  const transcribe = !!(tenant.voicemail_transcribe ?? 1);

  // Voicemail is ONLY enabled for personal (assigned) lines. If no broker
  // owns the dialled number, voicemail is disabled — shared/main lines do
  // not record messages.
  if (!calledNumber) {
    return {
      enabled: false,
      greetingUrl: null,
      greetingText: null,
      maxSeconds,
      transcribe,
    };
  }

  const [brokerRows] = await pool.query<RowDataPacket[]>(
    `SELECT voicemail_enabled, voicemail_greeting_text, voicemail_greeting_url
     FROM brokers
     WHERE tenant_id = ? AND status = 'active' AND twilio_caller_id = ?
     LIMIT 1`,
    [MORTGAGE_TENANT_ID, calledNumber],
  );
  const broker = brokerRows[0];
  if (!broker) {
    console.log(
      "[resolveVoicemailSettings] no broker found for calledNumber:",
      calledNumber,
      "→ voicemail disabled",
    );
    return {
      enabled: false,
      greetingUrl: null,
      greetingText: null,
      maxSeconds,
      transcribe,
    };
  }

  console.log(
    "[resolveVoicemailSettings] broker match found, voicemail_enabled:",
    broker.voicemail_enabled,
  );

  // Personal line — broker override falls back to tenant defaults when blank
  const enabled =
    broker.voicemail_enabled === null
      ? !!(tenant.voicemail_enabled ?? 1)
      : !!broker.voicemail_enabled;
  let greetingUrl: string | null = tenant.voicemail_greeting_url ?? null;
  let greetingText: string | null = tenant.voicemail_greeting_text ?? null;
  if (broker.voicemail_greeting_url) {
    greetingUrl = broker.voicemail_greeting_url;
    greetingText = null;
  } else if (broker.voicemail_greeting_text) {
    greetingText = broker.voicemail_greeting_text;
    greetingUrl = null;
  }

  return { enabled, greetingUrl, greetingText, maxSeconds, transcribe };
}

/**
 * POST /api/voice/voicemail-complete
 * Twilio fires this when the caller finishes recording (timeout, # key,
 * or hangup). We respond with a polite goodbye TwiML — the recording itself
 * is captured by the recordingStatusCallback (handleVoicemailRecording).
 * No auth — called by Twilio servers.
 */
const handleVoicemailComplete: RequestHandler = async (_req, res) => {
  res.set("Content-Type", "text/xml");
  const VoiceResponse = twilio.twiml.VoiceResponse;
  const twiml = new VoiceResponse();
  twiml.say(
    { voice: "Polly.Joanna" },
    "Thank you for your message. We will get back to you soon. Goodbye.",
  );
  twiml.hangup();
  return res.status(200).send(twiml.toString());
};

/**
 * POST /api/voice/call-screen
 * Twilio fires this URL when a forwarded <Number> leg is answered.
 * We require a keypress before bridging — carrier voicemail systems
 * won't press a key, so the leg hangs up and Twilio's <Dial> falls
 * through to the CRM voicemail instead of the carrier's.
 * No auth — called by Twilio servers.
 */
const handleCallScreen: RequestHandler = (req, res) => {
  res.set("Content-Type", "text/xml");
  // Log every field Twilio sends so we can trace carrier-voicemail intercepts
  // in Vercel logs. Key fields: CallSid, CallStatus, Called, From, Direction.
  console.log(
    "[call-screen] invoked",
    JSON.stringify({
      CallSid: req.body?.CallSid,
      CallStatus: req.body?.CallStatus,
      Called: req.body?.Called,
      To: req.body?.To,
      From: req.body?.From,
      Direction: req.body?.Direction,
      CallerCountry: req.body?.CallerCountry,
    }),
  );
  const VoiceResponse = twilio.twiml.VoiceResponse;
  const twiml = new VoiceResponse();
  // Give the broker 8 s to press any key; carrier voicemail won't answer.
  // IMPORTANT: the action URL must return empty <Response/> so Twilio bridges
  // the call after the keypress. Without action, Twilio re-requests this same
  // URL and the call never connects.
  const gather = twiml.gather({
    numDigits: 1,
    timeout: 8,
    action: `${getVoiceBaseUrl()}/api/voice/call-screen-accept`,
    method: "POST",
  });
  gather.say(
    { voice: "Polly.Joanna" },
    "Incoming call. Press any key to answer.",
  );
  // No key pressed within timeout → hang up this forwarded leg so Twilio
  // continues ringing browser clients and eventually hits CRM voicemail.
  twiml.hangup();
  const twimlStr = twiml.toString();
  console.log("[call-screen] responding with TwiML:", twimlStr);
  return res.send(twimlStr);
};

/**
 * POST /api/voice/call-screen-accept
 * Called by Twilio after the broker presses any key in the call-screen prompt.
 * Returning an empty <Response/> tells Twilio to bridge the call immediately.
 * No auth — called by Twilio servers.
 */
const handleCallScreenAccept: RequestHandler = (req, res) => {
  res.set("Content-Type", "text/xml");
  // Log so we can confirm the broker actually pressed a key (vs timeout+hangup).
  console.log(
    "[call-screen-accept] key pressed — bridging call",
    JSON.stringify({
      CallSid: req.body?.CallSid,
      Digits: req.body?.Digits,
      Called: req.body?.Called,
      From: req.body?.From,
    }),
  );
  // Empty response = bridge the call. Any verb here would play to the broker
  // before connecting; we want instant connection so we return nothing.
  return res.send("<Response/>");
};

/**
 * Builds the HTML email body for the voicemail transcript notification
 * sent to the mortgage banker assigned to the dialed Twilio number.
 */
function buildVoicemailEmailHtml(params: {
  bankerName: string;
  callerNumber: string;
  durationSec: number | null;
  transcriptionText: string;
  recordingUrl: string;
  receivedAt: Date;
  companyName: string;
}): string {
  const {
    bankerName,
    callerNumber,
    durationSec,
    transcriptionText,
    recordingUrl,
    receivedAt,
    companyName,
  } = params;

  const timeFormatted = receivedAt.toLocaleString("en-US", {
    month: "short",
    day: "numeric",
    year: "numeric",
    hour: "numeric",
    minute: "2-digit",
    hour12: true,
    timeZone: "America/Los_Angeles",
  });

  const durationLabel = durationSec
    ? `${Math.floor(durationSec / 60)}:${String(durationSec % 60).padStart(2, "0")} min`
    : "—";

  const transcriptBlock =
    transcriptionText.trim().length > 0
      ? transcriptionText.trim()
      : '<em style="color:#94a3b8;">No transcript available.</em>';

  const mp3Url = recordingUrl.endsWith(".mp3")
    ? recordingUrl
    : `${recordingUrl}.mp3`;

  return `<!DOCTYPE html>
<html lang="en">
<head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>New Voicemail</title></head>
<body style="margin:0;padding:0;background-color:#f1f5f9;font-family:Arial,Helvetica,sans-serif;">
  <table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color:#f1f5f9;padding:32px 16px;">
    <tr>
      <td align="center">
        <table width="100%" cellpadding="0" cellspacing="0" border="0" style="max-width:600px;background-color:#ffffff;border-radius:16px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,0.08);">

          <!-- Header banner -->
          <tr>
            <td style="background-color:#0f172a;padding:24px 32px;">
              <table width="100%" cellpadding="0" cellspacing="0" border="0">
                <tr>
                  <td>
                    <p style="margin:0;color:#e8192c;font-size:12px;font-weight:700;letter-spacing:1px;text-transform:uppercase;">Voicemail Notification</p>
                    <p style="margin:4px 0 0;color:#ffffff;font-size:20px;font-weight:700;">🎙️ New Voicemail Received</p>
                  </td>
                  <td style="text-align:right;vertical-align:top;">
                    <p style="margin:0;color:#94a3b8;font-size:12px;">${companyName}</p>
                  </td>
                </tr>
              </table>
            </td>
          </tr>

          <!-- Body -->
          <tr>
            <td style="padding:28px 32px 0;">

              <p style="margin:0 0 20px;color:#475569;font-size:14px;line-height:1.6;">
                Hi <strong style="color:#0f172a;">${bankerName}</strong>, you have a new voicemail on your personal line.
              </p>

              <!-- Caller info card -->
              <table width="100%" cellpadding="0" cellspacing="0" border="0"
                     style="background-color:#f8fafc;border:1px solid #e2e8f0;border-radius:12px;margin-bottom:20px;">
                <tr>
                  <td style="padding:20px 24px;">
                    <table width="100%" cellpadding="0" cellspacing="0" border="0">
                      <tr>
                        <td style="padding:5px 0;color:#64748b;font-size:13px;width:120px;">Caller</td>
                        <td style="padding:5px 0;color:#0f172a;font-size:15px;font-weight:700;">${callerNumber}</td>
                      </tr>
                      <tr>
                        <td style="padding:5px 0;color:#64748b;font-size:13px;">Received</td>
                        <td style="padding:5px 0;color:#0f172a;font-size:14px;">${timeFormatted} PT</td>
                      </tr>
                      <tr>
                        <td style="padding:5px 0;color:#64748b;font-size:13px;">Duration</td>
                        <td style="padding:5px 0;color:#0f172a;font-size:14px;">${durationLabel}</td>
                      </tr>
                    </table>
                  </td>
                </tr>
              </table>

              <!-- Transcript -->
              <p style="margin:0 0 8px;color:#0f172a;font-size:14px;font-weight:700;">Transcript</p>
              <div style="background-color:#f8fafc;border-left:4px solid #e8192c;border-radius:0 8px 8px 0;padding:16px 20px;margin-bottom:24px;font-size:14px;color:#334155;line-height:1.7;">
                ${transcriptBlock}
              </div>

              <!-- CTA button -->
              <table width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-bottom:28px;">
                <tr>
                  <td align="center">
                    <a href="${mp3Url}"
                       style="display:inline-block;background-color:#e8192c;color:#ffffff;font-size:14px;font-weight:700;padding:12px 28px;border-radius:8px;text-decoration:none;">
                      ▶&nbsp; Listen to Recording
                    </a>
                  </td>
                </tr>
              </table>

            </td>
          </tr>

          <!-- Footer -->
          <tr>
            <td style="background-color:#0f172a;padding:18px 32px;border-radius:0 0 16px 16px;text-align:center;">
              <p style="margin:0;color:#94a3b8;font-size:12px;">
                This notification was sent by ${companyName} CRM. The full voicemail thread is available in your Conversations inbox.
              </p>
            </td>
          </tr>

        </table>
      </td>
    </tr>
  </table>
</body>
</html>`;
}

/**
 * POST /api/voice/voicemail-recording
 * Twilio recordingStatusCallback for the voicemail <Record>.
 * Inserts a NEW communications row (is_voicemail=1) and broadcasts an Ably
 * event so the inbox refreshes in real time.
 * No auth — called by Twilio servers.
 */
const handleVoicemailRecording: RequestHandler = async (req, res) => {
  try {
    const {
      CallSid,
      RecordingUrl,
      RecordingDuration,
      RecordingStatus,
      RecordingSid,
      From,
      To,
    } = req.body as {
      CallSid?: string;
      RecordingUrl?: string;
      RecordingDuration?: string;
      RecordingStatus?: string;
      RecordingSid?: string;
      From?: string;
      To?: string;
    };

    if (RecordingStatus !== "completed" || !RecordingUrl) {
      return res.sendStatus(204);
    }

    const mp3Url = RecordingUrl.endsWith(".mp3")
      ? RecordingUrl
      : `${RecordingUrl}.mp3`;
    const durationSec = RecordingDuration
      ? parseInt(RecordingDuration, 10)
      : null;

    // Skip ultra-short hang-ups (< 2s of audio)
    if (durationSec !== null && durationSec < 2) {
      return res.sendStatus(204);
    }

    // Twilio's recordingStatusCallback body does NOT include From/To by
    // default — we forward them via query string from handleDialStatus.
    // Fall back to Twilio API lookup using CallSid if missing for any reason.
    let callerNumber = (req.query?.from as string) || From || "";
    let calledNumber: string | null = (req.query?.to as string) || To || null;

    if ((!callerNumber || !calledNumber) && CallSid && twilioClient) {
      try {
        const call = await twilioClient.calls(CallSid).fetch();
        if (!callerNumber) callerNumber = call.from || "";
        if (!calledNumber) calledNumber = call.to || null;
      } catch (e) {
        console.warn(
          "[handleVoicemailRecording] Twilio call lookup failed:",
          (e as any)?.message || e,
        );
      }
    }

    if (!callerNumber) callerNumber = "Unknown";

    const voicemailClientId = await resolveClientIdByPhone(
      pool,
      MORTGAGE_TENANT_ID,
      callerNumber,
    );
    const conversationId = voicemailClientId
      ? `conv_client_${voicemailClientId}`
      : await resolvePhoneConversationId(pool, MORTGAGE_TENANT_ID, {
          phone: callerNumber,
          inboxNumber: calledNumber,
        });
    const body = `🎙️ Voicemail from ${callerNumber}${
      durationSec ? ` (${durationSec}s)` : ""
    }`;
    // Use a distinct external_id so it doesn't collide with the original
    // inbound-call communication row that shares the same CallSid.
    const externalId = RecordingSid
      ? `vm_${RecordingSid}`
      : `vm_${CallSid || Date.now()}`;

    // Resolve the broker who owns the dialled Twilio number so we can set
    // to_broker_id on the communications row. Without this, voicemail rows
    // are unattributed and inbox attribution relies solely on inbox_number.
    let voicemailToBrokerId: number | null = null;
    let voicemailBankerEmail: string | null = null;
    let voicemailBankerName: string | null = null;
    if (calledNumber) {
      try {
        const [bkRows] = await pool.query<RowDataPacket[]>(
          `SELECT id, email, first_name, last_name
           FROM brokers
           WHERE tenant_id = ? AND status = 'active' AND twilio_caller_id = ?
           LIMIT 1`,
          [MORTGAGE_TENANT_ID, calledNumber],
        );
        if (bkRows.length > 0) {
          voicemailToBrokerId = bkRows[0].id as number;
          voicemailBankerEmail = (bkRows[0].email as string | null) ?? null;
          voicemailBankerName =
            `${bkRows[0].first_name} ${bkRows[0].last_name}`.trim() || null;
        }
      } catch (e) {
        console.warn(
          "[handleVoicemailRecording] broker lookup failed:",
          (e as any)?.message,
        );
      }
    }

    const [insertResult] = await pool.query<any>(
      `INSERT INTO communications
         (tenant_id, from_broker_id, to_user_id, to_broker_id, communication_type, direction,
          body, status, external_id, conversation_id, recording_url,
          recording_duration, is_voicemail, delivery_status, sent_at, created_at)
       VALUES (?, NULL, NULL, ?, 'call', 'inbound', ?, 'sent', ?, ?, ?, ?, 1, 'sent', NOW(), NOW())`,
      [
        MORTGAGE_TENANT_ID,
        voicemailToBrokerId,
        body,
        externalId,
        conversationId,
        mp3Url,
        durationSec,
      ],
    );

    await upsertConversationThread({
      tenantId: MORTGAGE_TENANT_ID,
      commId: insertResult.insertId,
      conversationId,
      applicationId: null,
      leadId: null,
      fromUserId: voicemailClientId,
      fromBrokerId: null,
      toUserId: voicemailClientId,
      toBrokerId: voicemailToBrokerId,
      communicationType: "call",
      direction: "inbound",
      body,
      inboxNumber: calledNumber,
      recipientPhone: callerNumber,
    }).catch((e) =>
      console.error("[handleVoicemailRecording] thread upsert error:", e),
    );

    // Broadcast so all online brokers see the voicemail instantly.
    await publishToAbly("voice:voicemail", "new", {
      commId: insertResult.insertId,
      conversationId,
      from: callerNumber,
      to: calledNumber,
      durationSec,
      callSid: CallSid,
    }).catch(() => {});
    await publishToAbly("conversations:all", "thread-updated", {
      conversationId,
      tenantId: MORTGAGE_TENANT_ID,
    }).catch(() => {});

    // Send an immediate email notification to the banker so they're alerted
    // even when auto-transcription is disabled (transcription email fires
    // separately only when Twilio transcribes). This ensures the banker is
    // ALWAYS notified on every voicemail.
    if (voicemailBankerEmail && !voicemailBankerEmail.startsWith("noemail_")) {
      try {
        const companyName = await fetchTenantCompanyName(
          pool,
          MORTGAGE_TENANT_ID,
        );
        const html = buildVoicemailEmailHtml({
          bankerName: voicemailBankerName || "Banker",
          callerNumber,
          durationSec,
          transcriptionText: "", // transcript not yet available
          recordingUrl: mp3Url,
          receivedAt: new Date(),
          companyName,
        });
        const durationDisplay = durationSec ? ` — ${durationSec}s` : "";
        await sendEmailMessage(
          voicemailBankerEmail,
          `🎙️ New Voicemail from ${callerNumber}${durationDisplay}`,
          html,
          true,
          undefined,
          {
            billing: systemEmailQuota("voicemail_notification", externalId),
          },
        ).catch((e) =>
          console.error(
            "[handleVoicemailRecording] immediate email failed:",
            e,
          ),
        );
      } catch (emailErr) {
        console.error(
          "[handleVoicemailRecording] email notification error:",
          emailErr,
        );
      }
    }

    return res.sendStatus(204);
  } catch (err) {
    console.error("[handleVoicemailRecording] Error:", err);
    return res.sendStatus(500);
  }
};

/**
 * POST /api/voice/voicemail-transcription
 * Twilio transcribeCallback — fires after voicemail audio is transcribed.
 * Patches the matching voicemail communications row.
 * No auth — called by Twilio servers.
 */
const handleVoicemailTranscription: RequestHandler = async (req, res) => {
  try {
    const { RecordingSid, TranscriptionText, TranscriptionStatus } =
      req.body as {
        RecordingSid?: string;
        TranscriptionText?: string;
        TranscriptionStatus?: string;
      };

    if (TranscriptionStatus !== "completed" || !RecordingSid) {
      return res.sendStatus(204);
    }

    const externalId = `vm_${RecordingSid}`;
    await pool.query(
      `UPDATE communications
       SET voicemail_transcription = ?
       WHERE external_id = ? AND tenant_id = ? AND is_voicemail = 1`,
      [TranscriptionText || null, externalId, MORTGAGE_TENANT_ID],
    );

    // Look up the conversation_id so the UI can patch in place.
    const [rows] = await pool.query<RowDataPacket[]>(
      `SELECT id, conversation_id FROM communications
       WHERE external_id = ? AND tenant_id = ? AND is_voicemail = 1
       LIMIT 1`,
      [externalId, MORTGAGE_TENANT_ID],
    );
    if (rows.length > 0) {
      await publishToAbly("voice:voicemail", "transcribed", {
        commId: rows[0].id,
        conversationId: rows[0].conversation_id,
        transcription: TranscriptionText || "",
      }).catch(() => {});

      // ── Voicemail transcript email to assigned mortgage banker ──────────
      // Only fires when the voicemail landed on a personal Twilio line
      // (twilio_caller_id) assigned to a mortgage banker.
      try {
        const conversationId: string = rows[0].conversation_id;

        // 1. Fetch conversation metadata: inbox number + caller + recording info
        const [threadRows] = await pool.query<RowDataPacket[]>(
          `SELECT ct.inbox_number, ct.client_phone,
                  c.recording_url, c.recording_duration, c.created_at
           FROM conversation_threads ct
           JOIN communications c ON c.conversation_id = ct.conversation_id
           WHERE ct.conversation_id = ?
             AND c.external_id = ?
           LIMIT 1`,
          [conversationId, externalId],
        );

        if (threadRows.length > 0) {
          const {
            inbox_number,
            client_phone,
            recording_url,
            recording_duration,
            created_at,
          } = threadRows[0] as {
            inbox_number: string | null;
            client_phone: string | null;
            recording_url: string | null;
            recording_duration: number | null;
            created_at: Date;
          };

          if (inbox_number) {
            // 2. Find the banker whose personal line received the call
            const [bankerRows] = await pool.query<RowDataPacket[]>(
              `SELECT email, first_name, last_name
               FROM brokers
               WHERE tenant_id = ?
                 AND status = 'active'
                 AND twilio_caller_id = ?
                 AND email NOT LIKE 'noemail_%'
               ORDER BY id ASC
               LIMIT 1`,
              [MORTGAGE_TENANT_ID, inbox_number],
            );

            if (bankerRows.length > 0) {
              const banker = bankerRows[0] as {
                email: string;
                first_name: string;
                last_name: string;
              };
              const bankerName =
                `${banker.first_name} ${banker.last_name}`.trim();

              const companyName = await fetchTenantCompanyName(
                pool,
                MORTGAGE_TENANT_ID,
              );

              const html = buildVoicemailEmailHtml({
                bankerName,
                callerNumber: client_phone || "Unknown",
                durationSec: recording_duration,
                transcriptionText: TranscriptionText || "",
                recordingUrl: recording_url || "",
                receivedAt:
                  created_at instanceof Date
                    ? created_at
                    : new Date(created_at),
                companyName,
              });

              const callerDisplay = client_phone || "Unknown";
              const durationDisplay = recording_duration
                ? ` — ${recording_duration}s`
                : "";
              const subject = `🎙️ New Voicemail from ${callerDisplay}${durationDisplay}`;

              await sendEmailMessage(
                banker.email,
                subject,
                html,
                true,
                undefined,
                {
                  billing: systemEmailQuota(
                    "voicemail_transcription",
                    externalId,
                  ),
                },
              ).catch((e) =>
                console.error(
                  "[handleVoicemailTranscription] email send failed:",
                  e,
                ),
              );
            }
          }
        }
      } catch (emailErr) {
        // Non-fatal — never block the 204 response to Twilio
        console.error(
          "[handleVoicemailTranscription] email notification error:",
          emailErr,
        );
      }
      // ────────────────────────────────────────────────────────────────────
    }

    return res.sendStatus(204);
  } catch (err) {
    console.error("[handleVoicemailTranscription] Error:", err);
    return res.sendStatus(500);
  }
};

/**
 * POST /api/voice/call-answered
 * Called by the broker whose browser accepted an inbound simultaneous-ring call.
 * Publishes a 'call-answered' event on Ably so all other online brokers immediately
 * dismiss their ringing notification — no waiting for the Twilio SDK cancel event.
 */
const handleVoiceCallAnswered: RequestHandler = async (req, res) => {
  try {
    const { callSid } = req.body as { callSid?: string };
    if (callSid) {
      await publishToAbly("voice:incoming", "call-answered", { callSid });
    }
    return res.json({ success: true });
  } catch (error) {
    console.error("[handleVoiceCallAnswered] Error:", error);
    return res
      .status(500)
      .json({ success: false, error: "Failed to broadcast call-answered" });
  }
};

/**
 * POST /api/voice/incoming
 * TwiML webhook called by Twilio when an external caller dials a Twilio number.
 * No broker-session auth — called by Twilio servers.
 *
 * Routing priority:
 *   1. All available brokers whose assigned number (twilio_caller_id) matches the dialled number.
 *   2. All other available brokers for the tenant.
 *   Twilio rings them all simultaneously; the first to accept wins.
 *   Fallback: if nobody is marked available, route to the first active broker so the call
 *   is never silently dropped.
 */
const handleVoiceIncoming: RequestHandler = async (req, res) => {
  res.setHeader("Content-Type", "text/xml");

  try {
    // The Twilio number that was dialled (E.164 or local format)
    const calledNumber =
      (req.body?.To as string) || (req.body?.Called as string) || "";

    // ---------- determine which brokers should ring ----------

    // 1) Check if this number is exclusively assigned to one broker.
    //    twilio_caller_id stores the E.164 number assigned to that broker.
    //    If assigned → ring ONLY that broker (personal line).
    //    If unassigned (shared) → ring all currently available brokers.
    const [assignedRows] = await pool.query<any>(
      `SELECT id FROM brokers
       WHERE tenant_id = ? AND status = 'active' AND twilio_caller_id = ?
       LIMIT 1`,
      [MORTGAGE_TENANT_ID, calledNumber],
    );

    let brokerIds: number[];

    if (assignedRows.length > 0) {
      // Personal line — ring exclusively the assigned broker regardless of
      // voice_available so their dedicated number always reaches them.
      brokerIds = [assignedRows[0].id as number];
    } else {
      // Shared line — ring all brokers who are currently marked available.
      const [availableRows] = await pool.query<any>(
        `SELECT id FROM brokers
         WHERE tenant_id = ? AND status = 'active' AND voice_available = 1
         ORDER BY id ASC
         LIMIT 10`,
        [MORTGAGE_TENANT_ID],
      );

      if (availableRows.length > 0) {
        brokerIds = availableRows.map((r: any) => r.id as number);
      } else {
        // Fallback: nobody available — route to first active broker so call isn't dropped.
        const [fallbackRows] = await pool.query<any>(
          `SELECT id FROM brokers
           WHERE tenant_id = ? AND status = 'active'
           ORDER BY id ASC LIMIT 1`,
          [MORTGAGE_TENANT_ID],
        );
        brokerIds =
          fallbackRows.length > 0
            ? [fallbackRows[0].id as number]
            : [parseInt(process.env.TWILIO_INCOMING_BROKER_ID || "1", 10)];
      }
    }

    const callerNumber =
      (req.body?.From as string) || (req.body?.Caller as string) || "Unknown";

    // Fetch call forwarding phones for the brokers who will ring
    const [forwardingRows] = await pool.query<any>(
      `SELECT id, call_forwarding_enabled, call_forwarding_phone
       FROM brokers WHERE id IN (${brokerIds.map(() => "?").join(",")}) AND tenant_id = ?`,
      [...brokerIds, MORTGAGE_TENANT_ID],
    );
    const forwardingMap = new Map<number, string | null>(
      forwardingRows.map((r: any) => [
        r.id as number,
        r.call_forwarding_enabled
          ? (r.call_forwarding_phone as string | null)
          : null,
      ]),
    );

    const VoiceResponse = twilio.twiml.VoiceResponse;
    const twiml = new VoiceResponse();
    const statusCallbackUrl = `${getVoiceBaseUrl()}/api/voice/dial-status`;
    const dial = twiml.dial({
      timeout: 10,
      // Twilio fires this URL on our server when any leg is answered — we use it
      // to broadcast the Ably call-answered event so all browsers dismiss instantly,
      // even when the answerer is a personal phone (not a browser).
      action: statusCallbackUrl,
      method: "POST",
      record: "record-from-answer-dual",
      recordingStatusCallback: `${getVoiceBaseUrl()}/api/voice/recording-status`,
      recordingStatusCallbackMethod: "POST",
      trim: "trim-silence",
    } as any);

    // Ring all target brokers simultaneously — first to accept wins.
    for (const bid of brokerIds) {
      dial.client(`broker_${bid}`);
      // If this broker has call forwarding enabled, also ring their personal phone.
      // The call-screen URL requires a keypress before bridging — carrier voicemail
      // systems won't press a key so their leg hangs up and CRM voicemail triggers
      // instead. handleCallScreenAccept returns empty <Response/> to bridge instantly.
      const fwdPhone = forwardingMap.get(bid);
      if (fwdPhone) {
        dial.number(
          {
            url: `${getVoiceBaseUrl()}/api/voice/call-screen`,
            method: "POST",
          } as any,
          fwdPhone,
        );
      }
    }

    // Respond to Twilio immediately — DB logging must NOT block the TwiML response.
    // Any delay here postpones the moment Twilio starts ringing the brokers, causing
    // the caller to hear silence and the call to drop after a single ring.
    const twimlOut = twiml.toString();
    console.log("[voice-incoming] responding with TwiML:", twimlOut);
    res.send(twimlOut);

    // Fire-and-forget: log the incoming call attempt asynchronously.
    void (async () => {
      const callClientId = await resolveClientIdByPhone(
        pool,
        MORTGAGE_TENANT_ID,
        callerNumber,
      );
      const conversationId = callClientId
        ? `conv_client_${callClientId}`
        : await resolvePhoneConversationId(pool, MORTGAGE_TENANT_ID, {
            phone: callerNumber,
            inboxNumber: calledNumber || null,
          });
      const body = `📞 Incoming call from ${callerNumber}`;
      const personalLineBrokerId: number | null =
        assignedRows.length > 0 ? (assignedRows[0].id as number) : null;
      try {
        const [commResult] = await pool.query<any>(
          `INSERT INTO communications
             (tenant_id, from_broker_id, to_user_id, communication_type, direction,
              body, status, external_id, conversation_id, delivery_status, sent_at, created_at)
           VALUES (?, NULL, NULL, 'call', 'inbound', ?, 'sent', ?, ?, 'sent', NOW(), NOW())`,
          [
            MORTGAGE_TENANT_ID,
            body,
            (req.body?.CallSid as string) || null,
            conversationId,
          ],
        );
        await upsertConversationThread({
          tenantId: MORTGAGE_TENANT_ID,
          commId: commResult.insertId,
          conversationId,
          applicationId: null,
          leadId: null,
          fromUserId: callClientId,
          fromBrokerId: personalLineBrokerId,
          toUserId: callClientId,
          toBrokerId: null,
          communicationType: "call",
          direction: "inbound",
          body,
          inboxNumber: calledNumber || null,
          recipientPhone: callerNumber,
        });
        await publishToAbly("conversations:all", "thread-updated", {
          conversationId,
          communicationType: "call",
        }).catch(() => undefined);
      } catch (logErr) {
        console.error("[handleVoiceIncoming] Log error:", logErr);
      }
    })();
  } catch (err) {
    console.error("[handleVoiceIncoming] Error:", err);
    // Still return valid TwiML so Twilio doesn't retry indefinitely
    const VoiceResponse = twilio.twiml.VoiceResponse;
    const twiml = new VoiceResponse();
    twiml.say(
      "We are unable to take your call right now. Please try again later.",
    );
    return res.send(twiml.toString());
  }
};

/**
 * POST /api/voice/fix-call-setup
 * Forces a re-verification and update of the TwiML App voiceUrl.
 * Call this when outbound calls fail with "update voice URL" errors.
 */
const handleFixCallSetup: RequestHandler = async (req, res) => {
  try {
    if (!twilioClient) {
      return res
        .status(503)
        .json({ success: false, error: "Twilio not configured" });
    }

    // Reset the cache so getOrCreateTwimlAppSid does a full verify
    cachedTwimlAppSid = process.env.TWILIO_TWIML_APP_SID || null;
    twimlAppVerified = false;

    const sid = await getOrCreateTwimlAppSid();
    if (!sid) {
      return res
        .status(500)
        .json({ success: false, error: "Could not create or find TwiML App" });
    }

    const voiceUrl = `${getVoiceBaseUrl()}/api/voice/twiml`;
    return res.json({
      success: true,
      twimlAppSid: sid,
      voiceUrl,
      message: "TwiML App voiceUrl verified and updated",
    });
  } catch (error) {
    console.error("[handleFixCallSetup] Error:", error);
    return res
      .status(500)
      .json({ success: false, error: "Failed to fix call setup" });
  }
};

/**
 * GET /api/voice/phone-numbers
 * Returns all Twilio phone numbers with webhook status + current broker assignment.
 */
const handleGetPhoneNumbers: RequestHandler = async (req, res) => {
  try {
    if (!twilioClient) {
      return res
        .status(503)
        .json({ success: false, error: "Twilio not configured" });
    }
    const incomingUrl = `${getVoiceBaseUrl()}/api/voice/incoming`;

    // Fetch numbers and broker assignments in parallel
    const [twilioNumbers, brokerRows] = await Promise.all([
      twilioClient.incomingPhoneNumbers.list({ limit: 50 }),
      pool.query<any>(
        `SELECT id, first_name, last_name, twilio_phone_sid, twilio_caller_id
         FROM brokers WHERE tenant_id = ? AND status = 'active' ORDER BY first_name ASC`,
        [MORTGAGE_TENANT_ID],
      ),
    ]);

    const brokers: {
      id: number;
      first_name: string;
      last_name: string;
      twilio_phone_sid: string | null;
      twilio_caller_id: string | null;
    }[] = (brokerRows as any)[0];

    // Build two maps for assignment lookup:
    // 1. twilio_phone_sid → broker  (set by UI's assignNumber)
    // 2. twilio_caller_id → broker  (set directly via migration/DB, no sid yet)
    const sidToBroker = new Map(
      brokers
        .filter((b) => b.twilio_phone_sid)
        .map((b) => [b.twilio_phone_sid!, b]),
    );
    const callerIdToBroker = new Map(
      brokers
        .filter((b) => b.twilio_caller_id && !b.twilio_phone_sid)
        .map((b) => [b.twilio_caller_id!, b]),
    );

    const result = twilioNumbers.map((n) => {
      const assignedBroker =
        sidToBroker.get(n.sid) ?? callerIdToBroker.get(n.phoneNumber);
      return {
        sid: n.sid,
        phoneNumber: n.phoneNumber,
        friendlyName: n.friendlyName,
        voiceUrl: n.voiceUrl,
        smsUrl: n.smsUrl,
        configured: n.voiceUrl === incomingUrl,
        smsConfigured:
          n.smsUrl === `${getVoiceBaseUrl()}/api/webhooks/inbound-sms`,
        capabilities: {
          voice: n.capabilities?.voice ?? false,
          sms: n.capabilities?.sms ?? false,
          mms: n.capabilities?.mms ?? false,
        },
        assignedBrokerId: assignedBroker?.id ?? null,
        assignedBrokerName: assignedBroker
          ? `${assignedBroker.first_name} ${assignedBroker.last_name}`
          : null,
      };
    });

    // Return the broker list so the UI can populate the assign dropdown
    const brokerList = brokers.map((b) => ({
      id: b.id,
      name: `${b.first_name} ${b.last_name}`,
    }));

    return res.json({
      success: true,
      numbers: result,
      incomingUrl,
      brokers: brokerList,
    });
  } catch (error) {
    console.error("[handleGetPhoneNumbers] Error:", error);
    return res
      .status(500)
      .json({ success: false, error: "Failed to list phone numbers" });
  }
};

/**
 * POST /api/voice/phone-numbers/:sid/assign
 * Assigns a Twilio phone number to a broker (or unassigns with brokerId: null).
 * Sets twilio_phone_sid + twilio_caller_id on the broker row.
 */
const handleAssignPhoneNumber: RequestHandler = async (req, res) => {
  try {
    const { sid } = req.params as { sid: string };
    const { brokerId } = req.body as { brokerId: number | null };

    // Resolve the E.164 number for the SID
    if (brokerId !== null && brokerId !== undefined) {
      if (!twilioClient) {
        return res
          .status(503)
          .json({ success: false, error: "Twilio not configured" });
      }
      const number = await twilioClient.incomingPhoneNumbers(sid).fetch();
      const callerIdE164 = number.phoneNumber;

      // Clear any previous broker that owned this SID
      await pool.query(
        `UPDATE brokers SET twilio_phone_sid = NULL, twilio_caller_id = NULL
         WHERE tenant_id = ? AND twilio_phone_sid = ?`,
        [MORTGAGE_TENANT_ID, sid],
      );
      // Assign to the new broker
      await pool.query(
        `UPDATE brokers SET twilio_phone_sid = ?, twilio_caller_id = ?
         WHERE id = ? AND tenant_id = ?`,
        [sid, callerIdE164, brokerId, MORTGAGE_TENANT_ID],
      );
      // Auto-configure voice and SMS webhooks so the newly assigned number
      // immediately routes inbound calls/SMS to our handlers without requiring
      // a separate "Configure All Webhooks" admin action.
      try {
        const incomingUrl = `${getVoiceBaseUrl()}/api/voice/incoming`;
        const smsIncomingUrl = `${getVoiceBaseUrl()}/api/webhooks/inbound-sms`;
        await twilioClient!.incomingPhoneNumbers(sid).update({
          voiceUrl: incomingUrl,
          voiceMethod: "POST",
          smsUrl: smsIncomingUrl,
          smsMethod: "POST",
        });
      } catch (webhookErr) {
        // Non-fatal — log but don't fail the assignment. Admin can manually
        // click "Configure All Webhooks" if this fails.
        console.error(
          "[handleAssignPhoneNumber] Webhook config failed (non-fatal):",
          webhookErr,
        );
      }
      return res.json({ success: true, sid, brokerId, callerIdE164 });
    } else {
      // Unassign
      await pool.query(
        `UPDATE brokers SET twilio_phone_sid = NULL, twilio_caller_id = NULL
         WHERE tenant_id = ? AND twilio_phone_sid = ?`,
        [MORTGAGE_TENANT_ID, sid],
      );
      return res.json({ success: true, sid, brokerId: null });
    }
  } catch (error) {
    console.error("[handleAssignPhoneNumber] Error:", error);
    return res
      .status(500)
      .json({ success: false, error: "Failed to assign phone number" });
  }
};

/**
 * POST /api/voice/phone-numbers/:sid/configure
 * Sets the Voice AND SMS webhooks on the given Twilio phone number.
 * Pass sid = "all" to configure every number at once.
 */
const handleConfigurePhoneNumber: RequestHandler = async (req, res) => {
  try {
    if (!twilioClient) {
      return res
        .status(503)
        .json({ success: false, error: "Twilio not configured" });
    }
    const { sid } = req.params as { sid: string };
    const incomingUrl = `${getVoiceBaseUrl()}/api/voice/incoming`;
    const smsIncomingUrl = `${getVoiceBaseUrl()}/api/webhooks/inbound-sms`;

    if (sid === "all") {
      const numbers = await twilioClient.incomingPhoneNumbers.list({
        limit: 50,
      });
      await Promise.all(
        numbers.map((n) =>
          twilioClient!.incomingPhoneNumbers(n.sid).update({
            voiceUrl: incomingUrl,
            voiceMethod: "POST",
            smsUrl: smsIncomingUrl,
            smsMethod: "POST",
          }),
        ),
      );
      return res.json({
        success: true,
        updated: numbers.length,
        incomingUrl,
        smsIncomingUrl,
      });
    }

    await twilioClient.incomingPhoneNumbers(sid).update({
      voiceUrl: incomingUrl,
      voiceMethod: "POST",
      smsUrl: smsIncomingUrl,
      smsMethod: "POST",
    });
    return res.json({ success: true, sid, incomingUrl, smsIncomingUrl });
  } catch (error) {
    console.error("[handleConfigurePhoneNumber] Error:", error);
    return res
      .status(500)
      .json({ success: false, error: "Failed to configure phone number" });
  }
};

/**
 * POST /api/voice/log
 * Called by the frontend after a call ends to record it in the DB.
 */
const handleVoiceLog: RequestHandler = async (req, res) => {
  try {
    const brokerId = (req as any).brokerId;
    const {
      client_id,
      application_id,
      phone,
      duration,
      call_status,
      call_sid,
      client_name,
      direction,
    } = req.body as {
      client_id?: number;
      application_id?: number;
      phone?: string;
      duration?: number;
      call_status?: string;
      call_sid?: string;
      client_name?: string;
      direction?: "inbound" | "outbound";
    };

    if (!phone) {
      return res
        .status(400)
        .json({ success: false, error: "phone is required" });
    }

    const normalizedPhone = phone.startsWith("+")
      ? phone
      : `+1${phone.replace(/\D/g, "")}`;

    // If the frontend didn't pass a client_id (e.g. call dialled from the
    // dialpad by typing a raw number), resolve the client from the phone so
    // the conversation thread is linked to the correct contact.
    let resolvedClientId: number | null = client_id ?? null;
    if (!resolvedClientId) {
      const lastTen = normalizedPhone.replace(/\D/g, "").slice(-10);
      if (lastTen.length === 10) {
        const [cRows] = await pool.query<RowDataPacket[]>(
          `SELECT id FROM clients
           WHERE tenant_id = ? AND RIGHT(REGEXP_REPLACE(phone, '[^0-9]', ''), 10) = ?
           LIMIT 1`,
          [MORTGAGE_TENANT_ID, lastTen],
        );
        if (cRows.length > 0) {
          resolvedClientId = cRows[0].id as number;
        }
      }
    }

    // Idempotency guard: if this call_sid was already logged, skip the insert
    // and return success. Prevents double-records when the frontend calls this
    // endpoint twice (e.g. from both the call 'disconnect' and 'ended' events).
    if (call_sid) {
      const [[existing]] = await pool.query<RowDataPacket[]>(
        `SELECT id FROM communications
         WHERE tenant_id = ? AND external_id = ? AND communication_type = 'call' LIMIT 1`,
        [MORTGAGE_TENANT_ID, call_sid],
      );
      if (existing) {
        return res.json({ success: true }); // already logged — idempotent
      }
    }

    const durationSec = duration ?? 0;
    const statusLabel = call_status ?? "completed";
    const body = `📞 Voice call — ${durationSec}s (${statusLabel})`;

    const conversationId = resolvedClientId
      ? `conv_client_${resolvedClientId}`
      : await resolvePhoneConversationId(pool, MORTGAGE_TENANT_ID, {
          phone: normalizedPhone,
        });

    const [commResult] = await pool.query<any>(
      `INSERT INTO communications
         (tenant_id, from_broker_id, to_user_id, communication_type, direction,
          body, status, external_id, conversation_id, delivery_status, sent_at, created_at)
       VALUES (?, ?, ?, 'call', ?, ?, 'sent', ?, ?, 'sent', NOW(), NOW())`,
      [
        MORTGAGE_TENANT_ID,
        brokerId,
        resolvedClientId,
        direction ?? "outbound",
        body,
        call_sid ?? null,
        conversationId,
      ],
    );

    await upsertConversationThread({
      tenantId: MORTGAGE_TENANT_ID,
      commId: commResult.insertId,
      conversationId,
      applicationId: application_id ?? null,
      leadId: null,
      fromUserId: null,
      fromBrokerId: brokerId,
      toUserId: resolvedClientId,
      toBrokerId: null,
      communicationType: "call",
      direction: "outbound",
      body,
      // Pass the normalised phone so upsertConversationThread can always do
      // its own phone→client fallback lookup even when resolvedClientId is null.
      recipientPhone: normalizedPhone,
    });

    const voiceMinutes = Math.max(1, Math.ceil(durationSec / 60));
    const voiceQuota = await wireVoiceQuota(voiceMinutes, {
      tenantId: MORTGAGE_TENANT_ID,
      source: "conversation",
      refType: "call",
      refId: call_sid || String(commResult.insertId),
    });
    if (!voiceQuota.allowed) {
      console.warn(
        `[voice] Quota record denied after call — sid=${call_sid ?? "n/a"} minutes=${voiceMinutes}`,
        voiceQuota,
      );
    }
    await pool.query(
      `UPDATE communications SET recording_duration = ? WHERE id = ?`,
      [durationSec, commResult.insertId],
    );

    return res.json({ success: true });
  } catch (error) {
    console.error("Error logging voice call:", error);
    return res
      .status(500)
      .json({ success: false, error: "Failed to log call" });
  }
};

/**
 * POST /api/voice/recording-status
 * Twilio fires this when a recording is ready. We save the recording URL back
 * onto the communications row that has the matching CallSid as external_id.
 * No auth — called directly by Twilio.
 */
const handleRecordingStatus: RequestHandler = async (req, res) => {
  try {
    const { CallSid, RecordingUrl, RecordingDuration, RecordingStatus } =
      req.body as {
        CallSid?: string;
        RecordingUrl?: string;
        RecordingDuration?: string;
        RecordingStatus?: string;
      };

    // Only store completed recordings
    if (RecordingStatus !== "completed" || !CallSid || !RecordingUrl) {
      return res.sendStatus(204);
    }

    // Twilio RecordingUrl doesn't include the .mp3 extension — append it for direct playback
    const mp3Url = RecordingUrl.endsWith(".mp3")
      ? RecordingUrl
      : `${RecordingUrl}.mp3`;

    await pool.query(
      `UPDATE communications
       SET recording_url = ?, recording_duration = ?
       WHERE external_id = ? AND communication_type = 'call' AND tenant_id = ?`,
      [
        mp3Url,
        RecordingDuration ? parseInt(RecordingDuration, 10) : null,
        CallSid,
        MORTGAGE_TENANT_ID,
      ],
    );

    return res.sendStatus(204);
  } catch (err) {
    console.error("[handleRecordingStatus] Error:", err);
    return res.sendStatus(500);
  }
};

/**
 * GET /api/voice/recording/:callSid
 * Proxies the Twilio recording MP3 to the browser, keeping Twilio credentials
 * server-side.
 *
 * Auth: Bearer token in Authorization header OR ?token= query param.
 * The query-param form is required for the HTML5 <audio> element, which
 * cannot set custom headers for src= requests.
 *
 * Query params:
 *   ?download=1  → adds Content-Disposition: attachment (triggers file save)
 */
const handleGetRecording: RequestHandler = async (req, res) => {
  try {
    const { callSid } = req.params as { callSid: string };
    const isDownload = req.query.download === "1";

    // --- Auth: header OR query param ---
    let sessionToken: string | undefined;
    const authHeader = req.headers.authorization;
    if (authHeader?.startsWith("Bearer ")) {
      sessionToken = authHeader.substring(7);
    } else if (typeof req.query.token === "string") {
      sessionToken = req.query.token;
    }
    if (!sessionToken) {
      return res.status(401).json({ success: false, error: "Unauthorized" });
    }
    let brokerId: number | undefined;
    try {
      const decoded = jwt.verify(sessionToken, JWT_SECRET, {
        algorithms: ["HS256"],
      }) as any;
      if (decoded.userType !== "broker") throw new Error("not a broker");
      brokerId = decoded.brokerId as number;
    } catch {
      return res.status(401).json({ success: false, error: "Invalid session" });
    }

    // --- Fetch recording URL from DB ---
    // Any authenticated broker in the tenant may stream any call recording.
    // Tenant isolation + valid JWT is sufficient — brokers are colleagues who
    // share access to all conversations within the same office.
    const [rows] = await pool.query<RowDataPacket[]>(
      `SELECT c.recording_url FROM communications c
       WHERE c.external_id = ? AND c.communication_type = 'call' AND c.tenant_id = ?
       LIMIT 1`,
      [callSid, MORTGAGE_TENANT_ID],
    );

    if (rows.length === 0 || !rows[0].recording_url) {
      return res
        .status(404)
        .json({ success: false, error: "Recording not found" });
    }

    const recordingUrl: string = rows[0].recording_url;

    // --- Proxy Twilio audio with Basic Auth ---
    const accountSid = process.env.TWILIO_ACCOUNT_SID;
    const authToken = process.env.TWILIO_AUTH_TOKEN;
    if (!accountSid || !authToken) {
      return res
        .status(503)
        .json({ success: false, error: "Twilio not configured" });
    }

    const credentials = Buffer.from(`${accountSid}:${authToken}`).toString(
      "base64",
    );

    // Forward Range header so the browser audio player can seek
    const upstreamHeaders: Record<string, string> = {
      Authorization: `Basic ${credentials}`,
    };
    if (req.headers.range) {
      upstreamHeaders["Range"] = req.headers.range;
    }

    const upstream = await fetch(recordingUrl, {
      headers: upstreamHeaders,
      redirect: "follow",
    });

    if (!upstream.ok && upstream.status !== 206) {
      console.error(
        `[handleGetRecording] Twilio returned ${upstream.status} for ${recordingUrl}`,
      );
      return res.status(upstream.status).json({
        success: false,
        error: "Failed to fetch recording from Twilio",
      });
    }

    res.setHeader("Content-Type", "audio/mpeg");
    res.setHeader("Accept-Ranges", "bytes");
    if (isDownload) {
      res.setHeader(
        "Content-Disposition",
        `attachment; filename="call-${callSid}.mp3"`,
      );
    }

    const contentLength = upstream.headers.get("content-length");
    if (contentLength) res.setHeader("Content-Length", contentLength);
    const contentRange = upstream.headers.get("content-range");
    if (contentRange) res.setHeader("Content-Range", contentRange);

    res.status(upstream.status === 206 ? 206 : 200);

    const reader = upstream.body?.getReader();
    if (!reader) return res.status(500).end();
    while (true) {
      const { done, value } = await reader.read();
      if (done) {
        res.end();
        break;
      }
      res.write(value);
    }
  } catch (err) {
    console.error("[handleGetRecording] Error:", err);
    return res
      .status(500)
      .json({ success: false, error: "Failed to stream recording" });
  }
};

/**
 * GET /api/voice/recording-check/:callSid
 * Lightweight poll endpoint — returns recording_url + recording_duration once
 * the Twilio recording-status webhook has stored them. Returns 404 while still processing.
 */
const handleRecordingCheck: RequestHandler = async (req, res) => {
  try {
    const { callSid } = req.params as { callSid: string };

    const [rows] = await pool.query<RowDataPacket[]>(
      `SELECT recording_url, recording_duration FROM communications
       WHERE external_id = ? AND communication_type = 'call' AND tenant_id = ?
       LIMIT 1`,
      [callSid, MORTGAGE_TENANT_ID],
    );

    if (rows.length === 0) {
      return res.status(404).json({ success: false, error: "Call not found" });
    }

    if (!rows[0].recording_url) {
      // Backfill fallback: if Twilio recording-status webhook was delayed/missed,
      // query Twilio directly by CallSid and persist the first completed recording.
      if (twilioClient && process.env.TWILIO_ACCOUNT_SID) {
        try {
          const recordings = await twilioClient.recordings.list({
            callSid,
            limit: 20,
          });
          const completed = recordings.find(
            (r: any) =>
              (r.status as string | undefined)?.toLowerCase?.() === "completed",
          );
          if (completed?.sid) {
            const recordingUrl = `https://api.twilio.com/2010-04-01/Accounts/${process.env.TWILIO_ACCOUNT_SID}/Recordings/${completed.sid}.mp3`;
            const recordingDuration =
              completed.duration != null
                ? parseInt(String(completed.duration), 10)
                : null;

            await pool.query(
              `UPDATE communications
               SET recording_url = COALESCE(recording_url, ?),
                   recording_duration = COALESCE(recording_duration, ?),
                   updated_at = NOW()
               WHERE external_id = ? AND communication_type = 'call' AND tenant_id = ?`,
              [
                recordingUrl,
                Number.isFinite(recordingDuration) ? recordingDuration : null,
                callSid,
                MORTGAGE_TENANT_ID,
              ],
            );

            return res.json({
              success: true,
              ready: true,
              recording_url: recordingUrl,
              recording_duration: Number.isFinite(recordingDuration)
                ? recordingDuration
                : null,
            });
          }
        } catch (twilioErr) {
          console.warn(
            `[handleRecordingCheck] Twilio fallback lookup failed for ${callSid}:`,
            twilioErr,
          );
        }
      }

      return res
        .status(202)
        .json({ success: true, ready: false, recording_url: null });
    }

    return res.json({
      success: true,
      ready: true,
      recording_url: rows[0].recording_url,
      recording_duration: rows[0].recording_duration ?? null,
    });
  } catch (err) {
    console.error("[handleRecordingCheck] Error:", err);
    return res.status(500).json({ success: false, error: "Internal error" });
  }
};

/**
 * GET /api/sms/media
 * Proxies a Twilio MMS media attachment back to the browser.
 * <img src> and <video src> cannot send an Authorization header, so we:
 *   1. Validate the JWT passed in ?token=
 *   2. Ensure the requested URL is a Twilio API URL
 *   3. Fetch from Twilio using Basic auth (AccountSid:AuthToken)
 *   4. Stream the response back with appropriate Content-Type + caching headers.
 */
const handleGetSmsMedia: RequestHandler = async (req, res) => {
  try {
    // ── Auth ────────────────────────────────────────────────────────────────
    const token = req.query.token as string | undefined;
    if (!token) return res.status(401).json({ error: "Missing token" });
    try {
      const { JWT_SECRET } = process.env;
      if (!JWT_SECRET) throw new Error("JWT_SECRET not set");
      (await import("jsonwebtoken")).default.verify(token, JWT_SECRET);
    } catch {
      return res.status(401).json({ error: "Invalid token" });
    }

    const rawUrl = req.query.url as string | undefined;
    if (!rawUrl) return res.status(400).json({ error: "Missing url" });

    // ── Security: only proxy allowed media URL origins ───────────────────────
    const isTwilioUrl = rawUrl.startsWith("https://api.twilio.com/");
    const isCdnUrl = rawUrl.startsWith("https://disruptinglabs.com/");
    if (!isTwilioUrl && !isCdnUrl) {
      return res.status(400).json({ error: "Invalid media URL" });
    }

    const twilioAccountSid = process.env.TWILIO_ACCOUNT_SID;
    const twilioAuthToken = process.env.TWILIO_AUTH_TOKEN;
    if (isTwilioUrl && (!twilioAccountSid || !twilioAuthToken)) {
      return res.status(503).json({ error: "Twilio not configured" });
    }

    const upstream = await fetch(rawUrl, {
      headers: isTwilioUrl
        ? {
            Authorization:
              "Basic " +
              Buffer.from(`${twilioAccountSid}:${twilioAuthToken}`).toString(
                "base64",
              ),
          }
        : {},
    });

    if (!upstream.ok) {
      console.error(
        `[handleGetSmsMedia] Upstream returned ${upstream.status} for ${rawUrl}`,
      );
      return res.status(upstream.status).json({ error: "Media fetch failed" });
    }

    const contentType =
      upstream.headers.get("content-type") || "application/octet-stream";
    res.set("Content-Type", contentType);
    res.set("Cache-Control", "private, max-age=86400");

    const buffer = await upstream.arrayBuffer();
    return res.send(Buffer.from(buffer));
  } catch (err) {
    console.error("[handleGetSmsMedia] Error:", err);
    return res.status(500).json({ error: "Internal error" });
  }
};

// Multer config: memory storage, 10 MB limit, MMS-allowed MIME types only
const mmsUpload = multer({
  storage: multer.memoryStorage(),
  limits: { fileSize: 5 * 1024 * 1024 },
  fileFilter: (_req, file, cb) => {
    const allowed = [
      "image/jpeg",
      "image/png",
      "image/gif",
      "image/webp",
      "video/mp4",
      "video/3gpp",
      "video/quicktime",
      "audio/mpeg",
      "audio/ogg",
      "audio/amr",
      "audio/wav",
      "application/pdf",
    ];
    if (allowed.includes(file.mimetype)) {
      cb(null, true);
    } else {
      cb(new Error(`Unsupported file type: ${file.mimetype}`));
    }
  },
});

/**
 * POST /api/sms/media/upload
 * Accepts a multipart file upload from the broker UI, forwards it to the
 * PHP uploadMMS.php endpoint (secret stays server-side), and returns the
 * public URL for use as Twilio mediaUrl.
 */
const handleUploadMMSMedia: RequestHandler = async (req, res) => {
  try {
    const file = (req as any).file as Express.Multer.File | undefined;
    if (!file) {
      return res.status(400).json({ error: "No file provided" });
    }

    const allowedTypes = [
      "image/jpeg",
      "image/png",
      "image/gif",
      "image/webp",
      "video/mp4",
      "video/3gpp",
      "video/quicktime",
      "audio/mpeg",
      "audio/ogg",
      "audio/wav",
      "audio/amr",
      "application/pdf",
    ];
    if (!allowedTypes.includes(file.mimetype)) {
      return res.status(400).json({ error: "Unsupported file type" });
    }

    // Store file bytes directly in the database so Twilio can fetch them
    // from our own public endpoint with the correct Content-Type.
    // The disruptinglabs.com CDN directory returns HTML for every request
    // (Apache catch-all), making it unusable for serving MMS media.
    const mediaId = crypto.randomUUID();
    // expires_at = 24 hours from now; Twilio processes MMS within minutes
    await pool.query(
      "INSERT INTO mms_media (id, content_type, data, expires_at) VALUES (?, ?, ?, DATE_ADD(NOW(), INTERVAL 72 HOUR))",
      [mediaId, file.mimetype, file.buffer],
    );

    // Build the public URL that Twilio will fetch when sending the MMS.
    // MMS_PUBLIC_URL must be set to the production domain when developing
    // locally so Twilio (an external service) can reach the endpoint.
    const mmsBase = process.env.MMS_PUBLIC_URL || getBaseUrl();
    const publicUrl = `${mmsBase}/api/sms/media/public/${mediaId}`;

    return res.json({
      success: true,
      url: publicUrl,
      content_type: file.mimetype,
      filename: file.originalname,
    });
  } catch (err) {
    console.error("[handleUploadMMSMedia] Error:", err);
    return res.status(500).json({ error: "Internal error" });
  }
};

/**
 * GET /api/sms/media/public/:id
 * Public (no-auth) endpoint that serves an MMS file stored in the database.
 * Twilio calls this URL directly when delivering the outbound MMS.
 * Files expire after 24 hours (set at insert time via expires_at column).
 */
const handleServeMmsMediaPublic: RequestHandler = async (req, res) => {
  try {
    const id = req.params.id as string;

    // Validate: UUID format only — prevents SQL injection and path traversal
    if (
      !id ||
      !/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/.test(id)
    ) {
      return res.status(400).json({ error: "Invalid media ID" });
    }

    const [rows] = await pool.query<any[]>(
      "SELECT content_type, data FROM mms_media WHERE id = ? AND expires_at > NOW()",
      [id],
    );

    if (!rows.length) {
      return res.status(404).json({ error: "Media not found or expired" });
    }

    const { content_type, data } = rows[0];
    res.set("Content-Type", content_type);
    res.set("Cache-Control", "public, max-age=3600");
    return res.send(Buffer.isBuffer(data) ? data : Buffer.from(data));
  } catch (err) {
    console.error("[handleServeMmsMediaPublic] Error:", err);
    return res.status(500).json({ error: "Internal error" });
  }
};

/**
 * GET /api/cron/expire-quota-reservations
 * Releases quota held by pending tenant_usage_reservations past expires_at.
 * Run every 15–30 min via cPanel cron.
 * Requires ?secret=CRON_SECRET or Authorization: Bearer CRON_SECRET.
 */
const handleCronExpireQuotaReservations: RequestHandler = async (req, res) => {
  const secret = process.env.CRON_SECRET;
  const provided =
    (req.query.secret as string | undefined) ||
    req.headers.authorization?.replace(/^Bearer\s+/i, "");
  if (!secret || provided !== secret) {
    return res.status(401).json({ error: "Unauthorized" });
  }
  try {
    const { expired } = await quotaService.expireStaleReservations(200);
    console.log(
      `[handleCronExpireQuotaReservations] Expired ${expired} stale reservation(s)`,
    );
    return res.json({ success: true, expired });
  } catch (err) {
    console.error("[handleCronExpireQuotaReservations] Error:", err);
    return res.status(500).json({ error: "Internal error" });
  }
};

/**
 * GET /api/cron/purge-mms-media
 * Deletes expired rows from mms_media (expires_at <= NOW()).
 * Run daily via cPanel cron — files are only needed by Twilio during delivery (minutes).
 * Requires ?secret=CRON_SECRET or Authorization: Bearer CRON_SECRET.
 */
const handleCronPurgeMmsMedia: RequestHandler = async (req, res) => {
  const secret = process.env.CRON_SECRET;
  const provided =
    (req.query.secret as string | undefined) ||
    req.headers.authorization?.replace(/^Bearer\s+/i, "");
  if (!secret || provided !== secret) {
    return res.status(401).json({ error: "Unauthorized" });
  }
  try {
    const [result] = await pool.query<any>(
      "DELETE FROM mms_media WHERE expires_at <= NOW()",
    );
    const deleted = result.affectedRows ?? 0;
    console.log(`[handleCronPurgeMmsMedia] Deleted ${deleted} expired row(s)`);
    return res.json({ success: true, deleted });
  } catch (err) {
    console.error("[handleCronPurgeMmsMedia] Error:", err);
    return res.status(500).json({ error: "Internal error" });
  }
};

/** Max rows touched per table per cron tick (avoids Vercel timeout on large backlogs). */
const PURGE_OLD_DATA_BATCH = 10_000;

/**
 * GET /api/cron/purge-old-data
 * Batched retention cleanup — logs, expired sessions, email body trim, etc.
 * Run weekly via cPanel cron; use scripts/purge-old-data.mjs --execute for one-time bulk purge.
 * Requires ?secret=CRON_SECRET or Authorization: Bearer CRON_SECRET.
 */
const handleCronPurgeOldData: RequestHandler = async (req, res) => {
  const secret = process.env.CRON_SECRET;
  const provided =
    (req.query.secret as string | undefined) ||
    req.headers.authorization?.replace(/^Bearer\s+/i, "");
  if (!secret || provided !== secret) {
    return res.status(401).json({ error: "Unauthorized" });
  }

  const batch = PURGE_OLD_DATA_BATCH;
  const results: Record<string, number> = {};

  const batchedDelete = async (
    key: string,
    sql: string,
    params: unknown[] = [],
  ) => {
    const [result] = await pool.query<any>(sql, params);
    results[key] = result.affectedRows ?? 0;
  };

  try {
    await batchedDelete(
      "mms_media",
      "DELETE FROM mms_media WHERE expires_at <= NOW() LIMIT ?",
      [batch],
    );
    await batchedDelete(
      "broker_sessions",
      "DELETE FROM broker_sessions WHERE expires_at < NOW() LIMIT ?",
      [batch],
    );
    await batchedDelete(
      "user_sessions",
      "DELETE FROM user_sessions WHERE expires_at < NOW() LIMIT ?",
      [batch],
    );
    await batchedDelete(
      "revoked_tokens",
      "DELETE FROM revoked_tokens WHERE expires_at < NOW() LIMIT ?",
      [batch],
    );
    await batchedDelete(
      "audit_logs",
      "DELETE FROM audit_logs WHERE created_at < DATE_SUB(NOW(), INTERVAL 90 DAY) LIMIT ?",
      [batch],
    );
    await batchedDelete(
      "email_sync_log",
      "DELETE FROM email_sync_log WHERE started_at < DATE_SUB(NOW(), INTERVAL 30 DAY) LIMIT ?",
      [batch],
    );
    await batchedDelete(
      "notifications",
      "DELETE FROM notifications WHERE is_read = 1 AND created_at < DATE_SUB(NOW(), INTERVAL 120 DAY) LIMIT ?",
      [batch],
    );
    await batchedDelete(
      "reminder_flow_step_logs",
      "DELETE FROM reminder_flow_step_logs WHERE created_at < DATE_SUB(NOW(), INTERVAL 90 DAY) LIMIT ?",
      [batch],
    );
    await batchedDelete(
      "reminder_flow_executions",
      `DELETE FROM reminder_flow_executions
       WHERE status IN ('completed','failed','cancelled')
         AND updated_at < DATE_SUB(NOW(), INTERVAL 180 DAY)
       LIMIT ?`,
      [batch],
    );
    await batchedDelete(
      "communications_system_event",
      `DELETE FROM communications
       WHERE communication_type = 'system_event'
         AND created_at < DATE_SUB(NOW(), INTERVAL 180 DAY)
       LIMIT ?`,
      [batch],
    );

    const [emailTrim] = await pool.query<any>(
      `UPDATE communications
       SET body = LEFT(body, 400)
       WHERE communication_type = 'email'
         AND CHAR_LENGTH(COALESCE(body,'')) > 400
         AND created_at < DATE_SUB(NOW(), INTERVAL 60 DAY)
       LIMIT ?`,
      [batch],
    );
    results.email_body_trim = emailTrim.affectedRows ?? 0;

    const [jsonTrim] = await pool.query<any>(
      `UPDATE communications
       SET provider_response = NULL, metadata = NULL
       WHERE created_at < DATE_SUB(NOW(), INTERVAL 90 DAY)
         AND (provider_response IS NOT NULL OR metadata IS NOT NULL)
       LIMIT ?`,
      [batch],
    );
    results.provider_json_trim = jsonTrim.affectedRows ?? 0;

    const total = Object.values(results).reduce((a, b) => a + b, 0);
    console.log(
      `[handleCronPurgeOldData] Purged ${total} row(s)/updates:`,
      results,
    );
    return res.json({ success: true, batch_limit: batch, results, total });
  } catch (err) {
    console.error("[handleCronPurgeOldData] Error:", err);
    return res.status(500).json({ error: "Internal error" });
  }
};

/**
 * GET /api/voice/calls
 * Return paginated call history (communications where type='call') for the authenticated broker.
 */
const handleGetCallHistory: RequestHandler = async (req, res) => {
  try {
    const brokerId = (req as any).brokerId;
    const page = Math.max(1, parseInt(req.query.page as string) || 1);
    const limit = Math.min(
      100,
      Math.max(1, parseInt(req.query.limit as string) || 50),
    );
    const offset = (page - 1) * limit;

    const [countRows] = await pool.query<any>(
      `SELECT COUNT(*) AS total
       FROM communications c
       LEFT JOIN conversation_threads ct
         ON c.conversation_id = ct.conversation_id AND ct.tenant_id = ?
       WHERE c.communication_type = 'call'
         AND c.tenant_id = ?
         AND (c.from_broker_id = ? OR ct.broker_id = ?)`,
      [MORTGAGE_TENANT_ID, MORTGAGE_TENANT_ID, brokerId, brokerId],
    );
    const total = countRows[0]?.total ?? 0;

    const [rows] = await pool.query<any>(
      `SELECT c.id, c.direction, c.body, c.status, c.external_id,
              c.conversation_id, c.created_at, c.sent_at,
              ct.client_name, ct.client_phone, ct.client_id
       FROM communications c
       LEFT JOIN conversation_threads ct
         ON c.conversation_id = ct.conversation_id AND ct.tenant_id = ?
       WHERE c.communication_type = 'call'
         AND c.tenant_id = ?
         AND (c.from_broker_id = ? OR ct.broker_id = ?)
       ORDER BY c.created_at DESC
       LIMIT ? OFFSET ?`,
      [
        MORTGAGE_TENANT_ID,
        MORTGAGE_TENANT_ID,
        brokerId,
        brokerId,
        limit,
        offset,
      ],
    );

    return res.json({
      success: true,
      calls: rows,
      pagination: { page, limit, total, totalPages: Math.ceil(total / limit) },
    });
  } catch (error) {
    console.error("Error fetching call history:", error);
    return res
      .status(500)
      .json({ success: false, error: "Failed to fetch call history" });
  }
};

/**
 * GET /api/conversations/lookup-contact
 * Look up a client by phone number to resolve a name for incoming calls.
 */
const handleLookupContact: RequestHandler = async (req, res) => {
  try {
    const { phone } = req.query;
    if (!phone || typeof phone !== "string") {
      return res
        .status(400)
        .json({ success: false, error: "phone is required" });
    }

    // Normalise to last-10-digits for fuzzy matching
    const digits = phone.replace(/\D/g, "");
    const lastTen = digits.slice(-10);
    const e164 = `+1${lastTen}`;

    // 1. Try clients table — match on exact, e164, or last-10-digit suffix
    const [clientRows] = await pool.query<any>(
      `SELECT id, first_name, last_name, phone
       FROM clients
       WHERE tenant_id = ?
         AND (
           phone = ?
           OR phone = ?
           OR RIGHT(REGEXP_REPLACE(phone, '[^0-9]', ''), 10) = ?
         )
       LIMIT 1`,
      [MORTGAGE_TENANT_ID, phone, e164, lastTen],
    );

    if (clientRows.length) {
      const c = clientRows[0];
      return res.json({
        success: true,
        found: true,
        client_id: c.id,
        client_name: `${c.first_name ?? ""} ${c.last_name ?? ""}`.trim(),
        phone: c.phone,
        source: "client",
      });
    }

    // 2. Fallback: check leads table (pre-conversion contacts)
    const [leadRows] = await pool.query<any>(
      `SELECT id, first_name, last_name, phone
       FROM leads
       WHERE tenant_id = ?
         AND (
           phone = ?
           OR phone = ?
           OR RIGHT(REGEXP_REPLACE(phone, '[^0-9]', ''), 10) = ?
         )
       LIMIT 1`,
      [MORTGAGE_TENANT_ID, phone, e164, lastTen],
    );

    if (leadRows.length) {
      const l = leadRows[0];
      return res.json({
        success: true,
        found: true,
        client_id: null,
        lead_id: l.id,
        client_name: `${l.first_name ?? ""} ${l.last_name ?? ""}`.trim(),
        phone: l.phone,
        source: "lead",
      });
    }

    // 3. Fallback: check conversation_threads for a stored client_name on this phone
    const [threadRows] = await pool.query<any>(
      `SELECT client_id, client_name, client_phone
       FROM conversation_threads
       WHERE tenant_id = ?
         AND (
           client_phone = ?
           OR client_phone = ?
           OR RIGHT(REGEXP_REPLACE(client_phone, '[^0-9]', ''), 10) = ?
         )
         AND client_name IS NOT NULL
         AND client_name != ''
       ORDER BY last_message_at DESC
       LIMIT 1`,
      [MORTGAGE_TENANT_ID, phone, e164, lastTen],
    );

    if (threadRows.length) {
      const t = threadRows[0];
      return res.json({
        success: true,
        found: true,
        client_id: t.client_id ?? null,
        client_name: t.client_name,
        phone: t.client_phone,
        source: "thread",
      });
    }

    return res.json({ success: true, found: false });
  } catch (error) {
    console.error("Error looking up contact:", error);
    return res
      .status(500)
      .json({ success: false, error: "Failed to lookup contact" });
  }
};

/**
 * GET /api/audit-logs
 * Get all audit logs with optional filters
 */
const handleGetAuditLogs: RequestHandler = async (req, res) => {
  try {
    const brokerId = (req as any).brokerId;
    const {
      actor_type,
      action,
      entity_type,
      status,
      from_date,
      to_date,
      limit = 100,
      offset = 0,
    } = req.query;

    // Build dynamic query
    let query = `
      SELECT 
        al.*,
        COALESCE(b.email, c.email) as actor_email,
        COALESCE(CONCAT(b.first_name, ' ', b.last_name), CONCAT(c.first_name, ' ', c.last_name)) as actor_name
      FROM audit_logs al
      LEFT JOIN brokers b ON al.broker_id = b.id
      LEFT JOIN clients c ON al.user_id = c.id
      WHERE al.tenant_id = ?
    `;

    const queryParams: any[] = [MORTGAGE_TENANT_ID];

    if (actor_type) {
      query += ` AND al.actor_type = ?`;
      queryParams.push(actor_type);
    }

    if (action) {
      query += ` AND al.action LIKE ?`;
      queryParams.push(`%${action}%`);
    }

    if (entity_type) {
      query += ` AND al.entity_type = ?`;
      queryParams.push(entity_type);
    }

    if (status) {
      query += ` AND al.status = ?`;
      queryParams.push(status);
    }

    if (from_date) {
      query += ` AND al.created_at >= ?`;
      queryParams.push(from_date);
    }

    if (to_date) {
      query += ` AND al.created_at <= ?`;
      queryParams.push(to_date);
    }

    query += ` ORDER BY al.created_at DESC LIMIT ${parseInt(limit as string)} OFFSET ${parseInt(offset as string)}`;

    const [logs] = await pool.query<RowDataPacket[]>(query, queryParams);

    // Get total count for pagination
    let countQuery = `SELECT COUNT(*) as total FROM audit_logs WHERE tenant_id = ?`;
    const countParams: any[] = [MORTGAGE_TENANT_ID];

    if (actor_type) {
      countQuery += ` AND actor_type = ?`;
      countParams.push(actor_type);
    }

    if (action) {
      countQuery += ` AND action LIKE ?`;
      countParams.push(`%${action}%`);
    }

    if (entity_type) {
      countQuery += ` AND entity_type = ?`;
      countParams.push(entity_type);
    }

    if (status) {
      countQuery += ` AND status = ?`;
      countParams.push(status);
    }

    if (from_date) {
      countQuery += ` AND created_at >= ?`;
      countParams.push(from_date);
    }

    if (to_date) {
      countQuery += ` AND created_at <= ?`;
      countParams.push(to_date);
    }

    const [countResult] = await pool.query<RowDataPacket[]>(
      countQuery,
      countParams,
    );

    // Create audit log for viewing audit logs
    await createAuditLog({
      actorType: "broker",
      actorId: brokerId,
      action: "view_audit_logs",
      ipAddress: req.ip,
      userAgent: req.headers["user-agent"],
    });

    res.json({
      success: true,
      logs,
      total: countResult[0].total,
      limit: parseInt(limit as string),
      offset: parseInt(offset as string),
    });
  } catch (error) {
    console.error("Error fetching audit logs:", error);
    res.status(500).json({
      success: false,
      error:
        error instanceof Error ? error.message : "Failed to fetch audit logs",
    });
  }
};

/**
 * GET /api/audit-logs/stats
 * Get audit log statistics
 */
const handleGetAuditLogStats: RequestHandler = async (req, res) => {
  try {
    const brokerId = (req as any).brokerId;

    // Get various statistics
    const [totalLogs] = await pool.query<RowDataPacket[]>(
      "SELECT COUNT(*) as count FROM audit_logs WHERE tenant_id = ?",
      [MORTGAGE_TENANT_ID],
    );

    const [logsByStatus] = await pool.query<RowDataPacket[]>(
      "SELECT status, COUNT(*) as count FROM audit_logs WHERE tenant_id = ? GROUP BY status",
      [MORTGAGE_TENANT_ID],
    );

    const [logsByActorType] = await pool.query<RowDataPacket[]>(
      "SELECT actor_type, COUNT(*) as count FROM audit_logs WHERE tenant_id = ? GROUP BY actor_type",
      [MORTGAGE_TENANT_ID],
    );

    const [logsByAction] = await pool.query<RowDataPacket[]>(
      `SELECT action, COUNT(*) as count 
       FROM audit_logs
       WHERE tenant_id = ? 
       GROUP BY action 
       ORDER BY count DESC 
       LIMIT 10`,
      [MORTGAGE_TENANT_ID],
    );

    const [recentActivity] = await pool.query<RowDataPacket[]>(
      `SELECT 
        DATE(created_at) as date, 
        COUNT(*) as count 
       FROM audit_logs 
       WHERE created_at >= DATE_SUB(NOW(), INTERVAL 30 DAY)
       GROUP BY DATE(created_at)
       ORDER BY date DESC`,
    );

    res.json({
      success: true,
      stats: {
        total: totalLogs[0].count,
        byStatus: logsByStatus,
        byActorType: logsByActorType,
        topActions: logsByAction,
        recentActivity,
      },
    });
  } catch (error) {
    console.error("Error fetching audit log stats:", error);
    res.status(500).json({
      success: false,
      error:
        error instanceof Error
          ? error.message
          : "Failed to fetch audit log stats",
    });
  }
};

/**
 * GET /api/reports/overview
 * Get comprehensive report overview with all statistics
 */
const handleGetReportsOverview: RequestHandler = async (req, res) => {
  try {
    const brokerId = (req as any).brokerId;
    const { from_date, to_date } = req.query;

    // Build date filter
    let dateFilter = "";
    const dateParams: any[] = [];
    if (from_date && to_date) {
      dateFilter = " AND created_at BETWEEN ? AND ?";
      dateParams.push(from_date, to_date);
    }

    // Loan statistics
    const [loanStats] = await pool.query<RowDataPacket[]>(
      `SELECT 
        COUNT(*) as total_loans,
        SUM(CASE WHEN status = 'approved' THEN 1 ELSE 0 END) as approved_loans,
        SUM(CASE WHEN status = 'submitted' THEN 1 ELSE 0 END) as pending_loans,
        SUM(CASE WHEN status = 'denied' THEN 1 ELSE 0 END) as rejected_loans,
        SUM(CASE WHEN status = 'under_review' THEN 1 ELSE 0 END) as in_review_loans,
        AVG(CAST(loan_amount AS DECIMAL(15,2))) as avg_loan_amount,
        SUM(CAST(loan_amount AS DECIMAL(15,2))) as total_loan_volume
      FROM loan_applications 
      WHERE broker_user_id = ? AND tenant_id = ?${dateFilter}`,
      [brokerId, MORTGAGE_TENANT_ID, ...dateParams],
    );

    // Loans by type
    const [loansByType] = await pool.query<RowDataPacket[]>(
      `SELECT loan_type, COUNT(*) as count 
       FROM loan_applications 
       WHERE broker_user_id = ? AND tenant_id = ?${dateFilter}
       GROUP BY loan_type`,
      [brokerId, MORTGAGE_TENANT_ID, ...dateParams],
    );

    // Loans by status over time
    const [loansTrend] = await pool.query<RowDataPacket[]>(
      `SELECT 
        DATE(created_at) as date,
        status,
        COUNT(*) as count
       FROM loan_applications 
       WHERE broker_user_id = ? AND tenant_id = ?${dateFilter}
       GROUP BY DATE(created_at), status
       ORDER BY date DESC
       LIMIT 30`,
      [brokerId, MORTGAGE_TENANT_ID, ...dateParams],
    );

    // Client statistics
    const [clientStats] = await pool.query<RowDataPacket[]>(
      `SELECT 
        COUNT(*) as total_clients,
        SUM(CASE WHEN status = 'active' THEN 1 ELSE 0 END) as active_clients,
        AVG(credit_score) as avg_credit_score
      FROM clients 
      WHERE assigned_broker_id = ?${dateFilter}`,
      [brokerId, ...dateParams],
    );

    // Task statistics
    const [taskStats] = await pool.query<RowDataPacket[]>(
      `SELECT 
        COUNT(*) as total_tasks,
        SUM(CASE WHEN t.status = 'completed' THEN 1 ELSE 0 END) as completed_tasks,
        SUM(CASE WHEN t.status = 'pending' THEN 1 ELSE 0 END) as pending_tasks,
        SUM(CASE WHEN t.status = 'in_progress' THEN 1 ELSE 0 END) as in_progress_tasks
      FROM tasks t
      JOIN loan_applications la ON t.application_id = la.id
      WHERE la.broker_user_id = ?${dateFilter.replace("created_at", "t.created_at")}`,
      [brokerId, ...dateParams],
    );

    // Communication statistics
    const [commStats] = await pool.query<RowDataPacket[]>(
      `SELECT 
        communication_type,
        COUNT(*) as count
      FROM communications c
      JOIN loan_applications la ON c.application_id = la.id
      WHERE la.broker_user_id = ?${dateFilter.replace("created_at", "c.created_at")}
      GROUP BY communication_type`,
      [brokerId, ...dateParams],
    );

    // Document statistics
    const [docStats] = await pool.query<RowDataPacket[]>(
      `SELECT 
        COUNT(*) as total_documents,
        SUM(CASE WHEN d.status = 'approved' THEN 1 ELSE 0 END) as verified_documents,
        document_type,
        COUNT(*) as count
      FROM documents d
      JOIN loan_applications la ON d.application_id = la.id
      WHERE la.broker_user_id = ?${dateFilter.replace("created_at", "d.created_at")}
      GROUP BY document_type`,
      [brokerId, ...dateParams],
    );

    res.json({
      success: true,
      data: {
        loans: loanStats[0],
        loansByType,
        loansTrend,
        clients: clientStats[0],
        tasks: taskStats[0],
        communications: commStats,
        documents: docStats,
      },
    });
  } catch (error) {
    console.error("Error fetching reports overview:", error);
    res.status(500).json({
      success: false,
      error:
        error instanceof Error
          ? error.message
          : "Failed to fetch reports overview",
    });
  }
};

/**
 * GET /api/reports/revenue
 * Get revenue and financial analytics
 */
const handleGetRevenueReport: RequestHandler = async (req, res) => {
  try {
    const brokerId = (req as any).brokerId;
    const { from_date, to_date, group_by = "month" } = req.query;

    let dateFilter = "";
    const dateParams: any[] = [];
    if (from_date && to_date) {
      dateFilter = " AND created_at BETWEEN ? AND ?";
      dateParams.push(from_date, to_date);
    }

    // Group by month or week
    const dateFormat = group_by === "week" ? "%Y-%u" : "%Y-%m";

    const [revenue] = await pool.query<RowDataPacket[]>(
      `SELECT 
        DATE_FORMAT(created_at, ?) as period,
        COUNT(*) as loan_count,
        SUM(CAST(loan_amount AS DECIMAL(15,2))) as total_amount,
        AVG(CAST(loan_amount AS DECIMAL(15,2))) as avg_amount,
        loan_type
      FROM loan_applications 
      WHERE broker_user_id = ? AND tenant_id = ?${dateFilter}
      GROUP BY period, loan_type
      ORDER BY period DESC`,
      [dateFormat, brokerId, MORTGAGE_TENANT_ID, ...dateParams],
    );

    res.json({
      success: true,
      data: revenue,
    });
  } catch (error) {
    console.error("Error fetching revenue report:", error);
    res.status(500).json({
      success: false,
      error:
        error instanceof Error
          ? error.message
          : "Failed to fetch revenue report",
    });
  }
};

/**
 * GET /api/reports/performance
 * Get broker/team performance metrics
 */
const handleGetPerformanceReport: RequestHandler = async (req, res) => {
  try {
    const brokerId = (req as any).brokerId;
    const { from_date, to_date } = req.query;

    let dateFilter = "";
    const dateParams: any[] = [];
    if (from_date && to_date) {
      dateFilter = " AND created_at BETWEEN ? AND ?";
      dateParams.push(from_date, to_date);
    }

    // Conversion rates
    const [conversionRate] = await pool.query<RowDataPacket[]>(
      `SELECT 
        COUNT(*) as total_applications,
        SUM(CASE WHEN status = 'approved' THEN 1 ELSE 0 END) as approved,
        ROUND((SUM(CASE WHEN status = 'approved' THEN 1 ELSE 0 END) / COUNT(*)) * 100, 2) as approval_rate
      FROM loan_applications 
      WHERE broker_user_id = ? AND tenant_id = ?${dateFilter}`,
      [brokerId, MORTGAGE_TENANT_ID, ...dateParams],
    );

    // Average processing time
    const [processingTime] = await pool.query<RowDataPacket[]>(
      `SELECT 
        AVG(DATEDIFF(updated_at, created_at)) as avg_days,
        status
      FROM loan_applications 
      WHERE broker_user_id = ? AND tenant_id = ?${dateFilter}
      GROUP BY status`,
      [brokerId, MORTGAGE_TENANT_ID, ...dateParams],
    );

    // Task completion rate
    const [taskCompletion] = await pool.query<RowDataPacket[]>(
      `SELECT 
        COUNT(*) as total_tasks,
        SUM(CASE WHEN t.status = 'completed' THEN 1 ELSE 0 END) as completed,
        ROUND((SUM(CASE WHEN t.status = 'completed' THEN 1 ELSE 0 END) / COUNT(*)) * 100, 2) as completion_rate,
        AVG(CASE WHEN t.status = 'completed' THEN DATEDIFF(t.updated_at, t.created_at) ELSE NULL END) as avg_completion_days
      FROM tasks t
      JOIN loan_applications la ON t.application_id = la.id
      WHERE la.broker_user_id = ?${dateFilter.replace("created_at", "t.created_at")}`,
      [brokerId, ...dateParams],
    );

    res.json({
      success: true,
      data: {
        conversionRate: conversionRate[0],
        processingTime,
        taskCompletion: taskCompletion[0],
      },
    });
  } catch (error) {
    console.error("Error fetching performance report:", error);
    res.status(500).json({
      success: false,
      error:
        error instanceof Error
          ? error.message
          : "Failed to fetch performance report",
    });
  }
};

