  /** Await scheduler emails before HTTP response — Vercel can freeze the lambda after res.json(). */
  async function dispatchSchedulerEmails(
    label: string,
    tasks: Array<() => Promise<void>>,
  ): Promise<void> {
    const results = await Promise.allSettled(tasks.map((run) => run()));
    results.forEach((result, index) => {
      if (result.status === "rejected") {
        console.error(
          `[SchedulerEmail] ${label} task ${index + 1} failed:`,
          result.reason,
        );
      }
    });
  }

  // ---- Zoom Server-to-Server OAuth helper ----

  let _zoomAccessToken: string | null = null;
  let _zoomTokenExpiry = 0;

  async function getZoomAccessToken(): Promise<string | null> {
    const accountId = process.env.ZOOM_ACCOUNT_ID;
    const clientId = process.env.ZOOM_CLIENT_ID;
    const clientSecret = process.env.ZOOM_CLIENT_SECRET;
    if (!accountId || !clientId || !clientSecret) return null;

    if (_zoomAccessToken && Date.now() < _zoomTokenExpiry) {
      return _zoomAccessToken;
    }

    const credentials = Buffer.from(`${clientId}:${clientSecret}`).toString(
      "base64",
    );
    const resp = await fetch(
      `https://zoom.us/oauth/token?grant_type=account_credentials&account_id=${accountId}`,
      {
        method: "POST",
        headers: {
          Authorization: `Basic ${credentials}`,
          "Content-Type": "application/x-www-form-urlencoded",
        },
      },
    );
    if (!resp.ok) {
      console.error("Zoom token fetch failed:", resp.status, await resp.text());
      return null;
    }
    const json = (await resp.json()) as {
      access_token: string;
      expires_in: number;
    };
    _zoomAccessToken = json.access_token;
    _zoomTokenExpiry = Date.now() + (json.expires_in - 60) * 1000; // refresh 60s early
    return _zoomAccessToken;
  }

  async function createZoomMeeting(opts: {
    topic: string;
    startDatetime: string; // ISO 8601 e.g. "2026-03-22T14:00:00"
    durationMinutes: number;
    timezone: string;
  }): Promise<{
    meeting_id: string;
    join_url: string;
    start_url: string;
  } | null> {
    const token = await getZoomAccessToken();
    if (!token) return null;

    const resp = await fetch("https://api.zoom.us/v2/users/me/meetings", {
      method: "POST",
      headers: {
        Authorization: `Bearer ${token}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        topic: opts.topic,
        type: 2, // scheduled
        start_time: opts.startDatetime,
        duration: opts.durationMinutes,
        timezone: opts.timezone,
        settings: {
          waiting_room: false,
          join_before_host: true,
          mute_upon_entry: false,
          participant_video: true,
          host_video: true,
        },
      }),
    });

    if (!resp.ok) {
      console.error(
        "Zoom create meeting failed:",
        resp.status,
        await resp.text(),
      );
      return null;
    }
    const data = (await resp.json()) as {
      id: number;
      join_url: string;
      start_url: string;
    };
    return {
      meeting_id: String(data.id),
      join_url: data.join_url,
      start_url: data.start_url,
    };
  }

  let _microsoftGraphAccessToken: string | null = null;
  let _microsoftGraphTokenExpiry = 0;

  async function getMicrosoftGraphAccessToken(): Promise<string | null> {
    const tenantId = process.env.OFFICE365_TENANT_ID;
    const clientId = process.env.OFFICE365_CLIENT_ID;
    const clientSecret = process.env.OFFICE365_CLIENT_SECRET;
    if (!tenantId || !clientId || !clientSecret) return null;

    if (_microsoftGraphAccessToken && Date.now() < _microsoftGraphTokenExpiry) {
      return _microsoftGraphAccessToken;
    }

    const params = new URLSearchParams();
    params.set("grant_type", "client_credentials");
    params.set("client_id", clientId);
    params.set("client_secret", clientSecret);
    params.set("scope", "https://graph.microsoft.com/.default");

    const resp = await fetch(
      `https://login.microsoftonline.com/${encodeURIComponent(tenantId)}/oauth2/v2.0/token`,
      {
        method: "POST",
        headers: { "Content-Type": "application/x-www-form-urlencoded" },
        body: params.toString(),
      },
    );

    if (!resp.ok) {
      console.error(
        "Microsoft Graph token fetch failed:",
        resp.status,
        await resp.text(),
      );
      return null;
    }

    const json = (await resp.json()) as {
      access_token: string;
      expires_in: number;
    };

    _microsoftGraphAccessToken = json.access_token;
    _microsoftGraphTokenExpiry = Date.now() + (json.expires_in - 60) * 1000;
    return _microsoftGraphAccessToken;
  }

  async function createTeamsMeeting(opts: {
    organizerEmail: string;
    subject: string;
    startDatetime: string;
    endDatetime: string;
  }): Promise<
    | {
        meeting_id: string;
        join_url: string;
        host_url: string | null;
      }
    | { policyPending: true }
    | null
  > {
    const normalizeGraphDateTime = (value: string): string => {
      // Graph onlineMeetings expects timezone-aware ISO datetimes.
      return /(?:Z|[+-]\d{2}:\d{2})$/.test(value) ? value : `${value}Z`;
    };

    const token = await getMicrosoftGraphAccessToken();
    if (!token) return null;
    const configuredOrganizerId =
      process.env.OFFICE365_TEAMS_ORGANIZER_ID?.trim() || "";
    const configuredOrganizerEmail =
      process.env.OFFICE365_TEAMS_ORGANIZER_EMAIL?.trim() || "";

    const organizerCandidates = Array.from(
      new Set(
        [configuredOrganizerId, configuredOrganizerEmail, opts.organizerEmail]
          .map((v) => v.trim())
          .filter(Boolean),
      ),
    );

    if (organizerCandidates.length === 0) {
      console.error("Teams create meeting failed: no organizer candidate");
      return null;
    }

    let lastError: { status: number; body: string; organizer: string } | null =
      null;
    let policyPendingDetected = false;

    for (const organizer of organizerCandidates) {
      const resp = await fetch(
        `https://graph.microsoft.com/v1.0/users/${encodeURIComponent(organizer)}/onlineMeetings`,
        {
          method: "POST",
          headers: {
            Authorization: `Bearer ${token}`,
            "Content-Type": "application/json",
          },
          body: JSON.stringify({
            subject: opts.subject,
            startDateTime: normalizeGraphDateTime(opts.startDatetime),
            endDateTime: normalizeGraphDateTime(opts.endDatetime),
          }),
        },
      );

      if (resp.ok) {
        const data = (await resp.json()) as {
          id: string;
          joinWebUrl: string;
        };
        return {
          meeting_id: data.id,
          join_url: data.joinWebUrl,
          host_url: data.joinWebUrl,
        };
      }

      const body = await resp.text();
      console.error(
        "Teams create meeting attempt failed:",
        resp.status,
        "organizer:",
        organizer,
        body,
      );
      lastError = { status: resp.status, body, organizer };

      if (resp.status === 404) {
        try {
          const parsed = JSON.parse(body);
          if (parsed?.error?.code === "UnknownError") {
            policyPendingDetected = true;
          }
        } catch {
          // body not JSON — treat as generic 404
        }
        continue;
      }
      if (resp.status === 403) {
        continue;
      }
    }

    if (lastError) {
      console.error(
        "Teams create meeting failed:",
        lastError.status,
        "organizer:",
        lastError.organizer,
        lastError.body,
      );
    }
    if (policyPendingDetected) return { policyPending: true };
    return null;
  }

  async function validateTeamsOrganizerEligibility(opts: {
    brokerEmail: string;
  }): Promise<{ ok: true } | { ok: false; error: string }> {
    const overrideOrganizerId =
      process.env.OFFICE365_TEAMS_ORGANIZER_ID?.trim() || "";
    const overrideOrganizerEmail =
      process.env.OFFICE365_TEAMS_ORGANIZER_EMAIL?.trim() || "";

    // If a global organizer override exists, teams meetings do not depend on
    // each broker email being a tenant user.
    if (overrideOrganizerId || overrideOrganizerEmail) {
      return { ok: true };
    }

    const token = await getMicrosoftGraphAccessToken();
    if (!token) {
      return {
        ok: false,
        error:
          "Teams is not configured in server environment. Set OFFICE365_TENANT_ID, OFFICE365_CLIENT_ID and OFFICE365_CLIENT_SECRET.",
      };
    }

    const resp = await fetch(
      `https://graph.microsoft.com/v1.0/users/${encodeURIComponent(opts.brokerEmail)}?$select=id,mail,userPrincipalName`,
      {
        headers: { Authorization: `Bearer ${token}` },
      },
    );

    if (resp.ok) {
      return { ok: true };
    }

    if (resp.status === 404) {
      return {
        ok: false,
        error:
          "Cannot enable Teams: this broker email is not a Microsoft 365 user in your tenant. Use a tenant mailbox for the broker or set OFFICE365_TEAMS_ORGANIZER_ID / OFFICE365_TEAMS_ORGANIZER_EMAIL as a global organizer.",
      };
    }

    if (resp.status === 403) {
      return {
        ok: false,
        error:
          "Cannot verify Teams eligibility for this broker email. Azure app permissions are insufficient to read users. Grant directory read permission or configure OFFICE365_TEAMS_ORGANIZER_ID / OFFICE365_TEAMS_ORGANIZER_EMAIL.",
      };
    }

    return {
      ok: false,
      error:
        "Unable to validate Teams organizer eligibility right now. Please try again in a moment.",
    };
  }

  /** YYYY-MM-DD for "today" in broker IANA timezone. */
  function todayDateStrInTimezone(timezone: string): string {
    return new Intl.DateTimeFormat("en-CA", { timeZone: timezone }).format(
      new Date(),
    );
  }

  /** 0=Sun … 6=Sat for YYYY-MM-DD interpreted in broker timezone. */
  function getDayOfWeekInTimezone(dateStr: string, timezone: string): number {
    const noonUtc = new Date(`${dateStr}T12:00:00Z`);
    const weekday = new Intl.DateTimeFormat("en-US", {
      timeZone: timezone,
      weekday: "short",
    }).format(noonUtc);
    const map: Record<string, number> = {
      Sun: 0,
      Mon: 1,
      Tue: 2,
      Wed: 3,
      Thu: 4,
      Fri: 5,
      Sat: 6,
    };
    return map[weekday] ?? noonUtc.getUTCDay();
  }

  /** UTC instant for wall-clock date + HH:mm in broker timezone. */
  function brokerLocalDateTimeToUtc(
    dateStr: string,
    timeStr: string,
    timezone: string,
  ): Date {
    const [y, mo, d] = dateStr.split("-").map(Number);
    const [h, mi] = timeStr.split(":").map(Number);
    const utcGuess = Date.UTC(y, mo - 1, d, h, mi, 0);
    const parts = new Intl.DateTimeFormat("en-US", {
      timeZone: timezone,
      year: "numeric",
      month: "2-digit",
      day: "2-digit",
      hour: "2-digit",
      minute: "2-digit",
      hour12: false,
    }).formatToParts(new Date(utcGuess));
    const get = (type: string) =>
      parseInt(parts.find((p) => p.type === type)?.value ?? "0", 10);
    const gotMs = Date.UTC(
      get("year"),
      get("month") - 1,
      get("day"),
      get("hour") % 24,
      get("minute"),
      0,
    );
    const wantedMs = Date.UTC(y, mo - 1, d, h, mi, 0);
    return new Date(utcGuess + (wantedMs - gotMs));
  }

  function addCalendarDaysInTimezone(
    dateStr: string,
    days: number,
    timezone: string,
  ): string {
    const base = brokerLocalDateTimeToUtc(dateStr, "12:00", timezone);
    const shifted = new Date(base.getTime() + days * 86_400_000);
    return new Intl.DateTimeFormat("en-CA", { timeZone: timezone }).format(
      shifted,
    );
  }

  // ---- Helper: convert a UTC Date to minutes-from-midnight in a given IANA timezone ----
  function utcDateToLocalMinutes(date: Date, timezone: string): number {
    const parts = new Intl.DateTimeFormat("en-US", {
      timeZone: timezone,
      hour: "2-digit",
      minute: "2-digit",
      hour12: false,
    }).formatToParts(date);
    const h =
      parseInt(parts.find((p) => p.type === "hour")?.value ?? "0", 10) % 24;
    const m = parseInt(
      parts.find((p) => p.type === "minute")?.value ?? "0",
      10,
    );
    return h * 60 + m;
  }

  // ---- Helper: compute available slots for a given date ----

  async function getAvailableSlotsForDate(
    brokerId: number,
    dateStr: string, // "YYYY-MM-DD"
    slotMinutes: number,
    bufferMinutes: number,
    minBookingHours: number,
    brokerTimezone = "America/Chicago",
  ): Promise<Array<{ time: string; end_time: string; available: boolean }>> {
    const dayOfWeek = getDayOfWeekInTimezone(dateStr, brokerTimezone);

    const [avRows] = await pool.query<RowDataPacket[]>(
      `SELECT start_time, end_time FROM scheduler_availability
       WHERE broker_id = ? AND day_of_week = ? AND is_active = 1`,
      [brokerId, dayOfWeek],
    );
    if (!avRows.length) return [];

    // Fetch already-booked slots for that day
    const [bookedRows] = await pool.query<RowDataPacket[]>(
      `SELECT meeting_time, meeting_end_time FROM scheduled_meetings
       WHERE broker_id = ? AND meeting_date = ? AND status NOT IN ('cancelled','no_show')`,
      [brokerId, dateStr],
    );

    // Fetch blocked ranges that overlap this date.
    // Use a ±1-day window so events near UTC midnight (but on the broker's local date) are included.
    const [blockedRows] = await pool.query<RowDataPacket[]>(
      `SELECT start_datetime, end_datetime FROM scheduler_blocked_ranges
       WHERE broker_id = ?
         AND start_datetime < DATE_ADD(?, INTERVAL 1 DAY)
         AND end_datetime   > DATE_SUB(?, INTERVAL 1 DAY)`,
      [brokerId, `${dateStr} 23:59:59`, `${dateStr} 00:00:00`],
    );

    const now = new Date();
    const minBookingMs = minBookingHours * 60 * 60 * 1000;

    const slots: Array<{ time: string; end_time: string; available: boolean }> =
      [];

    for (const av of avRows) {
      const [sh, sm] = (av.start_time as string).split(":").map(Number);
      const [eh, em] = (av.end_time as string).split(":").map(Number);
      let cursor = sh * 60 + sm;
      const endMinutes = eh * 60 + em;

      while (cursor + slotMinutes <= endMinutes) {
        const slotH = Math.floor(cursor / 60);
        const slotM = cursor % 60;
        const endH = Math.floor((cursor + slotMinutes) / 60);
        const endMinute = (cursor + slotMinutes) % 60;

        const slotTime = `${String(slotH).padStart(2, "0")}:${String(slotM).padStart(2, "0")}`;
        const slotEndTime = `${String(endH).padStart(2, "0")}:${String(endMinute).padStart(2, "0")}`;

        // Check minimum booking window (broker-local wall clock → UTC)
        const slotDateTime = brokerLocalDateTimeToUtc(
          dateStr,
          slotTime,
          brokerTimezone,
        );
        const tooSoon = slotDateTime.getTime() - now.getTime() < minBookingMs;

        // Check for conflict with existing meetings (include buffer)
        const conflict = bookedRows.some((b) => {
          const [bh, bm] = (b.meeting_time as string).split(":").map(Number);
          const [beh, bem] = (b.meeting_end_time as string)
            .split(":")
            .map(Number);
          const bookedStart = bh * 60 + bm - bufferMinutes;
          const bookedEnd = beh * 60 + bem + bufferMinutes;
          return cursor < bookedEnd && cursor + slotMinutes > bookedStart;
        });

        // Check for conflict with broker-blocked ranges (O365 + manual), incl. buffer.
        const blocked = blockedRows.some((br) => {
          const brStart = parseDbUtcDatetime(
            br.start_datetime as Date | string,
          );
          const brEnd = parseDbUtcDatetime(br.end_datetime as Date | string);
          const brStartMin =
            schedulerUtcToLocalMinutes(brStart, brokerTimezone) - bufferMinutes;
          const brEndMin =
            schedulerUtcToLocalMinutes(brEnd, brokerTimezone) + bufferMinutes;
          if (brEndMin <= brStartMin) {
            return cursor < brEndMin || cursor + slotMinutes > brStartMin;
          }
          return cursor < brEndMin && cursor + slotMinutes > brStartMin;
        });

        slots.push({
          time: slotTime,
          end_time: slotEndTime,
          available: !tooSoon && !conflict && !blocked,
        });

        cursor += slotMinutes;
      }
    }

    return slots;
  }

  // ---- Public scheduler handlers ----

  const handleGetPublicScheduler: RequestHandler = async (req, res) => {
    try {
      const { token } = req.params as { token?: string };

      let brokerRow: RowDataPacket | null = null;

      if (token) {
        const tokenField = isUUIDToken(token) ? "b.public_token" : "b.slug";
        const [rows] = await pool.query<RowDataPacket[]>(
          `SELECT b.id, b.first_name, b.last_name, b.email, b.phone, b.role, b.tenant_id,
                  b.timezone, bp.avatar_url, bp.years_experience
           FROM brokers b
           LEFT JOIN broker_profiles bp ON bp.broker_id = b.id
           WHERE ${tokenField} = ? AND b.status = 'active' AND b.tenant_id = ?`,
          [token, MORTGAGE_TENANT_ID],
        );
        brokerRow = rows[0] || null;
      } else {
        // Default: first active admin broker
        const [rows] = await pool.query<RowDataPacket[]>(
          `SELECT b.id, b.first_name, b.last_name, b.email, b.phone, b.role, b.tenant_id,
                  b.timezone, bp.avatar_url, bp.years_experience
           FROM brokers b
           LEFT JOIN broker_profiles bp ON bp.broker_id = b.id
           WHERE b.status = 'active' AND b.role = 'admin' AND b.tenant_id = ?
           ORDER BY b.id ASC LIMIT 1`,
          [MORTGAGE_TENANT_ID],
        );
        brokerRow = rows[0] || null;
      }

      if (!brokerRow) {
        return res.status(404).json({
          success: false,
          error: "Broker not found or scheduler unavailable",
        });
      }

      // Upsert default settings if missing
      await pool.query(
        `INSERT IGNORE INTO scheduler_settings
           (tenant_id, broker_id, meeting_title, meeting_description, slot_duration_minutes, buffer_time_minutes, advance_booking_days, min_booking_hours, timezone, allow_phone, allow_video, allow_teams, allow_office)
         VALUES (?, ?, 'Mortgage Consultation', 'Schedule a free consultation with our mortgage expert.', 30, 15, 30, 2, ?, 1, 1, 0, 1)`,
        [
          MORTGAGE_TENANT_ID,
          brokerRow.id,
          (brokerRow as any).timezone || "America/Chicago",
        ],
      );

      const [[settings]] = await pool.query<RowDataPacket[]>(
        `SELECT * FROM scheduler_settings WHERE broker_id = ? AND tenant_id = ?`,
        [brokerRow.id, MORTGAGE_TENANT_ID],
      );

      if (!settings.is_enabled) {
        return res
          .status(404)
          .json({ success: false, error: "Scheduler not available" });
      }

      // Build list of available dates in the next advance_booking_days days
      const brokerTimezone =
        settings.timezone || (brokerRow as any).timezone || "America/Chicago";
      let dateStr = todayDateStrInTimezone(brokerTimezone);
      const availableDates: string[] = [];

      for (let i = 0; i < settings.advance_booking_days; i++) {
        const slots = await getAvailableSlotsForDate(
          brokerRow.id,
          dateStr,
          settings.slot_duration_minutes,
          settings.buffer_time_minutes,
          settings.min_booking_hours,
          brokerTimezone,
        );
        if (slots.some((s) => s.available)) {
          availableDates.push(dateStr);
        }
        dateStr = addCalendarDaysInTimezone(dateStr, 1, brokerTimezone);
      }

      return res.json({
        success: true,
        broker: {
          broker_id: brokerRow.id,
          first_name: brokerRow.first_name,
          last_name: brokerRow.last_name,
          email: brokerRow.email,
          phone: brokerRow.phone,
          avatar_url: brokerRow.avatar_url,
          years_experience: brokerRow.years_experience,
          role: brokerRow.role,
          meeting_title: settings.meeting_title,
          meeting_description: settings.meeting_description,
          slot_duration_minutes: settings.slot_duration_minutes,
          advance_booking_days: settings.advance_booking_days,
          min_booking_hours: settings.min_booking_hours,
          timezone:
            settings.timezone ||
            (brokerRow as any).timezone ||
            "America/Chicago",
          allow_phone: !!settings.allow_phone,
          allow_video: !!settings.allow_video,
          allow_teams: !!settings.allow_teams,
          allow_office: !!settings.allow_office,
          is_enabled: !!settings.is_enabled,
        },
        available_dates: availableDates,
      });
    } catch (err) {
      console.error("handleGetPublicScheduler error:", err);
      return res
        .status(500)
        .json({ success: false, error: "Internal server error" });
    }
  };

  const handleGetPublicSlots: RequestHandler = async (req, res) => {
    try {
      const { token } = req.params as { token: string };
      const { date } = req.query as { date?: string };

      if (!date || !/^\d{4}-\d{2}-\d{2}$/.test(date)) {
        return res.status(400).json({
          success: false,
          error: "date query param required (YYYY-MM-DD)",
        });
      }

      let brokerId: number;
      if (token === "default") {
        const [rows] = await pool.query<RowDataPacket[]>(
          `SELECT id FROM brokers WHERE status = 'active' AND role = 'admin' AND tenant_id = ? ORDER BY id ASC LIMIT 1`,
          [MORTGAGE_TENANT_ID],
        );
        if (!rows[0])
          return res
            .status(404)
            .json({ success: false, error: "No broker found" });
        brokerId = rows[0].id;
      } else {
        const tokenField = isUUIDToken(token) ? "public_token" : "slug";
        const [rows] = await pool.query<RowDataPacket[]>(
          `SELECT id FROM brokers WHERE ${tokenField} = ? AND status = 'active' AND tenant_id = ?`,
          [token, MORTGAGE_TENANT_ID],
        );
        if (!rows[0])
          return res
            .status(404)
            .json({ success: false, error: "Broker not found" });
        brokerId = rows[0].id;
      }

      const [[settings]] = await pool.query<RowDataPacket[]>(
        `SELECT ss.slot_duration_minutes, ss.buffer_time_minutes, ss.min_booking_hours,
                COALESCE(ss.timezone, b.timezone, 'America/Chicago') AS timezone
         FROM scheduler_settings ss
         JOIN brokers b ON b.id = ss.broker_id AND b.tenant_id = ss.tenant_id
         WHERE ss.broker_id = ? AND ss.tenant_id = ?`,
        [brokerId, MORTGAGE_TENANT_ID],
      );
      if (!settings)
        return res
          .status(404)
          .json({ success: false, error: "Scheduler not configured" });

      const slots = await getAvailableSlotsForDate(
        brokerId,
        date,
        settings.slot_duration_minutes,
        settings.buffer_time_minutes,
        settings.min_booking_hours,
        settings.timezone || "America/Chicago",
      );

      return res.json({ success: true, slots });
    } catch (err) {
      console.error("handleGetPublicSlots error:", err);
      return res
        .status(500)
        .json({ success: false, error: "Internal server error" });
    }
  };

  const handleBookMeeting: RequestHandler = async (req, res) => {
    try {
      const {
        broker_token,
        client_name,
        client_email,
        client_phone,
        meeting_date,
        meeting_time,
        meeting_type,
        notes,
      } = req.body as {
        broker_token?: string;
        client_name?: string;
        client_email?: string;
        client_phone?: string;
        meeting_date?: string;
        meeting_time?: string;
        meeting_type?: MeetingType;
        notes?: string;
      };

      if (
        !broker_token ||
        !client_name ||
        !client_email ||
        !meeting_date ||
        !meeting_time ||
        !meeting_type
      ) {
        return res.status(400).json({
          success: false,
          error:
            "broker_token, client_name, client_email, meeting_date, meeting_time, and meeting_type are required",
        });
      }

      if (!/^\d{4}-\d{2}-\d{2}$/.test(meeting_date)) {
        return res
          .status(400)
          .json({ success: false, error: "meeting_date must be YYYY-MM-DD" });
      }
      if (!/^\d{2}:\d{2}$/.test(meeting_time)) {
        return res
          .status(400)
          .json({ success: false, error: "meeting_time must be HH:MM" });
      }

      const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
      if (!emailRegex.test(client_email)) {
        return res
          .status(400)
          .json({ success: false, error: "Invalid email address" });
      }

      let brokerId: number;
      let brokerData: RowDataPacket;

      if (broker_token === "default") {
        const [rows] = await pool.query<RowDataPacket[]>(
          `SELECT b.id, b.first_name, b.last_name, b.email, b.phone, b.public_token, b.timezone
           FROM brokers b WHERE b.status = 'active' AND b.role = 'admin' AND b.tenant_id = ?
           ORDER BY b.id ASC LIMIT 1`,
          [MORTGAGE_TENANT_ID],
        );
        if (!rows[0])
          return res
            .status(404)
            .json({ success: false, error: "No broker available" });
        brokerData = rows[0];
      } else {
        const tokenField = isUUIDToken(broker_token) ? "public_token" : "slug";
        const [rows] = await pool.query<RowDataPacket[]>(
          `SELECT b.id, b.first_name, b.last_name, b.email, b.phone, b.public_token, b.timezone
           FROM brokers b WHERE b.${tokenField} = ? AND b.status = 'active' AND b.tenant_id = ?`,
          [broker_token, MORTGAGE_TENANT_ID],
        );
        if (!rows[0])
          return res
            .status(404)
            .json({ success: false, error: "Broker not found" });
        brokerData = rows[0];
      }

      brokerId = brokerData.id;

      const [[settings]] = await pool.query<RowDataPacket[]>(
        `SELECT * FROM scheduler_settings WHERE broker_id = ? AND tenant_id = ?`,
        [brokerId, MORTGAGE_TENANT_ID],
      );

      if (!settings || !settings.is_enabled) {
        return res
          .status(400)
          .json({ success: false, error: "Scheduler is not available" });
      }

      if (meeting_type === "phone" && !settings.allow_phone) {
        return res
          .status(400)
          .json({ success: false, error: "Phone meetings are not available" });
      }
      if (meeting_type === "video" && !settings.allow_video) {
        return res
          .status(400)
          .json({ success: false, error: "Video meetings are not available" });
      }
      if (meeting_type === "teams" && !settings.allow_teams) {
        return res
          .status(400)
          .json({ success: false, error: "Teams meetings are not available" });
      }
      if (meeting_type === "office" && !settings.allow_office) {
        return res
          .status(400)
          .json({ success: false, error: "Office visits are not available" });
      }

      // Validate slot is truly available
      const allSlots = await getAvailableSlotsForDate(
        brokerId,
        meeting_date,
        settings.slot_duration_minutes,
        settings.buffer_time_minutes,
        settings.min_booking_hours,
        settings.timezone || brokerData.timezone || "America/Chicago",
      );

      const requestedSlot = allSlots.find((s) => s.time === meeting_time);
      if (!requestedSlot) {
        return res
          .status(400)
          .json({ success: false, error: "This time slot is not available" });
      }
      if (!requestedSlot.available) {
        return res
          .status(409)
          .json({ success: false, error: "This time slot is already taken" });
      }

      const schedulerPrecheck = await precheckSchedulerQuota({
        source: "scheduler",
        refType: "scheduled_meeting",
        refId: "pending",
      });
      if (!schedulerPrecheck.allowed) {
        return res
          .status(402)
          .json(schedulerQuotaDeniedResponse(schedulerPrecheck));
      }

      const bookingToken = crypto.randomUUID();

      // Create Zoom meeting for video calls; fall back gracefully if Zoom is not configured
      let zoomMeetingId: string | null = null;
      let zoomJoinUrl: string | null = null;
      let zoomStartUrl: string | null = null;
      let teamsMeetingId: string | null = null;
      let teamsJoinUrl: string | null = null;
      let teamsHostUrl: string | null = null;

      if (meeting_type === "video") {
        const zoomMeeting = await createZoomMeeting({
          topic: settings.meeting_title || "Mortgage Consultation",
          startDatetime: `${meeting_date}T${meeting_time}:00`,
          durationMinutes: settings.slot_duration_minutes,
          timezone:
            settings.timezone || brokerData.timezone || "America/Chicago",
        });
        if (zoomMeeting) {
          zoomMeetingId = zoomMeeting.meeting_id;
          zoomJoinUrl = zoomMeeting.join_url;
          zoomStartUrl = zoomMeeting.start_url;
        } else {
          return res.status(503).json({
            success: false,
            error:
              "Unable to create Zoom meeting right now. Please try again in a moment.",
          });
        }
      }
      if (meeting_type === "teams") {
        const [startHour, startMinute] = meeting_time.split(":").map(Number);
        const endMinutes =
          startHour * 60 + startMinute + settings.slot_duration_minutes;
        const endHour = Math.floor(endMinutes / 60);
        const endMinute = endMinutes % 60;
        const teamsMeeting = await createTeamsMeeting({
          organizerEmail: brokerData.email,
          subject: settings.meeting_title || "Mortgage Consultation",
          startDatetime: `${meeting_date}T${meeting_time}:00`,
          endDatetime: `${meeting_date}T${String(endHour).padStart(2, "0")}:${String(endMinute).padStart(2, "0")}:00`,
        });
        if (teamsMeeting && !("policyPending" in teamsMeeting)) {
          teamsMeetingId = teamsMeeting.meeting_id;
          teamsJoinUrl = teamsMeeting.join_url;
          teamsHostUrl = teamsMeeting.host_url;
        } else {
          const isPending = teamsMeeting && "policyPending" in teamsMeeting;
          return res.status(503).json({
            success: false,
            errorCode: isPending ? "TEAMS_POLICY_PENDING" : undefined,
            error: isPending
              ? "Teams meeting setup is still activating. This typically takes up to 1 hour after first setup. Please try again in a few minutes."
              : "Unable to create Teams meeting right now. Please try again in a moment.",
          });
        }
      }

      const [result] = await pool.query<ResultSetHeader>(
        `INSERT INTO scheduled_meetings
           (tenant_id, broker_id, client_name, client_email, client_phone,
            meeting_date, meeting_time, meeting_end_time, meeting_type,
            zoom_meeting_id, zoom_join_url, zoom_start_url,
            teams_meeting_id, teams_join_url,
            status, notes, booking_token, public_token)
          VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'confirmed', ?, ?, ?)`,
        [
          MORTGAGE_TENANT_ID,
          brokerId,
          client_name.trim(),
          client_email.trim().toLowerCase(),
          client_phone || null,
          meeting_date,
          meeting_time + ":00",
          requestedSlot.end_time + ":00",
          meeting_type,
          zoomMeetingId,
          zoomJoinUrl,
          zoomStartUrl,
          teamsMeetingId,
          teamsJoinUrl,
          notes || null,
          bookingToken,
          brokerData.public_token,
        ],
      );

      await recordSchedulerQuota({
        source: "scheduler",
        refType: "scheduled_meeting",
        refId: String(result.insertId),
      });

      const brokerName = `${brokerData.first_name} ${brokerData.last_name}`;

      await dispatchSchedulerEmails(`book:${result.insertId}`, [
        () =>
          sendMeetingConfirmationToClient({
            email: client_email.trim().toLowerCase(),
            clientName: client_name.trim(),
            brokerName,
            brokerEmail: brokerData.email,
            meetingId: result.insertId,
            meetingDate: meeting_date,
            meetingTime: meeting_time,
            meetingEndTime: requestedSlot.end_time,
            meetingType: meeting_type,
            videoRoomUrl: meeting_type === "teams" ? teamsJoinUrl : zoomJoinUrl,
            videoHostUrl: meeting_type === "teams" ? teamsHostUrl : zoomStartUrl,
            brokerPhone: brokerData.phone,
            bookingToken,
            notes: notes || null,
            brokerTimezone: brokerData.timezone || undefined,
            rescheduleToken: bookingToken,
          }),
        () =>
          sendMeetingNotificationToBroker({
            brokerEmail: brokerData.email,
            brokerName,
            clientName: client_name.trim(),
            clientEmail: client_email.trim().toLowerCase(),
            clientPhone: client_phone || null,
            meetingDate: meeting_date,
            meetingTime: meeting_time,
            meetingEndTime: requestedSlot.end_time,
            meetingType: meeting_type,
            videoRoomUrl: meeting_type === "teams" ? teamsJoinUrl : zoomJoinUrl,
            videoHostUrl: meeting_type === "teams" ? teamsHostUrl : zoomStartUrl,
            notes: notes || null,
            meetingId: result.insertId,
            brokerTimezone: brokerData.timezone || undefined,
          }),
      ]);

      // Auto-create client record from scheduler booking (upsert by email — ignore if already exists)
      try {
        const nameParts = client_name.trim().split(" ");
        const firstName = nameParts[0] ?? client_name.trim();
        const lastName = nameParts.slice(1).join(" ") || "-";
        await pool.query(
          `INSERT INTO clients
             (tenant_id, email, first_name, last_name, phone, assigned_broker_id, source, income_type, status)
           VALUES (?, ?, ?, ?, ?, ?, 'scheduler', 'W-2', 'active')
           ON DUPLICATE KEY UPDATE
             phone            = IF(phone IS NULL AND VALUES(phone) IS NOT NULL, VALUES(phone), phone),
             assigned_broker_id = IF(assigned_broker_id IS NULL, VALUES(assigned_broker_id), assigned_broker_id)`,
          [
            MORTGAGE_TENANT_ID,
            client_email.trim().toLowerCase(),
            firstName,
            lastName,
            client_phone || null,
            brokerId,
          ],
        );
      } catch (clientErr) {
        // Non-fatal — booking already confirmed, just log
        console.error("Scheduler auto-create client error:", clientErr);
      }

      return res.json({
        success: true,
        meeting_id: result.insertId,
        booking_token: bookingToken,
        zoom_join_url: zoomJoinUrl,
        zoom_start_url: zoomStartUrl,
        teams_join_url: teamsJoinUrl,
        meeting_date,
        meeting_time,
        meeting_type,
        broker_name: brokerName,
      });
    } catch (err) {
      console.error("handleBookMeeting error:", err);
      return res
        .status(500)
        .json({ success: false, error: "Internal server error" });
    }
  };

  // Returns broker public_token + client prefill data for a given booking token
  // Does NOT cancel — just used to pre-populate the reschedule form
  const handleGetRescheduleInfo: RequestHandler = async (req, res) => {
    try {
      const { bookingToken } = req.params as { bookingToken: string };

      const [rows] = await pool.query<RowDataPacket[]>(
        `SELECT sm.client_name, sm.client_email, sm.client_phone,
          sm.meeting_date, sm.meeting_time, sm.meeting_type, sm.status,
          b.public_token AS broker_public_token,
          CONCAT(b.first_name, ' ', b.last_name) AS broker_name,
          ss.timezone AS broker_timezone
         FROM scheduled_meetings sm
         LEFT JOIN brokers b ON b.id = sm.broker_id
         LEFT JOIN scheduler_settings ss
          ON ss.broker_id = sm.broker_id
               AND ss.tenant_id = sm.tenant_id
         WHERE sm.booking_token = ? AND sm.tenant_id = ?`,
        [bookingToken, MORTGAGE_TENANT_ID],
      );

      if (!rows[0]) {
        return res
          .status(404)
          .json({ success: false, error: "Booking not found" });
      }

      const meeting = rows[0];

      if (meeting.status === "cancelled") {
        return res.status(410).json({
          success: false,
          error: "This meeting has already been cancelled",
        });
      }

      return res.json({
        success: true,
        broker_public_token: meeting.broker_public_token,
        broker_name: meeting.broker_name,
        broker_timezone: meeting.broker_timezone,
        client_name: meeting.client_name,
        client_email: meeting.client_email,
        client_phone: meeting.client_phone,
        meeting_type: meeting.meeting_type,
        old_meeting_date: meeting.meeting_date,
        old_meeting_time: meeting.meeting_time,
      });
    } catch (err) {
      console.error("handleGetRescheduleInfo error:", err);
      return res
        .status(500)
        .json({ success: false, error: "Internal server error" });
    }
  };

  // Cancels the existing meeting and books a new slot atomically.
  // Body: { new_date: "YYYY-MM-DD", new_time: "HH:MM" }
  const handleRescheduleMeeting: RequestHandler = async (req, res) => {
    try {
      const { bookingToken } = req.params as { bookingToken: string };
      const { new_date, new_time } = req.body as {
        new_date?: string;
        new_time?: string;
      };

      if (!new_date || !new_time) {
        return res.status(400).json({
          success: false,
          error: "new_date and new_time are required",
        });
      }

      // Validate date / time format
      if (!/^\d{4}-\d{2}-\d{2}$/.test(new_date)) {
        return res
          .status(400)
          .json({ success: false, error: "new_date must be YYYY-MM-DD" });
      }
      if (!/^\d{2}:\d{2}$/.test(new_time)) {
        return res
          .status(400)
          .json({ success: false, error: "new_time must be HH:MM" });
      }

      // Load old meeting + broker data
      const [rows] = await pool.query<RowDataPacket[]>(
        `SELECT sm.id, sm.status, sm.client_name, sm.client_email,
                sm.client_phone, sm.meeting_type, sm.notes,
                b.id AS broker_id, b.public_token AS broker_public_token,
                b.first_name, b.last_name, b.email AS broker_email,
                b.phone AS broker_phone, b.timezone AS broker_timezone
         FROM scheduled_meetings sm
         LEFT JOIN brokers b ON b.id = sm.broker_id
         WHERE sm.booking_token = ? AND sm.tenant_id = ?`,
        [bookingToken, MORTGAGE_TENANT_ID],
      );

      if (!rows[0]) {
        return res
          .status(404)
          .json({ success: false, error: "Booking not found" });
      }

      const old = rows[0];

      if (old.status === "cancelled") {
        return res.status(410).json({
          success: false,
          error: "This booking has already been cancelled",
        });
      }

      // Load scheduler settings
      const [[settings]] = await pool.query<RowDataPacket[]>(
        `SELECT * FROM scheduler_settings WHERE broker_id = ? AND tenant_id = ?`,
        [old.broker_id, MORTGAGE_TENANT_ID],
      );

      if (!settings || !settings.is_enabled) {
        return res
          .status(400)
          .json({ success: false, error: "Scheduler is not available" });
      }

      // Validate that the requested new slot is actually available
      const allSlots = await getAvailableSlotsForDate(
        old.broker_id,
        new_date,
        settings.slot_duration_minutes,
        settings.buffer_time_minutes,
        settings.min_booking_hours,
        settings.timezone || old.broker_timezone || "America/Chicago",
      );

      const requestedSlot = allSlots.find((s) => s.time === new_time);
      if (!requestedSlot) {
        return res
          .status(400)
          .json({ success: false, error: "This time slot is not available" });
      }
      if (!requestedSlot.available) {
        return res
          .status(409)
          .json({ success: false, error: "This time slot is already taken" });
      }

      // Cancel the old meeting
      await pool.query(
        `UPDATE scheduled_meetings
         SET status = 'cancelled', cancelled_by = 'client',
             cancelled_reason = 'Rescheduled by client', cancelled_at = NOW()
         WHERE id = ? AND tenant_id = ?`,
        [old.id, MORTGAGE_TENANT_ID],
      );

      const reschedulePrecheck = await precheckSchedulerQuota({
        source: "scheduler",
        refType: "scheduled_meeting",
        refId: "pending",
      });
      if (!reschedulePrecheck.allowed) {
        return res
          .status(402)
          .json(schedulerQuotaDeniedResponse(reschedulePrecheck));
      }

      // Create Zoom meeting for video calls
      let zoomMeetingId: string | null = null;
      let zoomJoinUrl: string | null = null;
      let zoomStartUrl: string | null = null;
      let teamsMeetingId: string | null = null;
      let teamsJoinUrl: string | null = null;
      let teamsHostUrl: string | null = null;

      if (old.meeting_type === "video") {
        const zoomMeeting = await createZoomMeeting({
          topic: settings.meeting_title || "Mortgage Consultation",
          startDatetime: `${new_date}T${new_time}:00`,
          durationMinutes: settings.slot_duration_minutes,
          timezone:
            settings.timezone || old.broker_timezone || "America/Chicago",
        });
        if (zoomMeeting) {
          zoomMeetingId = zoomMeeting.meeting_id;
          zoomJoinUrl = zoomMeeting.join_url;
          zoomStartUrl = zoomMeeting.start_url;
        } else {
          return res.status(503).json({
            success: false,
            error:
              "Unable to create Zoom meeting right now. Please try rescheduling again in a moment.",
          });
        }
      }
      if (old.meeting_type === "teams") {
        const [startHour, startMinute] = new_time.split(":").map(Number);
        const endMinutes =
          startHour * 60 + startMinute + settings.slot_duration_minutes;
        const endHour = Math.floor(endMinutes / 60);
        const endMinute = endMinutes % 60;
        const teamsMeeting = await createTeamsMeeting({
          organizerEmail: old.broker_email,
          subject: settings.meeting_title || "Mortgage Consultation",
          startDatetime: `${new_date}T${new_time}:00`,
          endDatetime: `${new_date}T${String(endHour).padStart(2, "0")}:${String(endMinute).padStart(2, "0")}:00`,
        });
        if (teamsMeeting && !("policyPending" in teamsMeeting)) {
          zoomMeetingId = teamsMeeting.meeting_id;
          zoomJoinUrl = teamsMeeting.join_url;
          zoomStartUrl = teamsMeeting.host_url;
        } else {
          const isPending = teamsMeeting && "policyPending" in teamsMeeting;
          return res.status(503).json({
            success: false,
            errorCode: isPending ? "TEAMS_POLICY_PENDING" : undefined,
            error: isPending
              ? "Teams meeting setup is still activating. This typically takes up to 1 hour after first setup. Please try rescheduling again in a few minutes."
              : "Unable to create Teams meeting right now. Please try rescheduling again in a moment.",
          });
        }
      }

      const newBookingToken = crypto.randomUUID();

      // Insert new booking
      const [result] = await pool.query<ResultSetHeader>(
        `INSERT INTO scheduled_meetings
           (tenant_id, broker_id, client_name, client_email, client_phone,
            meeting_date, meeting_time, meeting_end_time, meeting_type,
            zoom_meeting_id, zoom_join_url, zoom_start_url,
          teams_meeting_id, teams_join_url,
            status, notes, booking_token, public_token)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'confirmed', ?, ?, ?)`,
        [
          MORTGAGE_TENANT_ID,
          old.broker_id,
          old.client_name,
          old.client_email,
          old.client_phone,
          new_date,
          new_time + ":00",
          requestedSlot.end_time + ":00",
          old.meeting_type,
          zoomMeetingId,
          zoomJoinUrl,
          zoomStartUrl,
          old.meeting_type === "teams" ? zoomMeetingId : null,
          old.meeting_type === "teams" ? zoomJoinUrl : null,
          old.notes,
          newBookingToken,
          old.broker_public_token,
        ],
      );

      await recordSchedulerQuota({
        source: "scheduler",
        refType: "scheduled_meeting",
        refId: String(result.insertId),
      });

      const brokerName = `${old.first_name} ${old.last_name}`;

      await dispatchSchedulerEmails(`reschedule:${result.insertId}`, [
        () =>
          sendMeetingConfirmationToClient({
            email: old.client_email,
            clientName: old.client_name,
            brokerName,
            brokerEmail: old.broker_email,
            meetingId: result.insertId,
            meetingDate: new_date,
            meetingTime: new_time,
            meetingEndTime: requestedSlot.end_time,
            meetingType: old.meeting_type,
            videoRoomUrl: zoomJoinUrl,
            videoHostUrl: zoomStartUrl,
            brokerPhone: old.broker_phone,
            bookingToken: newBookingToken,
            notes: old.notes || null,
            brokerTimezone: old.broker_timezone || undefined,
            rescheduleToken: newBookingToken,
          }),
        () =>
          sendMeetingNotificationToBroker({
            brokerEmail: old.broker_email,
            brokerName,
            clientName: old.client_name,
            clientEmail: old.client_email,
            clientPhone: old.client_phone || null,
            meetingDate: new_date,
            meetingTime: new_time,
            meetingEndTime: requestedSlot.end_time,
            meetingType: old.meeting_type,
            videoRoomUrl: zoomJoinUrl,
            videoHostUrl: zoomStartUrl,
            notes: old.notes || null,
            meetingId: result.insertId,
            brokerTimezone: old.broker_timezone || undefined,
          }),
      ]);

      return res.json({
        success: true,
        booking_token: newBookingToken,
        meeting_date: new_date,
        meeting_time: new_time,
        meeting_type: old.meeting_type,
        zoom_join_url: zoomJoinUrl,
        teams_join_url: old.meeting_type === "teams" ? zoomJoinUrl : null,
        broker_name: brokerName,
      });
    } catch (err) {
      console.error("handleRescheduleMeeting error:", err);
      return res
        .status(500)
        .json({ success: false, error: "Internal server error" });
    }
  };

  const handleCancelMeetingByToken: RequestHandler = async (req, res) => {
    try {
      const { bookingToken } = req.params as { bookingToken: string };
      const { reason } = req.body as { reason?: string };

      const [rows] = await pool.query<RowDataPacket[]>(
        `SELECT sm.*, b.first_name, b.last_name, b.email AS broker_email, b.phone AS broker_phone, b.timezone AS broker_timezone
         FROM scheduled_meetings sm
         LEFT JOIN brokers b ON b.id = sm.broker_id
         WHERE sm.booking_token = ? AND sm.tenant_id = ?`,
        [bookingToken, MORTGAGE_TENANT_ID],
      );

      if (!rows[0]) {
        return res
          .status(404)
          .json({ success: false, error: "Meeting not found" });
      }

      const meeting = rows[0];

      if (meeting.status === "cancelled") {
        return res
          .status(400)
          .json({ success: false, error: "Meeting is already cancelled" });
      }

      await pool.query(
        `UPDATE scheduled_meetings
         SET status = 'cancelled', cancelled_by = 'client', cancelled_reason = ?, cancelled_at = NOW()
         WHERE booking_token = ? AND tenant_id = ?`,
        [reason || null, bookingToken, MORTGAGE_TENANT_ID],
      );

      const brokerName = meeting.first_name
        ? `${meeting.first_name} ${meeting.last_name}`
        : "Your Mortgage Banker";

      await dispatchSchedulerEmails(`cancel:${bookingToken}`, [
        () =>
          sendMeetingCancellationEmail({
            email: meeting.client_email,
            clientName: meeting.client_name,
            brokerName,
            meetingDate: meeting.meeting_date,
            meetingTime: meeting.meeting_time,
            cancelledBy: "client",
            reason: reason || null,
            brokerTimezone: meeting.broker_timezone || undefined,
          }),
      ]);

      return res.json({
        success: true,
        message: "Meeting cancelled successfully",
      });
    } catch (err) {
      console.error("handleCancelMeetingByToken error:", err);
      return res
        .status(500)
        .json({ success: false, error: "Internal server error" });
    }
  };

  // ---- Admin scheduler handlers ----

  const handleGetSchedulerSettings: RequestHandler = async (req, res) => {
    try {
      const reqBrokerId = (req as any).brokerId as number;

      await pool.query(
        `INSERT INTO scheduler_settings
           (tenant_id, broker_id, meeting_title, meeting_description, slot_duration_minutes, buffer_time_minutes, advance_booking_days, min_booking_hours, timezone, allow_phone, allow_video, allow_teams, allow_office)
         VALUES (?, ?, 'Mortgage Consultation', 'Schedule a free consultation with our mortgage expert.', 30, 15, 30, 2, 'America/Chicago', 1, 1, 0, 1)
         ON DUPLICATE KEY UPDATE updated_at = updated_at`,
        [MORTGAGE_TENANT_ID, reqBrokerId],
      );

      const [[settings]] = await pool.query<RowDataPacket[]>(
        `SELECT * FROM scheduler_settings WHERE broker_id = ? AND tenant_id = ?`,
        [reqBrokerId, MORTGAGE_TENANT_ID],
      );

      if (!settings) {
        return res.status(404).json({
          success: false,
          error:
            "Scheduler settings not found for this broker. Ensure the broker exists and migrations have been applied.",
        });
      }

      const [availability] = await pool.query<RowDataPacket[]>(
        `SELECT * FROM scheduler_availability WHERE broker_id = ? AND tenant_id = ? ORDER BY day_of_week ASC`,
        [reqBrokerId, MORTGAGE_TENANT_ID],
      );

      return res.json({
        success: true,
        settings: {
          ...settings,
          is_enabled: !!settings.is_enabled,
          allow_phone: !!settings.allow_phone,
          allow_video: !!settings.allow_video,
          allow_teams: !!settings.allow_teams,
          allow_office: !!settings.allow_office,
        },
        availability: availability.map((a) => ({
          ...a,
          is_active: !!a.is_active,
        })),
      });
    } catch (err) {
      console.error("handleGetSchedulerSettings error:", err);
      return res
        .status(500)
        .json({ success: false, error: "Internal server error" });
    }
  };

  const handleUpdateSchedulerSettings: RequestHandler = async (req, res) => {
    try {
      const reqBrokerId = (req as any).brokerId as number;
      const {
        is_enabled,
        meeting_title,
        meeting_description,
        slot_duration_minutes,
        buffer_time_minutes,
        advance_booking_days,
        min_booking_hours,
        timezone,
        allow_phone,
        allow_video,
        allow_teams,
        allow_office,
        availability,
      } = req.body as {
        is_enabled?: boolean;
        meeting_title?: string;
        meeting_description?: string;
        slot_duration_minutes?: number;
        buffer_time_minutes?: number;
        advance_booking_days?: number;
        min_booking_hours?: number;
        timezone?: string;
        allow_phone?: boolean;
        allow_video?: boolean;
        allow_teams?: boolean;
        allow_office?: boolean;
        availability?: Array<{
          day_of_week: number;
          start_time: string;
          end_time: string;
          is_active: boolean;
        }>;
      };

      // Validate numeric fields
      const _numericFields: Record<string, unknown> = {
        slot_duration_minutes,
        buffer_time_minutes,
        advance_booking_days,
        min_booking_hours,
      };
      for (const [key, val] of Object.entries(_numericFields)) {
        if (val !== undefined && val !== null) {
          const n = Number(val);
          if (!Number.isFinite(n) || n <= 0 || !Number.isInteger(n)) {
            return res.status(400).json({
              success: false,
              error: `${key} must be a positive integer`,
            });
          }
        }
      }

      if (allow_teams === true) {
        const [[brokerRow]] = await pool.query<RowDataPacket[]>(
          `SELECT email FROM brokers WHERE id = ? AND tenant_id = ? LIMIT 1`,
          [reqBrokerId, MORTGAGE_TENANT_ID],
        );

        if (!brokerRow?.email) {
          return res.status(400).json({
            success: false,
            error:
              "Cannot enable Teams: broker email is missing. Update broker profile email first.",
          });
        }

        const eligibility = await validateTeamsOrganizerEligibility({
          brokerEmail: String(brokerRow.email),
        });
        if (!eligibility.ok) {
          const eligibilityError =
            "error" in eligibility
              ? eligibility.error
              : "Unable to validate Teams organizer eligibility right now.";
          return res.status(400).json({
            success: false,
            error: eligibilityError,
          });
        }
      }

      const [_updateResult] = await pool.query<ResultSetHeader>(
        `UPDATE scheduler_settings SET
           is_enabled = COALESCE(?, is_enabled),
           meeting_title = COALESCE(?, meeting_title),
           meeting_description = ?,
           slot_duration_minutes = COALESCE(?, slot_duration_minutes),
           buffer_time_minutes = COALESCE(?, buffer_time_minutes),
           advance_booking_days = COALESCE(?, advance_booking_days),
           min_booking_hours = COALESCE(?, min_booking_hours),
           timezone = COALESCE(?, timezone),
           allow_phone = COALESCE(?, allow_phone),
           allow_video = COALESCE(?, allow_video),
           allow_teams = COALESCE(?, allow_teams),
           allow_office = COALESCE(?, allow_office)
         WHERE broker_id = ? AND tenant_id = ?`,
        [
          is_enabled !== undefined ? (is_enabled ? 1 : 0) : null,
          meeting_title || null,
          meeting_description !== undefined
            ? meeting_description?.trim() || null
            : undefined,
          slot_duration_minutes ?? null,
          buffer_time_minutes ?? null,
          advance_booking_days ?? null,
          min_booking_hours ?? null,
          timezone || null,
          allow_phone !== undefined ? (allow_phone ? 1 : 0) : null,
          allow_video !== undefined ? (allow_video ? 1 : 0) : null,
          allow_teams !== undefined ? (allow_teams ? 1 : 0) : null,
          allow_office !== undefined ? (allow_office ? 1 : 0) : null,
          reqBrokerId,
          MORTGAGE_TENANT_ID,
        ],
      );

      if (_updateResult.affectedRows === 0) {
        await pool.query(
          `INSERT INTO scheduler_settings
             (tenant_id, broker_id, is_enabled, meeting_title, meeting_description,
              slot_duration_minutes, buffer_time_minutes, advance_booking_days,
              min_booking_hours, timezone, allow_phone, allow_video, allow_teams, allow_office)
           VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
          [
            MORTGAGE_TENANT_ID,
            reqBrokerId,
            is_enabled !== undefined ? (is_enabled ? 1 : 0) : 1,
            meeting_title || "Mortgage Consultation",
            meeting_description?.trim() || null,
            slot_duration_minutes ?? 30,
            buffer_time_minutes ?? 15,
            advance_booking_days ?? 30,
            min_booking_hours ?? 2,
            timezone || "America/Chicago",
            allow_phone !== undefined ? (allow_phone ? 1 : 0) : 1,
            allow_video !== undefined ? (allow_video ? 1 : 0) : 0,
            allow_teams !== undefined ? (allow_teams ? 1 : 0) : 0,
            allow_office !== undefined ? (allow_office ? 1 : 0) : 1,
          ],
        );
      }

      if (availability && Array.isArray(availability)) {
        // Replace all availability rows for this broker
        await pool.query(
          `DELETE FROM scheduler_availability WHERE broker_id = ? AND tenant_id = ?`,
          [reqBrokerId, MORTGAGE_TENANT_ID],
        );
        for (const av of availability) {
          if (
            av.day_of_week >= 0 &&
            av.day_of_week <= 6 &&
            av.start_time &&
            av.end_time
          ) {
            await pool.query(
              `INSERT INTO scheduler_availability (tenant_id, broker_id, day_of_week, start_time, end_time, is_active)
               VALUES (?, ?, ?, ?, ?, ?)`,
              [
                MORTGAGE_TENANT_ID,
                reqBrokerId,
                av.day_of_week,
                av.start_time,
                av.end_time,
                av.is_active ? 1 : 0,
              ],
            );
          }
        }
      }

      return res.json({ success: true, message: "Scheduler settings updated" });
    } catch (err) {
      console.error("handleUpdateSchedulerSettings error:", err);
      return res
        .status(500)
        .json({ success: false, error: "Internal server error" });
    }
  };

  const handleGetTeamsEligibility: RequestHandler = async (req, res) => {
    try {
      const reqBrokerId = (req as any).brokerId as number;

      const [[brokerRow]] = await pool.query<RowDataPacket[]>(
        `SELECT email FROM brokers WHERE id = ? AND tenant_id = ? LIMIT 1`,
        [reqBrokerId, MORTGAGE_TENANT_ID],
      );

      if (!brokerRow?.email) {
        return res.json({
          success: true,
          eligible: false,
          error:
            "Cannot enable Teams: broker email is missing. Update broker profile email first.",
        });
      }

      const eligibility = await validateTeamsOrganizerEligibility({
        brokerEmail: String(brokerRow.email),
      });

      if (!eligibility.ok) {
        const eligibilityError =
          "error" in eligibility
            ? eligibility.error
            : "Unable to validate Teams organizer eligibility right now.";
        return res.json({
          success: true,
          eligible: false,
          error: eligibilityError,
        });
      }

      // Non-destructive policy readiness check: attempt to list meetings.
      // Returns 200 if app access policy is applied, 404/UnknownError if pending.
      let policyReady = true;
      const overrideOrg =
        process.env.OFFICE365_TEAMS_ORGANIZER_ID?.trim() ||
        process.env.OFFICE365_TEAMS_ORGANIZER_EMAIL?.trim() ||
        "";
      if (!overrideOrg) {
        const policyToken = await getMicrosoftGraphAccessToken();
        if (policyToken) {
          const policyResp = await fetch(
            `https://graph.microsoft.com/v1.0/users/${encodeURIComponent(String(brokerRow.email))}/onlineMeetings?$top=1`,
            { headers: { Authorization: `Bearer ${policyToken}` } },
          );
          if (!policyResp.ok) {
            const policyBody = await policyResp.text().catch(() => "");
            try {
              const parsed = JSON.parse(policyBody);
              if (
                parsed?.error?.code === "UnknownError" ||
                policyResp.status === 404
              ) {
                policyReady = false;
              }
            } catch {
              if (policyResp.status === 404) policyReady = false;
            }
          }
        }
      }

      return res.json({ success: true, eligible: true, policyReady });
    } catch (err) {
      console.error("handleGetTeamsEligibility error:", err);
      return res
        .status(500)
        .json({ success: false, error: "Internal server error" });
    }
  };

  const handleGetScheduledMeetings: RequestHandler = async (req, res) => {
    try {
      const broker = (req as any).broker as { id: number; role: string };
      const { status, from, to, broker_id, page, limit } = req.query as {
        status?: string;
        from?: string;
        to?: string;
        broker_id?: string;
        page?: string;
        limit?: string;
      };

      const pageNum = Math.max(1, parseInt(page || "1", 10) || 1);
      const limitNum = Math.min(
        100,
        Math.max(1, parseInt(limit || "50", 10) || 50),
      );
      const offset = (pageNum - 1) * limitNum;

      let whereClause = `sm.tenant_id = ?`;
      const params: any[] = [MORTGAGE_TENANT_ID];

      // platform_owner may list all meetings or filter by broker_id; everyone else sees own only.
      if (broker.role === "platform_owner") {
        if (broker_id) {
          whereClause += ` AND sm.broker_id = ?`;
          params.push(parseInt(broker_id, 10));
        }
      } else {
        whereClause += ` AND sm.broker_id = ?`;
        params.push(broker.id);
      }

      if (status) {
        whereClause += ` AND sm.status = ?`;
        params.push(status);
      }
      if (from) {
        whereClause += ` AND sm.meeting_date >= ?`;
        params.push(from);
      }
      if (to) {
        whereClause += ` AND sm.meeting_date <= ?`;
        params.push(to);
      }

      const [[countRow]] = await pool.query<RowDataPacket[]>(
        `SELECT COUNT(*) AS total FROM scheduled_meetings sm WHERE ${whereClause}`,
        params,
      );
      const total = Number(countRow?.total ?? 0);

      const [meetings] = await pool.query<RowDataPacket[]>(
        `SELECT sm.*, b.first_name AS broker_first_name, b.last_name AS broker_last_name
         FROM scheduled_meetings sm
         LEFT JOIN brokers b ON b.id = sm.broker_id
         WHERE ${whereClause}
         ORDER BY sm.meeting_date ASC, sm.meeting_time ASC
         LIMIT ? OFFSET ?`,
        [...params, limitNum, offset],
      );

      return res.json({
        success: true,
        meetings: meetings.map((m) => ({
          ...m,
          meeting_date:
            m.meeting_date instanceof Date
              ? m.meeting_date.toISOString().split("T")[0]
              : m.meeting_date,
        })),
        total,
      });
    } catch (err) {
      console.error("handleGetScheduledMeetings error:", err);
      return res
        .status(500)
        .json({ success: false, error: "Internal server error" });
    }
  };

  const handleUpdateScheduledMeeting: RequestHandler = async (req, res) => {
    try {
      const { meetingId } = req.params as { meetingId: string };
      const { id: reqBrokerId, role } = (req as any).broker as {
        id: number;
        role: string;
      };
      const {
        status,
        broker_notes,
        meeting_date,
        meeting_time,
        meeting_type,
        cancelled_reason,
        cancelled_by,
      } = req.body as {
        status?: string;
        broker_notes?: string;
        meeting_date?: string;
        meeting_time?: string;
        meeting_type?: MeetingType;
        cancelled_reason?: string;
        cancelled_by?: "client" | "broker";
      };

      const [rows] = await pool.query<RowDataPacket[]>(
        `SELECT sm.*, b.first_name, b.last_name, b.email AS broker_email, b.timezone AS broker_timezone
         FROM scheduled_meetings sm
         LEFT JOIN brokers b ON b.id = sm.broker_id
         WHERE sm.id = ? AND sm.tenant_id = ?`,
        [parseInt(meetingId), MORTGAGE_TENANT_ID],
      );

      if (!rows[0]) {
        return res
          .status(404)
          .json({ success: false, error: "Meeting not found" });
      }

      const meeting = rows[0];

      if (role !== "platform_owner" && meeting.broker_id !== reqBrokerId) {
        return res.status(403).json({ success: false, error: "Access denied" });
      }

      const updates: string[] = [];
      const updateParams: any[] = [];

      if (status !== undefined) {
        updates.push("status = ?");
        updateParams.push(status);
      }
      if (broker_notes !== undefined) {
        updates.push("broker_notes = ?");
        updateParams.push(broker_notes);
      }
      if (meeting_date !== undefined) {
        updates.push("meeting_date = ?");
        updateParams.push(meeting_date);
      }
      if (meeting_type !== undefined) {
        updates.push("meeting_type = ?");
        updateParams.push(meeting_type);
      }
      if (cancelled_reason !== undefined) {
        updates.push("cancelled_reason = ?");
        updateParams.push(cancelled_reason);
      }
      if (cancelled_by !== undefined) {
        updates.push("cancelled_by = ?");
        updateParams.push(cancelled_by);
      }

      // If rescheduling, recalculate end time
      if (meeting_time !== undefined) {
        const [[settings]] = await pool.query<RowDataPacket[]>(
          `SELECT slot_duration_minutes FROM scheduler_settings WHERE broker_id = ? AND tenant_id = ?`,
          [meeting.broker_id, MORTGAGE_TENANT_ID],
        );
        const dur = settings?.slot_duration_minutes || 30;
        const [mh, mm] = meeting_time.split(":").map(Number);
        const endMin = mh * 60 + mm + dur;
        const endTime = `${String(Math.floor(endMin / 60)).padStart(2, "0")}:${String(endMin % 60).padStart(2, "0")}:00`;
        updates.push("meeting_time = ?", "meeting_end_time = ?");
        updateParams.push(meeting_time + ":00", endTime);
      }

      if (status === "cancelled") {
        updates.push("cancelled_at = NOW()");
        if (!cancelled_by) {
          updates.push("cancelled_by = ?");
          updateParams.push("broker");
        }
      }

      if (updates.length === 0) {
        return res
          .status(400)
          .json({ success: false, error: "No fields to update" });
      }

      updateParams.push(parseInt(meetingId), MORTGAGE_TENANT_ID);
      await pool.query(
        `UPDATE scheduled_meetings SET ${updates.join(", ")} WHERE id = ? AND tenant_id = ?`,
        updateParams,
      );

      // Send cancellation email if status changed to cancelled
      if (status === "cancelled") {
        const brokerName = meeting.first_name
          ? `${meeting.first_name} ${meeting.last_name}`
          : "Your Mortgage Banker";
        const meetingDateStr =
          meeting.meeting_date instanceof Date
            ? meeting.meeting_date.toISOString().split("T")[0]
            : meeting.meeting_date;

        await dispatchSchedulerEmails(`admin-cancel:${meetingId}`, [
          () =>
            sendMeetingCancellationEmail({
              email: meeting.client_email,
              clientName: meeting.client_name,
              brokerName,
              meetingDate: meetingDateStr,
              meetingTime: meeting.meeting_time,
              cancelledBy: "broker",
              reason: cancelled_reason || null,
              brokerTimezone: meeting.broker_timezone || undefined,
            }),
        ]);
      }

      return res.json({ success: true, message: "Meeting updated" });
    } catch (err) {
      console.error("handleUpdateScheduledMeeting error:", err);
      return res
        .status(500)
        .json({ success: false, error: "Internal server error" });
    }
  };

  const handleCreateScheduledMeeting: RequestHandler = async (req, res) => {
    try {
      const broker = (req as any).broker as {
        id: number;
        tenant_id: number;
        role: string;
      };
      const {
        client_name,
        client_email,
        client_phone,
        meeting_date,
        meeting_time,
        meeting_type,
        notes,
        target_broker_id,
      } = req.body as {
        client_name?: string;
        client_email?: string;
        client_phone?: string;
        meeting_date?: string;
        meeting_time?: string;
        meeting_type?: MeetingType;
        notes?: string;
        target_broker_id?: number;
      };

      if (
        !client_name ||
        !client_email ||
        !meeting_date ||
        !meeting_time ||
        !meeting_type
      ) {
        return res.status(400).json({
          success: false,
          error:
            "client_name, client_email, meeting_date, meeting_time, and meeting_type are required",
        });
      }

      const effectiveBrokerId = target_broker_id || broker.id;

      // Load broker info for email
      const [[brokerData]] = (await pool.query(
        `SELECT first_name, last_name, email, phone, timezone FROM brokers WHERE id = ? LIMIT 1`,
        [effectiveBrokerId],
      )) as [any[], any];

      const [[settings]] = await pool.query<RowDataPacket[]>(
        `SELECT slot_duration_minutes FROM scheduler_settings WHERE broker_id = ? AND tenant_id = ?`,
        [effectiveBrokerId, MORTGAGE_TENANT_ID],
      );
      const dur = settings?.slot_duration_minutes || 30;
      const [mh, mm] = meeting_time.split(":").map(Number);
      const endMin = mh * 60 + mm + dur;
      const endTime = `${String(Math.floor(endMin / 60)).padStart(2, "0")}:${String(endMin % 60).padStart(2, "0")}:00`;

      // Check for overlapping meetings for this broker
      const [overlapping] = await pool.query<RowDataPacket[]>(
        `SELECT id FROM scheduled_meetings
         WHERE broker_id = ?
           AND meeting_date = ?
           AND status NOT IN ('cancelled', 'no_show')
           AND meeting_time < ?
           AND meeting_end_time > ?
         LIMIT 1`,
        [effectiveBrokerId, meeting_date, endTime, meeting_time + ":00"],
      );
      if ((overlapping as RowDataPacket[]).length > 0) {
        return res.status(409).json({
          success: false,
          error:
            "This time slot is already booked. Please choose a different time.",
        });
      }

      const adminSchedPrecheck = await precheckSchedulerQuota({
        source: "scheduler",
        refType: "scheduled_meeting",
        refId: "pending",
      });
      if (!adminSchedPrecheck.allowed) {
        return res
          .status(402)
          .json(schedulerQuotaDeniedResponse(adminSchedPrecheck));
      }

      // Create Zoom meeting for video type
      let zoomMeetingId: string | null = null;
      let zoomJoinUrl: string | null = null;
      let zoomStartUrl: string | null = null;
      let teamsMeetingId: string | null = null;
      let teamsJoinUrl: string | null = null;
      let teamsHostUrl: string | null = null;

      if (meeting_type === "video") {
        try {
          const zoomMeeting = await createZoomMeeting({
            topic: `Mortgage Meeting — ${client_name.trim()}`,
            startDatetime: `${meeting_date}T${meeting_time}:00`,
            durationMinutes: dur,
            timezone: "America/Chicago",
          });
          if (zoomMeeting) {
            zoomMeetingId = zoomMeeting.meeting_id;
            zoomJoinUrl = zoomMeeting.join_url;
            zoomStartUrl = zoomMeeting.start_url;
          } else {
            return res.status(503).json({
              success: false,
              error:
                "Unable to create Zoom meeting right now. Please try again in a moment.",
            });
          }
        } catch (zoomErr) {
          console.error(
            "Zoom meeting creation error (admin booking):",
            zoomErr,
          );
          return res.status(503).json({
            success: false,
            error:
              "Unable to create Zoom meeting right now. Please try again in a moment.",
          });
        }
      }

      if (meeting_type === "teams") {
        try {
          const teamsMeeting = await createTeamsMeeting({
            organizerEmail: brokerData.email,
            subject: `Mortgage Meeting - ${client_name.trim()}`,
            startDatetime: `${meeting_date}T${meeting_time}:00`,
            endDatetime: `${meeting_date}T${endTime.slice(0, 5)}:00`,
          });
          if (teamsMeeting && !("policyPending" in teamsMeeting)) {
            teamsMeetingId = teamsMeeting.meeting_id;
            teamsJoinUrl = teamsMeeting.join_url;
            teamsHostUrl = teamsMeeting.host_url;
          } else {
            const isPending = teamsMeeting && "policyPending" in teamsMeeting;
            return res.status(503).json({
              success: false,
              errorCode: isPending ? "TEAMS_POLICY_PENDING" : undefined,
              error: isPending
                ? "Teams meeting setup is still activating. This typically takes up to 1 hour after first setup. Please try again in a few minutes."
                : "Unable to create Teams meeting right now. Please try again in a moment.",
            });
          }
        } catch (teamsErr) {
          console.error(
            "Teams meeting creation error (admin booking):",
            teamsErr,
          );
          return res.status(503).json({
            success: false,
            error:
              "Unable to create Teams meeting right now. Please try again in a moment.",
          });
        }
      }

      const bookingToken = crypto.randomUUID();

      const [result] = await pool.query<ResultSetHeader>(
        `INSERT INTO scheduled_meetings
           (tenant_id, broker_id, client_name, client_email, client_phone,
            meeting_date, meeting_time, meeting_end_time, meeting_type,
            zoom_meeting_id, zoom_join_url, zoom_start_url,
            teams_meeting_id, teams_join_url,
            status, notes, booking_token)
          VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'confirmed', ?, ?)`,
        [
          MORTGAGE_TENANT_ID,
          effectiveBrokerId,
          client_name.trim(),
          client_email.trim().toLowerCase(),
          client_phone || null,
          meeting_date,
          meeting_time + ":00",
          endTime,
          meeting_type,
          zoomMeetingId,
          zoomJoinUrl,
          zoomStartUrl,
          teamsMeetingId,
          teamsJoinUrl,
          notes || null,
          bookingToken,
        ],
      );

      await recordSchedulerQuota({
        source: "scheduler",
        refType: "scheduled_meeting",
        refId: String(result.insertId),
      });

      const brokerName = brokerData
        ? `${brokerData.first_name} ${brokerData.last_name}`
        : "Your Mortgage Banker";

      if (brokerData) {
        await dispatchSchedulerEmails(`admin-book:${result.insertId}`, [
          () =>
            sendMeetingConfirmationToClient({
              email: client_email.trim().toLowerCase(),
              clientName: client_name.trim(),
              brokerName,
              brokerEmail: brokerData.email,
              meetingId: result.insertId,
              meetingDate: meeting_date,
              meetingTime: meeting_time,
              meetingEndTime: endTime.slice(0, 5),
              meetingType: meeting_type,
              videoRoomUrl: meeting_type === "teams" ? teamsJoinUrl : zoomJoinUrl,
              videoHostUrl: meeting_type === "teams" ? teamsHostUrl : zoomStartUrl,
              brokerPhone: brokerData.phone || null,
              bookingToken,
              notes: notes || null,
              brokerTimezone: brokerData.timezone || undefined,
              rescheduleToken: bookingToken,
            }),
          () =>
            sendMeetingNotificationToBroker({
              brokerEmail: brokerData.email,
              brokerName,
              clientName: client_name.trim(),
              clientEmail: client_email.trim().toLowerCase(),
              clientPhone: client_phone || null,
              meetingDate: meeting_date,
              meetingTime: meeting_time,
              meetingEndTime: endTime.slice(0, 5),
              meetingType: meeting_type,
              videoRoomUrl: meeting_type === "teams" ? teamsJoinUrl : zoomJoinUrl,
              videoHostUrl: meeting_type === "teams" ? teamsHostUrl : zoomStartUrl,
              notes: notes || null,
              meetingId: result.insertId,
              brokerTimezone: brokerData.timezone || undefined,
            }),
        ]);
      }

      return res.json({
        success: true,
        meeting_id: result.insertId,
        booking_token: bookingToken,
        zoom_join_url: zoomJoinUrl,
        zoom_start_url: zoomStartUrl,
        teams_join_url: teamsJoinUrl,
      });
    } catch (err) {
      console.error("handleCreateScheduledMeeting error:", err);
      return res
        .status(500)
        .json({ success: false, error: "Internal server error" });
    }
  };

  // Register routes
  // Public
  expressApp.get("/api/public/scheduler", handleGetPublicScheduler);
  expressApp.get("/api/public/scheduler/:token", handleGetPublicScheduler);
  expressApp.get("/api/public/scheduler/:token/slots", handleGetPublicSlots);
  expressApp.post("/api/public/scheduler/book", handleBookMeeting);
  expressApp.post(
    "/api/public/scheduler/cancel/:bookingToken",
    handleCancelMeetingByToken,
  );
  expressApp.get(
    "/api/public/scheduler/reschedule/:bookingToken",
    handleGetRescheduleInfo,
  );
  expressApp.post(
    "/api/public/scheduler/reschedule/:bookingToken",
    handleRescheduleMeeting,
  );

  // Admin (authenticated)
  expressApp.get(
    "/api/scheduler/settings",
    verifyBrokerSession,
    handleGetSchedulerSettings,
  );
  expressApp.get(
    "/api/scheduler/settings/:brokerId",
    verifyBrokerSession,
    async (req, res) => {
      try {
        const targetBrokerId = parseInt(req.params.brokerId);
        if (isNaN(targetBrokerId)) {
          return res
            .status(400)
            .json({ success: false, error: "Invalid broker ID" });
        }
        const [[settings]] = await pool.query<RowDataPacket[]>(
          `SELECT * FROM scheduler_settings WHERE broker_id = ? AND tenant_id = ?`,
          [targetBrokerId, MORTGAGE_TENANT_ID],
        );
        const [availability] = await pool.query<RowDataPacket[]>(
          `SELECT * FROM scheduler_availability WHERE broker_id = ? AND tenant_id = ? ORDER BY day_of_week ASC`,
          [targetBrokerId, MORTGAGE_TENANT_ID],
        );
        return res.json({
          success: true,
          settings: settings
            ? {
                ...settings,
                is_enabled: !!settings.is_enabled,
                allow_phone: !!settings.allow_phone,
                allow_video: !!settings.allow_video,
                allow_teams: !!settings.allow_teams,
                allow_office: !!settings.allow_office,
              }
            : null,
          availability: availability.map((a) => ({
            ...a,
            is_active: !!a.is_active,
          })),
        });
      } catch (err) {
        console.error("handleGetSchedulerSettingsForBroker error:", err);
        return res
          .status(500)
          .json({ success: false, error: "Internal server error" });
      }
    },
  );
  expressApp.put(
    "/api/scheduler/settings",
    verifyBrokerSession,
    handleUpdateSchedulerSettings,
  );
  expressApp.get(
    "/api/scheduler/teams-eligibility",
    verifyBrokerSession,
    handleGetTeamsEligibility,
  );
  expressApp.get(
    "/api/scheduler/meetings",
    verifyBrokerSession,
    handleGetScheduledMeetings,
  );
  expressApp.post(
    "/api/scheduler/meetings",
    verifyBrokerSession,
    handleCreateScheduledMeeting,
  );
  expressApp.put(
    "/api/scheduler/meetings/:meetingId",
    verifyBrokerSession,
    handleUpdateScheduledMeeting,
  );

  // ─── Scheduler Blocked Ranges ─────────────────────────────────────────────

  // mysql2 with timezone:'+00:00' returns DATETIME columns as UTC Date objects.
  // Serialising them directly via res.json() appends a 'Z' suffix, which causes
  // the client to shift the value by the user's UTC offset. Instead we return a
  // plain local-time string (no 'Z'), so parseISO on the client treats it as
  // local time and displays the value the broker originally entered.
  const dtStr = (d: Date | string | null | undefined): string => {
    if (!d) return "";
    // Always return an unambiguous UTC ISO string (with Z suffix)
    const date =
      typeof d === "string"
        ? new Date(d.replace(" ", "T") + (d.endsWith("Z") ? "" : "Z"))
        : d;
    const p = (n: number) => String(n).padStart(2, "0");
    return `${date.getUTCFullYear()}-${p(date.getUTCMonth() + 1)}-${p(date.getUTCDate())}T${p(date.getUTCHours())}:${p(date.getUTCMinutes())}:${p(date.getUTCSeconds())}Z`;
  };

  const serializeBlockedRange = (row: RowDataPacket) => ({
    ...row,
    start_datetime: dtStr(row.start_datetime as Date | string),
    end_datetime: dtStr(row.end_datetime as Date | string),
    source: (row.source as string) ?? "manual",
    external_id: row.external_id ?? null,
  });

  const handleGetBlockedRanges: RequestHandler = async (req, res) => {
    try {
      const broker = (req as any).broker as { id: number };
      const [rows] = await pool.query<RowDataPacket[]>(
        `SELECT id, broker_id, start_datetime, end_datetime, label, source, external_id, created_at
         FROM scheduler_blocked_ranges
         WHERE broker_id = ? AND tenant_id = ?
         ORDER BY start_datetime ASC`,
        [broker.id, MORTGAGE_TENANT_ID],
      );
      return res.json({
        success: true,
        blocked_ranges: rows.map(serializeBlockedRange),
      });
    } catch (err) {
      console.error("handleGetBlockedRanges error:", err);
      return res
        .status(500)
        .json({ success: false, error: "Internal server error" });
    }
  };

  const handleAddBlockedRange: RequestHandler = async (req, res) => {
    try {
      const broker = (req as any).broker as { id: number };
      const { start_datetime, end_datetime, label } = req.body as {
        start_datetime: string;
        end_datetime: string;
        label: string;
      };

      if (!start_datetime || !end_datetime || !label?.trim()) {
        return res.status(400).json({
          success: false,
          error: "start_datetime, end_datetime, and label are required",
        });
      }

      if (new Date(end_datetime) <= new Date(start_datetime)) {
        return res.status(400).json({
          success: false,
          error: "end_datetime must be after start_datetime",
        });
      }

      // Normalize to MySQL UTC format regardless of whether the client sent a
      // local ISO string ("2026-05-22T13:00") or a UTC string ("...Z").
      const toMySQLUtc = (s: string) =>
        new Date(s)
          .toISOString()
          .replace("T", " ")
          .replace(/\.\d+Z$/, "");

      const [result] = await pool.query<ResultSetHeader>(
        `INSERT INTO scheduler_blocked_ranges
           (tenant_id, broker_id, start_datetime, end_datetime, label)
         VALUES (?, ?, ?, ?, ?)`,
        [
          MORTGAGE_TENANT_ID,
          broker.id,
          toMySQLUtc(start_datetime),
          toMySQLUtc(end_datetime),
          label || null,
        ],
      );

      const [[newRow]] = await pool.query<RowDataPacket[]>(
        `SELECT id, broker_id, start_datetime, end_datetime, label, source, external_id, created_at
         FROM scheduler_blocked_ranges WHERE id = ?`,
        [result.insertId],
      );

      return res.json({
        success: true,
        blocked_range: serializeBlockedRange(newRow),
      });
    } catch (err) {
      console.error("handleAddBlockedRange error:", err);
      return res
        .status(500)
        .json({ success: false, error: "Internal server error" });
    }
  };

  const handleDeleteBlockedRange: RequestHandler = async (req, res) => {
    try {
      const broker = (req as any).broker as { id: number };
      const { id } = req.params as { id: string };

      const [result] = await pool.query<ResultSetHeader>(
        `DELETE FROM scheduler_blocked_ranges
         WHERE id = ? AND broker_id = ? AND tenant_id = ?`,
        [id, broker.id, MORTGAGE_TENANT_ID],
      );

      if (result.affectedRows === 0) {
        return res
          .status(404)
          .json({ success: false, error: "Blocked range not found" });
      }

      return res.json({ success: true });
    } catch (err) {
      console.error("handleDeleteBlockedRange error:", err);
      return res
        .status(500)
        .json({ success: false, error: "Internal server error" });
    }
  };

  expressApp.get(
    "/api/scheduler/blocked-ranges",
    verifyBrokerSession,
    handleGetBlockedRanges,
  );
  expressApp.post(
    "/api/scheduler/blocked-ranges",
    verifyBrokerSession,
    handleAddBlockedRange,
  );
  expressApp.delete(
    "/api/scheduler/blocked-ranges/:id",
    verifyBrokerSession,
    handleDeleteBlockedRange,
  );

  // ─── O365 Calendar Sync ───────────────────────────────────────────────────

  const handleSyncO365Calendar: RequestHandler = async (req, res) => {
    try {
      const broker = (req as any).broker as { id: number };
      const brokerId = broker.id;

      // Find active O365 mailbox for this broker
      const [mailboxRows] = await pool.query<ConversationMailboxRow[]>(
        `SELECT * FROM conversation_email_mailboxes
         WHERE assigned_broker_id = ? AND tenant_id = ? AND provider = 'office365'
           AND status IN ('active','auth_required')
         LIMIT 1`,
        [brokerId, MORTGAGE_TENANT_ID],
      );

      if (!mailboxRows.length) {
        return res.status(404).json({
          success: false,
          error: "No connected Office 365 mailbox found for this account",
        });
      }

      const mailbox = mailboxRows[0] as ConversationMailboxRow;
      const { synced_count } = await syncO365CalendarForBroker(
        mailbox,
        brokerId,
      );

      // Notify the broker's client in real-time so the calendar grid refreshes
      await publishToAbly(
        `broker-notifications:${brokerId}`,
        "o365_calendar_synced",
        { synced_count },
      );

      const syncedAt = new Date().toISOString();

      return res.json({
        success: true,
        synced_count,
        last_synced_at: syncedAt,
        message: `Synced ${synced_count} event${synced_count !== 1 ? "s" : ""} from your Outlook calendar`,
      });
    } catch (err: any) {
      if (err instanceof Office365AuthRequiredError) {
        const isRedirect = err.message.toLowerCase().includes("redirect");
        return res.status(403).json({
          success: false,
          error: isRedirect
            ? `${err.message} Also ensure Azure App registration includes redirect URIs for both admin.encoremortgage.org and portal.encoremortgage.org.`
            : "Your Outlook connection expired. Go to Settings → Email, disconnect, then reconnect to restore calendar access.",
        });
      }

      const status = err?.response?.status ?? err?.status;
      const graphMsg: string =
        err?.response?.data?.error?.message || err?.message || "";

      if (status === 403) {
        console.warn(
          "handleSyncO365Calendar: calendar permission denied — mailbox needs reconnect",
          err?.response?.data,
        );
        return res.status(403).json({
          success: false,
          error:
            "Calendar access is not permitted with your current connection. Please reconnect your Outlook mailbox (Settings → Email) to grant calendar permissions, then try again.",
        });
      }

      if (status === 401) {
        return res.status(403).json({
          success: false,
          error:
            "Outlook sign-in expired. Reconnect your mailbox under Settings → Email, then try Sync Now again.",
        });
      }

      const sqlCode = String(err?.code || "");
      if (sqlCode === "ER_BAD_FIELD_ERROR" || sqlCode === "ER_NO_SUCH_TABLE") {
        console.error(
          "handleSyncO365Calendar: database schema missing o365 columns — run migration 20260519_120000_scheduler_blocked_ranges_o365_source.sql",
          err,
        );
        return res.status(500).json({
          success: false,
          error:
            "Calendar sync is not configured on the server database. Contact support to apply the scheduler migration.",
        });
      }

      console.error(
        "handleSyncO365Calendar error:",
        graphMsg || err,
        err?.response?.data ?? err,
      );
      return res.status(500).json({
        success: false,
        error:
          graphMsg && graphMsg.length < 200
            ? `Calendar sync failed: ${graphMsg}`
            : "Internal server error",
      });
    }
  };

  const handleGetO365CalendarStatus: RequestHandler = async (req, res) => {
    try {
      const broker = (req as any).broker as { id: number };

      const [mailboxRows] = await pool.query<RowDataPacket[]>(
        `SELECT id, mailbox_email, status, updated_at
         FROM conversation_email_mailboxes
         WHERE assigned_broker_id = ? AND tenant_id = ? AND provider = 'office365'
           AND status IN ('active','auth_required')
         LIMIT 1`,
        [broker.id, MORTGAGE_TENANT_ID],
      );

      const connected = mailboxRows.length > 0;

      const [[blockInfo]] = await pool.query<RowDataPacket[]>(
        `SELECT COUNT(*) AS count, MAX(created_at) AS last_block_at
         FROM scheduler_blocked_ranges
         WHERE broker_id = ? AND tenant_id = ? AND source = 'o365'`,
        [broker.id, MORTGAGE_TENANT_ID],
      );

      const lastRaw =
        blockInfo?.last_block_at ??
        (connected ? mailboxRows[0].updated_at : null);

      return res.json({
        success: true,
        connected,
        mailbox_email: connected
          ? (mailboxRows[0].mailbox_email as string)
          : null,
        synced_count: Number(blockInfo?.count ?? 0),
        last_synced_at: lastRaw ? dtStr(lastRaw as Date | string) : null,
      });
    } catch (err) {
      console.error("handleGetO365CalendarStatus error:", err);
      return res
        .status(500)
        .json({ success: false, error: "Internal server error" });
    }
  };

  expressApp.get(
    "/api/scheduler/calendar-sync/status",
    verifyBrokerSession,
    handleGetO365CalendarStatus,
  );
  expressApp.post(
    "/api/scheduler/calendar-sync",
    verifyBrokerSession,
    handleSyncO365Calendar,
  );

  // ─── Calendar Events ─────────────────────────────────────────────────────

  const handleGetCalendarEvents: RequestHandler = async (req, res) => {
    try {
      const broker = (req as any).broker as {
        id: number;
        tenant_id: number;
        role: string;
      };
      const {
        from,
        to,
        event_type,
        search,
        sort_by,
        sort_order,
        page,
        limit,
        calendar_month,
      } = req.query as {
        from?: string;
        to?: string;
        event_type?: string;
        search?: string;
        sort_by?: string;
        sort_order?: string;
        page?: string;
        limit?: string;
        /** YYYY-MM — calendar view mode: returns all events visible in that month,
         *  including yearly-recurrence events matched by month/day regardless of year.
         *  When present, pagination is skipped (limit set to 1000). */
        calendar_month?: string;
      };

      // calendar_month mode: fetch all visible events for that month (no pagination)
      const isCalendarView = !!(
        calendar_month && /^\d{4}-\d{2}$/.test(calendar_month)
      );
      const _parsedPage = parseInt(page ?? "1", 10);
      const _parsedLimit = parseInt(limit ?? "25", 10);
      const pageNum = isCalendarView
        ? 1
        : Math.max(1, Number.isFinite(_parsedPage) ? _parsedPage : 1);
      const limitNum = isCalendarView
        ? 1000
        : Math.min(
            100,
            Math.max(1, Number.isFinite(_parsedLimit) ? _parsedLimit : 25),
          );
      const offset = (pageNum - 1) * limitNum;

      const conditions: string[] = ["ce.tenant_id = ?"];
      const params: any[] = [broker.tenant_id];

      // platform_owner sees all tenant events; everyone else is scoped to events
      // they created or client-linked rows for clients they own (4-path model).
      if (broker.role !== "platform_owner") {
        conditions.push(CALENDAR_EVENT_BROKER_VISIBILITY_SQL);
        params.push(broker.id, ...loanOwnershipWhereParams(broker.id));
      }

      if (isCalendarView) {
        // For the calendar grid: yearly-recurring events match by month only (projected
        // to any year); non-recurring events must fall within the calendar month.
        const [yyyy, mm] = calendar_month!.split("-");
        const monthNum = parseInt(mm, 10);
        const firstDay = `${yyyy}-${mm}-01`;
        // Last day of month
        const lastDay = new Date(parseInt(yyyy, 10), monthNum, 0)
          .toISOString()
          .slice(0, 10);
        conditions.push(
          `(
            (ce.recurrence = 'yearly' AND MONTH(ce.event_date) = ?)
            OR
            (ce.recurrence != 'yearly' AND ce.event_date BETWEEN ? AND ?)
          )`,
        );
        params.push(monthNum, firstDay, lastDay);
      } else {
        if (from) {
          conditions.push("ce.event_date >= ?");
          params.push(from);
        }
        if (to) {
          conditions.push("ce.event_date <= ?");
          params.push(to);
        }
      }
      if (event_type && event_type !== "all") {
        conditions.push("ce.event_type = ?");
        params.push(event_type);
      }
      if (search && search.trim()) {
        conditions.push(
          `(ce.title LIKE ? OR CONCAT(c.first_name, ' ', c.last_name) LIKE ? OR ce.linked_person_name LIKE ?)`,
        );
        const like = `%${search.trim()}%`;
        params.push(like, like, like);
      }

      const allowedSortColumns: Record<string, string> = {
        event_date: "ce.event_date",
        title: "ce.title",
        event_type: "ce.event_type",
        linked_client_name: "linked_client_name",
        recurrence: "ce.recurrence",
      };
      const orderCol = allowedSortColumns[sort_by ?? ""] ?? "ce.event_date";
      const orderDir = sort_order?.toUpperCase() === "DESC" ? "DESC" : "ASC";

      const where = conditions.join(" AND ");

      // Total count (reuse same WHERE but no JOIN needed for count)
      const [[{ total }]] = (await pool.query(
        `SELECT COUNT(*) AS total
         FROM calendar_events ce
         LEFT JOIN clients c ON c.id = ce.linked_client_id
         WHERE ${where}`,
        params,
      )) as any;

      const [rows] = await pool.query(
        `SELECT ce.*,
                CONCAT(c.first_name, ' ', c.last_name) AS linked_client_name
         FROM calendar_events ce
         LEFT JOIN clients c ON c.id = ce.linked_client_id
         WHERE ${where}
         ORDER BY ${orderCol} ${orderDir}, ce.event_time ASC
         LIMIT ? OFFSET ?`,
        [...params, limitNum, offset],
      );

      const events = (rows as any[]).map((r) => ({
        ...r,
        all_day: r.all_day === 1 || r.all_day === true,
      }));

      res.json({
        success: true,
        events,
        total: Number(total),
        pagination: {
          page: pageNum,
          limit: limitNum,
          total: Number(total),
          totalPages: Math.ceil(Number(total) / limitNum),
        },
      });
    } catch (err) {
      console.error("handleGetCalendarEvents error:", err);
      res.status(500).json({ success: false, error: "Internal server error" });
    }
  };

  const handleCreateCalendarEvent: RequestHandler = async (req, res) => {
    try {
      const broker = (req as any).broker as { id: number; tenant_id: number };
      const {
        event_type,
        title,
        description,
        event_date,
        event_time,
        all_day,
        recurrence,
        color,
        linked_client_id,
        linked_person_name,
      } = req.body as {
        event_type?: string;
        title?: string;
        description?: string;
        event_date?: string;
        event_time?: string;
        all_day?: boolean;
        recurrence?: string;
        color?: string;
        linked_client_id?: number | null;
        linked_person_name?: string;
      };

      if (!event_type || !title?.trim() || !event_date) {
        return res.status(400).json({
          success: false,
          error: "event_type, title, and event_date are required",
        });
      }

      if (title.trim().length > 255) {
        return res.status(400).json({
          success: false,
          error: "title must be 255 characters or less",
        });
      }

      const validTypes = [
        "birthday",
        "home_anniversary",
        "realtor_anniversary",
        "important_date",
        "reminder",
        "other",
      ];
      if (!validTypes.includes(event_type)) {
        return res
          .status(400)
          .json({ success: false, error: "Invalid event_type" });
      }

      const brokerWithRole = (req as any).broker as {
        id: number;
        tenant_id: number;
        role: string;
      };
      if (linked_client_id) {
        const canLinkClient = await brokerCanAccessLinkedClient(
          brokerWithRole,
          linked_client_id,
        );
        if (!canLinkClient) {
          return res.status(403).json({
            success: false,
            error: "You do not have access to this client",
          });
        }
      }

      const [result] = await pool.query(
        `INSERT INTO calendar_events
           (tenant_id, broker_id, event_type, title, description,
            event_date, event_time, all_day, recurrence, color,
            linked_client_id, linked_person_name)
         VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
        [
          broker.tenant_id,
          broker.id,
          event_type,
          title.trim(),
          description?.trim() || null,
          event_date,
          event_time || null,
          all_day !== false ? 1 : 0,
          recurrence || "none",
          color || null,
          linked_client_id || null,
          linked_person_name?.trim() || null,
        ],
      );

      const insertId = (result as any).insertId;

      const [[created]] = (await pool.query(
        `SELECT ce.*,
                CONCAT(c.first_name, ' ', c.last_name) AS linked_client_name
         FROM calendar_events ce
         LEFT JOIN clients c ON c.id = ce.linked_client_id
         WHERE ce.id = ?`,
        [insertId],
      )) as any;

      res.status(201).json({
        success: true,
        event: { ...created, all_day: created.all_day === 1 },
      });
    } catch (err) {
      console.error("handleCreateCalendarEvent error:", err);
      res.status(500).json({ success: false, error: "Internal server error" });
    }
  };

  const handleUpdateCalendarEvent: RequestHandler = async (req, res) => {
    try {
      const broker = (req as any).broker as {
        id: number;
        tenant_id: number;
        role: string;
      };
      const eventId = parseInt(req.params.eventId, 10);

      // Verify ownership
      const [[existing]] = (await pool.query(
        `SELECT * FROM calendar_events WHERE id = ? AND tenant_id = ?`,
        [eventId, broker.tenant_id],
      )) as any;

      if (!existing) {
        return res
          .status(404)
          .json({ success: false, error: "Event not found" });
      }

      const canAccess = await brokerCanAccessCalendarEvent(broker, existing);
      if (!canAccess) {
        return res.status(403).json({ success: false, error: "Forbidden" });
      }

      const {
        event_type,
        title,
        description,
        event_date,
        event_time,
        all_day,
        recurrence,
        color,
        linked_client_id,
        linked_person_name,
      } = req.body;

      const updates: Record<string, any> = {};
      if (event_type !== undefined) updates.event_type = event_type;
      if (title !== undefined) updates.title = title.trim();
      if (description !== undefined) updates.description = description || null;
      if (event_date !== undefined) updates.event_date = event_date;
      if (event_time !== undefined) updates.event_time = event_time || null;
      if (all_day !== undefined) updates.all_day = all_day ? 1 : 0;
      if (recurrence !== undefined) updates.recurrence = recurrence;
      if (color !== undefined) updates.color = color || null;
      if (linked_client_id !== undefined)
        updates.linked_client_id = linked_client_id || null;
      if (linked_person_name !== undefined)
        updates.linked_person_name = linked_person_name?.trim() || null;

      if (Object.keys(updates).length === 0) {
        return res.json({ success: true });
      }

      const setClauses = Object.keys(updates)
        .map((k) => `${k} = ?`)
        .join(", ");
      await pool.query(
        `UPDATE calendar_events SET ${setClauses} WHERE id = ?`,
        [...Object.values(updates), eventId],
      );

      res.json({ success: true });
    } catch (err) {
      console.error("handleUpdateCalendarEvent error:", err);
      res.status(500).json({ success: false, error: "Internal server error" });
    }
  };

  const handleDeleteCalendarEvent: RequestHandler = async (req, res) => {
    try {
      const broker = (req as any).broker as {
        id: number;
        tenant_id: number;
        role: string;
      };
      const eventId = parseInt(req.params.eventId, 10);

      const [[existing]] = (await pool.query(
        `SELECT * FROM calendar_events WHERE id = ? AND tenant_id = ?`,
        [eventId, broker.tenant_id],
      )) as any;

      if (!existing) {
        return res
          .status(404)
          .json({ success: false, error: "Event not found" });
      }

      const canAccess = await brokerCanAccessCalendarEvent(broker, existing);
      if (!canAccess) {
        return res.status(403).json({ success: false, error: "Forbidden" });
      }

      await pool.query(`DELETE FROM calendar_events WHERE id = ?`, [eventId]);
      res.json({ success: true });
    } catch (err) {
      console.error("handleDeleteCalendarEvent error:", err);
      res.status(500).json({ success: false, error: "Internal server error" });
    }
  };

  /**
   * POST /api/calendar/sync-birthdays
   * Upserts birthday calendar events from all clients with date_of_birth,
   * and from all broker_profiles with date_of_birth (partners + mortgage bankers).
   * Admin only. Idempotent — safe to run multiple times.
   */
  const handleSyncBirthdays: RequestHandler = async (req, res) => {
    try {
      const broker = (req as any).broker as {
        id: number;
        tenant_id: number;
        role: string;
      };
      if (broker.role !== "admin" && broker.role !== "platform_owner") {
        return res.status(403).json({ success: false, error: "Admin only" });
      }

      let created = 0;
      let updated = 0;
      const _SYNC_CHUNK = 200;

      // ── 1. Clients (batched) ────────────────────────────────────────────
      const [clientRows] = (await pool.query(
        `SELECT id, first_name, last_name, date_of_birth
         FROM clients
         WHERE tenant_id = ? AND date_of_birth IS NOT NULL`,
        [broker.tenant_id],
      )) as [any[], any];

      if (clientRows.length > 0) {
        const clientIds = clientRows.map((c: any) => Number(c.id));

        // Single query: find all clients that already have a birthday event
        const [existingRows] = (await pool.query(
          `SELECT linked_client_id FROM calendar_events
           WHERE tenant_id = ? AND event_type = 'birthday'
             AND linked_client_id IN (?)`,
          [broker.tenant_id, clientIds],
        )) as [any[], any];
        const existingClientIds = new Set<number>(
          existingRows.map((r: any) => Number(r.linked_client_id)),
        );

        const toInsert: any[][] = [];
        const toUpdate: {
          clientId: number;
          title: string;
          eventDate: string;
        }[] = [];

        for (const c of clientRows) {
          const title = `${c.first_name} ${c.last_name}'s Birthday`;
          const raw = c.date_of_birth as Date | string;
          const eventDate =
            raw instanceof Date
              ? raw.toISOString().slice(0, 10)
              : String(raw).slice(0, 10);
          if (existingClientIds.has(Number(c.id))) {
            toUpdate.push({ clientId: Number(c.id), title, eventDate });
          } else {
            toInsert.push([
              broker.tenant_id,
              broker.id,
              "birthday",
              title,
              eventDate,
              1,
              "yearly",
              Number(c.id),
            ]);
          }
        }

        // Batch INSERT (chunked)
        for (let i = 0; i < toInsert.length; i += _SYNC_CHUNK) {
          const chunk = toInsert.slice(i, i + _SYNC_CHUNK);
          await pool.query(
            `INSERT INTO calendar_events
               (tenant_id, broker_id, event_type, title, event_date,
                all_day, recurrence, linked_client_id)
             VALUES ?`,
            [chunk],
          );
          created += chunk.length;
        }

        // Batch UPDATE via CASE WHEN linked_client_id (chunked)
        for (let i = 0; i < toUpdate.length; i += _SYNC_CHUNK) {
          const chunk = toUpdate.slice(i, i + _SYNC_CHUNK);
          const whenClauses = chunk.map(() => "WHEN ? THEN ?").join(" ");
          const params: any[] = [];
          chunk.forEach((u) => params.push(u.clientId, u.title));
          chunk.forEach((u) => params.push(u.clientId, u.eventDate));
          params.push(broker.tenant_id);
          params.push(chunk.map((u) => u.clientId));
          await pool.query(
            `UPDATE calendar_events
             SET title      = CASE linked_client_id ${whenClauses} END,
                 event_date = CASE linked_client_id ${whenClauses} END,
                 updated_at = NOW()
             WHERE tenant_id = ? AND event_type = 'birthday'
               AND linked_client_id IN (?)`,
            params,
          );
          updated += chunk.length;
        }
      }

      // ── 2. Broker profiles (partners + mortgage bankers) ───────────────
      const [brokerRows] = (await pool.query(
        `SELECT bp.date_of_birth, b.first_name, b.last_name, b.role
         FROM broker_profiles bp
         JOIN brokers b ON b.id = bp.broker_id
         WHERE b.tenant_id = ? AND bp.date_of_birth IS NOT NULL`,
        [broker.tenant_id],
      )) as [any[], any];

      for (const b of brokerRows) {
        const roleLabel = b.role === "admin" ? "Mortgage Banker" : "Partner";
        const title = `${b.first_name} ${b.last_name}'s Birthday (${roleLabel})`;
        const rawB = b.date_of_birth as Date | string;
        const eventDate =
          rawB instanceof Date
            ? rawB.toISOString().slice(0, 10)
            : String(rawB).slice(0, 10);

        const [[existing]] = (await pool.query(
          `SELECT id FROM calendar_events
           WHERE tenant_id = ? AND event_type = 'birthday'
             AND title = ? AND linked_client_id IS NULL
           LIMIT 1`,
          [broker.tenant_id, title],
        )) as [any[], any];

        if (existing) {
          await pool.query(
            `UPDATE calendar_events
             SET event_date = ?, updated_at = NOW()
             WHERE id = ?`,
            [eventDate, existing.id],
          );
          updated++;
        } else {
          await pool.query(
            `INSERT INTO calendar_events
               (tenant_id, broker_id, event_type, title, event_date,
                all_day, recurrence, linked_person_name)
             VALUES (?, ?, 'birthday', ?, ?, 1, 'yearly', ?)`,
            [
              broker.tenant_id,
              broker.id,
              title,
              eventDate,
              `${b.first_name} ${b.last_name}`,
            ],
          );
          created++;
        }
      }

      res.json({ success: true, created, updated });
    } catch (err) {
      console.error("handleSyncBirthdays error:", err);
      res.status(500).json({ success: false, error: "Internal server error" });
    }
  };

  expressApp.get(
    "/api/calendar/events",
    verifyBrokerSession,
    handleGetCalendarEvents,
  );
  expressApp.post(
    "/api/calendar/events",
    verifyBrokerSession,
    handleCreateCalendarEvent,
  );
  expressApp.put(
    "/api/calendar/events/:eventId",
    verifyBrokerSession,
    handleUpdateCalendarEvent,
  );
  expressApp.delete(
    "/api/calendar/events/:eventId",
    verifyBrokerSession,
    handleDeleteCalendarEvent,
  );
  expressApp.post(
    "/api/calendar/sync-birthdays",
    verifyBrokerSession,
    handleSyncBirthdays,
  );

  // ─── Contact Form ────────────────────────────────────────────────────────

  const handleSubmitContact: RequestHandler = async (req, res) => {
    try {
      const { name, email, phone, subject, message } = req.body as {
        name?: string;
        email?: string;
        phone?: string | null;
        subject?: string;
        message?: string;
      };

      if (
        !name?.trim() ||
        !email?.trim() ||
        !subject?.trim() ||
        !message?.trim()
      ) {
        return res.status(400).json({
          success: false,
          error: "name, email, subject, and message are required",
        });
      }

      const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
      if (!emailRegex.test(email.trim())) {
        return res
          .status(400)
          .json({ success: false, error: "Invalid email address" });
      }

      await pool.execute(
        `INSERT INTO contact_submissions (tenant_id, name, email, phone, subject, message)
         VALUES (?, ?, ?, ?, ?, ?)`,
        [
          MORTGAGE_TENANT_ID,
          name.trim().slice(0, 255),
          email.trim().toLowerCase().slice(0, 255),
          phone?.trim().slice(0, 30) || null,
          subject.trim().slice(0, 255),
          message.trim(),
        ],
      );

      return res.status(201).json({
        success: true,
        message: "Message received. We will be in touch shortly.",
      });
    } catch (err: any) {
      console.error("handleSubmitContact error:", err);
      return res
        .status(500)
        .json({ success: false, error: "Internal server error" });
    }
  };

  const handleGetContactSubmissions: RequestHandler = async (req, res) => {
    try {
      const page = Math.max(1, parseInt(req.query.page as string) || 1);
      const limit = Math.min(
        100,
        Math.max(1, parseInt(req.query.limit as string) || 30),
      );
      const offset = (page - 1) * limit;
      const search = (req.query.search as string) || "";
      const sortBy = (req.query.sortBy as string) || "created_at";
      const sortOrder =
        ((req.query.sortOrder as string) || "DESC").toUpperCase() === "ASC"
          ? "ASC"
          : "DESC";

      const CS_SORT: Record<string, string> = {
        name: "name",
        email: "email",
        subject: "subject",
        created_at: "created_at",
      };
      const safeSortBy = CS_SORT[sortBy] ?? "created_at";

      const searchWhere = search
        ? " AND (name LIKE ? OR email LIKE ? OR subject LIKE ? OR message LIKE ?)"
        : "";
      const searchParams: any[] = search
        ? [`%${search}%`, `%${search}%`, `%${search}%`, `%${search}%`]
        : [];

      const [[countRow]] = (await pool.execute(
        `SELECT COUNT(*) as total FROM contact_submissions WHERE tenant_id = ?${searchWhere}`,
        [MORTGAGE_TENANT_ID, ...searchParams],
      )) as [RowDataPacket[], any];
      const total = Number((countRow as any)?.total || 0);

      const [rows] = await pool.query(
        `SELECT id, name, email, phone, subject, message, is_read, read_by_broker_id, read_at, created_at
         FROM contact_submissions
         WHERE tenant_id = ?${searchWhere}
         ORDER BY ${safeSortBy} ${sortOrder}
         LIMIT ${limit} OFFSET ${offset}`,
        [MORTGAGE_TENANT_ID, ...searchParams],
      );

      return res.json({
        success: true,
        submissions: rows,
        pagination: {
          page,
          limit,
          total,
          totalPages: Math.ceil(total / limit),
        },
      });
    } catch (err: any) {
      console.error("handleGetContactSubmissions error:", err);
      return res
        .status(500)
        .json({ success: false, error: "Internal server error" });
    }
  };

  expressApp.post(
    "/api/contact",
    (expressApp as any).locals.limiters.publicForm,
    handleSubmitContact,
  );
  expressApp.get(
    "/api/contact",
    verifyBrokerSession,
    handleGetContactSubmissions,
  );

  // ─── Realtor Prospecting Pipeline ────────────────────────────────────────

  /**
   * GET /api/realtor-prospects
   * List all realtor prospects for the tenant, filterable by stage/status/search/owner.
   * Returns results scoped to the logged-in broker unless they're superadmin.
   */
  const handleGetRealtorProspects: RequestHandler = async (req, res) => {
    try {
      const brokerId = (req as any).brokerId as number;
      const brokerRole = (req as any).brokerRole as string;
      const {
        stage,
        status,
        search,
        owner_broker_id,
        page = "1",
        limit = "200",
      } = req.query as Record<string, string>;

      const conditions: string[] = ["rp.tenant_id = ?"];
      const params: any[] = [MORTGAGE_TENANT_ID];

      // Non-platform-owner sees only their own or prospects they own / created
      if (brokerRole !== "platform_owner") {
        conditions.push(
          "(rp.created_by_broker_id = ? OR rp.owner_broker_id = ?)",
        );
        params.push(brokerId, brokerId);
      }

      if (stage) {
        conditions.push("rp.stage = ?");
        params.push(stage);
      }
      if (status) {
        conditions.push("rp.status = ?");
        params.push(status);
      }
      if (owner_broker_id) {
        conditions.push("rp.owner_broker_id = ?");
        params.push(parseInt(owner_broker_id));
      }
      if (search) {
        conditions.push(
          "(rp.opportunity_name LIKE ? OR rp.contact_name LIKE ? OR rp.contact_email LIKE ? OR rp.business_name LIKE ?)",
        );
        const s = `%${search}%`;
        params.push(s, s, s, s);
      }

      const whereClause = conditions.join(" AND ");
      const pageNum = Math.max(1, parseInt(page));
      const limitNum = Math.min(500, Math.max(1, parseInt(limit)));
      const offset = (pageNum - 1) * limitNum;

      const [rows] = await pool.query<RowDataPacket[]>(
        `SELECT rp.*,
                ob.first_name AS owner_first_name,
                ob.last_name  AS owner_last_name,
                cb.first_name AS creator_first_name,
                cb.last_name  AS creator_last_name
         FROM realtor_prospects rp
         LEFT JOIN brokers ob ON ob.id = rp.owner_broker_id AND ob.tenant_id = rp.tenant_id
         LEFT JOIN brokers cb ON cb.id = rp.created_by_broker_id AND cb.tenant_id = rp.tenant_id
         WHERE ${whereClause}
         ORDER BY rp.created_at DESC
         LIMIT ? OFFSET ?`,
        [...params, limitNum, offset],
      );

      const [countRows] = await pool.query<RowDataPacket[]>(
        `SELECT COUNT(*) AS total FROM realtor_prospects rp WHERE ${whereClause}`,
        params,
      );
      const total = (countRows[0]?.total as number) || 0;

      res.json({
        success: true,
        prospects: rows.map((r) => ({
          ...r,
          tags: r.tags ?? [],
          followers: r.followers ?? [],
          add_to_refi_rates_dropped: Boolean(r.add_to_refi_rates_dropped),
        })),
        pagination: {
          page: pageNum,
          limit: limitNum,
          total,
          totalPages: Math.ceil(total / limitNum),
        },
      });
    } catch (error) {
      console.error("Error fetching realtor prospects:", error);
      res
        .status(500)
        .json({ success: false, error: "Failed to fetch realtor prospects" });
    }
  };

  /**
   * POST /api/realtor-prospects
   * Create a new realtor prospect opportunity.
   */
  const handleCreateRealtorProspect: RequestHandler = async (req, res) => {
    try {
      const brokerId = (req as any).brokerId as number;
      const {
        opportunity_name,
        stage = "contact_attempted",
        status = "open",
        opportunity_value = 0,
        contact_name,
        contact_email,
        contact_phone,
        business_name,
        opportunity_source,
        tags,
        notes,
        owner_broker_id,
        followers,
        progress_report,
        add_to_refi_rates_dropped = false,
      } = req.body;

      if (!opportunity_name?.trim()) {
        return res
          .status(400)
          .json({ success: false, error: "opportunity_name is required" });
      }

      const VALID_STAGES = [
        "contact_attempted",
        "contacted",
        "appt_set",
        "waiting_for_1st_deal",
        "first_deal_funded",
        "second_deal_funded",
        "top_agent_whale",
      ];
      if (!VALID_STAGES.includes(stage)) {
        return res
          .status(400)
          .json({ success: false, error: "Invalid stage value" });
      }

      const [result] = await pool.query<ResultSetHeader>(
        `INSERT INTO realtor_prospects
           (tenant_id, stage, status, opportunity_name, opportunity_value,
            contact_name, contact_email, contact_phone, business_name,
            opportunity_source, tags, notes, owner_broker_id, followers,
            progress_report, add_to_refi_rates_dropped, created_by_broker_id)
         VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
        [
          MORTGAGE_TENANT_ID,
          stage,
          status,
          opportunity_name.trim(),
          opportunity_value || 0,
          contact_name || null,
          contact_email || null,
          contact_phone || null,
          business_name || null,
          opportunity_source || null,
          tags ? JSON.stringify(tags) : null,
          notes || null,
          owner_broker_id || null,
          followers ? JSON.stringify(followers) : null,
          progress_report || null,
          add_to_refi_rates_dropped ? 1 : 0,
          brokerId,
        ],
      );

      const [newRows] = await pool.query<RowDataPacket[]>(
        `SELECT rp.*,
                ob.first_name AS owner_first_name, ob.last_name AS owner_last_name,
                cb.first_name AS creator_first_name, cb.last_name AS creator_last_name
         FROM realtor_prospects rp
         LEFT JOIN brokers ob ON ob.id = rp.owner_broker_id AND ob.tenant_id = rp.tenant_id
         LEFT JOIN brokers cb ON cb.id = rp.created_by_broker_id AND cb.tenant_id = rp.tenant_id
         WHERE rp.id = ?`,
        [result.insertId],
      );

      const prospect = newRows[0];
      res.status(201).json({
        success: true,
        prospect: {
          ...prospect,
          tags: prospect.tags ?? [],
          followers: prospect.followers ?? [],
          add_to_refi_rates_dropped: Boolean(
            prospect.add_to_refi_rates_dropped,
          ),
        },
        message: "Realtor prospect created successfully",
      });
    } catch (error) {
      console.error("Error creating realtor prospect:", error);
      res
        .status(500)
        .json({ success: false, error: "Failed to create realtor prospect" });
    }
  };

  /**
   * GET /api/realtor-prospects/:id
   * Get a single realtor prospect by ID.
   */
  const handleGetRealtorProspect: RequestHandler = async (req, res) => {
    try {
      const brokerId = (req as any).brokerId as number;
      const brokerRole = (req as any).brokerRole as string;
      const id = parseInt(req.params.id);

      const [rows] = await pool.query<RowDataPacket[]>(
        `SELECT rp.*,
                ob.first_name AS owner_first_name, ob.last_name AS owner_last_name,
                cb.first_name AS creator_first_name, cb.last_name AS creator_last_name
         FROM realtor_prospects rp
         LEFT JOIN brokers ob ON ob.id = rp.owner_broker_id AND ob.tenant_id = rp.tenant_id
         LEFT JOIN brokers cb ON cb.id = rp.created_by_broker_id AND cb.tenant_id = rp.tenant_id
         WHERE rp.id = ? AND rp.tenant_id = ?`,
        [id, MORTGAGE_TENANT_ID],
      );

      if (rows.length === 0) {
        return res
          .status(404)
          .json({ success: false, error: "Prospect not found" });
      }

      const prospect = rows[0];
      if (
        brokerRole !== "platform_owner" &&
        prospect.created_by_broker_id !== brokerId &&
        prospect.owner_broker_id !== brokerId
      ) {
        return res.status(403).json({ success: false, error: "Access denied" });
      }

      res.json({
        success: true,
        prospect: {
          ...prospect,
          tags: prospect.tags ?? [],
          followers: prospect.followers ?? [],
          add_to_refi_rates_dropped: Boolean(
            prospect.add_to_refi_rates_dropped,
          ),
        },
      });
    } catch (error) {
      console.error("Error fetching realtor prospect:", error);
      res
        .status(500)
        .json({ success: false, error: "Failed to fetch realtor prospect" });
    }
  };

  /**
   * PATCH /api/realtor-prospects/:id/stage
   * Update only the stage of a realtor prospect (for drag-and-drop).
   */
  const handleUpdateRealtorProspectStage: RequestHandler = async (req, res) => {
    try {
      const brokerId = (req as any).brokerId as number;
      const brokerRole = (req as any).brokerRole as string;
      const id = parseInt(req.params.id);
      const { stage } = req.body;

      const VALID_STAGES = [
        "contact_attempted",
        "contacted",
        "appt_set",
        "waiting_for_1st_deal",
        "first_deal_funded",
        "second_deal_funded",
        "top_agent_whale",
      ];
      if (!stage || !VALID_STAGES.includes(stage)) {
        return res
          .status(400)
          .json({ success: false, error: "Invalid stage value" });
      }

      const [rows] = await pool.query<RowDataPacket[]>(
        "SELECT id, created_by_broker_id, owner_broker_id FROM realtor_prospects WHERE id = ? AND tenant_id = ?",
        [id, MORTGAGE_TENANT_ID],
      );

      if (rows.length === 0) {
        return res
          .status(404)
          .json({ success: false, error: "Prospect not found" });
      }

      const prospect = rows[0];
      if (
        brokerRole !== "platform_owner" &&
        prospect.created_by_broker_id !== brokerId &&
        prospect.owner_broker_id !== brokerId
      ) {
        return res.status(403).json({ success: false, error: "Access denied" });
      }

      await pool.query(
        "UPDATE realtor_prospects SET stage = ?, updated_at = NOW() WHERE id = ? AND tenant_id = ?",
        [stage, id, MORTGAGE_TENANT_ID],
      );

      // Fire prospect reminder flows for the new stage (non-blocking).
      triggerProspectReminderFlows(id, stage, MORTGAGE_TENANT_ID).catch((err) =>
        console.error(
          `❌ triggerProspectReminderFlows failed for prospect #${id} stage=${stage}:`,
          err,
        ),
      );

      res.json({
        success: true,
        id,
        stage,
        message: "Stage updated successfully",
      });
    } catch (error) {
      console.error("Error updating realtor prospect stage:", error);
      res.status(500).json({ success: false, error: "Failed to update stage" });
    }
  };

