  // GET /api/realtor-broadcasts/:id/recipients — paginated recipient delivery log
  const handleGetBroadcastRecipients: RequestHandler = async (req, res) => {
    try {
      const brokerRole = (req as any).brokerRole as string;
      if (brokerRole !== "platform_owner") {
        return res
          .status(403)
          .json({ success: false, error: "Platform owner access required" });
      }

      const broadcastId = parseInt(req.params.id);
      const page = Math.max(1, parseInt((req.query.page as string) || "1"));
      const limit = Math.min(
        200,
        Math.max(1, parseInt((req.query.limit as string) || "100")),
      );
      const offset = (page - 1) * limit;

      const [rows] = await pool.query<RowDataPacket[]>(
        `SELECT rbr.id, rbr.broadcast_id, rbr.broker_id, rbr.prospect_id,
                COALESCE(
                  rbr.recipient_name,
                  CONCAT_WS(' ', b.first_name, b.last_name),
                  rp.contact_name
                ) AS recipient_name,
                COALESCE(rbr.recipient_email, b.email, rp.contact_email) AS recipient_email,
                COALESCE(rbr.recipient_phone, b.phone, rp.contact_phone) AS recipient_phone,
                rbr.email_status,
                CASE
                  WHEN rbr.sms_status = 'skipped_no_contact'
                    AND COALESCE(rbr.recipient_phone, b.phone, rp.contact_phone) IS NOT NULL
                    AND TRIM(COALESCE(rbr.recipient_phone, b.phone, rp.contact_phone)) != ''
                    AND (b.sms_blast_opted_in = 0 OR c.sms_blast_opted_in = 0)
                    THEN 'opted_out'
                  ELSE rbr.sms_status
                END AS sms_status,
                rbr.email_ext_id, rbr.sms_ext_id, rbr.conversation_id,
                COALESCE(
                  rbr.error_message,
                  CASE
                    WHEN rbr.sms_status = 'skipped_no_contact'
                      AND COALESCE(rbr.recipient_phone, b.phone, rp.contact_phone) IS NOT NULL
                      AND TRIM(COALESCE(rbr.recipient_phone, b.phone, rp.contact_phone)) != ''
                      AND (b.sms_blast_opted_in = 0 OR c.sms_blast_opted_in = 0)
                      THEN 'Recipient opted out of SMS broadcasts'
                    ELSE NULL
                  END
                ) AS error_message,
                rbr.sent_at
         FROM realtor_broadcast_recipients rbr
         LEFT JOIN brokers b
           ON b.id = rbr.broker_id AND b.tenant_id = rbr.tenant_id
         LEFT JOIN realtor_prospects rp
           ON rp.id = rbr.prospect_id AND rp.tenant_id = rbr.tenant_id
         LEFT JOIN clients c
           ON c.tenant_id = rbr.tenant_id
          AND rbr.recipient_email IS NOT NULL
          AND TRIM(rbr.recipient_email) != ''
          AND LOWER(TRIM(c.email)) = LOWER(TRIM(rbr.recipient_email))
         WHERE rbr.broadcast_id = ? AND rbr.tenant_id = ?
         ORDER BY rbr.id ASC
         LIMIT ? OFFSET ?`,
        [broadcastId, MORTGAGE_TENANT_ID, limit, offset],
      );

      const [countRows] = await pool.query<RowDataPacket[]>(
        `SELECT COUNT(*) AS total
         FROM realtor_broadcast_recipients
         WHERE broadcast_id = ? AND tenant_id = ?`,
        [broadcastId, MORTGAGE_TENANT_ID],
      );

      return res.json({
        success: true,
        recipients: rows,
        total: countRows[0]?.total || 0,
      });
    } catch (err) {
      console.error("[Get broadcast recipients] error:", err);
      return res
        .status(500)
        .json({ success: false, error: "Failed to fetch recipients" });
    }
  };

  // DELETE /api/realtor-broadcasts/:id — delete draft or scheduled only
  const handleDeleteBroadcast: RequestHandler = async (req, res) => {
    try {
      const brokerId = (req as any).brokerId as number;
      const brokerRole = (req as any).brokerRole as string;
      const broadcastId = parseInt(req.params.id);
      if (brokerRole !== "platform_owner") {
        return res
          .status(403)
          .json({ success: false, error: "Platform owner access required" });
      }

      const [rows] = await pool.query<RowDataPacket[]>(
        `SELECT id, status FROM realtor_broadcasts
         WHERE id = ? AND tenant_id = ? AND created_by = ?`,
        [broadcastId, MORTGAGE_TENANT_ID, brokerId],
      );
      if (!rows.length) {
        return res
          .status(404)
          .json({ success: false, error: "Broadcast not found" });
      }
      if (!["draft", "scheduled"].includes(rows[0].status)) {
        return res.status(400).json({
          success: false,
          error:
            "Only draft or scheduled broadcasts can be deleted. Sent broadcasts are retained for audit purposes.",
        });
      }

      await quotaService.releaseBroadcastReservation(
        MORTGAGE_TENANT_ID,
        broadcastId,
      );

      await pool.query(
        `DELETE FROM realtor_broadcasts WHERE id = ? AND tenant_id = ?`,
        [broadcastId, MORTGAGE_TENANT_ID],
      );

      await createAuditLog({
        actorType: "broker",
        actorId: brokerId,
        action: "broadcast_deleted",
        entityType: "realtor_broadcast",
        entityId: broadcastId,
      });

      return res.json({ success: true });
    } catch (err) {
      console.error("[Delete broadcast] error:", err);
      return res
        .status(500)
        .json({ success: false, error: "Failed to delete broadcast" });
    }
  };

  // GET /api/realtor-broadcasts/unsubscribe — public CAN-SPAM opt-out link
  const handleBroadcastUnsubscribe: RequestHandler = async (req, res) => {
    try {
      const token = req.query.token as string;
      if (!token) {
        return res.status(400).send("<h3>Invalid unsubscribe link.</h3>");
      }

      const [rows] = await pool.query<RowDataPacket[]>(
        `SELECT rbr.id, rbr.recipient_email, rb.tenant_id
         FROM realtor_broadcast_recipients rbr
         JOIN realtor_broadcasts rb ON rb.id = rbr.broadcast_id
         WHERE rbr.unsubscribe_token = ? LIMIT 1`,
        [token],
      );

      if (!rows.length) {
        return res
          .status(400)
          .send(
            "<h3>This unsubscribe link is invalid or has already been used.</h3>",
          );
      }

      const { recipient_email, tenant_id } = rows[0];

      // Record opt-out (UPSERT — idempotent)
      await pool.query(
        `INSERT IGNORE INTO realtor_email_unsubscribes (tenant_id, email)
         VALUES (?, ?)`,
        [tenant_id, recipient_email],
      );

      // Mark the recipient row
      await pool.query(
        `UPDATE realtor_broadcast_recipients
         SET email_status = 'unsubscribed', updated_at = NOW()
         WHERE unsubscribe_token = ?`,
        [token],
      );

      return res.status(200).send(
        `<html><body style="font-family:sans-serif;padding:40px;max-width:500px;margin:auto;">
            <h2>You've been unsubscribed.</h2>
            <p>You will no longer receive broadcast emails from this platform.</p>
            <p style="color:#999;font-size:13px;">If this was a mistake, please contact your broker.</p>
          </body></html>`,
      );
    } catch (err) {
      console.error("[Broadcast unsubscribe] error:", err);
      return res
        .status(500)
        .send("<h3>An error occurred. Please try again.</h3>");
    }
  };

  // ─── Phase 2: Email open tracking pixel ───────────────────────────────────
  // Public endpoint — embedded in every broadcast email as a 1×1 invisible image.
  // GET /api/track/open/:token
  const TRACKING_PIXEL_GIF = Buffer.from(
    "R0lGODlhAQABAIAAAAAAAP///yH5BAEAAAAALAAAAAABAAEAAAIBRAA7",
    "base64",
  );
  const handleTrackEmailOpen: RequestHandler = async (req, res) => {
    res.set({
      "Content-Type": "image/gif",
      "Cache-Control": "no-store, no-cache, must-revalidate, proxy-revalidate",
      Pragma: "no-cache",
      Expires: "0",
    });
    res.send(TRACKING_PIXEL_GIF);
    // Fire-and-forget status update — do NOT block the pixel response
    const token = req.params.token;
    if (token) {
      pool
        .query(
          `UPDATE realtor_broadcast_recipients
           SET email_status = 'opened', updated_at = NOW()
           WHERE unsubscribe_token = ? AND email_status = 'sent'`,
          [token],
        )
        .catch((err) =>
          console.error("[Open tracking] DB update failed:", err),
        );
    }
  };

  // ─── Phase 2: Re-send failed recipients ───────────────────────────────────
  // POST /api/realtor-broadcasts/:id/resend-failed
  const handleResendFailed: RequestHandler = async (req, res) => {
    let reservedNewly = false;
    const broadcastId = parseInt(req.params.id);
    try {
      const brokerId = (req as any).brokerId as number;
      const brokerRole = (req as any).brokerRole as string;

      if (brokerRole !== "platform_owner") {
        return res
          .status(403)
          .json({ success: false, error: "Platform owner access required" });
      }

      const [bRows] = await pool.query<RowDataPacket[]>(
        `SELECT id, status, is_cancelled, channel, body_sms FROM realtor_broadcasts
         WHERE id = ? AND tenant_id = ?`,
        [broadcastId, MORTGAGE_TENANT_ID],
      );
      if (!bRows.length) {
        return res
          .status(404)
          .json({ success: false, error: "Broadcast not found" });
      }
      const effectiveStatus = bRows[0].is_cancelled
        ? "cancelled"
        : bRows[0].status;
      const broadcastSmsBody = String(bRows[0].body_sms || "");
      logBroadcastTrace("resend_failed_requested", {
        broadcastId,
        brokerId,
        rawStatus: bRows[0].status,
        effectiveStatus,
        channel: bRows[0].channel,
      });
      if (["sending", "draft", "scheduled"].includes(effectiveStatus)) {
        return res.status(400).json({
          success: false,
          error:
            "Cannot retry while broadcast is in draft/scheduled/sending state",
        });
      }

      const channel: string = bRows[0].channel;
      const [failedRows] = await pool.query<RowDataPacket[]>(
        `SELECT
           SUM(
             CASE
               WHEN (? IN ('email','both'))
                    AND email_status = 'failed'
                    AND recipient_email IS NOT NULL
                    AND TRIM(recipient_email) != ''
               THEN 1 ELSE 0
             END
           ) AS email_failed,
           SUM(
             CASE
               WHEN (? IN ('sms','both'))
                    AND sms_status = 'failed'
                    AND recipient_phone IS NOT NULL
                    AND TRIM(recipient_phone) != ''
               THEN 1 ELSE 0
             END
           ) AS sms_failed
         FROM realtor_broadcast_recipients
         WHERE broadcast_id = ? AND tenant_id = ?`,
        [channel, channel, broadcastId, MORTGAGE_TENANT_ID],
      );
      const emailFailed = Number(failedRows[0]?.email_failed ?? 0);
      const smsFailed = Number(failedRows[0]?.sms_failed ?? 0);
      const retriableUnits = emailFailed + smsFailed;
      if (!retriableUnits) {
        return res.json({ success: true, retried: 0 });
      }
      const hasOutstanding =
        await quotaService.hasOutstandingBroadcastReservation(
          MORTGAGE_TENANT_ID,
          broadcastId,
        );
      if (!hasOutstanding) {
        const reserve = await reserveBroadcastQuota({
          tenantId: MORTGAGE_TENANT_ID,
          broadcastId,
          channel,
          smsBody: broadcastSmsBody,
          estimatedEmailUnits: emailFailed,
          estimatedSmsUnits: smsFailed,
        });
        if (!reserve.ok) {
          return res.status(402).json({
            ...(reserve.denial ??
              quotaExceededPayload(reserve.quota.sms_segments)),
            quota: reserve.quota,
          });
        }
        reservedNewly = true;
      }
      const setClauses: string[] = [];
      if (channel === "email" || channel === "both") {
        setClauses.push(
          "email_status = CASE WHEN email_status = 'failed' THEN 'pending' ELSE email_status END",
        );
      }
      if (channel === "sms" || channel === "both") {
        setClauses.push(
          "sms_status = CASE WHEN sms_status = 'failed' THEN 'pending' ELSE sms_status END",
        );
      }

      const [updateResult] = await pool.query<ResultSetHeader>(
        `UPDATE realtor_broadcast_recipients
         SET ${setClauses.join(", ")}, error_message = NULL, updated_at = NOW()
         WHERE broadcast_id = ? AND tenant_id = ?`,
        [broadcastId, MORTGAGE_TENANT_ID],
      );

      if (!updateResult.affectedRows) {
        await quotaService.releaseBroadcastReservation(
          MORTGAGE_TENANT_ID,
          broadcastId,
        );
        logBroadcastTrace("resend_failed_noop", {
          broadcastId,
          reason: "No recipient rows updated",
        });
        return res.json({ success: true, retried: 0 });
      }

      // Move broadcast back to sending so the UI reflects progress
      await pool.query(
        `UPDATE realtor_broadcasts
         SET status = 'sending',
             is_cancelled = 0,
             completed_at = NULL,
             started_at = COALESCE(started_at, NOW()),
             updated_at = NOW()
         WHERE id = ? AND tenant_id = ?`,
        [broadcastId, MORTGAGE_TENANT_ID],
      );

      // Fire send loop — processes only newly-pending recipients
      sendBroadcastAsync(broadcastId).catch((err) =>
        console.error(`[Resend failed] Broadcast #${broadcastId} error:`, err),
      );
      logBroadcastTrace("resend_failed_queued", {
        broadcastId,
        retriedRows: updateResult.affectedRows,
      });

      await createAuditLog({
        actorType: "broker",
        actorId: brokerId,
        action: "broadcast_resend_failed",
        entityType: "realtor_broadcast",
        entityId: broadcastId,
      });

      return res.json({ success: true, retried: updateResult.affectedRows });
    } catch (err) {
      if (reservedNewly && Number.isFinite(broadcastId)) {
        await quotaService
          .releaseBroadcastReservation(MORTGAGE_TENANT_ID, broadcastId)
          .catch((releaseErr) =>
            console.error("[Resend failed] reservation release:", releaseErr),
          );
      }
      console.error("[Resend failed] error:", err);
      return res.status(500).json({ success: false, error: "Failed to retry" });
    }
  };

  // ─── Phase 4: Re-trigger pending recipients safely ────────────────────────
  // POST /api/realtor-broadcasts/:id/resend-pending
  const handleResendPending: RequestHandler = async (req, res) => {
    let reservedNewly = false;
    const broadcastId = parseInt(req.params.id);
    try {
      const brokerId = (req as any).brokerId as number;
      const brokerRole = (req as any).brokerRole as string;

      if (brokerRole !== "platform_owner") {
        return res
          .status(403)
          .json({ success: false, error: "Platform owner access required" });
      }

      const [bRows] = await pool.query<RowDataPacket[]>(
        `SELECT id, status, is_cancelled, channel, body_sms FROM realtor_broadcasts
         WHERE id = ? AND tenant_id = ?`,
        [broadcastId, MORTGAGE_TENANT_ID],
      );
      if (!bRows.length) {
        return res
          .status(404)
          .json({ success: false, error: "Broadcast not found" });
      }
      const effectiveStatus = bRows[0].is_cancelled
        ? "cancelled"
        : bRows[0].status;
      const broadcastSmsBody = String(bRows[0].body_sms || "");
      logBroadcastTrace("resend_pending_requested", {
        broadcastId,
        brokerId,
        rawStatus: bRows[0].status,
        effectiveStatus,
        channel: bRows[0].channel,
      });
      if (["sending", "draft", "scheduled"].includes(effectiveStatus)) {
        return res.status(400).json({
          success: false,
          error:
            "Cannot re-trigger pending recipients while broadcast is in draft/scheduled/sending state",
        });
      }

      const channel: string = bRows[0].channel;

      // Rehydrate skipped rows from latest CRM contact data so previously
      // unreachable recipients become re-triggerable after profile updates.
      if (channel === "email" || channel === "both") {
        await pool.query(
          `UPDATE realtor_broadcast_recipients rbr
           JOIN brokers b ON b.id = rbr.broker_id AND b.tenant_id = rbr.tenant_id
           SET rbr.recipient_email = b.email,
               rbr.email_status = CASE
                 WHEN rbr.email_status = 'skipped_no_contact'
                      AND b.email IS NOT NULL AND TRIM(b.email) != ''
                 THEN 'pending'
                 ELSE rbr.email_status
               END,
               rbr.updated_at = NOW()
           WHERE rbr.broadcast_id = ? AND rbr.tenant_id = ?
             AND rbr.email_status = 'skipped_no_contact'`,
          [broadcastId, MORTGAGE_TENANT_ID],
        );
        await pool.query(
          `UPDATE realtor_broadcast_recipients rbr
           JOIN realtor_prospects rp ON rp.id = rbr.prospect_id AND rp.tenant_id = rbr.tenant_id
           SET rbr.recipient_email = rp.contact_email,
               rbr.email_status = CASE
                 WHEN rbr.email_status = 'skipped_no_contact'
                      AND rp.contact_email IS NOT NULL AND TRIM(rp.contact_email) != ''
                 THEN 'pending'
                 ELSE rbr.email_status
               END,
               rbr.updated_at = NOW()
           WHERE rbr.broadcast_id = ? AND rbr.tenant_id = ?
             AND rbr.email_status = 'skipped_no_contact'`,
          [broadcastId, MORTGAGE_TENANT_ID],
        );
        await pool.query(
          `UPDATE realtor_broadcast_recipients rbr
           JOIN clients c
             ON c.tenant_id = rbr.tenant_id
            AND rbr.recipient_phone IS NOT NULL
            AND TRIM(rbr.recipient_phone) != ''
            AND RIGHT(REGEXP_REPLACE(c.phone, '[^0-9]', ''), 10)
                = RIGHT(REGEXP_REPLACE(rbr.recipient_phone, '[^0-9]', ''), 10)
           SET rbr.recipient_email = c.email,
               rbr.email_status = CASE
                 WHEN rbr.email_status = 'skipped_no_contact'
                      AND c.email IS NOT NULL AND TRIM(c.email) != ''
                 THEN 'pending'
                 ELSE rbr.email_status
               END,
               rbr.updated_at = NOW()
           WHERE rbr.broadcast_id = ? AND rbr.tenant_id = ?
             AND rbr.email_status = 'skipped_no_contact'`,
          [broadcastId, MORTGAGE_TENANT_ID],
        );
      }

      if (channel === "sms" || channel === "both") {
        await pool.query(
          `UPDATE realtor_broadcast_recipients rbr
           JOIN brokers b ON b.id = rbr.broker_id AND b.tenant_id = rbr.tenant_id
           SET rbr.recipient_phone = CASE
                 WHEN COALESCE(b.sms_blast_opted_in, 1) = 1 THEN b.phone
                 ELSE rbr.recipient_phone
               END,
               rbr.sms_status = CASE
                 WHEN rbr.sms_status = 'skipped_no_contact'
                      AND COALESCE(b.sms_blast_opted_in, 1) = 1
                      AND b.phone IS NOT NULL AND TRIM(b.phone) != ''
                 THEN 'pending'
                 ELSE rbr.sms_status
               END,
               rbr.updated_at = NOW()
           WHERE rbr.broadcast_id = ? AND rbr.tenant_id = ?
             AND rbr.sms_status = 'skipped_no_contact'`,
          [broadcastId, MORTGAGE_TENANT_ID],
        );
        await pool.query(
          `UPDATE realtor_broadcast_recipients rbr
           JOIN realtor_prospects rp ON rp.id = rbr.prospect_id AND rp.tenant_id = rbr.tenant_id
           SET rbr.recipient_phone = rp.contact_phone,
               rbr.sms_status = CASE
                 WHEN rbr.sms_status = 'skipped_no_contact'
                      AND rp.contact_phone IS NOT NULL AND TRIM(rp.contact_phone) != ''
                 THEN 'pending'
                 ELSE rbr.sms_status
               END,
               rbr.updated_at = NOW()
           WHERE rbr.broadcast_id = ? AND rbr.tenant_id = ?
             AND rbr.sms_status = 'skipped_no_contact'`,
          [broadcastId, MORTGAGE_TENANT_ID],
        );
        await pool.query(
          `UPDATE realtor_broadcast_recipients rbr
           JOIN clients c
             ON c.tenant_id = rbr.tenant_id
            AND rbr.recipient_email IS NOT NULL
            AND TRIM(rbr.recipient_email) != ''
            AND LOWER(TRIM(c.email)) = LOWER(TRIM(rbr.recipient_email))
           SET rbr.recipient_phone = c.phone,
               rbr.sms_status = CASE
                 WHEN rbr.sms_status = 'skipped_no_contact'
                      AND COALESCE(c.sms_blast_opted_in, 1) = 1
                      AND c.phone IS NOT NULL AND TRIM(c.phone) != ''
                 THEN 'pending'
                 ELSE rbr.sms_status
               END,
               rbr.updated_at = NOW()
           WHERE rbr.broadcast_id = ? AND rbr.tenant_id = ?
             AND rbr.sms_status = 'skipped_no_contact'`,
          [broadcastId, MORTGAGE_TENANT_ID],
        );
      }

      const [pendingRows] = await pool.query<RowDataPacket[]>(
        `SELECT
           SUM(
             CASE
               WHEN (? IN ('email','both'))
                    AND email_status = 'pending'
                    AND recipient_email IS NOT NULL
                    AND TRIM(recipient_email) != ''
               THEN 1 ELSE 0
             END
           ) AS email_pending,
           SUM(
             CASE
               WHEN (? IN ('sms','both'))
                    AND sms_status = 'pending'
                    AND recipient_phone IS NOT NULL
                    AND TRIM(recipient_phone) != ''
               THEN 1 ELSE 0
             END
           ) AS sms_pending
         FROM realtor_broadcast_recipients
         WHERE broadcast_id = ? AND tenant_id = ?`,
        [channel, channel, broadcastId, MORTGAGE_TENANT_ID],
      );

      const emailPending = Number(pendingRows[0]?.email_pending ?? 0);
      const smsPending = Number(pendingRows[0]?.sms_pending ?? 0);
      const retried = emailPending + smsPending;
      if (!retried) {
        logBroadcastTrace("resend_pending_noop", {
          broadcastId,
          emailPending,
          smsPending,
        });
        return res.json({ success: true, retried: 0 });
      }
      const hasOutstanding =
        await quotaService.hasOutstandingBroadcastReservation(
          MORTGAGE_TENANT_ID,
          broadcastId,
        );
      if (!hasOutstanding) {
        const reserve = await reserveBroadcastQuota({
          tenantId: MORTGAGE_TENANT_ID,
          broadcastId,
          channel,
          smsBody: broadcastSmsBody,
          estimatedEmailUnits: emailPending,
          estimatedSmsUnits: smsPending,
        });
        if (!reserve.ok) {
          return res.status(402).json({
            ...(reserve.denial ??
              quotaExceededPayload(reserve.quota.sms_segments)),
            quota: reserve.quota,
          });
        }
        reservedNewly = true;
      }

      // Move broadcast back to sending; clear cancellation for intentional re-run.
      await pool.query(
        `UPDATE realtor_broadcasts
         SET status = 'sending',
             is_cancelled = 0,
             completed_at = NULL,
             started_at = COALESCE(started_at, NOW()),
             updated_at = NOW()
         WHERE id = ? AND tenant_id = ?`,
        [broadcastId, MORTGAGE_TENANT_ID],
      );

      sendBroadcastAsync(broadcastId).catch((err) =>
        console.error(`[Resend pending] Broadcast #${broadcastId} error:`, err),
      );
      logBroadcastTrace("resend_pending_queued", {
        broadcastId,
        retried,
        emailPending,
        smsPending,
      });

      await createAuditLog({
        actorType: "broker",
        actorId: brokerId,
        action: "broadcast_resend_pending",
        entityType: "realtor_broadcast",
        entityId: broadcastId,
        changes: { retried, emailPending, smsPending },
      });

      return res.json({ success: true, retried });
    } catch (err) {
      if (reservedNewly && Number.isFinite(broadcastId)) {
        await quotaService
          .releaseBroadcastReservation(MORTGAGE_TENANT_ID, broadcastId)
          .catch((releaseErr) =>
            console.error("[Resend pending] reservation release:", releaseErr),
          );
      }
      console.error("[Resend pending] error:", err);
      return res.status(500).json({
        success: false,
        error: "Failed to re-trigger pending recipients",
      });
    }
  };

  // ─── Phase 2: Export recipients as CSV ────────────────────────────────────
  // GET /api/realtor-broadcasts/:id/recipients/export
  const handleExportBroadcastRecipients: RequestHandler = async (req, res) => {
    try {
      const brokerRole = (req as any).brokerRole as string;
      if (brokerRole !== "platform_owner") {
        return res
          .status(403)
          .json({ success: false, error: "Platform owner access required" });
      }

      const broadcastId = parseInt(req.params.id);
      const [bRows] = await pool.query<RowDataPacket[]>(
        `SELECT title FROM realtor_broadcasts WHERE id = ? AND tenant_id = ?`,
        [broadcastId, MORTGAGE_TENANT_ID],
      );
      if (!bRows.length) {
        return res
          .status(404)
          .json({ success: false, error: "Broadcast not found" });
      }

      const [rows] = await pool.query<RowDataPacket[]>(
        `SELECT recipient_name, recipient_email, recipient_phone,
                email_status, sms_status, ab_variant, error_message, sent_at
         FROM realtor_broadcast_recipients
         WHERE broadcast_id = ? AND tenant_id = ?
         ORDER BY id ASC`,
        [broadcastId, MORTGAGE_TENANT_ID],
      );

      const escape = (v: string | null | undefined) =>
        `"${(v ?? "").toString().replace(/"/g, '""').slice(0, 500)}"`;

      const header =
        "Name,Email,Phone,Email Status,SMS Status,A/B Variant,Error,Sent At";
      const csvLines = (rows as any[]).map((r) =>
        [
          escape(r.recipient_name),
          escape(r.recipient_email),
          escape(r.recipient_phone),
          r.email_status ?? "",
          r.sms_status ?? "",
          r.ab_variant ?? "",
          escape(r.error_message),
          r.sent_at ? new Date(r.sent_at).toISOString() : "",
        ].join(","),
      );

      const csv = [header, ...csvLines].join("\n");
      const safeTitle = (bRows[0].title ?? "broadcast")
        .replace(/[^a-z0-9]/gi, "-")
        .toLowerCase()
        .slice(0, 40);

      res.setHeader("Content-Type", "text/csv; charset=utf-8");
      res.setHeader(
        "Content-Disposition",
        `attachment; filename="broadcast-${broadcastId}-${safeTitle}.csv"`,
      );
      return res.send(csv);
    } catch (err) {
      console.error("[Export broadcast recipients] error:", err);
      return res
        .status(500)
        .json({ success: false, error: "Failed to export" });
    }
  };

  // ─── Phase 3: Saved audience segments ─────────────────────────────────────

  // GET /api/broadcast-segments
  const handleGetSavedSegments: RequestHandler = async (req, res) => {
    try {
      const brokerRole = (req as any).brokerRole as string;
      if (brokerRole !== "platform_owner") {
        return res
          .status(403)
          .json({ success: false, error: "Platform owner access required" });
      }
      const [rows] = await pool.query<RowDataPacket[]>(
        `SELECT id, name, filter_json, created_at
         FROM broadcast_saved_segments
         WHERE tenant_id = ?
         ORDER BY created_at DESC`,
        [MORTGAGE_TENANT_ID],
      );
      return res.json({
        success: true,
        segments: rows.map((r) => ({
          ...r,
          filter_json:
            typeof r.filter_json === "string"
              ? safeJsonParse(r.filter_json, null)
              : r.filter_json,
        })),
      });
    } catch (err) {
      console.error("[Get saved segments] error:", err);
      return res
        .status(500)
        .json({ success: false, error: "Failed to fetch segments" });
    }
  };

  // POST /api/broadcast-segments
  const handleCreateSavedSegment: RequestHandler = async (req, res) => {
    try {
      const brokerId = (req as any).brokerId as number;
      const brokerRole = (req as any).brokerRole as string;
      if (brokerRole !== "platform_owner") {
        return res
          .status(403)
          .json({ success: false, error: "Platform owner access required" });
      }
      const { name, filter_json } = req.body as {
        name: string;
        filter_json: any;
      };
      if (!name?.trim() || !filter_json) {
        return res
          .status(400)
          .json({ success: false, error: "name and filter_json are required" });
      }
      const [result] = await pool.query<ResultSetHeader>(
        `INSERT INTO broadcast_saved_segments (tenant_id, created_by, name, filter_json)
         VALUES (?, ?, ?, ?)`,
        [
          MORTGAGE_TENANT_ID,
          brokerId,
          name.trim(),
          JSON.stringify(filter_json),
        ],
      );
      return res.status(201).json({ success: true, id: result.insertId });
    } catch (err) {
      console.error("[Create saved segment] error:", err);
      return res
        .status(500)
        .json({ success: false, error: "Failed to save segment" });
    }
  };

  // DELETE /api/broadcast-segments/:id
  const handleDeleteSavedSegment: RequestHandler = async (req, res) => {
    try {
      const brokerId = (req as any).brokerId as number;
      const brokerRole = (req as any).brokerRole as string;
      if (brokerRole !== "platform_owner") {
        return res
          .status(403)
          .json({ success: false, error: "Platform owner access required" });
      }
      const segmentId = parseInt(req.params.id);
      await pool.query(
        `DELETE FROM broadcast_saved_segments
         WHERE id = ? AND tenant_id = ? AND created_by = ?`,
        [segmentId, MORTGAGE_TENANT_ID, brokerId],
      );
      return res.json({ success: true });
    } catch (err) {
      console.error("[Delete saved segment] error:", err);
      return res
        .status(500)
        .json({ success: false, error: "Failed to delete segment" });
    }
  };

  // Cron: process scheduled broadcasts every 5 min
  // curl -s "https://admin.encoremortgage.org/api/cron/process-scheduled-broadcasts?secret=CRON_SECRET"
  const handleProcessScheduledBroadcasts: RequestHandler = async (req, res) => {
    const secret = req.query.secret;
    if (secret !== process.env.CRON_SECRET) {
      return res.status(401).json({ error: "Unauthorized" });
    }

    try {
      const [due] = await pool.query<RowDataPacket[]>(
        `SELECT id FROM realtor_broadcasts
         WHERE status = 'scheduled'
           AND scheduled_at <= NOW()
           AND is_cancelled = 0
         ORDER BY scheduled_at ASC
         LIMIT 10`,
      );
      logBroadcastTrace("scheduled_cron_due_loaded", {
        dueCount: due.length,
        dueBroadcastIds: due.map((r) => r.id),
      });

      for (const row of due) {
        // Mark sending before firing — prevents double-pickup
        await pool.query(
          `UPDATE realtor_broadcasts
           SET status = 'sending', started_at = NOW(), updated_at = NOW()
           WHERE id = ?`,
          [row.id],
        );
        sendBroadcastAsync(row.id).catch((err) =>
          console.error(`❌ Scheduled broadcast #${row.id} failed:`, err),
        );
        logBroadcastTrace("scheduled_cron_dispatched", {
          broadcastId: row.id,
        });
      }

      return res.json({ success: true, fired: due.length });
    } catch (err) {
      console.error("[Scheduled broadcasts cron] error:", err);
      return res.status(500).json({ success: false, error: "Cron failed" });
    }
  };

